import os
import json
import typing
import tempfile
import uuid
from pathlib import Path

_MAX_JSON_ITEM_LENGTH = 10_000


def _get_safe_base_dir() -> Path:
    """Return the safe base directory at call time."""
    return Path.cwd().resolve()


def _is_within_base(path: Path, base: Path) -> bool:
    """Return True if *path* is inside *base* (including the base itself)."""
    try:
        return path.is_relative_to(base)  # Python â¥3.9
    except AttributeError:
        # Fallback for older Python versions
        try:
            path = path.resolve()
            base = base.resolve()
        except RuntimeError:
            return False
        return base == path or base in path.parents


def generate_candidate_set(
    gen_func: typing.Callable[[], typing.Iterable],
    max_size: int,
    output_path: str = "candidates.json",
) -> set:
    """
    Generate a set of candidates using ``gen_func`` ensuring the set size equals ``max_size``.
    Writes the persisted candidate list to ``output_path`` as JSON inside a safe base directory.
    """

    # Input validation
    if not callable(gen_func):
        raise ValueError("gen_func must be callable")
    if not isinstance(max_size, int) or max_size <= 0:
        raise ValueError("max_size must be a positive integer")
    if not isinstance(output_path, str) or not output_path.strip():
        raise ValueError("output_path must be a nonâempty string")

    # Candidate generation
    candidates: set = set()
    try:
        for item in gen_func():
            # Prepare a JSONâserializable immutable representation
            if isinstance(item, (list, dict)):
                try:
                    json_str = json.dumps(
                        item,
                        sort_keys=True,
                        separators=(",", ":"),
                    )
                except (TypeError, ValueError):
                    continue
                if len(json_str) > _MAX_JSON_ITEM_LENGTH:
                    continue
                immutable_item = json_str
            elif isinstance(item, (str, int, float, bool, type(None))):
                immutable_item = item
            else:
                # Skip untrusted or nonâserializable types
                continue

            # Verify JSON serializability of the final value
            try:
                json.dumps(immutable_item)
            except (TypeError, ValueError):
                continue

            # At this point the item is safe to hash (builtâin immutable types)
            try:
                hash(immutable_item)
            except Exception as exc:
                raise RuntimeError("Unexpected error during hashing") from exc

            candidates.add(immutable_item)
            if len(candidates) >= max_size:
                break
    except Exception as e:
        raise RuntimeError("Error while generating candidates") from e

    if len(candidates) != max_size:
        raise AssertionError(
            f"Candidate set size {len(candidates)} does not match required max_size {max_size}"
        )

    # Resolve and validate output path
    base_dir = _get_safe_base_dir()
    output_file = Path(output_path).expanduser()
    if not output_file.is_absolute():
        output_file = (base_dir / output_file).resolve()
    else:
        output_file = output_file.resolve()

    if not _is_within_base(output_file, base_dir):
        raise ValueError("output_path must reside within the safe base directory")

    # Prepare output directory securely
    output_dir = output_file.parent
    try:
        # Create directory with strict permissions if it does not exist
        output_dir.mkdir(parents=True, mode=0o700, exist_ok=True)
        # Ensure the directory itself is not a symlink (TOCTOU mitigation)
        if output_dir.is_symlink():
            raise RuntimeError("Output directory resolves to a symlink")
        # Reâvalidate after creation
        if not _is_within_base(output_dir.resolve(), base_dir):
            raise RuntimeError("Output directory is outside of safe base directory")
    except Exception as e:
        raise RuntimeError("Failed to prepare output directory") from e

    # Secure atomic write using a temporary file with O_NOFOLLOW
    try:
        temp_name = f".tmp_{uuid.uuid4().hex}"
        temp_path = output_dir / temp_name
        flags = (
            os.O_WRONLY
            | os.O_CREAT
            | os.O_EXCL
            | getattr(os, "O_NOFOLLOW", 0)
        )
        fd = os.open(str(temp_path), flags, 0o600)
        try:
            with os.fdopen(fd, "w", encoding="utf-8") as tmp_file:
                json.dump(list(candidates), tmp_file, ensure_ascii=False, indent=2)
        except Exception:
            os.close(fd)
            raise
        # Final path validation before replace
        final_path = output_file.resolve()
        if not _is_within_base(final_path, base_dir):
            raise RuntimeError("Final output path is outside of safe base directory")
        os.replace(str(temp_path), str(output_file))
    except Exception as e:
        # Cleanup temporary file on failure
        try:
            if temp_path.exists():
                temp_path.unlink()
        except Exception:
            pass
        raise RuntimeError("Failed to write candidates to file") from e

    return candidates

import secrets
from typing import Any, List, Tuple, Sequence

_MAX_DIMENSION_DEPTH = 10
_MAX_DIMENSION_SIZE = 10_000


def _validate_dimensions(array: Any, dims: Sequence[int]) -> None:
    # dims must be a nonâempty list or tuple of positive integers (bool excluded)
    if not isinstance(dims, (list, tuple)):
        raise TypeError("Dimensions must be provided as a list or tuple")
    if not dims:
        raise ValueError("Dimensions sequence cannot be empty")
    if len(dims) > _MAX_DIMENSION_DEPTH:
        raise ValueError(f"Dimensions depth exceeds maximum of {_MAX_DIMENSION_DEPTH}")

    for d in dims:
        if isinstance(d, bool) or not isinstance(d, int):
            raise TypeError("All dimension sizes must be integers")
        if d <= 0:
            raise ValueError("Dimension sizes must be positive integers")
        if d > _MAX_DIMENSION_SIZE:
            raise ValueError(f"Dimension size {d} exceeds maximum of {_MAX_DIMENSION_SIZE}")

    # array must be a list or tuple
    if not isinstance(array, (list, tuple)):
        raise TypeError("Array must be a list or tuple")

    def _check(arr: Any, expected: Sequence[int], depth: int = 0) -> None:
        if depth >= len(expected):
            return
        if not isinstance(arr, (list, tuple)):
            raise TypeError("Array structure does not match dimensions")
        if len(arr) != expected[depth]:
            raise ValueError("Array size mismatches provided dimensions")
        for sub in arr:
            _check(sub, expected, depth + 1)

    _check(array, dims)


def _generate_intervals(dims: Sequence[int]) -> List[Tuple[int, int]]:
    intervals: List[Tuple[int, int]] = []
    for size in dims:
        start = secrets.randbelow(size)
        # size - start is guaranteed > 0
        end = start + secrets.randbelow(size - start)
        intervals.append((start, end))
    return intervals


def _slice_recursive(arr: Any, intervals: List[Tuple[int, int]], depth: int = 0) -> Any:
    if depth >= len(intervals):
        return arr
    if depth > _MAX_DIMENSION_DEPTH:
        raise RecursionError("Maximum recursion depth exceeded")
    start, end = intervals[depth]
    sliced = arr[start : end + 1]
    return [_slice_recursive(sub, intervals, depth + 1) for sub in sliced]


def random_subarray(original: List[Any], dimensions: List[int]) -> Any:
    try:
        _validate_dimensions(original, dimensions)
        intervals = _generate_intervals(dimensions)
        return _slice_recursive(original, intervals)
    except (TypeError, ValueError, RecursionError) as e:
        raise ValueError("Invalid input for random_subarray") from e

