import json
import threading
import logging
from typing import Any, Callable, Dict, Type, Optional

# Configure logger for internal diagnostics (do not expose to end users)
_logger = logging.getLogger(__name__)
_handler = logging.StreamHandler()
_formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
_handler.setFormatter(_formatter)
_logger.addHandler(_handler)
_logger.setLevel(logging.WARNING)


class SecureJSONError(Exception):
    """Base exception for secure JSON operations."""
    pass


class JSONSerializable:
    """
    Base class providing secure JSON serialization / deserialization.
    Subclasses may extend functionality while keeping security guarantees.
    """

    __slots__ = ('_data',)

    def __init__(self, data: Optional[Dict[str, Any]] = None) -> None:
        if data is None:
            data = {}
        if not isinstance(data, dict):
            raise SecureJSONError("Initialization data must be a dictionary.")
        # Store a shallow copy to prevent external mutation
        self._data = dict(data)

    @property
    def data(self) -> Dict[str, Any]:
        """Readâonly view of internal data."""
        return dict(self._data)

    def to_json(self) -> str:
        """
        Convert the internal data to a JSON string.
        Uses safe defaults and deterministic output.
        """
        try:
            json_str = json.dumps(
                self._data,
                ensure_ascii=False,
                sort_keys=True,
                separators=(',', ':')
            )
            return json_str
        except (TypeError, ValueError) as exc:
            _logger.exception("Failed to serialize to JSON.")
            raise SecureJSONError("Unable to serialize object to JSON.") from exc

    @classmethod
    def _check_depth_and_size(
        cls,
        obj: Any,
        max_depth: int = 20,
        max_items: int = 1000,
        _current_depth: int = 0,
        _item_counter: list = None
    ) -> None:
        """
        Recursively ensure the parsed JSON object does not exceed depth or item limits.
        """
        if _item_counter is None:
            _item_counter = [0]  # mutable counter shared across recursions

        if _current_depth > max_depth:
            raise SecureJSONError(f"JSON structure exceeds maximum depth of {max_depth}.")

        if isinstance(obj, dict):
            _item_counter[0] += len(obj)
            if _item_counter[0] > max_items:
                raise SecureJSONError(f"JSON contains more than {max_items} items.")
            for v in obj.values():
                cls._check_depth_and_size(v, max_depth, max_items, _current_depth + 1, _item_counter)
        elif isinstance(obj, list):
            _item_counter[0] += len(obj)
            if _item_counter[0] > max_items:
                raise SecureJSONError(f"JSON contains more than {max_items} items.")
            for item in obj:
                cls._check_depth_and_size(item, max_depth, max_items, _current_depth + 1, _item_counter)

    @classmethod
    def from_json(cls: Type['JSONSerializable'], json_str: str) -> 'JSONSerializable':
        """
        Create an instance from a JSON string.
        Validates input type, size, and structural limits before parsing.
        """
        if not isinstance(json_str, str):
            raise SecureJSONError("Input must be a JSON string.")
        # Limit size to mitigate DoS (e.g., 1â¯MiB)
        max_length = 1 * 1024 * 1024
        if len(json_str) > max_length:
            raise SecureJSONError("JSON string exceeds allowed size.")
        try:
            obj = json.loads(json_str)
            # Enforce depth and item limits
            cls._check_depth_and_size(obj)
            if not isinstance(obj, dict):
                raise SecureJSONError("Topâlevel JSON must be an object.")
            return cls(obj)
        except json.JSONDecodeError as exc:
            _logger.exception("Invalid JSON input.")
            raise SecureJSONError("Invalid JSON format.") from exc
        except SecureJSONError:
            raise
        except Exception as exc:
            _logger.exception("Unexpected error during JSON parsing.")
            raise SecureJSONError("Error processing JSON input.") from exc


# Registry for factory functions
_factory_registry: Dict[str, Callable[..., JSONSerializable]] = {}
_registry_lock = threading.Lock()


def register_factory(
    factory_id: str,
    factory_func: Callable[..., JSONSerializable],
    *,
    allow_overwrite: bool = False
) -> None:
    """
    Register a factory function under a unique identifier.

    Args:
        factory_id: Nonâempty string identifier for the factory.
        factory_func: Callable that returns a JSONSerializable instance.
        allow_overwrite: If False (default), attempting to register an existing ID raises an error.
    """
    if not isinstance(factory_id, str) or not factory_id:
        raise SecureJSONError("Factory ID must be a nonâempty string.")
    if not callable(factory_func):
        raise SecureJSONError("Factory function must be callable.")

    with _registry_lock:
        if not allow_overwrite and factory_id in _factory_registry:
            raise SecureJSONError(f"Factory ID '{factory_id}' is already registered.")
        _factory_registry[factory_id] = factory_func
    # No debug logging to avoid leaking internal identifiers


def create_instance(factory_id: str, *args: Any, **kwargs: Any) -> JSONSerializable:
    """
    Create a new instance using the factory associated with the given ID.
    Additional positional and keyword arguments are forwarded to the factory.
    """
    if not isinstance(factory_id, str) or not factory_id:
        raise SecureJSONError("Factory ID must be a nonâempty string.")
    with _registry_lock:
        factory = _factory_registry.get(factory_id)
    if factory is None:
        raise SecureJSONError(f"No factory registered for ID '{factory_id}'.")
    try:
        instance = factory(*args, **kwargs)
        if not isinstance(instance, JSONSerializable):
            raise SecureJSONError("Factory did not return a JSONSerializable instance.")
        return instance
    except Exception as exc:  # pylint: disable=broad-except
        _logger.exception("Factory execution failed for ID: %s", factory_id)
        raise SecureJSONError("Error creating instance via factory.") from exc


# Example subclass (can be defined elsewhere)
class User(JSONSerializable):
    def __init__(self, username: str, email: str) -> None:
        if not isinstance(username, str) or not isinstance(email, str):
            raise SecureJSONError("Username and email must be strings.")
        super().__init__({'username': username, 'email': email})


# Register example factory (illustrative; registration occurs at import time)
def _user_factory(username: str, email: str) -> User:
    return User(username=username, email=email)


register_factory('user', _user_factory)

