import re
import base64
import binascii

# Fallback implementation for OneLogin_Saml2_Utils when the real library is unavailable
try:
    from onelogin.saml2.utils import OneLogin_Saml2_Utils  # type: ignore
except ImportError:
    class OneLogin_Saml2_Utils:
        @staticmethod
        def format_private_key(pkey: str) -> str:
            if not isinstance(pkey, str):
                raise TypeError("Private key must be a string")
            cleaned = re.sub(r"\s+", "", pkey)
            lines = [cleaned[i : i + 64] for i in range(0, len(cleaned), 64)]
            pem_body = "
".join(lines)
            return (
                "-----BEGIN PRIVATE KEY-----
"
                + pem_body
                + "
-----END PRIVATE KEY-----
"
            )

# Cryptography library is required for proper validation
try:
    from cryptography.hazmat.primitives import serialization
    from cryptography.hazmat.backends import default_backend
    from cryptography.exceptions import UnsupportedAlgorithm
    from cryptography.hazmat.primitives.asymmetric import rsa, ec, dsa, ed25519, ed448
except ImportError as exc:
    raise ImportError(
        "cryptography library is required for private key handling"
    ) from exc

_BASE64_REGEX = re.compile(r"^[A-Za-z0-9+/=]*$")

_MAX_KEY_LENGTH = 8192  # 8 KiB limit for base64 representation


def _sanitize_key(raw_key: str) -> str:
    if not isinstance(raw_key, str):
        raise TypeError("Private key must be a string")

    key = raw_key.strip()
    key = re.sub(r"-----BEGIN PRIVATE KEY-----", "", key, flags=re.IGNORECASE)
    key = re.sub(r"-----END PRIVATE KEY-----", "", key, flags=re.IGNORECASE)
    key = re.sub(r"\s+", "", key)

    if not key:
        raise ValueError("Private key is empty after sanitization")

    if len(key) > _MAX_KEY_LENGTH:
        raise ValueError("Private key exceeds maximum allowed length")

    if not _BASE64_REGEX.fullmatch(key):
        raise ValueError("Private key contains invalid characters")

    try:
        decoded = base64.b64decode(key, validate=True)
    except binascii.Error:
        raise ValueError("Invalid base64 encoding")

    try:
        private_key = serialization.load_der_private_key(
            decoded, password=None, backend=default_backend()
        )
    except (ValueError, TypeError, UnsupportedAlgorithm):
        raise ValueError("Decoded data is not a valid private key")

    if isinstance(private_key, rsa.RSAPrivateKey):
        if private_key.key_size < 2048:
            raise ValueError("RSA key size must be at least 2048 bits")
    elif isinstance(private_key, ec.EllipticCurvePrivateKey):
        allowed_curves = (
            ec.SECP256R1,
            ec.SECP384R1,
            ec.SECP521R1,
            ed25519.Ed25519,
            ed448.Ed448,
        )
        if not isinstance(private_key.curve, allowed_curves):
            raise ValueError("Unsupported elliptic curve for private key")
    elif isinstance(private_key, dsa.DSAPrivateKey):
        if private_key.key_size < 2048:
            raise ValueError("DSA key size must be at least 2048 bits")
    else:
        raise ValueError("Unsupported private key type")

    return key


def format_private_key_fixed(raw_key: str) -> str:
    try:
        sanitized = _sanitize_key(raw_key)
        formatted = OneLogin_Saml2_Utils.format_private_key(sanitized)
        return formatted
    except (TypeError, ValueError):
        raise ValueError("Failed to format private key")

import ipaddress
import re
import threading
from dataclasses import dataclass, field
from typing import List, Optional

_bridges_lock = threading.Lock()


class BridgeCreationError(Exception):
    """Generic error raised when a bridge cannot be created."""
    pass


def _validate_ip(ip_str: str) -> str:
    if not isinstance(ip_str, str):
        raise BridgeCreationError("Invalid IP address.")
    ip_str = ip_str.strip()
    try:
        ip_obj = ipaddress.ip_address(ip_str)
    except ValueError:
        raise BridgeCreationError("Invalid IP address format.")
    if ip_obj.is_private or ip_obj.is_loopback or ip_obj.is_link_local or ip_obj.is_reserved:
        raise BridgeCreationError("IP address belongs to a prohibited range.")
    return ip_str


def _validate_port(port) -> int:
    if isinstance(port, str):
        port = port.strip()
        if not port.isdigit():
            raise BridgeCreationError("Port must be a numeric value.")
        port = int(port)
    if not isinstance(port, int):
        raise BridgeCreationError("Port must be an integer.")
    if not (1 <= port <= 65535):
        raise BridgeCreationError("Port must be between 1 and 65535.")
    return port


_FINGERPRINT_REGEX = re.compile(r"^[A-Fa-f0-9]{64}$")


def _validate_fingerprint(fp: str) -> str:
    if not isinstance(fp, str):
        raise BridgeCreationError("Fingerprint must be a string.")
    fp = fp.strip()
    if not _FINGERPRINT_REGEX.fullmatch(fp):
        raise BridgeCreationError("Fingerprint must be a valid SHA-256 (64) hex string.")
    return fp.lower()


def _validate_transport(transport: Optional[str]) -> Optional[str]:
    if transport is None:
        return None
    if not isinstance(transport, str):
        raise BridgeCreationError("Pluggable transport must be a string.")
    transport = transport.strip()
    if not re.fullmatch(r"^[A-Za-z0-9_-]{1,32}$", transport):
        raise BridgeCreationError("Invalid pluggable transport identifier.")
    return transport


@dataclass(frozen=True)
class Bridge:
    ip: str = field(metadata={"description": "IP address of the bridge"})
    port: int = field(metadata={"description": "TCP port of the bridge"})
    fingerprint: str = field(metadata={"description": "Bridge identity fingerprint"})
    pluggable_transport: Optional[str] = field(default=None, metadata={"description": "Optional transport name"})


def create_bridge(
    bridges: List[Bridge],
    ip: str,
    port,
    fingerprint: str,
    pluggable_transport: Optional[str] = None,
) -> Bridge:
    """
    Create a Bridge object after validating inputs, add it to the provided list,
    and return the created Bridge.
    """
    try:
        validated_ip = _validate_ip(ip)
        validated_port = _validate_port(port)
        validated_fp = _validate_fingerprint(fingerprint)
        validated_transport = _validate_transport(pluggable_transport)

        new_bridge = Bridge(
            ip=validated_ip,
            port=validated_port,
            fingerprint=validated_fp,
            pluggable_transport=validated_transport,
        )

        with _bridges_lock:
            for existing in bridges:
                if (
                    existing.ip == new_bridge.ip
                    and existing.port == new_bridge.port
                    and existing.fingerprint == new_bridge.fingerprint
                ):
                    raise BridgeCreationError("A bridge with the same IP, port, and fingerprint already exists.")
            bridges.append(new_bridge)

        return new_bridge
    except BridgeCreationError:
        raise
    except Exception:
        raise BridgeCreationError("Failed to create bridge due to an internal error.")

