import os
import pathlib
import logging
import numpy as np
import tensorflow as tf

_logger = logging.getLogger(__name__)
if not _logger.handlers:
    handler = logging.StreamHandler()
    formatter = logging.Formatter("%(asctime)s - %(levelname)s - %(message)s")
    handler.setFormatter(formatter)
    _logger.addHandler(handler)
    _logger.setLevel(logging.INFO)


_MAX_ELEMENTS_PER_WEIGHT = 10_000_000  # adjustable limit


def _is_subpath(child: pathlib.Path, parent: pathlib.Path) -> bool:
    try:
        child.relative_to(parent)
        return True
    except ValueError:
        return False


def update_and_save_model(model, layer_names, weight_dict, save_path, save_format="tf"):
    """
    Update specified layers with provided weights and save the model securely.

    Args:
        model: TensorFlow Keras model instance.
        layer_names (list[str]): Names of layers to update.
        weight_dict (dict): Mapping from layer name to list/tuple of weight arrays.
        save_path (str or pathlib.Path): Destination file name (within the dedicated models directory).
        save_format (str): 'tf' for TensorFlow SavedModel or 'h5' for HDF5.

    Raises:
        TypeError, ValueError, RuntimeError on validation or operation failure.
    """
    # ---- Basic argument validation -------------------------------------------------
    if not hasattr(model, "get_layer"):
        raise TypeError("Provided model does not support get_layer method")
    if not isinstance(layer_names, (list, tuple)):
        raise TypeError("layer_names must be a list or tuple")
    if not all(isinstance(name, str) for name in layer_names):
        raise TypeError("All items in layer_names must be strings")
    if not isinstance(weight_dict, dict):
        raise TypeError("weight_dict must be a dictionary")
    if not isinstance(save_path, (str, pathlib.Path)):
        raise TypeError("save_path must be a string or pathlib.Path")
    if save_format not in ("tf", "h5"):
        raise ValueError("save_format must be either 'tf' or 'h5'")

    # ---- Secure path handling ------------------------------------------------------
    cwd = pathlib.Path.cwd().resolve()
    models_dir = (cwd / "models").resolve()
    models_dir.mkdir(parents=True, exist_ok=True)

    # Use only the filename part to prevent path injection
    filename = pathlib.Path(save_path).name
    target_path = (models_dir / filename).resolve()

    if not _is_subpath(target_path, models_dir):
        raise ValueError("Resolved save_path is outside the allowed models directory")

    if target_path.exists():
        raise FileExistsError(f"Target file '{target_path}' already exists; refusing to overwrite")

    # ---- Layer weight updates -------------------------------------------------------
    for name in layer_names:
        try:
            layer = model.get_layer(name)
        except Exception as exc:
            raise ValueError(f"Layer '{name}' not found in the model") from exc

        if name not in weight_dict:
            raise ValueError(f"No weight entry provided for layer '{name}'")

        new_weights = weight_dict[name]
        if not isinstance(new_weights, (list, tuple)):
            raise TypeError(f"Weights for layer '{name}' must be provided as list or tuple")

        expected_weights = layer.get_weights()
        if len(new_weights) != len(expected_weights):
            raise ValueError(
                f"Weight count mismatch for layer '{name}': expected {len(expected_weights)}, got {len(new_weights)}"
            )

        for nw, ew in zip(new_weights, expected_weights):
            if not isinstance(nw, (np.ndarray, tf.Tensor)):
                raise TypeError(f"Weight for layer '{name}' must be a NumPy array or TensorFlow Tensor")
            if isinstance(nw, np.ndarray):
                if nw.size > _MAX_ELEMENTS_PER_WEIGHT:
                    raise ValueError(
                        f"Weight array for layer '{name}' exceeds allowed size ({_MAX_ELEMENTS_PER_WEIGHT} elements)"
                    )
            else:  # tf.Tensor
                if tf.size(nw).numpy() > _MAX_ELEMENTS_PER_WEIGHT:
                    raise ValueError(
                        f"Weight tensor for layer '{name}' exceeds allowed size ({_MAX_ELEMENTS_PER_WEIGHT} elements)"
                    )
            if nw.shape != ew.shape:
                raise ValueError(
                    f"Shape mismatch for layer '{name}' weight: expected {ew.shape}, got {nw.shape}"
                )

        try:
            layer.set_weights(new_weights)
            _logger.info("Updated weights for layer '%s'", name)
        except Exception as exc:
            raise RuntimeError(f"Failed to set weights for layer '{name}'") from exc

    # ---- Save the model ------------------------------------------------------------
    try:
        tf.keras.models.save_model(model, str(target_path), overwrite=False, save_format=save_format)
        _logger.info("Model saved successfully to %s", target_path)
    except Exception as exc:
        raise RuntimeError("Failed to save the model") from exc

