_MAX_JSON_DEPTH = 10
_MAX_PAYLOAD_SIZE = 10 * 1024  # 10â¯KB


def _is_valid_port(port: int) -> bool:
    return isinstance(port, int) and 1024 <= port <= 65535


def _sanitize_host(host: str) -> str:
    if not isinstance(host, str) or not host:
        raise ValueError("Invalid host")
    try:
        socket.inet_pton(socket.AF_INET, host)
        return host
    except OSError:
        try:
            socket.inet_pton(socket.AF_INET6, host)
            return host
        except OSError:
            if host == "localhost":
                return "127.0.0.1"
            raise ValueError("Host must be a valid IP address or localhost")


def _json_depth(obj, current=0) -> int:
    if not isinstance(obj, (dict, list)):
        return current
    if isinstance(obj, dict):
        if not obj:
            return current + 1
        return max(_json_depth(v, current + 1) for v in obj.values())
    else:  # list
        if not obj:
            return current + 1
        return max(_json_depth(v, current + 1) for v in obj)


def _safe_loads(raw: bytes) -> dict:
    data = json.loads(raw.decode("utf-8"))
    if _json_depth(data) > _MAX_JSON_DEPTH:
        raise ValueError("JSON depth exceeds limit")
    return data


class ThreadingHTTPServer(socketserver.ThreadingMixIn, HTTPServer):
    daemon_threads = True


class _SecureHandler(BaseHTTPRequestHandler):
    server_version = "MockSecureHTTP/1.0"
    protocol_version = "HTTP/1.1"

    def _json_response(self, data: dict, status: int = 200) -> None:
        payload = json.dumps(data).encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", "application/json; charset=utf-8")
        self.send_header("Content-Length", str(len(payload)))
        self.end_headers()
        self.wfile.write(payload)

    def do_GET(self):
        try:
            response = {"message": "Mock server is running", "path": self.path}
            self._json_response(response)
        except Exception:
            logger.exception("Unhandled GET error")
            self._json_response({"error": "Internal server error"}, status=500)

    def do_POST(self):
        try:
            content_length = int(self.headers.get("Content-Length", 0))
            if content_length > _MAX_PAYLOAD_SIZE:
                self._json_response({"error": "Payload too large"}, status=413)
                return
            raw = self.rfile.read(content_length)
            try:
                data = _safe_loads(raw)
            except (json.JSONDecodeError, ValueError):
                self._json_response({"error": "Invalid JSON"}, status=400)
                return
            # Respond without echoing the full payload to avoid reflection issues
            self._json_response({"status": "received"}, status=200)
        except Exception:
            logger.exception("Unhandled POST error")
            self._json_response({"error": "Internal server error"}, status=500)

    def log_message(self, format: str, *args):
        # Use logging's builtâin argument handling to avoid injection
        logger.info("%s - - [%s] %s", self.client_address[0],
                    self.log_date_time_string(),
                    format % args)


class MockServer:
    def __init__(self,
                 port: int,
                 host: str = "127.0.0.1",
                 handler_class: Optional[Callable[..., BaseHTTPRequestHandler]] = None,
                 certfile: Optional[str] = None,
                 keyfile: Optional[str] = None):
        if not _is_valid_port(port):
            raise ValueError("Port must be an integer between 1024 and 65535")
        if not certfile or not keyfile:
            raise ValueError("Both certfile and keyfile must be provided for TLS")
        self.port = port
        self.host = _sanitize_host(host)
        self.handler_class = handler_class or _SecureHandler
        self.certfile = certfile
        self.keyfile = keyfile
        self._httpd: Optional[ThreadingHTTPServer] = None
        self._thread: Optional[threading.Thread] = None
        self._stop_event = threading.Event()

    def _run(self):
        try:
            server_address = (self.host, self.port)
            self._httpd = ThreadingHTTPServer(server_address, self.handler_class)
            # Wrap the socket with TLS
            context = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)
            context.load_cert_chain(certfile=self.certfile, keyfile=self.keyfile)
            self._httpd.socket = context.wrap_socket(self._httpd.socket, server_side=True)
            self._httpd.timeout = 1
            logger.info("Mock server listening on https://%s:%s", self.host, self.port)
            while not self._stop_event.is_set():
                self._httpd.handle_request()
        except OSError as e:
            logger.error("Failed to bind mock server: %s", e)
        finally:
            if self._httpd:
                self._httpd.server_close()
                logger.info("Mock server on %s:%s stopped", self.host, self.port)

    def start(self):
        if self._thread and self._thread.is_alive():
            raise RuntimeError("Mock server is already running")
        self._stop_event.clear()
        self._thread = threading.Thread(target=self._run, daemon=True, name="MockServerThread")
        self._thread.start()

    def stop(self):
        self._stop_event.set()
        if self._thread:
            self._thread.join(timeout=5)
            if self._thread.is_alive():
                logger.warning("Mock server thread did not terminate cleanly")
            self._thread = None


def start_mock_server(port: int,
                      host: str = "127.0.0.1",
                      handler: Optional[Callable[..., BaseHTTPRequestHandler]] = None,
                      certfile: Optional[str] = None,
                      keyfile: Optional[str] = None) -> MockServer:
    """
    Create and start a mock HTTPS server for testing.

    :param port: TCP port (1024-65535) to listen on.
    :param host: Host address; defaults to loopback.
    :param handler: Optional custom request handler subclassing BaseHTTPRequestHandler.
    :param certfile: Path to PEMâencoded certificate file.
    :param keyfile: Path to PEMâencoded private key file.
    :return: MockServer instance; call .stop() when finished.
    """
    server = MockServer(port=port, host=host, handler_class=handler,
                        certfile=certfile, keyfile=keyfile)
    server.start()
    return server

