def generate_dataset(columns: Iterable[str], runs: int, size: int) -> List[Dict[str, int]]:
    """
    Generate a dataset with random integer values.

    Args:
        columns: An iterable of column names (strings). Names must contain only
                 alphanumeric characters and underscores.
        runs: Number of rows to generate (must be a positive integer).
        size: Upper exclusive bound for random values (must be a positive integer).

    Returns:
        A list of dictionaries, each representing a row with column/value pairs.

    Raises:
        ValueError: If input validation fails.
    """
    # Input validation
    if not isinstance(runs, int) or runs <= 0:
        raise ValueError("Parameter 'runs' must be a positive integer.")
    if not isinstance(size, int) or size <= 0:
        raise ValueError("Parameter 'size' must be a positive integer.")
    if isinstance(columns, str):
        raise ValueError("Parameter 'columns' must be an iterable of strings, not a single string.")
    if not isinstance(columns, Iterable):
        raise ValueError("Parameter 'columns' must be an iterable of strings.")

    column_list: List[str] = []
    for col in columns:
        if not isinstance(col, str):
            raise ValueError("All column names must be strings.")
        if not _is_safe_column_name(col):
            raise ValueError(f"Invalid column name '{col}'.")
        column_list.append(col)

    if not column_list:
        raise ValueError("At least one column must be provided.")

    # Limit checks to avoid excessive memory usage
    max_rows = 10_000_000
    if runs > max_rows:
        raise ValueError(f"'runs' exceeds safe limit of {max_rows} rows.")

    dataset: List[Dict[str, int]] = []
