import ipaddress
from typing import Dict, List, Union, Iterable, Optional


_MAX_IPS = 10_000
_MAX_PORTS_PER_IP = 1_024
_MAX_COUNTRIES = 1_000


def _is_valid_ip(ip: str) -> bool:
    """Validate that a string is a correctly formatted IP address."""
    if not isinstance(ip, str):
        return False
    try:
        ipaddress.ip_address(ip)
        return True
    except ValueError:
        return False


def _is_valid_port(port: int) -> bool:
    """Validate that a port number is an integer between 1 and 65535."""
    return isinstance(port, int) and 1 <= port <= 65535


def _normalize_countries(countries: Optional[Iterable]) -> List[str]:
    """
    Return a list of lowercase country codes stripped of whitespace.
    Nonâiterable, empty, or overly large inputs return an empty list.
    """
    if not isinstance(countries, Iterable) or isinstance(countries, (str, bytes)):
        return []
    # Prevent excessive memory usage
    result: List[str] = []
    for i, c in enumerate(countries):
        if i >= _MAX_COUNTRIES:
            break
        if isinstance(c, str):
            result.append(c.strip().lower())
    return result


def _extract_ports(ports: Union[int, Iterable]) -> List[int]:
    """
    Convert a port specification to a list of integers.
    Nonâinteger entries are ignored. Limits the number of ports returned.
    """
    extracted: List[int] = []
    if isinstance(ports, int):
        extracted.append(ports)
    elif isinstance(ports, Iterable) and not isinstance(ports, (str, bytes)):
        for i, p in enumerate(ports):
            if i >= _MAX_PORTS_PER_IP:
                break
            if isinstance(p, int):
                extracted.append(p)
    return extracted


def get_blocked_ips(
    ip_port_map: Optional[Dict[str, Union[int, Iterable]]],
    block_countries: Optional[Iterable],
) -> Dict[str, List[int]]:
    """
    Returns a dictionary of blocked IP addresses and their valid ports
    when 'cn' (China) is among the blocked countries.
    Invalid inputs yield an empty result.
    """
    blocked: Dict[str, List[int]] = {}

    # Normalize and validate block_countries list
    normalized_countries = _normalize_countries(block_countries)
    if "cn" not in normalized_countries:
        return blocked

    if not isinstance(ip_port_map, dict):
        return blocked

    for i, (ip, ports) in enumerate(ip_port_map.items()):
        if i >= _MAX_IPS:
            break
        if not _is_valid_ip(ip):
            continue

        port_candidates = _extract_ports(ports)
        valid_ports = [p for p in port_candidates if _is_valid_port(p)]
        if not valid_ports:
            continue

        blocked[ip] = valid_ports

    return blocked

