def is_valid_url(url: str) -> bool:
    if not isinstance(url, str):
        return False
    url = url.strip()
    if len(url) > 2048 or not url:
        return False

    parsed = urllib.parse.urlparse(url)

    # Scheme check
    if parsed.scheme.lower() not in ALLOWED_SCHEMES:
        return False

    # Disallow user info and fragments
    if parsed.username or parsed.password or parsed.fragment:
        return False

    # Netloc and hostname validation
    if not parsed.netloc:
        return False
    hostname = parsed.hostname
    if not hostname:
        return False

    # Disallow control characters
    if any(ord(ch) < 32 or ch.isspace() for ch in url):
        return False

    # Disallow private / loopback IPs when hostname is an IP literal
    try:
        ip = ipaddress.ip_address(hostname)
        if ip.is_private or ip.is_loopback:
            return False
    except ValueError:
        pass  # not an IP, continue

    # Convert to ASCII/Punycode for whitelist comparison
    try:
        hostname_ascii = idna.encode(hostname).decode("ascii")
    except idna.IDNAError:
        return False

    if hostname_ascii.lower() not in ALLOWED_HOSTS:
        return False

    return True


