# Configuration constants
MAX_FEATURES = 100
MAX_STRING_LEN = 1024

logger = logging.getLogger(__name__)

def _sanitize_string(value: str) -> str:
    """Trim whitespace and enforce length limits on string values."""
    stripped = value.strip()
    if len(stripped) > MAX_STRING_LEN:
        raise ValueError(
            f"String value exceeds maximum length of {MAX_STRING_LEN} characters."
        )
    return stripped

def _validate_features(features: Dict[str, Any]) -> Dict[str, Any]:
    """Validate and sanitize external feature input."""
    if not isinstance(features, dict):
        raise TypeError("Features must be a dictionary.")
    if len(features) > MAX_FEATURES:
        raise ValueError(
            f"Too many features; maximum allowed is {MAX_FEATURES}."
        )

    sanitized: Dict[str, Any] = {}
    for key, value in features.items():
        if not isinstance(key, str) or not key.strip():
            raise ValueError("Feature keys must be nonâempty strings.")
        key = key.strip()
        if isinstance(value, str):
            sanitized[key] = _sanitize_string(value)
        elif isinstance(value, (int, float, bool)):
            sanitized[key] = value
        else:
            raise ValueError(
                f"Feature '{key}' has disallowed type {type(value).__name__}."
            )
    return sanitized

@dataclass(frozen=False)
class Plan:
    """Immutable identifier with mutable, validated feature set."""
    id: uuid.UUID = field(default_factory=uuid.uuid4, init=False)
    features: Dict[str, Any] = field(default_factory=dict)

    def __post_init__(self) -> None:
        # Ensure features are validated and detached from external references
        object.__setattr__(self, "features", dict(_validate_features(self.features)))

    def __setattr__(self, name: str, value: Any) -> None:
        # Prevent modification of the identifier after initial creation
        if name == "id" and "id" in self.__dict__:
            raise AttributeError("Plan identifier is immutable.")
        super().__setattr__(name, value)

def create_and_modify_plan(external_features: Dict[str, Any]) -> Plan:
    """
    Create a Plan from external input, modify its features,
    and verify the identifier remains unchanged.
    Returns the modified Plan instance.
    """
    try:
        safe_features = _validate_features(external_features)
        original_plan = Plan(features=safe_features)
        original_id = original_plan.id

        # Modify features safely
        for key, value in list(original_plan.features.items()):
            if isinstance(value, bool):
                original_plan.features[key] = not value
            elif isinstance(value, (int, float)):
                original_plan.features[key] = value + 1
            elif isinstance(value, str):
                original_plan.features[key] = _sanitize_string(value)
            # Allowed types left unchanged

        # Verify identifier stability
        if original_plan.id != original_id:
            raise RuntimeError("Plan identifier altered during modification.")

        logger.info("Plan created and modified successfully; identifier unchanged.")
        return original_plan
    except Exception as exc:
        logger.error("Failed to process plan: %s", exc)
        raise RuntimeError("Plan processing failed.") from exc

