import logging
import traceback

# Configure secure logging
log_path = pathlib.Path(__file__).resolve().parent / "error.log"
if not log_path.exists():
    log_path.touch(mode=0o600, exist_ok=True)
else:
    os.chmod(log_path, 0o600)

logging.basicConfig(
    filename=str(log_path),
    level=logging.ERROR,
    format="%(asctime)s %(levelname)s %(message)s",
)


def run_date_format(fmt: str) -> str:
    """Return the current date formatted according to the given strftime pattern."""
    try:
        return datetime.datetime.now().strftime(fmt)
    except Exception as e:
        raise RuntimeError("Failed to retrieve date.") from e


def get_current_date_parts():
    year = run_date_format("%Y")
    month = run_date_format("%m")
    day = run_date_format("%d")
    return int(year), int(month), int(day)


def get_previous_date(days: int, current_date: datetime.date) -> datetime.date:
    return current_date - datetime.timedelta(days=days)


def read_last_entry(file_path: pathlib.Path) -> str:
    """Read only the last line of a file safely, avoiding TOCTOU race conditions."""
    max_size = 1 * 1024 * 1024  # 1â¯MiB
    fd = None
    try:
        # Open the file without following symlinks to prevent TOCTOU attacks.
        fd = os.open(str(file_path), os.O_RDONLY | os.O_NOFOLLOW)
        st = os.fstat(fd)

        # Ensure the file is a regular file.
        if not stat.S_ISREG(st.st_mode):
            raise RuntimeError("File is not a regular file.")

        if st.st_size > max_size:
            raise RuntimeError("File too large to process safely.")

        # Convert the file descriptor to a file object.
        with os.fdopen(fd, "r", encoding="utf-8") as f:
            fd = None  # fd is now managed by the context manager
            last_line = None
            for line in f:
                last_line = line
            if not last_line:
                return ""
            return last_line.rstrip("
")
    except FileNotFoundError:
        return ""
    except OSError as e:
        raise RuntimeError("Unable to read the last entry file.") from e
    finally:
        if fd is not None:
            os.close(fd)


def sanitize_days(value: str) -> int:
    if not value.isdigit():
        raise argparse.ArgumentTypeError("Days must be a non-negative integer.")
    days = int(value)
    if days < 0 or days > 36525:  # limit to 100 years
        raise argparse.ArgumentTypeError("Days out of acceptable range.")
    return days


def main():
    parser = argparse.ArgumentParser(description="Retrieve dates and read last entry.")
    parser.add_argument(
        "--days",
        required=True,
        type=sanitize_days,
        help="Number of days to look back from today.",
    )
    args = parser.parse_args()

    try:
        cur_year, cur_month, cur_day = get_current_date_parts()
        current_date = datetime.date(cur_year, cur_month, cur_day)
        previous_date = get_previous_date(args.days, current_date)

        data_dir = pathlib.Path(__file__).resolve().parent / "data"
        entry_file = data_dir / "last_entry"
        last_entry = read_last_entry(entry_file)

        output = {
            "current": {"year": cur_year, "month": cur_month, "day": cur_day},
            "previous": {
                "year": previous_date.year,
                "month": previous_date.month,
                "day": previous_date.day,
            },
            "last_entry": last_entry,
        }
        print(output)
    except (RuntimeError, argparse.ArgumentError, ValueError) as e:
        logging.error("Handled error: %s", e, exc_info=True)
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)
    except Exception as e:
        logging.error("Unexpected error", exc_info=True)
        print("Error: An unexpected error occurred.", file=sys.stderr)
        sys.exit(1)


