_IDENTIFIER_PATTERN = re.compile(r"^[A-Za-z_][A-Za-z0-9_]{0,62}$")

# Restrict password characters to a set known to be safe in PostgreSQL literals
_SAFE_PASSWORD_ALPHABET = (
    string.ascii_letters + string.digits + "!@#$%^&*()-_=+[]{};:,.<>?"
)


def _is_valid_identifier(name: str) -> bool:
    """Return True if the supplied string conforms to PostgreSQL identifier rules."""
    return bool(_IDENTIFIER_PATTERN.fullmatch(name))


def _generate_secure_password(length: int = 24) -> str:
    """Generate a strong random password using a safe character set."""
    if length < 16:
        raise ValueError("Password length must be at least 16 characters.")
    return "".join(secrets.choice(_SAFE_PASSWORD_ALPHABET) for _ in range(length))


def _validate_admin_conn_params(params: Dict[str, Any]) -> None:
    """Ensure required keys for an administrative connection are present."""
    required_keys = {"host", "port", "user", "password", "dbname"}
    missing = required_keys - params.keys()
    if missing:
        raise ValueError(f"Administrative connection parameters missing: {missing}")
    # Simple type checks
    for key in required_keys:
        if not isinstance(params[key], (str, int)):
            raise TypeError(f"Connection parameter '{key}' must be a string or int.")


def create_database_and_user(
