def import_modules_with_flags(module_names: List[str], dlopen_flags: int) -> Dict[str, Any]:
    """
    Temporarily set dlopen flags, import the specified whitelisted modules, and restore the original flags.

    Args:
        module_names: List of whitelisted module names to import.
        dlopen_flags: Flags to set for dynamic loading (must be an allowed value).

    Returns:
        Dictionary mapping module names to the imported module objects.

    Raises:
        ValueError: If inputs are invalid or modules are not whitelisted.
        RuntimeError: If importing fails.
    """
    if not isinstance(module_names, list):
        raise ValueError("module_names must be a list")
    if not isinstance(dlopen_flags, int) or dlopen_flags < 0:
        raise ValueError("dlopen_flags must be a nonânegative integer")
    if dlopen_flags not in _ALLOWED_DLOPEN_FLAGS:
        raise ValueError("dlopen_flags contains disallowed value")

    name_pattern = re.compile(r'^[A-Za-z_][A-Za-z0-9_]*$')
    for name in module_names:
