import sys
import tempfile
import runpy
from types import CodeType
from typing import Any, Callable, Dict, Tuple


class CodeValidationError(Exception):
    """Raised when user code contains disallowed constructs."""


def _limited_builtins() -> Dict[str, Any]:
    """Return a dictionary of safe builtâin functions."""
    allowed = {
        "abs",
        "bool",
        "dict",
        "float",
        "int",
        "len",
        "list",
        "max",
        "min",
        "range",
        "str",
        "sum",
        "print",
        "enumerate",
        "zip",
        "set",
        "tuple",
    }
    return {k: getattr(builtins, k) for k in allowed}


def _is_subscript_of_builtin(node: ast.Subscript) -> bool:
    """Detect ``__builtins__['something']`` patterns."""
    return isinstance(node.value, ast.Name) and node.value.id == "__builtins__"


def _validate_ast(node: ast.AST) -> None:
    """Validate that the AST contains only safe constructs."""
    disallowed_calls = {
        "eval",
        "exec",
        "open",
        "__import__",
        "compile",
        "getattr",
        "setattr",
        "delattr",
        "globals",
        "locals",
        "vars",
        "type",
        "super",
    }

    for child in ast.walk(node):
        if isinstance(child, (ast.Import, ast.ImportFrom)):
            raise CodeValidationError(f"Disallowed import: {type(child).__name__}")

        if isinstance(child, ast.Attribute):
            raise CodeValidationError("Attribute access is not allowed")

        if isinstance(child, ast.Lambda):
            raise CodeValidationError("Lambda expressions are not allowed")

        if isinstance(child, (ast.ClassDef, ast.With, ast.Try, ast.AsyncFunctionDef,
                              ast.AsyncFor, ast.AsyncWith)):
            raise CodeValidationError(f"Disallowed statement: {type(child).__name__}")

        if isinstance(child, ast.Subscript) and _is_subscript_of_builtin(child):
            raise CodeValidationError("Subscript access to __builtins__ is not allowed")

        if isinstance(child, ast.Call):
            func = child.func
            if isinstance(func, ast.Name) and func.id in disallowed_calls:
                raise CodeValidationError(f"Disallowed function call: {func.id}")

            if isinstance(func, ast.Name):
                if func.id not in _limited_builtins() and func.id not in {"True", "False", "None"}:
                    raise CodeValidationError(f"Call to unknown name: {func.id}")


def _safe_compare(a: Any, b: Any) -> bool:
    """Compare two values in a sideâeffectâfree way."""
    try:
        a_json = json.dumps(a, sort_keys=True)
        b_json = json.dumps(b, sort_keys=True)
        return a_json == b_json
    except (TypeError, ValueError):
