def validate_user_code(
    user_code: str,
    func_name: str,
    args: Tuple[Any, ...] = (),
    kwargs: Dict[str, Any] | None = None,
    reference_impl: Callable[..., Any] | None = None,
    timeout_seconds: int = 2,
    max_code_size: int = 10_000,
) -> bool:
    """Validate and execute untrusted Python code safely."""
    if not isinstance(user_code, str):
        raise TypeError("user_code must be a string")
    if not isinstance(func_name, str):
        raise TypeError("func_name must be a string")
    if not isinstance(args, tuple):
        raise TypeError("args must be a tuple")
    if kwargs is None:
        kwargs = {}
    if not isinstance(kwargs, dict):
        raise TypeError("kwargs must be a dict")
    if len(user_code) > max_code_size:
        raise CodeValidationError("Code size exceeds limit")

    try:
        parsed = ast.parse(user_code, mode="exec")
        _validate_ast(parsed)
    except (SyntaxError, CodeValidationError):
        return False

    with tempfile.NamedTemporaryFile("w", delete=False, suffix=".py") as tmp_file:
        tmp_file.write(user_code)
        code_path = tmp_file.name

    result_queue: multiprocessing.Queue = multiprocessing.Queue()
    process = multiprocessing.Process(
        target=_run_in_subprocess,
        args=(code_path, func_name, args, kwargs, reference_impl, result_queue),
    )
    process.start()
    process.join(timeout_seconds)

    if process.is_alive():
        process.terminate()
        process.join()
        return False

    try:
        success, payload = result_queue.get_nowait()
    except Exception:
        return False

    if not success:
        return False

    return bool(payload)

