CREATE OR REPLACE FUNCTION safe_table_ops(p_table_name TEXT, p_data JSONB)
RETURNS VOID
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql        TEXT;
    v_val        TEXT;
    v_temp_name  TEXT;
    v_len        INTEGER;
    v_is_array   BOOLEAN;
BEGIN
    IF p_table_name IS NULL
       OR p_table_name !~ '^[a-zA-Z_][a-zA-Z0-9_]*$' THEN
        RAISE EXCEPTION 'Invalid table name';
    END IF;

    IF lower(p_table_name) IN (
        'select','insert','update','delete','table','create','drop','alter',
        'grant','revoke','where','from','into','and','or','not','as',
        'null','true','false'
    ) THEN
        RAISE EXCEPTION 'Table name cannot be a reserved keyword';
    END IF;

    SELECT jsonb_typeof(p_data) = 'array' INTO v_is_array;
    IF NOT v_is_array THEN
        RAISE EXCEPTION 'p_data must be a JSONB array';
    END IF;

    SELECT jsonb_array_length(p_data) INTO v_len;
    IF v_len > 10000 THEN
        RAISE EXCEPTION 'Array size exceeds allowed limit';
    END IF;

    v_temp_name := format('temp_%s_%s', p_table_name, replace(gen_random_uuid()::text, '-', ''));

    v_sql := format(
        'CREATE TEMP TABLE %I (id INTEGER GENERATED ALWAYS AS IDENTITY PRIMARY KEY, val TEXT NOT NULL) ON COMMIT DROP',
        v_temp_name
    );
    EXECUTE v_sql;

    FOR v_val IN
        SELECT elem->>'val' FROM jsonb_array_elements(p_data) AS elem
    LOOP
        EXECUTE format('INSERT INTO %I (val) VALUES ($1)', v_temp_name) USING v_val;
    END LOOP;

    EXECUTE format('DROP TABLE IF EXISTS %I', v_temp_name);
EXCEPTION
    WHEN OTHERS THEN
        BEGIN
            EXECUTE format('DROP TABLE IF EXISTS %I', v_temp_name);
        EXCEPTION
            WHEN OTHERS THEN NULL;
        END;
        RAISE;
END;
$$;

import logging
from dataclasses import dataclass, asdict
from typing import Any, List, Dict, Optional, Set, Union

# Configure logger with minimal exposure
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

ALLOWED_NOTE_TYPES: Set[str] = {
    "whole",
    "half",
    "quarter",
    "eighth",
    "sixteenth",
}

MIN_COORD, MAX_COORD = -10000.0, 10000.0
MIN_TIME, MAX_TIME = 0.0, 86400.0  # up to 24 hours


@dataclass(frozen=True)
class MusicalNote:
    x: float
    y: float
    time: float
    note_type: str
    curve: Optional[Dict[str, Any]] = None
    repeat: int = 1

    def to_dict(self) -> Dict[str, Any]:
        return asdict(self)


def _is_bool(value: Any) -> bool:
    return isinstance(value, bool)


def _validate_number(value: Any, name: str, min_val: float, max_val: float) -> float:
    if _is_bool(value) or not isinstance(value, (int, float)):
        raise ValueError(f"Invalid {name}")
    numeric = float(value)
    if not (min_val <= numeric <= max_val):
        raise ValueError(f"{name} out of range")
    return numeric


def _validate_string(value: Any, name: str, allowed: Optional[Set[str]] = None) -> str:
    if _is_bool(value) or not isinstance(value, str):
        raise ValueError(f"Invalid {name}")
    if allowed is not None and value not in allowed:
        raise ValueError(f"Unsupported {name}")
    return value


def _validate_repeat(value: Any) -> int:
    if value is None:
        return 1
    if _is_bool(value) or not isinstance(value, int) or value < 1:
        raise ValueError("Invalid repeat count")
    return value


def _sanitize_value(val: Any) -> Any:
    """Recursively sanitize primitive values for curve data."""
    if isinstance(val, (int, float, str)):
        return val
    if isinstance(val, list):
        return [_sanitize_value(item) for item in val]
    if isinstance(val, dict):
        return _sanitize_curve(val)
    raise ValueError("Unsupported value type in curve")


def _sanitize_curve(curve: Any) -> Optional[Dict[str, Any]]:
    if curve is None:
        return None
    if _is_bool(curve) or not isinstance(curve, dict):
        raise ValueError("Invalid curve")
    sanitized: Dict[str, Any] = {}
    for k, v in curve.items():
        if not isinstance(k, str):
            raise ValueError("Curve keys must be strings")
        sanitized[k] = _sanitize_value(v)
    return sanitized


def create_musical_notes(raw_notes: List[Any]) -> List[Dict[str, Any]]:
    """
    Convert a list of raw note specifications into validated MusicalNote dictionaries.
    """
    if not isinstance(raw_notes, list):
        raise TypeError("Input must be a list")

    processed: List[Dict[str, Any]] = []
    for idx, item in enumerate(raw_notes):
        try:
            if not isinstance(item, dict):
                raise ValueError("Note entry must be a dictionary")

            x = _validate_number(item.get("x"), "x", MIN_COORD, MAX_COORD)
            y = _validate_number(item.get("y"), "y", MIN_COORD, MAX_COORD)
            time = _validate_number(item.get("time"), "time", MIN_TIME, MAX_TIME)
            note_type = _validate_string(item.get("type"), "type", ALLOWED_NOTE_TYPES)

            curve = _sanitize_curve(item.get("curve"))
            repeat = _validate_repeat(item.get("repeat"))

            note = MusicalNote(
                x=x,
                y=y,
                time=time,
                note_type=note_type,
                curve=curve,
                repeat=repeat,
            )
            processed.append(note.to_dict())
        except Exception:
            logger.warning("Skipping invalid note at index %s", idx)
            continue

    return processed

