import argparse
import logging
import os
import sys
import re
import stat
from pathlib import Path
import pkgutil

PLACEHOLDER = "{{MODULES}}"
MODULE_REGEX = re.compile(r'^[A-Za-z_][A-Za-z0-9_]*(\.[A-Za-z_][A-Za-z0-9_]*)*$')
MAX_TEMPLATE_SIZE = 5 * 1024 * 1024  # 5â¯MiB
MAX_MODULES = 10_000
SAFE_OUTPUT_DIR = Path("/var/lib/readme_generator/output").resolve()


def configure_logging() -> logging.Logger:
    logger = logging.getLogger("readme_generator")
    logger.setLevel(logging.INFO)
    handler = logging.StreamHandler(sys.stderr)
    formatter = logging.Formatter("%(asctime)s - %(levelname)s - %(message)s")
    handler.setFormatter(formatter)
    logger.addHandler(handler)
    return logger


def validate_path(path_str: str, must_exist: bool = True) -> Path:
    p = Path(path_str)
    if not p.is_absolute():
        raise ValueError(f"Path must be absolute: {path_str}")

    try:
        resolved = p.resolve(strict=must_exist)
    except Exception as exc:
        raise ValueError(f"Invalid path: {path_str}") from exc

    for ancestor in resolved.parents:
        if ancestor.is_symlink():
            raise ValueError(f"Path component is a symbolic link: {ancestor}")

    if resolved.is_symlink():
        raise ValueError(f"Path itself is a symbolic link: {resolved}")

    return resolved


def validate_output_path(path: Path) -> Path:
    if not str(path).startswith(str(SAFE_OUTPUT_DIR)):
        raise ValueError(f"Output path must be inside the safe directory {SAFE_OUTPUT_DIR}")
    return path


def ensure_safe_output_dir() -> None:
    if not SAFE_OUTPUT_DIR.exists():
        SAFE_OUTPUT_DIR.mkdir(parents=True, mode=0o700, exist_ok=True)
    else:
        if not SAFE_OUTPUT_DIR.is_dir():
            raise RuntimeError(f"Safe output path {SAFE_OUTPUT_DIR} is not a directory.")
        if not os.access(SAFE_OUTPUT_DIR, os.W_OK):
            raise RuntimeError(f"Safe output directory {SAFE_OUTPUT_DIR} is not writable.")


def open_secure_file(path: Path) -> int:
    if not path.is_absolute():
        raise ValueError("Output path must be absolute.")

    parent_path = path.parent
    filename = path.name

    dir_flags = os.O_RDONLY
    if hasattr(os, "O_DIRECTORY"):
        dir_flags |= os.O_DIRECTORY
    if hasattr(os, "O_NOFOLLOW"):
        dir_flags |= os.O_NOFOLLOW

    parent_fd = os.open(str(parent_path), dir_flags)
    try:
        parent_stat = os.fstat(parent_fd)
        if not stat.S_ISDIR(parent_stat.st_mode):
            raise ValueError("Parent path is not a directory.")

        file_flags = os.O_WRONLY | os.O_CREAT | os.O_EXCL
        if hasattr(os, "O_NOFOLLOW"):
            file_flags |= os.O_NOFOLLOW

        fd = os.openat(parent_fd, filename, file_flags, 0o600)
        return fd
    finally:
        os.close(parent_fd)


def get_package_modules(package_path: Path) -> list[str]:
    if not package_path.is_dir():
        raise ValueError("Package path must be a directory.")
    modules: list[str] = []
    for finder, name, ispkg in pkgutil.iter_modules([str(package_path)]):
        try:
            spec = finder.find_spec(name)
            if spec and spec.origin:
                modules.append(name)
        except Exception:
            continue
    return sorted(set(modules))


def sanitize_module_names(modules: list[str]) -> list[str]:
    return [name for name in modules if MODULE_REGEX.fullmatch(name)]


def generate_readme(
    template_path: Path,
    output_path: Path,
    modules: list[str],
    logger: logging.Logger,
) -> None:
    try:
        size = template_path.stat().st_size
        if size > MAX_TEMPLATE_SIZE:
            raise ValueError("Template file exceeds maximum allowed size.")
    except Exception as exc:
        logger.error("Failed to inspect template file size.")
        raise RuntimeError("Template size check error.") from exc

    try:
        content = template_path.read_text(encoding="utf-8")
    except Exception as e:
        logger.error("Failed to read template file.")
        raise RuntimeError("Template read error.") from e

    module_section = "
".join(f"- `{m}`" for m in modules)

    if PLACEHOLDER not in content:
        logger.warning("Placeholder not found in template; appending module list at the end.")
        content = f"{content}

{module_section}"
    else:
        content = content.replace(PLACEHOLDER, module_section)

    try:
        fd = open_secure_file(output_path)
        with os.fdopen(fd, "w", encoding="utf-8") as out_file:
            out_file.write(content)
    except Exception as e:
        logger.error("Failed to write README file.")
        raise RuntimeError("Output write error.") from e


def main() -> None:
    logger = configure_logging()
    ensure_safe_output_dir()

    parser = argparse.ArgumentParser(description="Generate README from template.")
    parser.add_argument(
        "--template",
        required=True,
        help="Absolute path to the README template file.",
    )
    parser.add_argument(
        "--output",
        required=True,
        help="Absolute path for the generated README file (must be within safe directory).",
    )
    parser.add_argument(
        "--package",
        required=True,
        help="Absolute path to the package directory to inspect.",
    )
    args = parser.parse_args()

    try:
        template_path = validate_path(args.template, must_exist=True)
        raw_output_path = validate_path(args.output, must_exist=False)
        output_path = validate_output_path(raw_output_path)
        package_path = validate_path(args.package, must_exist=True)
    except ValueError as ve:
        logger.error(str(ve))
        sys.exit(1)

    try:
        raw_modules = get_package_modules(package_path)
        safe_modules = sanitize_module_names(raw_modules)
        if len(safe_modules) > MAX_MODULES:
            raise ValueError("Too many modules to process.")
    except Exception as e:
        logger.error(f"Failed to retrieve module list: {e}")
        sys.exit(1)

    try:
        generate_readme(template_path, output_path, safe_modules, logger)
        logger.info(f"README generated successfully at {output_path}")
    except Exception:
        logger.error("README generation failed.")
        sys.exit(1)


if __name__ == "__main__":
    main()

