def _is_path_inside_base(path: Path) -> bool:
    try:
        return path.is_relative_to(BASE_DIR)
    except AttributeError:
        base_str = str(BASE_DIR)
        path_str = str(path)
        if os.name == "nt":
            base_str = os.path.normcase(base_str)
            path_str = os.path.normcase(path_str)
        return os.path.commonpath([base_str, path_str]) == base_str


def _sanitize_path(file_path: str) -> Path:
    if not isinstance(file_path, str):
        raise ValueError("File path must be a string.")
    try:
        candidate = (BASE_DIR / file_path).expanduser()
        normalized = Path(os.path.normpath(str(candidate)))
        if not _is_path_inside_base(normalized):
            raise PermissionError(f"Access to {normalized} is prohibited.")
        return normalized
    except Exception as e:
        logger.debug(f"Path sanitization error for '{file_path}': {e}")
        raise


def _extract_sequence_number(line: str) -> Optional[int]:
    match = re.search(r"\d+", line)
    return int(match.group()) if match else None


def read_sort_and_get_sequence(file_path: str) -> Optional[int]:
    try:
        path = _sanitize_path(file_path)
    except Exception:
        logger.error("Invalid file path provided.")
        return None

    if not _HAS_O_NOFOLLOW:
        logger.error("Platform does not support O_NOFOLLOW; operation aborted.")
        return None

    fd = None
    try:
        fd = os.open(str(path), os.O_RDONLY | os.O_NOFOLLOW)

        try:
            real_path = Path(os.readlink(f"/proc/self/fd/{fd}")).resolve()
            if not _is_path_inside_base(real_path):
                raise PermissionError("Escaped base directory after opening.")
        except Exception as e:
            os.close(fd)
            logger.debug(f"Post-open path validation failed: {e}")
            raise PermissionError("Escaped base directory after opening.") from e

        st = os.fstat(fd)

        if not stat.S_ISREG(st.st_mode):
            logger.error("File is not a regular file.")
            return None

        if st.st_size > MAX_FILE_SIZE:
            logger.error("File size exceeds the allowed limit.")
            return None

        with os.fdopen(fd, "r", encoding="utf-8", errors="replace") as f:
            fd = None  # Managed by fdopen now
            max_line: Optional[str] = None
            for raw_line in f:
                line = raw_line.rstrip("
")
                if max_line is None or line > max_line:
                    max_line = line

        if not max_line:
            logger.info("File is empty.")
            return None

        seq_num = _extract_sequence_number(max_line)
        if seq_num is None:
            logger.info("No sequence number found in the last line.")
        return seq_num

    except PermissionError as pe:
        logger.error(str(pe))
        return None
    except OSError:
        logger.error("Failed to open the file securely.")
        return None
    finally:
        if fd is not None:
            try:
                os.close(fd)
            except OSError:
                pass

