#!/usr/bin/env python3
import argparse
import logging
import os
import re
import shutil
import sys
import uuid
from pathlib import Path

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler(sys.stdout)],
)

# Allowed characters for identifiers (columns/rows)
VALID_NAME_RE = re.compile(r"^[A-Za-z0-9_]+$")
SAFE_NAME_RE = re.compile(r"[^\w.-]")


def sanitize_line(line: str) -> str:
    """Validate and sanitize a line from input files."""
    line = line.strip()
    if not line:
        return ""
    if not VALID_NAME_RE.fullmatch(line):
        raise ValueError(f"Invalid identifier detected: {line}")
    return line


def read_identifiers(file_path: Path) -> set[str]:
    """Read and sanitize identifiers from a given file."""
    identifiers = set()
    try:
        with file_path.open("r", encoding="utf-8") as f:
            for raw_line in f:
                try:
                    line = sanitize_line(raw_line)
                except ValueError as e:
                    logging.warning("Skipping line in %s: %s", file_path, e)
                    continue
                if line:
                    identifiers.add(line)
    except (OSError, IOError) as e:
        logging.error("Failed to read %s: %s", file_path, e)
        raise
    return identifiers


def is_removable(name: str) -> bool:
    """Determine if a file should be removed based on custom criteria."""
    return name.startswith("tmp_") and name.endswith(".log")


def safe_copy(src: Path, dst: Path) -> None:
    """Copy file using safe permissions and without following symlinks."""
    try:
        shutil.copy2(src, dst, follow_symlinks=False)
        os.chmod(dst, 0o600)
    except (OSError, IOError) as e:
        logging.error("Failed to copy %s to %s: %s", src, dst, e)
        raise


def resolve_and_check(path: Path, base: Path) -> Path:
    """Resolve a path and ensure it is within the given base directory."""
    resolved = path.resolve()
    try:
