import os
import sqlite3
import logging
from typing import Any, Dict, List

# Configuration
BASE_DB_DIR = os.path.abspath("/var/app/databases")  # adjust as needed
MAX_STRING_LENGTH = 1024
MAX_NUMERIC_ABS = 10**12
ALLOWED_SQL_COMMANDS = {"SELECT", "INSERT", "UPDATE", "DELETE"}

# Logger setup
logger = logging.getLogger(__name__)
if not logger.handlers:
    handler = logging.StreamHandler()
    formatter = logging.Formatter("%(asctime)s - %(levelname)s - %(message)s")
    handler.setFormatter(formatter)
    logger.addHandler(handler)
    logger.setLevel(logging.INFO)


def _validate_query_template(query: str) -> None:
    if not isinstance(query, str):
        raise TypeError("Query template must be a string.")

    # Disallow comments
    if "--" in query or "/*" in query or "*/" in query:
        raise ValueError("SQL comments are not allowed in the query template.")

    # Normalise whitespace and strip trailing semicolons
    stripped = query.strip()
    while stripped.endswith(";"):
        stripped = stripped[:-1].strip()

    # Ensure only a single statement
    if ";" in stripped:
        raise ValueError("Multiple SQL statements are not allowed.")

    # Whitelist allowed commands
    tokens = stripped.split()
    if not tokens:
        raise ValueError("Empty query.")
    command = tokens[0].upper()
    if command not in ALLOWED_SQL_COMMANDS:
        raise ValueError(f"SQL command '{command}' is not permitted.")


def _validate_parameters(params: Dict[str, Any]) -> None:
    if not isinstance(params, dict):
        raise TypeError("Parameters must be provided as a dictionary.")
    for key, value in params.items():
        if not isinstance(key, str):
            raise TypeError("Parameter keys must be strings.")
        if not isinstance(value, (str, int, float, type(None), bool)):
            raise TypeError(f"Unsupported parameter type for key '{key}'.")
        if isinstance(value, str) and len(value) > MAX_STRING_LENGTH:
            raise ValueError(f"String parameter '{key}' exceeds maximum length.")
        if isinstance(value, (int, float)):
            if abs(value) > MAX_NUMERIC_ABS:
                raise ValueError(f"Numeric parameter '{key}' exceeds allowed magnitude.")


def _get_db_connection(scope: Dict[str, Any]) -> sqlite3.Connection:
    if "connection" in scope:
        conn = scope["connection"]
        if not isinstance(conn, sqlite3.Connection):
            raise TypeError("Provided 'connection' is not a valid sqlite3.Connection object.")
        return conn

    if "db_path" in scope:
        db_path = scope["db_path"]
        if not isinstance(db_path, str):
            raise TypeError("Database path must be a string.")

        # Resolve and whitelist the path
        real_path = os.path.realpath(db_path)
        if not os.path.commonpath([real_path, BASE_DB_DIR]) == BASE_DB_DIR:
            raise ValueError("Database path is outside the allowed directory.")

        # Open readâonly connection; fail fast if not possible
        try:
            conn = sqlite3.connect(f"file:{real_path}?mode=ro", uri=True, check_same_thread=False)
        except sqlite3.OperationalError as e:
            raise RuntimeError(f"Unable to open database in readâonly mode: {e}")
        return conn

    raise KeyError("Scope must contain either 'connection' or 'db_path'.")


def execute_query(query_template: str, scope: Dict[str, Any], parameters: Dict[str, Any]) -> List[Dict[str, Any]]:
    """
    Execute a parameterised SQL query safely.

    :param query_template: SQL query with placeholders (e.g., ``SELECT * FROM users WHERE id = :id``)
    :param scope: Dictionary containing execution context (e.g., database path or connection)
    :param parameters: Mapping of placeholder names to values
    :return: List of rows as dictionaries
    """
    try:
        _validate_query_template(query_template)
        _validate_parameters(parameters)

        conn = _get_db_connection(scope)
        conn.row_factory = sqlite3.Row

        with conn:
            cursor = conn.execute(query_template, parameters)
            rows = cursor.fetchall()
            return [dict(row) for row in rows]

    except Exception:
        logger.error("Error executing query.")
        raise RuntimeError("Failed to execute query.") from None

import ast
import logging

# Configure internal logger
logger = logging.getLogger(__name__)
logger.addHandler(logging.NullHandler())

_MAX_AST_NODES = 500
_MAX_AST_DEPTH = 50
_ALLOWED_NAMES = {"None": None, "True": True, "False": False}


def _is_allowed_attr(name: str) -> bool:
    """Allow only public attribute names (no leading underscore)."""
    return not name.startswith("_")


def _is_allowed_node(node: ast.AST, depth: int = 0) -> bool:
    """Validate AST nodes against a whitelist, with depth and size limits."""
    if depth > _MAX_AST_DEPTH:
        return False

    # Quick size check
    if len(list(ast.walk(node))) > _MAX_AST_NODES:
        return False

    allowed_types = (
        ast.Module,
        ast.Assign,
        ast.Name,
        ast.Load,
        ast.Store,
        ast.Constant,
        ast.Expr,
        ast.Attribute,
    )
    if not isinstance(node, allowed_types):
        return False

    if isinstance(node, ast.Attribute):
        # Must be of the form: self.<attr>
        if not (isinstance(node.value, ast.Name) and node.value.id == "self"):
            return False
        if not _is_allowed_attr(node.attr):
            return False

    for child in ast.iter_child_nodes(node):
        if not _is_allowed_node(child, depth + 1):
            return False
    return True


def _evaluate_constant(node: ast.AST):
    """Safely evaluate a Constant node."""
    if isinstance(node, ast.Constant):
        return node.value
    raise ValueError("Unsupported expression type for constant evaluation")


def _validate_instance(instance):
    """Ensure the instance uses the builtâin __setattr__ and has a mutable __dict__."""
    if not hasattr(instance, "__dict__"):
        raise TypeError("Instance must have a __dict__ attribute")
    builtin_setattr = object.__setattr__
    instance_setattr = getattr(instance.__class__, "__setattr__", builtin_setattr)
    if instance_setattr is not builtin_setattr:
        raise ValueError("Instance overrides __setattr__; operation not permitted")


def _execute_ast(parsed_ast: ast.Module, instance):
    """
    Walk the validated AST and perform allowed assignments.
    Supports statements like:
        self.some_attr = <constant>
    """
    _validate_instance(instance)

    for stmt in parsed_ast.body:
        if isinstance(stmt, ast.Assign):
            # Only simple singleâtarget assignments are allowed.
            if len(stmt.targets) != 1:
                raise ValueError("Multiple assignment targets are not allowed")
            target = stmt.targets[0]

            if not isinstance(target, ast.Attribute):
                raise ValueError("Only attribute assignments are permitted")
            if not (isinstance(target.value, ast.Name) and target.value.id == "self"):
                raise ValueError("Assignments must be made on 'self' object")
            if not _is_allowed_attr(target.attr):
                raise ValueError(f"Assignment to disallowed attribute '{target.attr}'")

            # Rightâhand side must be a constant or allowed name.
            if isinstance(stmt.value, ast.Constant):
                value = _evaluate_constant(stmt.value)
            elif isinstance(stmt.value, ast.Name):
                if stmt.value.id in _ALLOWED_NAMES:
                    value = _ALLOWED_NAMES[stmt.value.id]
                else:
                    raise ValueError(f"Use of name '{stmt.value.id}' is not allowed")
            else:
                raise ValueError("Only constant values are permitted on the rightâhand side")

            setattr(instance, target.attr, value)

        elif isinstance(stmt, ast.Expr):
            # Allow lone constant expressions (e.g., a docstring).
            if not isinstance(stmt.value, ast.Constant):
                raise ValueError("Only constant expressions are allowed")
        else:
            raise ValueError("Only assignment and expression statements are permitted")


def modify_instance_var(instance, code_str: str):
    """
    Executes a restricted code string to modify public attributes of `instance`.
    Prints the resulting attributes after execution.
    """
    if not isinstance(code_str, str):
        raise TypeError("code_str must be a string")
    if len(code_str) > 200:
        raise ValueError("code_str exceeds allowed length")

    try:
        parsed_ast = ast.parse(code_str, mode="exec")
    except SyntaxError:
        print("Invalid code syntax")
        return

    if not _is_allowed_node(parsed_ast):
        print("Disallowed code content")
        return

    try:
        _execute_ast(parsed_ast, instance)
    except Exception as exc:
        logger.exception("Error during code execution")
        print("Error during code execution")
        return

    safe_attrs = {k: v for k, v in vars(instance).items() if not k.startswith("_")}
    print("Modified instance attributes:", safe_attrs)

import os
