# Configure logger â avoid logging sensitive data
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Whitelists for safe selection
OPTIMIZER_WHITELIST = {
    "adam": tf.keras.optimizers.Adam,
    "sgd": tf.keras.optimizers.SGD,
    "rmsprop": tf.keras.optimizers.RMSprop,
}
LOSS_WHITELIST = {
    "mse": tf.keras.losses.MeanSquaredError,
    "binary_crossentropy": tf.keras.losses.BinaryCrossentropy,
    "categorical_crossentropy": tf.keras.losses.CategoricalCrossentropy,
}
METRIC_WHITELIST = {
    "accuracy": tf.keras.metrics.Accuracy,
    "binary_accuracy": tf.keras.metrics.BinaryAccuracy,
    "categorical_accuracy": tf.keras.metrics.CategoricalAccuracy,
    "mae": tf.keras.metrics.MeanAbsoluteError,
}


def _is_safe_path(base: Path, target: Path) -> bool:
    """Return True if target is within base after resolution."""
    try:
        base_resolved = base.resolve(strict=True)
        target_resolved = target.resolve(strict=True)
    except Exception:
        return False
    return target_resolved.is_relative_to(base_resolved)


def _validate_path(base_dir: Path, file_path: str) -> Path:
    """Validate that file_path is a child of base_dir and exists."""
    if not isinstance(file_path, str) or not file_path:
        raise ValueError("File path must be a nonâempty string.")
    candidate = (base_dir / file_path).resolve()
    if not _is_safe_path(base_dir, candidate):
        raise ValueError("Path traversal detected.")
    if not candidate.is_file():
        raise ValueError("Requested file does not exist.")
    return candidate


def _validate_params(params: Dict[str, Any] | None) -> Dict[str, Any]:
    """Allow only simple scalar types for optimizer/loss parameters."""
    if not params:
        return {}
    if not isinstance(params, dict):
        raise ValueError("Parameters must be a dictionary.")
    safe_params = {}
    for k, v in params.items():
        if not isinstance(k, str):
            raise ValueError("Parameter keys must be strings.")
        if isinstance(v, (int, float, bool, str)):
            safe_params[k] = v
        else:
            raise ValueError(f"Unsupported parameter type for '{k}'.")
    return safe_params


def _get_optimizer(name: str, params: Dict[str, Any] | None = None) -> tf.keras.optimizers.Optimizer:
    if not isinstance(name, str):
        raise ValueError("Optimizer name must be a string.")
    if name.lower() not in OPTIMIZER_WHITELIST:
        raise ValueError("Unsupported optimizer.")
    optimizer_cls = OPTIMIZER_WHITELIST[name.lower()]
    safe_params = _validate_params(params)
    return optimizer_cls(**safe_params)


def _get_loss(name: str, params: Dict[str, Any] | None = None) -> tf.keras.losses.Loss:
    if not isinstance(name, str):
        raise ValueError("Loss name must be a string.")
    if name.lower() not in LOSS_WHITELIST:
        raise ValueError("Unsupported loss function.")
    loss_cls = LOSS_WHITELIST[name.lower()]
    safe_params = _validate_params(params)
    return loss_cls(**safe_params)


def _get_metrics(names: List[str]) -> List[tf.keras.metrics.Metric]:
    if not isinstance(names, list):
        raise ValueError("Metrics configuration must be a list.")
    metrics = []
    for n in names:
        if not isinstance(n, str):
            raise ValueError("Metric names must be strings.")
        if n.lower() not in METRIC_WHITELIST:
            raise ValueError(f"Unsupported metric: {n}")
        metrics.append(METRIC_WHITELIST[n.lower()]())
    return metrics


def _build_model(layers_cfg: List[Dict[str, Any]], input_shape: Union[tuple, List[int]]) -> tf.keras.Model:
    """Construct a Sequential model from a whitelistâvalidated layer configuration."""
    if not isinstance(layers_cfg, list) or not layers_cfg:
        raise ValueError("Layer configuration must be a nonâempty list.")
    model = tf.keras.Sequential()
    model.add(tf.keras.layers.InputLayer(input_shape=tuple(input_shape)))
    for layer_cfg in layers_cfg:
        if not isinstance(layer_cfg, dict):
            raise ValueError("Each layer configuration must be a dictionary.")
        layer_type = layer_cfg.get("type", "").lower()
        if layer_type != "dense":
            raise ValueError(f"Unsupported layer type: {layer_type}")
        if "units" not in layer_cfg:
            raise ValueError("Dense layer must specify 'units'.")
        try:
            units = int(layer_cfg["units"])
        except Exception:
            raise ValueError("'units' must be an integer.")
        activation = layer_cfg.get("activation")
        if activation is not None and not isinstance(activation, str):
            raise ValueError("Activation must be a string if provided.")
        model.add(tf.keras.layers.Dense(units=units, activation=activation))
    return model


def compile_ml_model(config: Dict[str, Any]) -> tf.keras.Model:
    """
    Load data, optionally preprocess, build and compile a Keras model using safe defaults.
    Expected config keys:
        - base_dir: str (root directory for data files)
        - train_data: str (relative path to training CSV)
        - test_data: str (relative path to testing CSV)
        - target_column: str
        - preprocess: bool (if True, StandardScaler is applied)
        - model_layers: list of layer dicts (e.g., {"type":"dense","units":64,"activation":"relu"})
        - optimizer: dict {"name": "...", "params": {...}}
        - loss: dict {"name": "...", "params": {...}}
        - metrics: list of metric names
    Returns a compiled tf.keras.Model instance.
    """
    try:
        # Base directory validation
        base_dir_raw = config.get("base_dir", ".")
        if not isinstance(base_dir_raw, str) or not base_dir_raw:
            raise ValueError("base_dir must be a nonâempty string.")
        base_dir = Path(base_dir_raw).resolve()
        if not base_dir.is_dir():
            raise ValueError("Invalid base directory.")

        # Required file paths
        train_path = _validate_path(base_dir, config["train_data"])
        test_path = _validate_path(base_dir, config["test_data"])

        # Load CSV data
        df_train = pd.read_csv(train_path)
        df_test = pd.read_csv(test_path)

        # Target column validation
        target_col = config.get("target_column")
        if not isinstance(target_col, str) or not target_col:
            raise ValueError("target_column must be a nonâempty string.")
        if target_col not in df_train.columns or target_col not in df_test.columns:
            raise ValueError("Target column missing in data.")

        # Feature / label separation
        X_train = df_train.drop(columns=[target_col]).to_numpy(dtype=np.float32)
        y_train = df_train[target_col].to_numpy()
        X_test = df_test.drop(columns=[target_col]).to_numpy(dtype=np.float32)
        y_test = df_test[target_col].to_numpy()

        # Optional preprocessing
        if config.get("preprocess", False):
            scaler = StandardScaler()
            X_train = scaler.fit_transform(X_train)
            X_test = scaler.transform(X_test)

        # Input shape determination
        if X_train.ndim != 2:
            raise ValueError("Training features must be a 2âdimensional array.")
        input_shape = X_train.shape[1:]

        # Model construction
        layers_cfg = config.get("model_layers")
        model = _build_model(layers_cfg, input_shape)

        # Optimizer / loss / metrics configuration
        optimizer_cfg = config.get("optimizer")
        loss_cfg = config.get("loss")
        if not isinstance(optimizer_cfg, dict) or not isinstance(loss_cfg, dict):
            raise ValueError("Optimizer and loss configurations must be dictionaries.")
        optimizer = _get_optimizer(optimizer_cfg.get("name", ""), optimizer_cfg.get("params"))
        loss = _get_loss(loss_cfg.get("name", ""), loss_cfg.get("params"))
        metrics = _get_metrics(config.get("metrics", []))

        # Compile model
        model.compile(optimizer=optimizer, loss=loss, metrics=metrics)

        logger.info("Model compiled successfully.")
        return model

    except Exception as exc:
        logger.error("Failed to compile model: %s", type(exc).__name__)
        raise RuntimeError("Model compilation failed.") from exc

import os
