# Define a safe base directory for all operations
SAFE_BASE_DIR = Path("/opt/kickstart").resolve(strict=False)

def _is_within_safe_base(p: Path) -> bool:
    try:
        p_resolved = p.resolve(strict=False)
        return SAFE_BASE_DIR == p_resolved or SAFE_BASE_DIR in p_resolved.parents
    except Exception:
        return False

def _sanitize_path(path: str) -> Path:
    p = Path(path).resolve(strict=False)
    if not p.is_absolute():
        raise KickstartSetupError("Path must be absolute.")
    if not _is_within_safe_base(p):
        raise KickstartSetupError(f"Path {p} is outside the allowed directory {SAFE_BASE_DIR}.")
    return p

def _validate_hostname(hostname: str) -> str:
    if not isinstance(hostname, str):
        raise KickstartSetupError("Hostname must be a string.")
    if len(hostname) > 255:
        raise KickstartSetupError("Hostname too long.")
    pattern = re.compile(r"^(?!-)[A-Z0-9-]{1,63}(?<!-)$", re.IGNORECASE)
    for label in hostname.split("."):
        if not pattern.fullmatch(label):
            raise KickstartSetupError("Invalid hostname format.")
    return hostname

def _validate_basedir(basedir: str) -> str:
    if not isinstance(basedir, str):
        raise KickstartSetupError("Base directory must be a string.")
    parsed = urlparse(basedir)
    if parsed.scheme not in ("http", "https"):
        raise KickstartSetupError("Base directory must be a valid http(s) URL.")
    if not parsed.netloc:
        raise KickstartSetupError("Base directory URL missing network location.")
    if parsed.query or parsed.fragment:
        raise KickstartSetupError("Base directory must not contain query or fragment.")
    if not re.fullmatch(r'(\/[A-Za-z0-9._-]*)*', parsed.path):
        raise KickstartSetupError("Base directory path contains invalid characters.")
    if re.search(r'[^A-Za-z0-9._:/-]', basedir):
        raise KickstartSetupError("Base directory contains illegal characters.")
    return basedir.rstrip("/")

def _validate_timezone(tz: str) -> str:
    if not isinstance(tz, str):
        raise KickstartSetupError("Timezone must be a string.")
    if not re.fullmatch(r"[A-Za-z_]+/[A-Za-z_]+", tz):
        raise KickstartSetupError("Timezone format is invalid.")
    zoneinfo_path = Path("/usr/share/zoneinfo") / tz
    if not zoneinfo_path.is_file():
        raise KickstartSetupError("Specified timezone does not exist on this system.")
    return tz

def _escape_value(value: str, file_suffix: str) -> str:
    if re.search(r'[�-]', value):
        raise KickstartSetupError("Value contains prohibited control characters.")
    if file_suffix == ".sh":
        return shlex.quote(value)
    if file_suffix == ".ks":
        if re.search(r'[;&`$|<>]', value):
            raise KickstartSetupError("Invalid characters in value for Kickstart file.")
        if re.search(r'\s', value):
            raise KickstartSetupError("Whitespace not allowed in Kickstart substitution value.")
        if not re.fullmatch(r'[-A-Za-z0-9._/@]+', value):
            raise KickstartSetupError("Invalid characters in Kickstart substitution value.")
        return value
    return value.replace("
", "").replace("", "")

def _replace_placeholders(file_path: Path, substitutions: dict):
    try:
        content = file_path.read_text(encoding="utf-8")
        for placeholder, raw_value in substitutions.items():
            escaped = _escape_value(raw_value, file_path.suffix)
            content = content.replace(placeholder, escaped)
        file_path.write_text(content, encoding="utf-8")
    except Exception as e:
        raise KickstartSetupError(f"Failed to process file {file_path.name}.") from e

def _copy_and_process(src_dir: Path, dst_dir: Path, subs: dict):
    try:
        for src_path in src_dir.rglob("*"):
            rel_path = src_path.relative_to(src_dir)
            dest_path = dst_dir / rel_path

            if src_path.is_dir():
                if src_path.is_symlink():
                    continue
                dest_path.mkdir(parents=True, exist_ok=True)
                continue

            if src_path.is_symlink():
                continue

            dest_path.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy(str(src_path), str(dest_path))
            dest_path.chmod(0o644)
            _replace_placeholders(dest_path, subs)
    except Exception as e:
        raise KickstartSetupError("Error during file copy/processing.") from e

def _set_timezone(tz: str):
    try:
        localtime = Path("/etc/localtime")
        zoneinfo = Path("/usr/share/zoneinfo") / tz
        lock_path = Path("/etc/localtime.lock")

        if lock_path.is_symlink():
            raise KickstartSetupError("Lock path is a symlink.")

        fd_lock = os.open(str(lock_path), os.O_CREAT | os.O_EXCL | os.O_WRONLY, 0o600)
        with os.fdopen(fd_lock, "w") as lock_file:
            fcntl.flock(lock_file, fcntl.LOCK_EX)

            fd_tmp, tmp_path = tempfile.mkstemp(prefix="localtime.", dir="/etc")
            os.close(fd_tmp)
            try:
                shutil.copy2(str(zoneinfo), tmp_path)
                os.replace(tmp_path, str(localtime))
            finally:
                Path(tmp_path).unlink(missing_ok=True)

            fcntl.flock(lock_file, fcntl.LOCK_UN)
    except Exception as e:
        raise KickstartSetupError("Failed to set system timezone.") from e

def _run_command(command: list):
    try:
        subprocess.run(
            command,
            check=True,
            capture_output=True,
            text=True,
            cwd="/",
        )
    except subprocess.CalledProcessError as e:
        raise KickstartSetupError("Command execution failed.") from e

def setup_kickstart(
    source_dir: str,
    destination_dir: str,
    hostname: str,
    basedir: str,
    timezone: str,
):
    src = _sanitize_path(source_dir)
    dst = _sanitize_path(destination_dir)

    if not src.is_dir():
        raise KickstartSetupError("Source directory does not exist.")
    dst.mkdir(parents=True, exist_ok=True)

    hostname = _validate_hostname(hostname)
    basedir = _validate_basedir(basedir)
    timezone = _validate_timezone(timezone)

    substitutions = {
        "{{HOSTNAME}}": hostname,
        "{{BASEURL}}": basedir,
        "{{TIMEZONE}}": timezone,
    }

    _copy_and_process(src, dst, substitutions)

    try:
        for file in dst.rglob("*"):
            if file.is_file() and file.suffix in {".sh", ".ks"}:
                file.chmod(0o644)
    except Exception as e:
        raise KickstartSetupError("Failed to set file permissions.") from e

    _set_timezone(timezone)
    _run_command(["systemctl", "restart", "systemd-timesyncd"])

if __name__ == "__main__":
    if len(sys.argv) != 6:
        sys.stderr.write(
            "Usage: python3 kickstart_setup.py <source_dir> <destination_dir> <hostname> <basedir> <timezone>
"
        )
        sys.exit(1)

    try:
        setup_kickstart(
            source_dir=sys.argv[1],
            destination_dir=sys.argv[2],
            hostname=sys.argv[3],
            basedir=sys.argv[4],
            timezone=sys.argv[5],
        )
        print("Kickstart configuration deployed successfully.")
    except KickstartSetupError as exc:
        sys.stderr.write(f"Error: {exc}
")
        sys.exit(1)

