import os
import json
import time
import logging
import re
from typing import Any, Dict, Optional
from urllib.parse import urlparse

import requests
from requests.exceptions import (
    RequestException,
    Timeout,
    ConnectionError,
    HTTPError,
)

# Configure logger (avoid sensitive data)
logger = logging.getLogger(__name__)
handler = logging.StreamHandler()
formatter = logging.Formatter("%(asctime)s %(levelname)s %(message)s")
handler.setFormatter(formatter)
logger.addHandler(handler)
logger.setLevel(logging.INFO)

# Load configuration from environment (leastâprivilege)
API_URL = os.getenv("WORKSPACE_API_URL")
API_KEY = os.getenv("WORKSPACE_API_KEY")
TIMEOUT_SECONDS = int(os.getenv("WORKSPACE_API_TIMEOUT", "10"))
MAX_RETRIES = int(os.getenv("WORKSPACE_MAX_RETRIES", "5"))
BASE_BACKOFF = float(os.getenv("WORKSPACE_BACKOFF_BASE", "1.0"))

# Allowed API hostnames (adjust as needed)
_ALLOWED_API_HOSTS = {"api.mycompany.com"}

# Validation limits
MAX_CONTEXT_ITEMS = 50
MAX_CONTEXT_BYTES = 5_000

# Simple sanitisation patterns
_ALLOWED_MESSAGE_RE = re.compile(r"^[ -~]{1,2000}$")  # printable ASCII, max 2000 chars
_ALLOWED_CONTEXT_KEY_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")


def _is_allowed_url(url: str) -> bool:
    try:
        parsed = urlparse(url)
    except Exception:
        return False
    return (
        parsed.scheme == "https"
        and parsed.hostname in _ALLOWED_API_HOSTS
    )


def _validate_message(message: str) -> None:
    if not isinstance(message, str):
        raise ValueError("Message must be a string")
    if not _ALLOWED_MESSAGE_RE.fullmatch(message):
        raise ValueError("Message contains disallowed characters or exceeds length limits")


def _validate_context(context: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    if context is None:
        return {}
    if not isinstance(context, dict):
        raise ValueError("Context must be a dict")
    if len(context) > MAX_CONTEXT_ITEMS:
        raise ValueError(f"Context contains too many items (max {MAX_CONTEXT_ITEMS})")
    sanitized: Dict[str, Any] = {}
    for k, v in context.items():
        if not isinstance(k, str) or not _ALLOWED_CONTEXT_KEY_RE.fullmatch(k):
            raise ValueError(f"Invalid context key: {k}")
        if not isinstance(v, (str, int, float, bool, type(None))):
            raise ValueError(f"Invalid context value type for key {k}")
        sanitized[k] = v
    # Size check after sanitisation
    try:
        serialized = json.dumps(sanitized, ensure_ascii=True).encode()
    except Exception as exc:
        raise ValueError("Failed to serialize context") from exc
    if len(serialized) > MAX_CONTEXT_BYTES:
        raise ValueError(f"Context size exceeds limit of {MAX_CONTEXT_BYTES} bytes")
    return sanitized


def send_message_to_workspace(message: str, context: Optional[Dict[str, Any]] = None) -> str:
    """
    Sends a text message to the AI workspace and returns the response.
    Retries until a valid response is obtained or the maximum retry limit is exceeded.
    """
    if not API_URL or not API_KEY:
        raise RuntimeError("Workspace configuration is missing")
    if not _is_allowed_url(API_URL):
        raise RuntimeError("Invalid or insecure API_URL configuration")

    _validate_message(message)
    safe_context = _validate_context(context)

    payload = {"message": message, "context": safe_context}

    headers = {
        "Authorization": f"Bearer {API_KEY}",
        "Content-Type": "application/json",
        "Accept": "application/json",
    }

    attempt = 0
    while attempt < MAX_RETRIES:
        try:
            response = requests.post(
                API_URL,
                headers=headers,
                data=json.dumps(payload, ensure_ascii=True),
                timeout=TIMEOUT_SECONDS,
                verify=True,
            )
            response.raise_for_status()
            data = response.json()
            if not isinstance(data, dict) or "response" not in data:
                raise ValueError("Invalid response format received")
            if not isinstance(data["response"], str):
                raise ValueError("Response field is not a string")
            return data["response"]
        except (Timeout, ConnectionError):
            logger.warning("Network issue on attempt %d", attempt + 1)
        except HTTPError as e:
            status = e.response.status_code if e.response else "unknown"
            logger.warning(
                "HTTP error %s on attempt %d", status, attempt + 1
            )
        except (RequestException, ValueError) as e:
            logger.warning(
                "Error on attempt %d: %s", attempt + 1, type(e).__name__
            )
        finally:
            attempt += 1
            if attempt < MAX_RETRIES:
                backoff = BASE_BACKOFF * (2 ** (attempt - 1))
                time.sleep(backoff)

    raise RuntimeError("Failed to obtain a valid response after multiple attempts")

