import os
import re
import sqlite3
import logging
from typing import Any, Dict, List, Tuple

# Configuration
ALLOWED_DIR = os.getenv("ALLOWED_DIR", "/var/app/data")
ALLOWED_TABLES = {"users", "orders"}
ALLOWED_COLUMNS = {
    "users": {"id", "username", "email"},
    "orders": {"id", "user_id", "total"},
}
MAX_STRING_LENGTH = 4096
MAX_ROWS = 1000
MAX_PARAMETER_SIZE = 1_048_576  # 1 MB limit for binary-like data

logger = logging.getLogger(__name__)

def _validate_db_path(db_path: str) -> str:
    if not isinstance(db_path, str) or not db_path:
        raise ValueError("Invalid database path.")
    abs_path = os.path.abspath(db_path)
    real_path = os.path.realpath(abs_path)
    allowed_path = os.path.realpath(ALLOWED_DIR)
    if os.path.commonpath([real_path, allowed_path]) != allowed_path:
        raise ValueError("Database path is not within the allowed directory.")
    return real_path

def _validate_table_name(table: str) -> str:
    if not isinstance(table, str):
        raise ValueError("Table name must be a string.")
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", table):
        raise ValueError("Invalid table name format.")
    if table not in ALLOWED_TABLES:
        raise ValueError("Table name is not authorized.")
    return table

def _validate_condition(table: str, condition: Dict[str, Any]) -> Tuple[List[str], List[Any]]:
    if not isinstance(condition, dict) or not condition:
        raise ValueError("Condition must be a nonâempty dictionary.")
    allowed_cols = ALLOWED_COLUMNS.get(table, set())
    where_clauses: List[str] = []
    parameters: List[Any] = []
    for col, val in condition.items():
        if not isinstance(col, str) or not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", col):
            raise ValueError(f"Invalid column name in condition: {col}")
        if col not in allowed_cols:
            raise ValueError(f"Column '{col}' is not permitted for table '{table}'.")
        # Accept only scalar types
        if not isinstance(val, (str, int, float, bool, type(None))):
            raise ValueError(f"Unsupported value type for column '{col}'.")
        if isinstance(val, str) and len(val) > MAX_STRING_LENGTH:
            raise ValueError(f"String value for column '{col}' exceeds maximum length.")
        if isinstance(val, (bytes, bytearray)):
            if len(val) > MAX_PARAMETER_SIZE:
                raise ValueError(f"Binary value for column '{col}' exceeds size limit.")
        where_clauses.append(f"{col} = ?")
        parameters.append(val)
    return where_clauses, parameters

def _open_db_secure(db_path: str) -> Tuple[sqlite3.Connection, int]:
    fd = os.open(db_path, os.O_RDWR | os.O_NOFOLLOW)
    try:
        conn = sqlite3.connect(f"file:fd={fd}?mode=rw", uri=True)
        return conn, fd
    except Exception:
        os.close(fd)
        raise

def delete_and_fetch(
    db_path: str,
    table: str,
    condition: Dict[str, Any],
) -> List[Tuple]:
    """
    Delete rows from *table* that match *condition* and return the remaining rows.
    """
    try:
        db_path = _validate_db_path(db_path)
        table = _validate_table_name(table)
        where_clauses, parameters = _validate_condition(table, condition)
    except ValueError as ve:
        logger.debug("Input validation failed: %s", ve)
        raise RuntimeError("Invalid input.") from ve

    where_sql = " AND ".join(where_clauses)
    delete_sql = f"DELETE FROM {table} WHERE {where_sql}"
    select_sql = f"SELECT * FROM {table} WHERE NOT ({where_sql}) LIMIT {MAX_ROWS}"

    try:
        conn, fd = _open_db_secure(db_path)
        try:
            conn.execute("PRAGMA foreign_keys = ON")
            with conn:
                conn.execute(delete_sql, parameters)
                cursor = conn.execute(select_sql, parameters)
                rows = cursor.fetchall()
            if logger.isEnabledFor(logging.DEBUG):
                logger.debug("Executed DELETE on table %s", table)
                logger.debug("Executed SELECT on table %s", table)
            return rows
        finally:
            conn.close()
            os.close(fd)
    except sqlite3.Error as e:
        logger.error("Database operation failed.")
        raise RuntimeError("Database operation failed.") from e

import os
import sys
import gzip
import pathlib
import tempfile
from typing import Iterable, List

# ---------- Configuration ----------
SAFE_BASE_DIR = pathlib.Path.cwd() / "sandbox"  # All files must reside here
MAX_UNCOMPRESSED_SIZE = 10 * 1024 * 1024 * 1024  # 10 GiB
MAX_COMPRESSED_SIZE = 100 * 1024 * 1024  # 100 MiB


class GFF3ToGTFError(Exception):
    """Generic error for GFF3 to GTF conversion."""


def _has_symlink_component(p: pathlib.Path) -> bool:
    try:
        if p.is_symlink():
            return True
        for ancestor in p.parents:
            if ancestor.is_symlink():
                return True
        return False
    except Exception:
        return True


def _is_within_safe_base(p: pathlib.Path) -> bool:
    try:
        base = SAFE_BASE_DIR.resolve(strict=True)
        target = p.resolve(strict=True)

        if _has_symlink_component(p):
            return False

        return target == base or base in target.parents
    except Exception:
        return False


def _open_input(path: pathlib.Path) -> Iterable[str]:
    """Open a GFF3 file, handling optional gzip compression safely."""
    try:
        if not path.is_file() or path.is_symlink():
            raise GFF3ToGTFError("Input path must be a regular file (no symlinks).")
        if path.suffix.lower() == ".gz":
            if path.stat().st_size > MAX_COMPRESSED_SIZE:
                raise GFF3ToGTFError("Compressed input exceeds allowed size.")
            with gzip.open(path, "rb") as gz:
                total = 0
                for raw_line in gz:
                    line = raw_line.decode("utf-8", errors="replace")
                    total += len(line.encode("utf-8"))
                    if total > MAX_UNCOMPRESSED_SIZE:
                        raise GFF3ToGTFError("Decompressed data exceeds allowed size.")
                    yield line
        else:
            with path.open("r", encoding="utf-8", errors="replace") as f:
                total = 0
                for line in f:
                    total += len(line.encode("utf-8"))
                    if total > MAX_UNCOMPRESSED_SIZE:
                        raise GFF3ToGTFError("Input data exceeds allowed size.")
                    yield line
    except OSError:
        raise GFF3ToGTFError("Unable to read input file.")


def _validate_dialect(dialect: str) -> None:
    allowed = {"default"}
    if dialect not in allowed:
        raise GFF3ToGTFError(f"Unsupported dialect: {dialect!r}")


def _validate_numeric_fields(start: str, end: str, score: str, phase: str) -> None:
    try:
        if start != ".":
            s = int(start)
            if s < 1:
                raise ValueError
        if end != ".":
            e = int(end)
            if e < 1:
                raise ValueError
        if start != "." and end != "." and int(end) < int(start):
            raise ValueError
        if score not in (".", ""):
            sc = float(score)
            if sc != sc or sc in (float("inf"), float("-inf")):
                raise ValueError
        if phase not in (".", ""):
            p = int(phase)
            if p not in (0, 1, 2):
                raise ValueError
    except ValueError:
        raise GFF3ToGTFError("Numeric field validation failed.")


def _escape_gtf_value(val: str) -> str:
    # Escape backslashes and double quotes for GTF attributes
    return val.replace("\", r"\").replace('"', r""")


def _convert_attributes(attr_field: str) -> str:
    parts: List[str] = []
    for attribute in attr_field.split(";"):
        attribute = attribute.strip()
        if not attribute:
            continue
        if "=" in attribute:
            key, val = attribute.split("=", 1)
        elif " " in attribute:
            key, val = attribute.split(" ", 1)
        else:
            key, val = attribute, ""
        key = key.strip()
        val = _escape_gtf_value(val.strip())
        parts.append(f'{key} "{val}";')
    return " ".join(parts)


def _atomic_write_path(out_path: pathlib.Path) -> pathlib.Path:
    """Create an atomic temporary file in the target directory and return its path."""
    temp_dir = out_path.parent
    if not temp_dir.is_dir() or temp_dir.is_symlink():
        raise GFF3ToGTFError("Output directory is invalid.")
    tmp = tempfile.NamedTemporaryFile(
        dir=temp_dir,
        prefix=".tmp_",
        suffix=".gtf",
        delete=False,
        mode="w",
        encoding="utf-8",
    )
    tmp_path = pathlib.Path(tmp.name)
    tmp.close()
    os.chmod(tmp_path, 0o600)
    return tmp_path


def convert_gff3_to_gtf(input_path: str, output_path: str, dialect: str = "default") -> None:
    try:
        in_path = pathlib.Path(input_path).resolve()
        out_path = pathlib.Path(output_path).resolve()

        # Ensure paths are inside the sandbox and free of symlink components
        if not _is_within_safe_base(in_path):
            raise GFF3ToGTFError("Input path is outside the allowed directory.")
        if not _is_within_safe_base(out_path):
            raise GFF3ToGTFError("Output path is outside the allowed directory.")
        if not _is_within_safe_base(out_path.parent):
            raise GFF3ToGTFError("Output directory is outside the allowed directory.")

        # Verify output directory
