import argparse
import json
import logging
import os
import sys
import io
from pathlib import Path

from PIL import Image, UnidentifiedImageError
import numpy as np

# Configure logger without exposing sensitive data
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler(sys.stderr)],
)

DEFAULT_MAX_IMAGE_DIMENSION = 4096  # default limit, can be overridden via CLI
MAX_ANNOTATIONS = 10_000  # maximum number of annotation entries
MAX_JSON_DEPTH = 10  # maximum allowed nesting depth for JSON structures
ALLOWED_JSON_EXT = {".json"}
ALLOWED_VOCAB_EXT = {".json"}
ALLOWED_IMAGE_EXT = {".jpg", ".jpeg", ".png", ".bmp", ".tiff", ".tif"}
MAX_IMAGE_BYTES = 20 * 1024 * 1024  # 20â¯MiB limit per image file
MAX_IMAGES_TO_PROCESS = 5_000  # cap on number of images processed per run

def _has_symlink_component(p: Path) -> bool:
    """Return True if any component of the path (including the path itself) is a symlink."""
    for ancestor in p.parents:
        if ancestor.is_symlink():
            return True
    return p.is_symlink()


def open_no_follow(path: Path):
    """Open a file descriptor with O_NOFOLLOW and return a binary file object."""
    flags = os.O_RDONLY | getattr(os, "O_NOFOLLOW", 0)
    fd = os.open(str(path), flags)
    return os.fdopen(fd, "rb")


def open_no_follow_text(path: Path, encoding="utf-8"):
    """Open a text file with O_NOFOLLOW and return a text file object."""
    binary = open_no_follow(path)
    return io.TextIOWrapper(binary, encoding=encoding)


def validate_file(path_str: str, allowed_ext: set) -> Path:
    """Validate that a path points to an existing regular file with an allowed extension and no symlinks."""
    p = Path(path_str).expanduser()
    if not p.is_absolute():
        raise ValueError("Path must be absolute")
    if _has_symlink_component(p):
        raise ValueError("Path contains symlink component")
    if not p.is_file():
        raise ValueError("File does not exist or is not a regular file")
    if p.suffix.lower() not in allowed_ext:
        raise ValueError("Unsupported file extension")
    return p


def validate_directory(dir_str: str) -> Path:
    """Validate that a directory exists, is absolute, and contains no symlink components."""
    d = Path(dir_str).expanduser()
    if not d.is_absolute():
        raise ValueError("Directory path must be absolute")
    if _has_symlink_component(d):
        raise ValueError("Directory contains symlink component")
    if not d.is_dir():
        raise ValueError("Invalid directory")
    return d


def _check_json_depth(obj, current_depth=0):
    if current_depth > MAX_JSON_DEPTH:
        raise ValueError("JSON exceeds maximum allowed nesting depth")
    if isinstance(obj, dict):
        for v in obj.values():
            _check_json_depth(v, current_depth + 1)
    elif isinstance(obj, list):
        for item in obj:
            _check_json_depth(item, current_depth + 1)


def load_annotations(json_path: Path) -> dict:
    """Load annotations from a JSON file with size, count, and depth limits."""
    try:
        if json_path.stat().st_size > 10 * 1024 * 1024:  # 10â¯MiB limit
            raise ValueError("Annotations file too large")
        with open_no_follow_text(json_path) as f:
            data = json.load(f)
        if not isinstance(data, dict):
            raise ValueError("Annotations JSON must be an object")
        if len(data) > MAX_ANNOTATIONS:
            raise ValueError("Annotations contain too many entries")
        _check_json_depth(data)
        return data
    except (OSError, json.JSONDecodeError) as e:
        logging.error("Failed to load annotations")
        raise ValueError("Unable to read annotations") from e


class Vocabulary:
    """Simple vocabulary class loaded from a JSON specification."""

    def __init__(self, spec: dict):
        self.type = spec.get("type", "identity")
        self.params = spec.get("params", {})

    def transform(self, features):
        if self.type == "identity":
            return features
        raise NotImplementedError(f"Unsupported vocabulary type: {self.type}")


def load_vocab(vocab_path: Path) -> Vocabulary:
    """Load a vocabulary definition from a JSON file."""
    try:
        with open_no_follow_text(vocab_path) as f:
            spec = json.load(f)
        if not isinstance(spec, dict):
            raise ValueError("Vocabulary JSON must be an object")
        _check_json_depth(spec)
        return Vocabulary(spec)
    except (OSError, json.JSONDecodeError) as e:
        logging.error("Failed to load vocabulary")
        raise ValueError("Unable to read vocabulary") from e


def load_image(image_path: Path, max_dim: int) -> Image.Image:
    """Open an image, validate dimensions, file size, and return a RGB copy."""
    if image_path.is_symlink():
        raise ValueError("Symlinked image files are not allowed")
    if image_path.stat().st_size > MAX_IMAGE_BYTES:
        raise ValueError("Image file exceeds size limit")
    try:
        with Image.open(open_no_follow(image_path)) as img:
            if img.width > max_dim or img.height > max_dim:
                raise ValueError("Image dimensions exceed allowed limit")
            Image.MAX_IMAGE_PIXELS = max_dim * max_dim
            img.load()
            return img.convert("RGB")
    except (OSError, UnidentifiedImageError, ValueError) as e:
        logging.warning("Skipping invalid image")
        raise


def extract_features(image: Image.Image) -> np.ndarray:
    """Resize, normalize, and flatten an image into a feature vector."""
    target_size = (224, 224)
    img_resized = image.resize(target_size, Image.LANCZOS)
    arr = np.asarray(img_resized, dtype=np.float32) / 255.0
    return arr.flatten()


def is_subpath(child: Path, parent: Path) -> bool:
    """Return True if child resolves to a location within parent."""
    child_resolved = child.resolve()
    parent_resolved = parent.resolve()
    try:
        return child_resolved.is_relative_to(parent_resolved)
    except AttributeError:
        child_parts = child_resolved.parts
        parent_parts = parent_resolved.parts
        return child_parts[: len(parent_parts)] == parent_parts


def process_dataset(
    annotations_path: Path,
    vocab_path: Path,
    image_dir: Path,
    max_dim: int,
) -> list:
    annotations = load_annotations(annotations_path)
    vocab = load_vocab(vocab_path)

    if not hasattr(vocab, "transform"):
        raise ValueError("Vocabulary object must implement a 'transform' method")

    features_list = []
    processed_count = 0

    for img_name in annotations.keys():
        if processed_count >= MAX_IMAGES_TO_PROCESS:
            logging.warning("Reached maximum number of images to process (%d)", MAX_IMAGES_TO_PROCESS)
            break

        img_path = (image_dir / img_name).resolve()
        if not is_subpath(img_path, image_dir):
            logging.warning("Image path escapes image directory, skipping")
            continue
        if img_path.suffix.lower() not in ALLOWED_IMAGE_EXT:
            logging.warning("Unsupported image format, skipping")
            continue
        if not img_path.is_file() or img_path.is_symlink():
            logging.warning("Image file not found or is a symlink, skipping")
            continue
        try:
            img = load_image(img_path, max_dim)
            raw_feat = extract_features(img)
            transformed = vocab.transform([raw_feat])
            features_list.append(transformed[0])
            processed_count += 1
        except Exception:
            continue

    return features_list


def main():
    parser = argparse.ArgumentParser(
        description="Load image dataset, extract features using a JSON-defined vocabulary."
    )
    parser.add_argument(
        "--annotations",
        required=True,
        help="Path to JSON file containing image annotations.",
    )
    parser.add_argument(
        "--vocab",
        required=True,
        help="Path to JSON file defining the vocabulary.",
    )
    parser.add_argument(
        "--image-dir",
        required=True,
        help="Directory containing the images.",
    )
    parser.add_argument(
        "--max-dim",
        type=int,
        default=DEFAULT_MAX_IMAGE_DIMENSION,
        help="Maximum allowed image dimension (default: %(default)s).",
    )
    args = parser.parse_args()

    try:
        annotations_path = validate_file(args.annotations, ALLOWED_JSON_EXT)
        vocab_path = validate_file(args.vocab, ALLOWED_VOCAB_EXT)
        image_dir = validate_directory(args.image_dir)
        max_dim = args.max_dim
        if max_dim <= 0 or max_dim > 16384:
            raise ValueError("Invalid max-dim value")
    except ValueError:
        logging.error("Invalid input parameters")
        sys.exit(1)

    try:
        features = process_dataset(annotations_path, vocab_path, image_dir, max_dim)
        output = [feat.tolist() for feat in features]
        json.dump(output, sys.stdout)
    except Exception:
        logging.error("Processing failed")
        sys.exit(1)


if __name__ == "__main__":
    main()

