# ----- Configuration -----
# Whitelist of safe factory callables (builtâin constructors)
_SAFE_FACTORY_NAMES = {
    "int",
    "list",
    "dict",
    "set",
    "str",
    "float",
    "bool",
    "tuple",
}
# Whitelist of safe key types (immutable builtâins)
_SAFE_KEY_TYPES = (int, str, float, bool, bytes, tuple)

# Maximum number of factories and keys allowed to prevent resource exhaustion
_MAX_FACTORIES = 1000
_MAX_KEYS = 1000
# ---------------------------


def _is_safe_callable(obj: Any) -> bool:
    """Return True only if *obj* is a callable that is explicitly allowed."""
    if not callable(obj):
        return False
    module = getattr(obj, "__module__", None)
    name = getattr(obj, "__name__", None)
    return module == "builtins" and name in _SAFE_FACTORY_NAMES


def _is_hashable(obj: Any) -> bool:
    """Check if an object is hashable (usable as a dict key)."""
    try:
        hash(obj)
        return True
    except Exception:
        return False


def _is_safe_key(obj: Any) -> bool:
    """Return True only if *obj* is a hashable instance of a permitted immutable type."""
    return isinstance(obj, _SAFE_KEY_TYPES) and _is_hashable(obj)


def test_defaultdict_repr_and_missing(
    factories: Iterable[Callable[[], Any]],
    keys: Iterable[Any],
) -> bool:
    """
    Tests ``repr`` and ``__missing__`` of ``defaultdict`` with supplied factories and keys.

    Returns True when all checks succeed; raises an exception otherwise.
    """
    # Validate factories iterable
    if not isinstance(factories, Iterable):
        raise TypeError("factories must be an iterable of callables")
    safe_factories: List[Callable[[], Any]] = []
    for fn in factories:
        if not _is_safe_callable(fn):
            raise ValueError(f"Factory {fn!r} is not an allowed safe callable.")
        safe_factories.append(fn)

    if len(safe_factories) > _MAX_FACTORIES:
        raise ValueError(
            f"Number of factories ({len(safe_factories)}) exceeds allowed maximum of {_MAX_FACTORIES}."
        )

    # Validate keys iterable
    if not isinstance(keys, Iterable):
        raise TypeError("keys must be an iterable of hashable, immutable objects")
    safe_keys: List[Any] = []
    for k in keys:
        if not _is_safe_key(k):
            raise ValueError(f"Key {k!r} is not of an allowed immutable, hashable type.")
        safe_keys.append(k)

    if len(safe_keys) > _MAX_KEYS:
        raise ValueError(
            f"Number of keys ({len(safe_keys)}) exceeds allowed maximum of {_MAX_KEYS}."
        )

    # Run tests for each factory/key combination
    for factory in safe_factories:
        dd = collections.defaultdict(factory)

        # ---- repr checks ----
        r = repr(dd)
        if "defaultdict" not in r:
            raise AssertionError("repr must contain class name 'defaultdict'")
        if hasattr(factory, "__name__") and factory.__name__ not in r:
            raise AssertionError("repr must contain the factory name")

        # ---- missing key handling via normal access ----
        for key in safe_keys:
            try:
                expected = factory()
            except Exception as exc:
                raise RuntimeError(f"Factory {factory!r} raised an exception.") from exc
            actual = dd[key]  # triggers __missing__
            if actual != expected:
                raise AssertionError(f"Factory result mismatch for key {key!r}")
            if key not in dd:
                raise AssertionError(f"Key {key!r} not inserted after missing handling")
            if dd[key] is not actual:
                raise AssertionError("Stored value must be the same object returned by factory")

        # ---- direct __missing__ test ----
        new_key = object()
        try:
            missing_result = dd.__missing__(new_key)  # type: ignore[attr-defined]
            expected_missing = factory()
            if missing_result != expected_missing:
                raise AssertionError("__missing__ must return factory result")
            if new_key not in dd:
                raise AssertionError("Key added by __missing__ is missing")
        except Exception as exc:
            raise RuntimeError("Unexpected error during __missing__ test.") from exc

        # ---- repr after insertions ----
        r_after = repr(dd)
        for key in safe_keys:
            # Use safe representation based on type to avoid executing custom __repr__
            safe_repr = f"{key!r}"
            if safe_repr not in r_after:
                raise AssertionError("repr must include string representation of inserted keys")
        new_key_repr = f"{new_key!r}"
        if new_key_repr not in r_after:
            raise AssertionError("repr must include representation of the key added via __missing__")

    return True


if __name__ == "__main__":
    try:
        factories_to_test = [int, list]  # only whitelisted factories
        keys_to_test = [1, "a", (2, 3)]
        test_defaultdict_repr_and_missing(factories_to_test, keys_to_test)
        print("All defaultdict tests passed.")
    except AssertionError as ae:
        print(f"Assertion failed: {ae}", file=sys.stderr)
        sys.exit(1)
    except Exception as ex:
        print(f"Error during testing: {ex}", file=sys.stderr)
        sys.exit(1)

import json
from decimal import Decimal, InvalidOperation
from typing import Any, Dict


class Quantity:
    __slots__ = ("_amount", "_unit", "_upper_bound")

    _MAX_NUMERIC_STR_LENGTH = 100  # Prevent extremely long numeric strings

    def __init__(self, data: Dict[str, Any]) -> None:
        if not isinstance(data, dict):
            raise ValueError("Input must be a dictionary")
        # Defensive copy to avoid external mutation
        data_copy = dict(data)
        try:
            raw_amount = data_copy["amount"]
            raw_unit = data_copy["unit"]
            raw_upper = data_copy["upperBound"]
        except (KeyError, TypeError):
            raise ValueError("Missing required fields: 'amount', 'unit', 'upperBound'")
        self._amount = self._parse_decimal(raw_amount, "amount")
        self._unit = self._validate_unit(raw_unit)
        self._upper_bound = self._parse_decimal(raw_upper, "upperBound")
        if self._upper_bound < self._amount:
            raise ValueError("upperBound must be greater than or equal to amount")

    @classmethod
    def fromWikibase(cls, wikibase_json: Dict[str, Any]) -> "Quantity":
        if not isinstance(wikibase_json, dict):
            raise ValueError("Wikibase input must be a dictionary")
        # Defensive copy
        json_copy = dict(wikibase_json)
        try:
            amount = json_copy["amount"]
            unit = json_copy["unit"]
            upper = json_copy["upperBound"]
        except (KeyError, TypeError):
            raise ValueError("Wikibase JSON missing required fields")
        return cls({"amount": amount, "unit": unit, "upperBound": upper})

    @staticmethod
    def _parse_decimal(value: Any, field_name: str) -> Decimal:
        if isinstance(value, (int, float, str)):
            # Convert to string in a controlled manner
            if isinstance(value, float):
                # Represent float with full precision to avoid scientific notation issues
                value_str = format(value, ".17g")
            else:
                value_str = str(value)
            if len(value_str) > Quantity._MAX_NUMERIC_STR_LENGTH:
                raise ValueError(f"'{field_name}' string representation is too long")
            try:
                dec = Decimal(value_str)
            except (InvalidOperation, ValueError):
                raise ValueError(f"Invalid numeric value for '{field_name}'")
            # Reject NaN or infinite values
            if not dec.is_finite():
                raise ValueError(f"'{field_name}' must be a finite number")
            return dec
        raise ValueError(f"'{field_name}' must be a number")

    @staticmethod
    def _validate_unit(value: Any) -> str:
        if not isinstance(value, str):
            raise ValueError("unit must be a string")
        cleaned = value.strip()
        if not cleaned:
            raise ValueError("unit cannot be empty")
        # Reject control characters
        if any(ord(ch) < 32 for ch in cleaned):
            raise ValueError("unit contains invalid characters")
        return cleaned

    def to_dict(self) -> Dict[str, Any]:
        return {
            "amount": str(self._amount),
            "unit": self._unit,
            "upperBound": str(self._upper_bound),
        }

    def __str__(self) -> str:
        # json.dumps is safe here because all fields are validated
        return json.dumps(
            self.to_dict(),
            ensure_ascii=False,
            separators=(",", ":")
        )

    def __eq__(self, other: Any) -> bool:
        if not isinstance(other, Quantity):
            return NotImplemented
        return (
            self._amount == other._amount
            and self._unit == other._unit
            and self._upper_bound == other._upper_bound
        )

