def _is_path_within_base(path: pathlib.Path, base: pathlib.Path) -> bool:
    """Return True if `path` is a descendant of `base`."""
    try:
        # Python 3.9+
        return path.is_relative_to(base)
    except AttributeError:
        # Fallback for older Python versions
        try:
            return base in path.parents or path == base
        except Exception:
            return False


def read_settings(file_path: str, defaults: Dict[str, Any]) -> Dict[str, Any]:
    """
    Reads a simple key=value settings file and returns a dictionary.
    Missing keys are filled with values from ``defaults``.
    All file handling errors result in returning ``defaults`` without
    leaking exception details.
    """
    if not isinstance(file_path, str):
