import os
import sys
import math
import logging
from pathlib import Path
from typing import Dict, List

# Configure safe logger
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler(sys.stderr)]
)
logger = logging.getLogger(__name__)

MAX_FILE_SIZE = 10 * 1024 * 1024          # 10â¯MiB per alignment file
MAX_TOTAL_SIZE = 100 * 1024 * 1024       # 100â¯MiB total for concatenated alignments
MAX_FILES = 1000                         # Upper bound on number of alignment files

class SecureReportError(Exception):
    """Custom exception for report generation errors."""
    pass

def _contains_symlink(p: Path) -> bool:
    """Return True if any component of the path (including the final one) is a symlink."""
    try:
        for ancestor in p.parents:
            if ancestor.is_symlink():
                return True
        if p.is_symlink():
            return True
        return False
    except OSError:
        return False

def _validate_directory(dir_path: Path) -> Path:
    """Validate that the provided path is a safe existing directory."""
    try:
        resolved = dir_path.resolve(strict=True)
    except OSError as e:
        raise SecureReportError("Invalid directory path.") from e

    if _contains_symlink(dir_path):
        raise SecureReportError("Symlinks are not allowed in directory path components.")
    if not resolved.is_dir():
        raise SecureReportError("Provided path is not a directory.")
    return resolved

def _ensure_within_base(base: Path, target: Path) -> Path:
    """Resolve target and ensure it stays inside base directory."""
    try:
        resolved = target.resolve(strict=False)
    except OSError as e:
        raise SecureReportError(f"Unable to resolve path: {target}") from e
    try:
        resolved.relative_to(base)
    except ValueError:
        raise SecureReportError(f"Path escapes base directory: {target}")
    if resolved.is_symlink():
        raise SecureReportError("Symlink detected in target path.")
    return resolved

def _read_statistics(stat_file: Path) -> Dict[str, str]:
    """Parse the statistics file securely."""
    expected_keys = {"Reticulations", "Taxa", "Increase", "Decrease", "Outgroup"}
    stats: Dict[str, str] = {}
    try:
        with stat_file.open("r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line or ":" not in line:
                    continue
                key, value = (part.strip() for part in line.split(":", 1))
                if key in expected_keys:
                    stats[key] = value
    except (OSError, UnicodeDecodeError) as e:
        raise SecureReportError("Failed to read statistics file.") from e

    missing = expected_keys - stats.keys()
    if missing:
        raise SecureReportError(f"Statistics file missing keys: {', '.join(missing)}")
    return stats

def _resize_value(value: str, coefficient: float) -> str:
    """Resize numeric value by coefficient safely."""
    try:
        numeric = float(value)
        resized = numeric * coefficient
        if value.isdigit():
            return str(int(round(resized)))
        return f"{resized:.4f}"
    except ValueError:
        return value

def _gather_alignment_files(base_dir: Path) -> List[Path]:
    """Collect alignment files with known extensions, skipping symlinks and enforcing a count limit."""
    extensions = {".fasta", ".fa", ".aln", ".phy"}
    files: List[Path] = []
    try:
        for entry in base_dir.iterdir():
            if entry.is_file() and not entry.is_symlink() and entry.suffix.lower() in extensions:
                files.append(entry)
    except OSError as e:
        raise SecureReportError("Failed while scanning alignment files.") from e

    if len(files) > MAX_FILES:
        raise SecureReportError(f"Too many alignment files (maximum allowed is {MAX_FILES}).")
    return files

def generate_report(
    directory: str,
    coefficient: float = 1.0,
    statistics_filename: str = "statistics.txt",
    output_filename: str = "report.txt"
) -> None:
    """
    Generate a secure report from a directory containing a statistics file and alignment files.
    The report includes parsed statistics (with resized Increase/Decrease) and concatenated alignments.
    """
    if not (isinstance(coefficient, (int, float)) and coefficient > 0 and not math.isnan(coefficient)):
        raise SecureReportError("Coefficient must be a positive number.")

    base_dir = _validate_directory(Path(directory))

    # Validate and resolve statistics file path
    stat_path = _ensure_within_base(base_dir, base_dir / statistics_filename)
    if not stat_path.is_file():
        raise SecureReportError("Statistics file not found in the directory.")

    stats = _read_statistics(stat_path)

    # Resize numeric fields
    stats["Increase"] = _resize_value(stats["Increase"], coefficient)
    stats["Decrease"] = _resize_value(stats["Decrease"], coefficient)

    # Gather alignment files
    alignment_files = _gather_alignment_files(base_dir)
    if not alignment_files:
        raise SecureReportError("No alignment files found.")

    # Verify size limits with TOCTOU protection
    total_size = 0
    for file_path in alignment_files:
        if file_path.is_symlink():
            raise SecureReportError(f"Symlink detected in alignment files: {file_path.name}")

        fd = os.open(file_path, os.O_RDONLY)
        try:
            st = os.fstat(fd)
            size = st.st_size
