            os.close(fd)

    if total_size > MAX_TOTAL_SIZE:
        raise SecureReportError("Total size of alignment files exceeds allowed limit.")

    # Prepare output path securely
    output_path = _ensure_within_base(base_dir, base_dir / output_filename)

    # Create and write report atomically
    try:
        fd_out = os.open(output_path, os.O_WRONLY | os.O_CREAT | os.O_EXCL, 0o600)
        with os.fdopen(fd_out, "w", encoding="utf-8") as out_file:
            out_file.write(f"Reticulations: {stats['Reticulations']}
")
            out_file.write(f"Taxa: {stats['Taxa']}
")
            out_file.write(f"Increase: {stats['Increase']}
")
            out_file.write(f"Decrease: {stats['Decrease']}
")
            out_file.write(f"Outgroup: {stats['Outgroup']}
")
            out_file.write("
")
            out_file.write("=== Concatenated Alignments ===
")

            for file_path in alignment_files:
                # Open each alignment file securely and stream its contents
                fd_in = os.open(file_path, os.O_RDONLY)
                try:
                    with os.fdopen(fd_in, "r", encoding="utf-8") as src:
                        for chunk in iter(lambda: src.read(8192), ""):
                            out_file.write(chunk)
                finally:
                    # fd_in is closed by the context manager; no extra close needed
                    pass
                out_file.write("
")
        logger.info("Report generated successfully.")
    except FileExistsError:
        raise SecureReportError("Report file already exists.") from None
    except OSError as e:
        raise SecureReportError("Failed to write the report file.") from e

import hashlib
from typing import Optional


_ALLOWED_ALGORITHMS = {
    "sha256": hashlib.sha256,
    "sha384": hashlib.sha384,
    "sha512": hashlib.sha512,
}


class SecureHasher:
    """
    Wrapper around hashlib objects providing safe update, digest,
    and cloning capabilities.
    """

    __slots__ = ("_hash",)

    def __init__(self, algorithm: str = "sha256", data: Optional[str] = None):
        if not isinstance(algorithm, str) or not algorithm.strip():
            raise ValueError("Algorithm name must be a nonâempty string.")
        algo_func = _ALLOWED_ALGORITHMS.get(algorithm.strip().lower())
        if algo_func is None:
            raise ValueError("Unsupported or insecure hash algorithm.")
        self._hash = algo_func()
        if data is not None:
            self.update(data)

    def update(self, data: str) -> None:
        if not isinstance(data, str):
            raise ValueError("Input data must be a string.")
        # Encode using UTF-8; errors are replaced to avoid UnicodeDecodeError leakage
        self._hash.update(data.encode("utf-8", errors="replace"))

    def hexdigest(self) -> str:
        return self._hash.hexdigest()

    def digest(self) -> bytes:
        return self._hash.digest()

    def clone(self) -> "SecureHasher":
        cloned = SecureHasher.__new__(SecureHasher)
        cloned._hash = self._hash.copy()
        return cloned


def compute_hash(data: str, algorithm: str = "sha256") -> str:
    """
    Compute the hexadecimal hash of the provided string using the specified algorithm.
    """
    if not isinstance(data, str):
        raise ValueError("Data to hash must be a string.")
    try:
        hasher = SecureHasher(algorithm, data)
        return hasher.hexdigest()
    except Exception:
        raise ValueError("Failed to compute hash.")

