def _format_url(scheme: str, ip: str, path: str) -> str:
    """Build a URL handling IPv4 and IPv6 correctly."""
    try:
        ip_obj = ipaddress.ip_address(ip)
    except ValueError as exc:
        raise ValueError("Invalid IP address") from exc

    host = f"[{ip}]" if ip_obj.version == 6 else ip
    safe_path = quote(path, safe="/")
    return f"{scheme}://{host}:2379{safe_path}"


def _validate_path(path: str) -> None:
    """Validate Etcd key path."""
    if not isinstance(path, str) or not path.startswith("/"):
        raise ValueError("Path must be a non-empty string starting with '/'")
    if len(path) > MAX_PATH_LENGTH:
        raise ValueError(f"Path length exceeds maximum of {MAX_PATH_LENGTH} characters")
    if not re.fullmatch(r"(/[A-Za-z0-9._-]+)*", path):
        raise ValueError("Path contains illegal characters")
    if any(segment == ".." for segment in path.split("/")):
        raise ValueError("Path must not contain '..' segments")


def _ip_allowed(
    ip_obj: Union[ipaddress.IPv4Address, ipaddress.IPv6Address],
    allowed_networks: List[Union[ipaddress.IPv4Network, ipaddress.IPv6Network]],
) -> bool:
    """Determine whether an IP is permitted based on an explicit allowâlist."""
    for net in allowed_networks:
        if ip_obj in net:
            return True
    return False


def _parse_allowed_networks(
    networks: Optional[List[str]],
) -> List[Union[ipaddress.IPv4Network, ipaddress.IPv6Network]]:
    """Validate and parse CIDR strings, raising on any malformed entry."""
    if not networks:
        raise ValueError("allowed_networks must be a nonâempty list of CIDR strings")
    parsed: List[Union[ipaddress.IPv4Network, ipaddress.IPv6Network]] = []
    for net_str in networks:
        try:
            net = ipaddress.ip_network(net_str, strict=False)
            parsed.append(net)
        except ValueError as exc:
            raise ValueError(f"Invalid CIDR entry in allowed_networks: '{net_str}'") from exc
    return parsed


def get_etcd_data(
    ip: str,
    path: str,
    cert_path: Optional[str] = None,
    key_path: Optional[str] = None,
    ca_path: Optional[str] = None,
    timeout: int = 5,
    allowed_networks: Optional[List[str]] = None,
) -> Dict[str, Any]:
    """
    Retrieve data from an Etcd cluster.

    Args:
        ip: IP address of the Etcd node.
        path: Etcd key path (must start with '/').
        cert_path: Path to client TLS certificate (PEM).
        key_path: Path to client TLS private key (PEM).
        ca_path: Path to CA certificate (PEM) for server verification.
        timeout: Maximum seconds to wait for the request (must be > 0).
        allowed_networks: List of CIDR strings whitelisting allowed IPs (required).

    Returns:
