    # Input validation
    _validate_path(path)

    try:
        ip_obj = ipaddress.ip_address(ip)
    except ValueError as exc:
        raise ValueError("Invalid IP address") from exc

    # Validate and parse allowed networks
    allowed_nets = _parse_allowed_networks(allowed_networks)

    if not _ip_allowed(ip_obj, allowed_nets):
        raise ValueError("IP address is not permitted by allowed_networks")

    if not isinstance(timeout, (int, float)) or timeout <= 0:
        raise ValueError("timeout must be a positive number")

    scheme = "https"
    url = _format_url(scheme, ip, path)

    # Prepare TLS context
    ssl_context = ssl.create_default_context(purpose=ssl.Purpose.SERVER_AUTH)
    ssl_context.minimum_version = ssl.TLSVersion.TLSv1_2

    if ca_path:
        if not os.path.isfile(ca_path):
            raise ValueError("CA certificate file not found")
        ssl_context.load_verify_locations(cafile=ca_path)
        verify_param = ca_path
    else:
        verify_param = True  # default system CAs

    if cert_path:
        if not os.path.isfile(cert_path):
            raise ValueError("Client certificate file not found")
        if key_path:
            if not os.path.isfile(key_path):
                raise ValueError("Client key file not found")
            ssl_context.load_cert_chain(certfile=cert_path, keyfile=key_path)
        else:
            ssl_context.load_cert_chain(certfile=cert_path)

    session = requests.Session()
    session.mount("https://", TLSAdapter(ssl_context))

    request_kwargs: Dict[str, Any] = {
        "timeout": timeout,
        "stream": True,
        "verify": verify_param,
    }
    if cert_path:
        request_kwargs["cert"] = (cert_path, key_path) if key_path else cert_path

    try:
        with session.get(url, **request_kwargs) as resp:
            resp.raise_for_status()
            content_chunks = []
            total_len = 0
            for chunk in resp.iter_content(chunk_size=8192):
                if not chunk:
                    break
                total_len += len(chunk)
                if total_len > MAX_RESPONSE_SIZE:
                    raise RuntimeError("Response size exceeds allowed limit")
