# Upper bounds for backâoff parameters
_MAX_INITIAL_SLEEP = 5.0      # seconds
_MAX_MAX_SLEEP = 60.0         # seconds
_MAX_FACTOR = 5.0
_MAX_TIMEOUT = 300.0          # seconds

def _is_process_running(pid: int) -> bool:
    """Check if a process with the given PID is running."""
    try:
        os.kill(pid, 0)
    except OSError as e:
        if e.errno == errno.ESRCH:
            return False
        if e.errno == errno.EPERM:
            return True
        return False
    else:
        return True

def _get_system_directory() -> str:
    """Return the Windows system directory using a safe system call."""
    buf = ctypes.create_unicode_buffer(260)
    if ctypes.windll.kernel32.GetSystemDirectoryW(buf, ctypes.sizeof(buf)) == 0:
        raise RuntimeError("Unable to retrieve Windows system directory")
    return buf.value

def _get_taskkill_path() -> str:
    """Return the absolute path to the genuine Windows taskkill executable."""
    system_dir = _get_system_directory()
    taskkill = os.path.join(system_dir, "taskkill.exe")
    if os.path.isfile(taskkill) and os.access(taskkill, os.X_OK):
        return taskkill
    raise RuntimeError("taskkill executable not found at expected location")

def _get_process_start_time(pid: int):
    """Return a monotonically increasing identifier for a process."""
    if os.name == "nt":
        PROCESS_QUERY_LIMITED_INFORMATION = 0x1000
        handle = ctypes.windll.kernel32.OpenProcess(
            PROCESS_QUERY_LIMITED_INFORMATION, False, pid
        )
        if not handle:
            return None
        try:
            creation = ctypes.wintypes.FILETIME()
            exit_ft = ctypes.wintypes.FILETIME()
            kernel_ft = ctypes.wintypes.FILETIME()
            user_ft = ctypes.wintypes.FILETIME()
            if not ctypes.windll.kernel32.GetProcessTimes(
                handle,
                ctypes.byref(creation),
                ctypes.byref(exit_ft),
                ctypes.byref(kernel_ft),
                ctypes.byref(user_ft),
            ):
                return None
            ft = (creation.dwHighDateTime << 32) + creation.dwLowDateTime
            seconds = ft * 1e-7
            epoch_diff = 11644473600  # Seconds between 1601â01â01 and 1970â01â01
            return seconds - epoch_diff
        finally:
            ctypes.windll.kernel32.CloseHandle(handle)
    else:
