def _validate_backoff_params(initial_sleep, max_sleep, factor, timeout) -> bool:
    """Validate backâoff parameters against defined safety limits."""
    if not (0 < initial_sleep <= _MAX_INITIAL_SLEEP):
        return False
    if not (0 < max_sleep <= _MAX_MAX_SLEEP):
        return False
    if max_sleep < initial_sleep:
        return False
    if not (1 < factor <= _MAX_FACTOR):
        return False
    if not (0 < timeout <= _MAX_TIMEOUT):
        return False
    return True

def terminate_process(pid, initial_sleep=0.1, max_sleep=5.0, factor=2.0, timeout=30.0):
    """
    Gracefully terminate a process identified by PID.

    Returns:
        0  - Process terminated successfully.
        -1 - Process not running.
        -2 - Permission denied, timeout, invalid input, or other error.
    """
    if not isinstance(pid, int) or pid <= 0:
        return -2
    if not all(isinstance(v, (int, float)) for v in (initial_sleep, max_sleep, factor, timeout)):
        return -2
    if not _validate_backoff_params(initial_sleep, max_sleep, factor, timeout):
