    original_start = _get_process_start_time(pid)
    if original_start is None:
        return -1  # Process not running or unable to query

    start_time = time.time()
    sleep_time = initial_sleep

    while True:
        if time.time() - start_time > timeout:
            return -2  # Timeout without successful termination

        if is_windows:
            env = {
                "SYSTEMROOT": os.getenv("SystemRoot", ""),
                "PATH": os.getenv("PATH", "")
