            if (now - data['created_at']).total_seconds() > TOKEN_EXPIRATION_SECONDS:
                return False
            if not hmac.compare_digest(data['hash'], token_hash):
                return False
            data['used'] = True
            return True

    def exists(self, user_id: uuid.UUID) -> bool:
        with self._lock:
            return user_id in self._store

token_store = TokenStore()

# ----------------------------------------------------------------------
# Simple rate limiter (inâmemory)
# ----------------------------------------------------------------------
class RateLimiter:
    def __init__(self):
        self._hits = {}
        self._lock = Lock()

    def is_allowed(self, ip: str) -> bool:
        now = time.time()
        with self._lock:
            hits = self._hits.get(ip, [])
            # Remove outdated hits
            hits = [t for t in hits if now - t < RATE_LIMIT_WINDOW]
            if len(hits) >= RATE_LIMIT:
                self._hits[ip] = hits
                return False
            hits.append(now)
            self._hits[ip] = hits
            return True

rate_limiter = RateLimiter()

def rate_limit():
    ip = request.remote_addr or 'unknown'
    if not rate_limiter.is_allowed(ip):
        current_app.logger.warning(f'Rate limit exceeded for IP {ip}')
        raise TooManyRequests('Too many requests, please try again later.')

