class BaseResetView:
    login_endpoint = 'login'

    @staticmethod
    def _validate_uid(uid: str) -> uuid.UUID:
        try:
            uid_obj = uuid.UUID(uid)
            if uid_obj.version != 4:
                raise ValueError()
            return uid_obj
        except (ValueError, AttributeError):
            raise BadRequest('Invalid request.') from None

    @staticmethod
    def _validate_token(token: str) -> str:
        if not isinstance(token, str) or not TOKEN_REGEX.fullmatch(token):
            raise BadRequest('Invalid request.') from None
        return token

    def _get_login_url(self) -> str:
        try:
            return url_for(self.login_endpoint, _external=True)
        except Exception as exc:  # pragma: no cover
            current_app.logger.error(f'Login URL generation failed: {exc}')
            return '/login'

# ----------------------------------------------------------------------
# Reset request view
# ----------------------------------------------------------------------
class ResetRequestView(BaseResetView):
    def dispatch(self, uid: str, token: str):
        self._validate_uid(uid)
        self._validate_token(token)

        login_url = self._get_login_url()
        try:
            return render_template('reset_request.html', login_url=login_url)
        except Exception as exc:  # pragma: no cover
            current_app.logger.error(f'Render error: {exc}')
            raise InternalServerError('Unable to process request.') from None

