# Reset complete view
# ----------------------------------------------------------------------
class ResetCompleteView(BaseResetView):
    def dispatch(self, uid: str, token: str, password: str):
        user_id = self._validate_uid(uid)
        self._validate_token(token)
        if not isinstance(password, str) or len(password) < 8:
            raise BadRequest('Invalid request.')

        if not token_store.verify_and_consume(user_id, token):
            raise BadRequest('Invalid or expired token.')

        # Here you would update the user's password in the database.
