            current_app.logger.error(f'Render error: {exc}')
            raise InternalServerError('Unable to process request.') from None

# ----------------------------------------------------------------------
# Flask view registration
# ----------------------------------------------------------------------
def register_reset_views(app: Flask):
    if not isinstance(app, Flask):
        raise TypeError('app must be a Flask instance')

    request_view = ResetRequestView()
    complete_view = ResetCompleteView()

    @app.route('/reset/request', methods=['POST'])
    def reset_request():
        try:
            rate_limit()
            data = request.get_json(silent=True) or {}
            uid = data.get('uid')
            token = data.get('token')
            if not uid or not token:
                raise BadRequest('Invalid request.')
            return request_view.dispatch(uid, token)
        except BadRequest:
            return 'Invalid request.', 400
        except TooManyRequests:
            return 'Too many requests, try again later.', 429
        except InternalServerError:
            return 'An unexpected error occurred.', 500

    @app.route('/reset/complete', methods=['POST'])
    def reset_complete():
        try:
            rate_limit()
            data = request.get_json(silent=True) or {}
            uid = data.get('uid')
            token = data.get('token')
            password = data.get('password')
            if not uid or not token or not password:
                raise BadRequest('Invalid request.')
            return complete_view.dispatch(uid, token, password)
        except BadRequest:
            return 'Invalid request.', 400
        except TooManyRequests:
            return 'Too many requests, try again later.', 429
        except InternalServerError:
            return 'An unexpected error occurred.', 500

    # Ensure a login endpoint exists for URL generation
    if not app.view_functions.get('login'):
        @app.route('/login', methods=['GET'])
        def login():
            return render_template('login.html')

import argparse
import hashlib
import json
import logging
import os
import sys
import tempfile
from pathlib import Path
from typing import Dict

CHUNK_SIZE = 8192
DEFAULT_HASH_STORE = "hash_store.json"

logger = logging.getLogger(__name__)
handler = logging.StreamHandler(sys.stderr)
formatter = logging.Formatter("%(asctime)s - %(levelname)s - %(message)s")
handler.setFormatter(formatter)
logger.setLevel(logging.INFO)
logger.addHandler(handler)
logger.propagate = False


def compute_hash(file_path: Path) -> str:
    """Compute SHA-256 hash of a file using a file descriptor to avoid TOCTOU."""
    sha256 = hashlib.sha256()
    try:
        flags = os.O_RDONLY
        if hasattr(os, "O_NOFOLLOW"):
            flags |= os.O_NOFOLLOW
        fd = os.open(str(file_path), flags)
        with os.fdopen(fd, "rb") as f:
            while True:
                chunk = f.read(CHUNK_SIZE)
                if not chunk:
                    break
                sha256.update(chunk)
    except OSError as e:
        logger.error("Unable to read file.")
        raise RuntimeError from e
    return sha256.hexdigest()


def load_hash_store(store_path: Path) -> Dict[str, str]:
    """Load stored hashes from JSON file; returns empty dict if file missing."""
    if not store_path.is_file():
        return {}
    try:
        with store_path.open("r", encoding="utf-8") as f:
            data = json.load(f)
            if not isinstance(data, dict):
                raise ValueError("Invalid hash store format")
            return {str(k): str(v) for k, v in data.items()}
    except (OSError, json.JSONDecodeError, ValueError) as e:
        logger.error("Failed to load hash store.")
        raise RuntimeError from e


def atomic_write_json(data: Dict[str, str], target: Path) -> None:
    """Write JSON data atomically with restrictive permissions."""
    dir_path = target.parent
    try:
        fd, tmp_path = tempfile.mkstemp(dir=dir_path, prefix=".tmp", suffix=".json")
        os.close(fd)
        tmp_file = Path(tmp_path)
        try:
            with tmp_file.open("w", encoding="utf-8") as f:
                json.dump(data, f, ensure_ascii=False, indent=2)
            os.chmod(tmp_file, 0o600)
            tmp_file.replace(target)
            os.chmod(target, 0o600)
        finally:
            if tmp_file.exists():
                tmp_file.unlink(missing_ok=True)
    except OSError as e:
        logger.error("Unable to write hash store.")
        raise RuntimeError from e


def validate_path(path: Path, base: Path, must_exist: bool = True) -> Path:
    """Resolve path and ensure it resides within the allowed base directory."""
    base_resolved = base.resolve()
    if must_exist:
        try:
            resolved = path.resolve(strict=True)
        except OSError as e:
            logger.error("File does not exist.")
            raise RuntimeError from e
    else:
        # Resolve as much as possible without requiring the final component to exist
        resolved = (path.parent.resolve() / path.name).resolve()
    try:
        resolved.relative_to(base_resolved)
    except ValueError:
        logger.error("Access to the specified path is prohibited.")
        raise RuntimeError
    return resolved


def main() -> None:
    parser = argparse.ArgumentParser(description="File version verifier")
    parser.add_argument(
        "file",
        type=Path,
        help="Path to the target file",
    )
    parser.add_argument(
        "--store",
        type=Path,
        default=Path(DEFAULT_HASH_STORE),
        help="Path to the hash store JSON file",
    )
    args = parser.parse_args()

    cwd = Path.cwd()
    try:
        target_file = validate_path(args.file, cwd, must_exist=True)
        store_path = validate_path(args.store, cwd, must_exist=False)
    except RuntimeError:
        sys.exit(1)

    try:
        current_hash = compute_hash(target_file)
    except RuntimeError:
        sys.exit(1)

    try:
        hash_store = load_hash_store(store_path)
    except RuntimeError:
        sys.exit(1)

    stored_hash = hash_store.get(str(target_file), "")
    if stored_hash == current_hash:
        logger.info("File version matches stored version.")
    else:
        hash_store[str(target_file)] = current_hash
        try:
            atomic_write_json(hash_store, store_path)
            logger.info("Stored version updated.")
        except RuntimeError:
            sys.exit(1)


if __name__ == "__main__":
    main()

import re
import math
import numpy as np
from scipy import stats

# Upper bound for the number of sample values to mitigate potential DoS
_MAX_SAMPLE_ITEMS = 100_000

# Build a whitelist of continuous distributions that provide a ppf method
_WHITELISTED_DISTS = {
    name for name in dir(stats)
    if isinstance(getattr(stats, name, None), stats.rv_continuous)
}

def _is_number(value):
    return isinstance(value, (int, float)) and not (math.isnan(value) or math.isinf(value))

def _sanitize_distribution_name(name):
    if not isinstance(name, str):
        raise ValueError("Distribution name must be a string.")
    # Disallow leading underscore
    if not re.fullmatch(r"[A-Za-z][A-Za-z0-9_]*", name):
        raise ValueError("Invalid distribution name format.")
    if name not in _WHITELISTED_DISTS:
        raise ValueError(f"Distribution '{name}' is not supported.")
    return name

def _sanitize_values(values):
    if not isinstance(values, (list, tuple)):
        raise ValueError("Values must be provided as a list or tuple.")
    if len(values) > _MAX_SAMPLE_ITEMS:
        raise ValueError(f"Number of values exceeds maximum allowed ({_MAX_SAMPLE_ITEMS}).")
    cleaned = [float(v) for v in values if _is_number(v)]
    if not cleaned:
        raise ValueError("No valid numeric values supplied.")
    return cleaned

def _validate_dist_params(dist_gen, params):
    # Retrieve allowed parameter names: shape parameters plus loc and scale
    dummy_dist = dist_gen()
    shape_params = set()
    if dummy_dist.shapes:
        shape_params = {s.strip() for s in dummy_dist.shapes.split(",")}
    allowed = shape_params.union({"loc", "scale"})
    for key in params:
        if key not in allowed:
            raise ValueError(f"Invalid parameter '{key}' for distribution '{dist_gen.name}'. Allowed parameters: {sorted(allowed)}")

def get_percentile_function(dist_name, values, *, dist_params=None, perc_method='linear'):
    """
    Returns a callable that computes the percentile (ppf) for the specified distribution.
    If the distribution lacks a native ppf, an empirical percentile based on `values`
    is used instead.
    """
    dist_name = _sanitize_distribution_name(dist_name)
    sample_values = _sanitize_values(values)
    dist_params = dist_params or {}

    dist_gen = getattr(stats, dist_name)
    _validate_dist_params(dist_gen, dist_params)

    try:
        dist = dist_gen(**dist_params)
    except Exception as exc:
        raise ValueError(f"Failed to create distribution '{dist_name}' with provided parameters: {exc}") from exc

    if hasattr(dist, "ppf") and callable(dist.ppf):
        def ppf_func(probs):
            if not isinstance(probs, (list, tuple, np.ndarray)):
                raise ValueError("Probabilities must be a list, tuple, or numpy array.")
            prob_array = np.asarray(probs, dtype=float)
            if np.any((prob_array < 0) | (prob_array > 1)):
                raise ValueError("Probabilities must be within the interval [0, 1].")
            try:
                return dist.ppf(prob_array)
            except Exception as exc:
                raise ValueError(f"Error computing the percentile function: {exc}") from exc
        return ppf_func
    else:
        sorted_vals = np.sort(sample_values)

        def empirical_ppf(probs):
            if not isinstance(probs, (list, tuple, np.ndarray)):
                raise ValueError("Probabilities must be a list, tuple, or numpy array.")
            prob_array = np.asarray(probs, dtype=float)
            if np.any((prob_array < 0) | (prob_array > 1)):
                raise ValueError("Probabilities must be within the interval [0, 1].")
            try:
                percentiles = prob_array * 100.0
                return np.percentile(sorted_vals, percentiles, method=perc_method)
            except Exception as exc:
                raise ValueError(f"Error computing empirical percentiles: {exc}") from exc
        return empirical_ppf

