_ENV_KEY_FILE = "SECRETS_MANAGER_KEY_FILE"


def _load_encryption_key() -> bytes:
    """
    Load a 256âbit AES key securely.
    Preference order:
    1. File pointed to by SECRETS_MANAGER_KEY_FILE (must have mode 0o600)
    2. Environment variable SECRETS_MANAGER_KEY (fallback, discouraged)
    3. Generate a fresh random key if neither is provided.
    """
    key_file_path = os.getenv(_ENV_KEY_FILE)
    if key_file_path:
        path = Path(key_file_path)
        if not path.is_file():
            raise ValueError(f"Key file '{key_file_path}' does not exist")
        # Ensure file permissions are restrictive (owner read/write only)
        st = path.stat()
        if stat.S_IMODE(st.st_mode) not in (0o600, 0o400):
            raise PermissionError(
                f"Key file '{key_file_path}' must have permissions 0600 or 0400"
            )
        key_data = path.read_bytes()
        if len(key_data) != 32:
            raise ValueError("Key file must contain exactly 32 raw bytes")
        return key_data

    env_key = os.getenv(_ENV_KEY_NAME)
    if env_key:
        try:
            key = base64.b64decode(env_key.encode())
            if len(key) != 32:
                raise ValueError
            logger.warning(
                "Loading encryption key from environment variable is discouraged."
            )
            return key
        except Exception as exc:
            raise ValueError("Invalid encryption key in environment") from exc

    # No supplied key â generate a new one (caller should persist it securely)
    logger.info("No encryption key supplied; generating a temporary key.")
    return AESGCM.generate_key(bit_length=256)


