import sys
import subprocess
import shutil
import resource
import stat
from collections import Counter
from pathlib import Path

MAX_EXTRACTED_SIZE = 10 * 1024 * 1024  # 10â¯MiB
EXTRACTION_TIMEOUT = 30  # seconds
TRUSTED_BINARY_DIRS = ("/usr/bin", "/bin", "/usr/local/bin")
SAFE_ENV = {"PATH": "/usr/bin:/bin"}


def safe_path(path_str: str) -> Path:
    if "�" in path_str:
        raise ValueError("Invalid path: null byte detected.")
    p = Path(path_str).expanduser()

    # Check each component for symlinks before any resolution
    components = [p] + list(p.parents)
    for comp in components:
        try:
            if comp.is_symlink():
                raise ValueError(f"Symlink component not allowed: {comp}")
        except OSError as e:
            raise ValueError(f"Unable to stat component: {comp}") from e

    try:
        resolved = p.resolve(strict=True)
    except FileNotFoundError as e:
        raise FileNotFoundError(f"File not found: {path_str}") from e

    if not resolved.is_file():
        raise FileNotFoundError(f"Path is not a regular file: {resolved}")
    return resolved


def _get_pdftotext_path() -> str:
    binary = shutil.which("pdftotext")
    if not binary:
        raise RuntimeError("pdftotext binary not found in PATH.")
    bin_path = Path(binary).resolve()
    if not bin_path.is_file():
        raise RuntimeError("pdftotext binary path is not a file.")
    if bin_path.is_symlink():
        raise RuntimeError("pdftotext binary must not be a symlink.")
    if not any(str(bin_path).startswith(d + os.sep) for d in TRUSTED_BINARY_DIRS):
        raise RuntimeError("pdftotext binary is not in a trusted directory.")
    return str(bin_path)


def _set_resource_limits():
    limit = MAX_EXTRACTED_SIZE * 2
    resource.setrlimit(resource.RLIMIT_AS, (limit, limit))
    if hasattr(resource, "RLIMIT_DATA"):
        resource.setrlimit(resource.RLIMIT_DATA, (limit, limit))
    resource.setrlimit(resource.RLIMIT_CPU, (EXTRACTION_TIMEOUT, EXTRACTION_TIMEOUT))


def extract_text(pdf_path: Path) -> str:
    binary = _get_pdftotext_path()
    try:
        proc = subprocess.Popen(
            [binary, "-layout", str(pdf_path), "-"],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            env=SAFE_ENV,
            preexec_fn=_set_resource_limits,
        )
    except Exception as e:
        raise RuntimeError("Failed to start PDF extraction tool.") from e

    stdout_chunks = []
    total_read = 0
    try:
        while True:
            chunk = proc.stdout.read(8192)
            if not chunk:
                break
            total_read += len(chunk)
            if total_read > MAX_EXTRACTED_SIZE:
                proc.kill()
                raise RuntimeError("Extracted text exceeds size limit.")
            stdout_chunks.append(chunk)
    finally:
        proc.stdout.close()

    try:
        proc.wait(timeout=EXTRACTION_TIMEOUT)
    except subprocess.TimeoutExpired:
        proc.kill()
        raise RuntimeError("PDF extraction timed out.")

    stderr_data = proc.stderr.read().decode("utf-8", errors="ignore")
    proc.stderr.close()

    if proc.returncode != 0:
        raise RuntimeError(f"PDF extraction failed: {stderr_data.strip()}")

    output_bytes = b"".join(stdout_chunks)
    return output_bytes.decode("utf-8", errors="replace")


def tokenize(text: str) -> list[str]:
    return re.findall(r" \w+ ", text.lower())


def build_bow(tokens: list[str]) -> dict[str, int]:
    return dict(Counter(tokens))


def write_bow(bow: dict[str, int], base_dir_fd: int, rel_path: Path) -> None:
    # Ensure no symlink exists in any intermediate directory component
    parent_parts = rel_path.parent.parts
    for i in range(len(parent_parts)):
        sub_path = Path(*parent_parts[: i + 1])
        try:
            st = os.stat(sub_path, dir_fd=base_dir_fd, follow_symlinks=False)
        except FileNotFoundError as e:
            raise ValueError(f"Directory component does not exist: {sub_path}") from e
        if stat.S_ISLNK(st.st_mode):
            raise ValueError(f"Symlink component not allowed: {sub_path}")

    flags = os.O_WRONLY | os.O_CREAT | os.O_EXCL
    fd = os.open(str(rel_path), flags, 0o600, dir_fd=base_dir_fd)
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            json.dump(bow, f, ensure_ascii=False, separators=(",", ":"))
    except Exception:
        os.close(fd)
        raise


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="PDF to Bag-of-Words converter")
    parser.add_argument(
        "pdf_file",
        type=str,
        help="Path to the input PDF file",
    )
    parser.add_argument(
        "output_file",
        type=str,
        nargs="?",
        default="bow.json",
        help="Filename for the output JSON (stored in a safe directory)",
    )
    return parser.parse_args()


def main() -> None:
    args = parse_args()

    pdf_path = safe_path(args.pdf_file)

    base_output_dir = Path.home() / ".bow_output"
    base_output_dir.mkdir(parents=True, exist_ok=True)

    output_candidate = Path(args.output_file).expanduser()
    if output_candidate.is_absolute():
        output_candidate = output_candidate.relative_to(output_candidate.root)

    output_path = (base_output_dir / output_candidate).resolve()
    try:
        output_path.relative_to(base_output_dir)
    except ValueError:
        print(f"Output path escapes allowed directory: {output_path}", file=sys.stderr)
        sys.exit(1)

    base_dir_fd = os.open(str(base_output_dir), os.O_RDONLY)
    try:
        rel_output = output_path.relative_to(base_output_dir)
        text = extract_text(pdf_path)
        tokens = tokenize(text)
        bow = build_bow(tokens)
        write_bow(bow, base_dir_fd, rel_output)
    except Exception as exc:
        print(f"Error: {exc}", file=sys.stderr)
        sys.exit(1)
    finally:
        os.close(base_dir_fd)


if __name__ == "__main__":
    main()

import os
import json
import logging
import stat
import threading
from pathlib import Path
from typing import Any, Iterable, Tuple

logger = logging.getLogger(__name__)
logger.addHandler(logging.NullHandler())

# Global lock to protect temporary umask changes
_umask_lock = threading.Lock()

# Secure creation of base directory with restrictive permissions
BASE_DIR = Path("/tmp/secure_shelf").resolve()
with _umask_lock:
    _old_umask = os.umask(0)
    try:
        BASE_DIR.mkdir(parents=True, exist_ok=True, mode=0o700)
    finally:
        os.umask(_old_umask)


def _is_allowed(value: Any, allowed: Tuple[type, ...]) -> bool:
    """Return True only if value and all nested items are instances of allowed builtin types."""
    if not isinstance(value, allowed):
        return False
    if isinstance(value, (list, tuple, set)):
        return all(_is_allowed(v, allowed) for v in value)
    if isinstance(value, dict):
        for k, v in value.items():
            if not isinstance(k, str):
                return False
            if not _is_allowed(v, allowed):
                return False
        return True
    return True


def _to_serializable(obj: Any) -> Any:
    """Convert containers to JSONâcompatible structures."""
    if isinstance(obj, (list, tuple, set)):
        return [_to_serializable(i) for i in obj]
    if isinstance(obj, dict):
        return {k: _to_serializable(v) for k, v in obj.items()}
    return obj


def _validate_path(full_path: Path) -> None:
    """Validate that the path stays inside BASE_DIR and contains no symlinks."""
    try:
        relative = full_path.relative_to(BASE_DIR)
    except ValueError:
        raise ValueError("Path traversal detected")

    # Walk each existing component to ensure it is not a symlink
    current = BASE_DIR
    for part in relative.parts:
        current = current / part
        try:
            st = os.lstat(current)
        except FileNotFoundError:
            # Component does not exist yet (final file); stop checking further parts.
            break
        if stat.S_ISLNK(st.st_mode):
            raise ValueError("Symlink in path is not allowed")


def create_data_filter(
    storage_path: str,
    allowed_types: Iterable[type],
    operation: str,
    data: Any = None,
    key: str = "default",
) -> Any:
    if operation not in ("record", "playback"):
        raise ValueError("Invalid operation")
    if not isinstance(storage_path, str):
        raise ValueError("storage_path must be a string")
    if not isinstance(key, str):
        raise ValueError("key must be a string")

    # Validate allowed_types contain type objects
    allowed = tuple(allowed_types)
    if not allowed:
        raise ValueError("allowed_types cannot be empty")
    if not all(isinstance(t, type) for t in allowed):
        raise ValueError("allowed_types must contain type objects")

    # Reject absolute or traversal paths before concatenation
    sp = Path(storage_path)
    if sp.is_absolute() or ".." in sp.parts:
        raise ValueError("storage_path must be a relative safe path")

    try:
        full_path = BASE_DIR / sp
        _validate_path(full_path)

        # Create parent directory securely
        parent = full_path.parent
        if not parent.is_dir():
            with _umask_lock:
                _old_umask = os.umask(0)
                try:
                    parent.mkdir(parents=True, exist_ok=True, mode=0o700)
                finally:
                    os.umask(_old_umask)
    except Exception:
        logger.error("Failed to resolve storage_path")
        raise RuntimeError("Storage configuration error") from None

    json_path = full_path.with_suffix(".json")
    max_size = 1 * 1024 * 1024  # 1â¯MiB size limit for stored JSON

    try:
        fd = os.open(
            str(json_path),
            os.O_RDWR | os.O_CREAT | os.O_NOFOLLOW,
            0o600,
        )
        # Verify that the opened file resides within BASE_DIR
        try:
            real_path = Path(os.readlink(f"/proc/self/fd/{fd}")).resolve()
        except Exception:
            real_path = None
        if real_path is None or not str(real_path).startswith(str(BASE_DIR)):
            os.close(fd)
            raise ValueError("Path traversal detected after opening file")

        with os.fdopen(fd, "r+", encoding="utf-8") as f:
            f.seek(0)
            content = f.read(max_size + 1)
            if len(content) > max_size:
                raise ValueError("Stored data exceeds size limit")
            try:
                store = json.loads(content) if content else {}
            except json.JSONDecodeError:
                store = {}

            if operation == "record":
                if data is None:
                    raise ValueError("Data must be provided for record operation")
                if not _is_allowed(data, allowed):
                    raise ValueError("Data contains disallowed types")
                store[key] = _to_serializable(data)
                f.seek(0)
                f.truncate()
                json.dump(store, f, separators=(",", ":"))
                f.flush()
                os.fsync(f.fileno())
                return True
            else:  # playback
                if key not in store:
                    raise RuntimeError("Requested key not found")
                stored = store[key]
                if not _is_allowed(stored, allowed):
                    raise RuntimeError("Stored data contains disallowed types")
                return stored
    except OSError as exc:
        logger.error("File operation failed")
        raise RuntimeError("Data storage error") from exc

import os
import stat
import subprocess
import logging
import tempfile
from pathlib import Path
from typing import List, Tuple

SAFE_VM_ROOT_BASE = Path("/srv/vm_roots").resolve()
SSH_KEYGEN_ABS = "/usr/bin/ssh-keygen"


def _is_subpath(child: Path, parent: Path) -> bool:
    try:
        child.relative_to(parent)
        return True
    except ValueError:
        return False


def _assert_path_safe(base: Path, target: Path) -> None:
    """Raise ValueError if *target* is outside *base* or contains symlinks."""
    resolved = target.resolve()
    if not _is_subpath(resolved, base):
        raise ValueError(f"Path {resolved} is outside allowed base {base}")
    for p in resolved.parents:
        if p == base.parent:
            break
        if p.is_symlink():
            raise ValueError(f"Symlink component detected in path: {p}")
    if resolved.is_symlink():
        raise ValueError(f"Symlink component detected in path: {resolved}")


def _safe_mkdir(dir_path: Path, base: Path, mode: int = 0o700) -> None:
    """
    Create a directory atomically and verify that it is not a symlink
    and resides under *base*.
    """
    try:
        os.mkdir(dir_path, mode=mode)
    except FileExistsError:
        # Directory already exists; ensure it is a real directory
        pass
    except OSError as exc:
        raise RuntimeError(f"Unable to create directory {dir_path}: {exc}") from exc

    # Reâvalidate after creation
    try:
        st = os.lstat(dir_path)
    except OSError as exc:
        raise RuntimeError(f"Unable to stat directory {dir_path}: {exc}") from exc

    if stat.S_ISLNK(st.st_mode):
        raise RuntimeError(f"Directory {dir_path} is a symlink after creation")
    if not stat.S_ISDIR(st.st_mode):
        raise RuntimeError(f"Path {dir_path} is not a directory after creation")

    _assert_path_safe(base, dir_path)


def generate_ssh_keys(vm_root_path: str, logger_name: str) -> None:
    logger = logging.getLogger(logger_name)

    if not isinstance(vm_root_path, str) or not vm_root_path:
        raise ValueError("vm_root_path must be a nonâempty string")

    root_path = Path(vm_root_path).resolve()
    if not root_path.is_absolute():
        raise ValueError("vm_root_path must be an absolute path")
    if not root_path.is_dir():
        raise ValueError(f"vm_root_path does not exist or is not a directory: {root_path}")
    if not _is_subpath(root_path, SAFE_VM_ROOT_BASE):
        raise ValueError(f"vm_root_path must be within {SAFE_VM_ROOT_BASE}")

    ssh_dir = root_path / "etc" / "ssh"
    try:
        _assert_path_safe(SAFE_VM_ROOT_BASE, ssh_dir)
        _safe_mkdir(ssh_dir, SAFE_VM_ROOT_BASE, mode=0o700)
    except Exception as exc:
        rel = ssh_dir.relative_to(SAFE_VM_ROOT_BASE)
        logger.error("Failed to prepare SSH directory %s: %s", rel, exc)
        return

    allowed_key_types = {"rsa", "ed25519", "ecdsa"}
    keys: List[Tuple[str, str, str | None]] = [
        ("ssh_host_rsa_key", "rsa", "4096"),
        ("ssh_host_ed25519_key", "ed25519", None),
        ("ssh_host_ecdsa_key", "ecdsa", "256"),
    ]

    for filename, key_type, bits in keys:
        if key_type not in allowed_key_types:
            logger.error("Unsupported key type encountered: %s", key_type)
            continue

        private_key_path = ssh_dir / filename
        public_key_path = ssh_dir / f"{filename}.pub"

        for p in (private_key_path, public_key_path):
            try:
                if p.is_file() or p.is_symlink():
                    p.unlink(missing_ok=True, follow_symlinks=False)
            except Exception as exc:
                rel = p.relative_to(SAFE_VM_ROOT_BASE)
                logger.warning("Could not remove existing key file %s: %s", rel, exc)

        try:
            _assert_path_safe(SAFE_VM_ROOT_BASE, private_key_path)
        except Exception as exc:
            rel = private_key_path.relative_to(SAFE_VM_ROOT_BASE)
            logger.error("Key path validation failed for %s: %s", rel, exc)
            continue

        if not Path(SSH_KEYGEN_ABS).is_file():
            logger.error("ssh-keygen binary not found at %s", SSH_KEYGEN_ABS)
            return

        cmd = [
            SSH_KEYGEN_ABS,
            "-q",
            "-t", key_type,
            "-f", str(private_key_path),
            "-N", "",
        ]
        if bits:
            cmd.extend(["-b", bits])

        try:
            result = subprocess.run(
                cmd,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                env={"PATH": "/usr/bin"},
                cwd=str(ssh_dir),
                check=False,
            )
        except Exception as exc:
            logger.error("Failed to execute ssh-keygen for %s: %s", key_type, exc)
            continue

        if result.returncode != 0:
            logger.error(
                "ssh-keygen failed for type %s (file %s): %s",
                key_type,
                private_key_path.name,
                result.stderr.strip(),
            )
            continue

        # Verify generated files are regular files and not symlinks
        try:
            for p, mode in ((private_key_path, 0o600), (public_key_path, 0o644)):
                st = os.lstat(p)
                if not stat.S_ISREG(st.st_mode):
                    raise RuntimeError(f"{p} is not a regular file")
                if stat.S_ISLNK(st.st_mode):
                    raise RuntimeError(f"{p} is a symlink")
                p.chmod(mode)
        except Exception as exc:
            rel = private_key_path.relative_to(SAFE_VM_ROOT_BASE)
            logger.warning("Failed to validate/set permissions for keys %s: %s", rel, exc)

    sshd_config_path = ssh_dir / "sshd_config"
    try:
        _assert_path_safe(SAFE_VM_ROOT_BASE, sshd_config_path)
        existing_lines = sshd_config_path.read_text(encoding="utf-8").splitlines()
    except FileNotFoundError:
        existing_lines = []
    except Exception as exc:
        logger.error("Unable to read sshd_config: %s", exc)
        return

    hostkey_lines = {f"HostKey {ssh_dir / fn}" for fn, _, _ in keys}

    new_lines: List[str] = []
    seen_hostkey = set()
    for line in existing_lines:
        stripped = line.strip()
        if stripped.lower().startswith("hostkey"):
            parts = stripped.split(None, 1)
            if len(parts) == 2:
                key_name = Path(parts[1]).name
                abs_path = (ssh_dir / key_name).resolve()
                replacement = f"HostKey {abs_path}"
                if replacement not in seen_hostkey:
                    new_lines.append(replacement)
                    seen_hostkey.add(replacement)
            continue
        new_lines.append(line)

    for hk in sorted(hostkey_lines):
        if hk not in seen_hostkey:
            new_lines.append(hk)

    try:
        with tempfile.NamedTemporaryFile(
            mode="w",
            encoding="utf-8",
            delete=False,
            dir=str(ssh_dir),
            prefix="sshd_config.",
            suffix=".tmp",
            mode=0o600,
        ) as tmp:
            tmp.write("
".join(new_lines) + "
")
            temp_path = Path(tmp.name)
        temp_path.replace(sshd_config_path)
        sshd_config_path.chmod(0o644)
    except Exception as exc:
        logger.error("Failed to write updated sshd_config: %s", exc)
        return

    logger.info("SSH host keys regenerated and sshd_config updated successfully.")

import argparse
import json
import logging
import os
import pathlib
import stat
import sys
import tempfile
from typing import Any, List, Set

MAX_FILE_SIZE = 1 * 1024 * 1024  # 1â¯MiB
MAX_JSON_DEPTH = 100
MAX_JSON_ELEMENTS = 10000

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    stream=sys.stderr,
)
logger = logging.getLogger(__name__)


def _no_symlink_in_path(path: pathlib.Path) -> None:
    """Raise ValueError if any component of *path* (including the final one) is a symlink."""
    # Build an absolute path without resolving symlinks
    abs_path = pathlib.Path(os.path.abspath(str(path)))
    parts = abs_path.parts
    # Start from the root (or drive on Windows)
    cur = pathlib.Path(parts[0])
    for part in parts[1:]:
        cur = cur / part
        try:
            st = os.lstat(cur)
        except FileNotFoundError as exc:
            raise ValueError(f"Path component does not exist: {cur}") from exc
        if stat.S_ISLNK(st.st_mode):
            raise ValueError(f"Symlink detected in path component: {cur}")


def validate_path(path_str: str) -> pathlib.Path:
    """Validate that *path_str* points to an existing regular file and contains no symlinks."""
    expanded = os.path.expanduser(path_str)
    absolute = os.path.abspath(expanded)
    p = pathlib.Path(absolute)

    _no_symlink_in_path(p)

    try:
        st = os.lstat(p)
    except FileNotFoundError as exc:
        raise ValueError(f"File not found: {p}") from exc

    if not stat.S_ISREG(st.st_mode):
        raise ValueError(f"Not a regular file: {p}")
    return p


def validate_output_path(path_str: str) -> pathlib.Path:
    """Validate that *path_str* can be safely written to: parent exists, no symlinks in any component,
    and the target itself is not a symlink (it may or may not exist)."""
    expanded = os.path.expanduser(path_str)
    absolute = os.path.abspath(expanded)
    p = pathlib.Path(absolute)

    _no_symlink_in_path(p.parent)

    if p.is_dir():
        raise ValueError(f"Output path is a directory: {p}")

    # Ensure the target itself is not a symlink if it exists
    try:
        st = os.lstat(p)
        if stat.S_ISLNK(st.st_mode):
            raise ValueError(f"Output path is a symlink: {p}")
    except FileNotFoundError:
        pass  # Acceptable; file will be created

    return p


def _json_structure_check(
    obj: Any,
    depth: int = 0,
    max_depth: int = MAX_JSON_DEPTH,
    max_elements: int = MAX_JSON_ELEMENTS,
    counter: List[int] = None,
) -> None:
    if counter is None:
        counter = [0]
    if depth > max_depth:
        raise ValueError("JSON exceeds maximum nesting depth")
    counter[0] += 1
    if counter[0] > max_elements:
        raise ValueError("JSON exceeds maximum number of elements")
    if isinstance(obj, dict):
        for k, v in obj.items():
            _json_structure_check(k, depth + 1, max_depth, max_elements, counter)
            _json_structure_check(v, depth + 1, max_depth, max_elements, counter)
    elif isinstance(obj, (list, tuple, set)):
        for item in obj:
            _json_structure_check(item, depth + 1, max_depth, max_elements, counter)


def safe_load(path: pathlib.Path) -> Any:
    """Open *path* without following symlinks and safely load JSON."""
    fd = os.open(str(path), os.O_RDONLY | os.O_NOFOLLOW)
    try:
        sb = os.fstat(fd)
        if not stat.S_ISREG(sb.st_mode):
            raise ValueError("Not a regular file")
        if sb.st_size > MAX_FILE_SIZE:
            raise ValueError("File too large")
        with os.fdopen(fd, "rb") as f:
            data = json.load(f)
        _json_structure_check(data)
        return data
    finally:
        try:
            os.close(fd)
        except OSError:
            pass


def safe_dump(obj: Any, path: pathlib.Path) -> None:
    """Write *obj* as JSON to *path* atomically, avoiding symlink races."""
    data = json.dumps(obj, ensure_ascii=False, separators=(",", ":")).encode("utf-8")
    if len(data) > MAX_FILE_SIZE:
        raise ValueError("Data exceeds maximum allowed size")

    # Write to a temporary file in the same directory
    tmp_fd, tmp_name = tempfile.mkstemp(dir=str(path.parent), prefix=".tmp.", text=False)
    try:
        os.fchmod(tmp_fd, 0o600)
        with os.fdopen(tmp_fd, "wb") as tmp_file:
            tmp_file.write(data)

        # Atomically replace without a prior symlink check
        os.replace(tmp_name, str(path))
    finally:
        try:
            os.unlink(tmp_name)
        except OSError:
            pass


def linear_interpolate(values: List[float], target_len: int) -> List[float]:
    if not values:
        return []
    if target_len <= 1:
        return [values[0]]
    n = len(values) - 1
    step = n / (target_len - 1)
    result = []
    for i in range(target_len):
        pos = i * step
        lower = int(pos)
        upper = min(lower + 1, n)
        ratio = pos - lower
        interp = values[lower] * (1 - ratio) + values[upper] * ratio
        result.append(interp)
    return result


def _replace(obj: Any, search: str, replace: str, visited: Set[int]) -> Any:
    if id(obj) in visited:
        return obj
    visited.add(id(obj))
    if isinstance(obj, str):
        return obj.replace(search, replace)
    if isinstance(obj, list):
        return [_replace(item, search, replace, visited) for item in obj]
    if isinstance(obj, tuple):
        return tuple(_replace(item, search, replace, visited) for item in obj)
    if isinstance(obj, set):
        new_set = set()
        for item in obj:
            new_item = _replace(item, search, replace, visited)
            try:
                hash(new_item)
                new_set.add(new_item)
            except TypeError:
                new_set.add(item)
        return new_set
    if isinstance(obj, dict):
        new_dict = {}
        for k, v in obj.items():
            new_k = _replace(k, search, replace, visited)
            new_v = _replace(v, search, replace, visited)
            try:
                hash(new_k)
                new_dict[new_k] = new_v
            except TypeError:
                new_dict[k] = v
        return new_dict
    return obj


def replace_in_obj(obj: Any, search: str, replace: str) -> Any:
    return _replace(obj, search, replace, set())


def main() -> None:
    parser = argparse.ArgumentParser(description="Process JSON files securely.")
    parser.add_argument("--interp-input", required=True, help="Path to JSON file for interpolation")
    parser.add_argument("--interp-output", required=True, help="Path to write interpolated JSON")
    parser.add_argument("--interp-points", type=int, required=True, help="Number of points after interpolation")
    parser.add_argument("--replace-input", required=True, help="Path to JSON file for search/replace")
    parser.add_argument("--replace-output", required=True, help="Path to write modified JSON")
    parser.add_argument("--search", required=True, help="String to search for")
    parser.add_argument("--replace", required=True, help="String to replace with")
    args = parser.parse_args()

    try:
        if args.interp_points <= 0:
            raise ValueError("interp-points must be a positive integer")
        interp_input_path = validate_path(args.interp_input)
        interp_output_path = validate_output_path(args.interp_output)
        replace_input_path = validate_path(args.replace_input)
        replace_output_path = validate_output_path(args.replace_output)

        data = safe_load(interp_input_path)
        if not isinstance(data, list) or not all(isinstance(x, (int, float)) for x in data):
            raise TypeError("Interpolation input must be a list of numbers")
        interpolated = linear_interpolate([float(x) for x in data], args.interp_points)
        safe_dump(interpolated, interp_output_path)

        data2 = safe_load(replace_input_path)
        modified = replace_in_obj(data2, args.search, args.replace)
        safe_dump(modified, replace_output_path)

    except (ValueError, PermissionError, IOError, json.JSONDecodeError, TypeError) as e:
        logger.debug("Operation failed: %s", e, exc_info=True)
        sys.stderr.write("Error: operation failed.
")
        sys.exit(1)
    except Exception as e:
        logger.exception("Unexpected error")
        sys.stderr.write("An unexpected error occurred.
")
        sys.exit(1)


if __name__ == "__main__":
    main()

import argparse
import ast
import json
import logging
import os
import sys
import multiprocessing
import traceback
from types import MappingProxyType
from typing import Any, Dict, Tuple, Union

# Configure logger (error messages are generic to avoid leaking script contents)
logging.basicConfig(level=logging.ERROR, format="%(message)s")
_internal_logger = logging.getLogger("secure_executor_internal")
_internal_logger.setLevel(logging.DEBUG)

# Whitelisted safe builtins (immutable proxy will be used at runtime)
SAFE_BUILTINS: Dict[str, Any] = {
    "abs": abs,
    "all": all,
    "any": any,
    "bool": bool,
    "dict": dict,
    "enumerate": enumerate,
    "float": float,
    "int": int,
    "len": len,
    "list": list,
    "map": map,
    "max": max,
    "min": min,
    "range": range,
    "set": set,
    "sorted": sorted,
    "str": str,
    "sum": sum,
    "tuple": tuple,
    "zip": zip,
}
_SAFE_BUILTINS_PROXY = MappingProxyType(SAFE_BUILTINS)

# Directory that may contain scripts
SCRIPTS_ROOT = os.path.realpath(os.path.abspath("scripts"))


class SecurityError(Exception):
    """Raised when the script contains disallowed constructs."""


class SecureASTValidator(ast.NodeVisitor):
    """Reject unsafe AST nodes."""

    BLACKLISTED_NAMES = {
        "eval",
        "exec",
        "compile",
        "open",
        "__import__",
        "input",
        "globals",
        "locals",
        "vars",
        "dir",
    }

    def visit_Import(self, node: ast.Import) -> None:
        raise SecurityError("Import statements are not allowed")

    def visit_ImportFrom(self, node: ast.ImportFrom) -> None:
        raise SecurityError("Import statements are not allowed")

    def visit_Call(self, node: ast.Call) -> None:
        if isinstance(node.func, ast.Name) and node.func.id in self.BLACKLISTED_NAMES:
            raise SecurityError(f"Use of '{node.func.id}' is not allowed")
        if isinstance(node.func, ast.Attribute):
            raise SecurityError("Attribute calls are not allowed")
        self.generic_visit(node)

    def visit_Attribute(self, node: ast.Attribute) -> None:
        raise SecurityError("Attribute access is not allowed")


def _validate_path(path: str) -> str:
    if not isinstance(path, str):
        raise TypeError("Path must be a string")
    abs_path = os.path.abspath(path) if not os.path.isabs(path) else path
    real_path = os.path.realpath(abs_path)

    # Ensure the resolved path is inside the allowed scripts directory
    if not os.path.commonpath([SCRIPTS_ROOT, real_path]) == SCRIPTS_ROOT:
        _internal_logger.debug(
            "Path validation failed: outside allowed directory (%s)", real_path
        )
        raise ValueError("Invalid script path")
    if not os.path.isfile(real_path):
        _internal_logger.debug(
            "Path validation failed: file not found (%s)", real_path
        )
        raise FileNotFoundError("Invalid script path")
    if os.path.getsize(real_path) > 1_048_576:
        _internal_logger.debug(
            "Path validation failed: file too large (%s)", real_path
        )
        raise ValueError("Invalid script path")
    return real_path


def _validate_script(script: str) -> None:
    try:
        parsed = ast.parse(script, mode="exec")
    except SyntaxError as exc:
        raise SecurityError(f"Script contains syntax errors: {exc}") from exc
    validator = SecureASTValidator()
    validator.visit(parsed)


def _is_safe_value(value: Any) -> bool:
    if isinstance(value, (str, int, float, bool, type(None))):
        return True
    if isinstance(value, (list, tuple, set)):
        return all(_is_safe_value(v) for v in value)
    if isinstance(value, dict):
        return all(isinstance(k, str) and _is_safe_value(v) for k, v in value.items())
    return False


def _result_size_ok(value: Any, max_items: int = 1000) -> bool:
    """Recursively ensure collections do not exceed max_items."""
    if isinstance(value, (list, tuple, set)):
        if len(value) > max_items:
            return False
        return all(_result_size_ok(v, max_items) for v in value)
    if isinstance(value, dict):
        if len(value) > max_items:
            return False
        return all(isinstance(k, str) and _result_size_ok(v, max_items) for k, v in value.items())
    return True


def _sanitize_locals(local_vars: Dict[str, Any]) -> Dict[str, Any]:
    sanitized: Dict[str, Any] = {}
    for k, v in local_vars.items():
        if not isinstance(k, str):
            raise TypeError("All keys in local_vars must be strings")
        if not _is_safe_value(v):
            raise TypeError(f"Unsafe value for key '{k}' in local_vars")
        sanitized[k] = v
    return sanitized


def _worker(
    script: str,
    secondary_path: Union[str, None],
    local_vars: Dict[str, Any],
    result_queue: multiprocessing.Queue,
) -> None:
    try:
        # Resource limits (Unix only)
        try:
            import resource

            # Limit CPU time (seconds)
            resource.setrlimit(resource.RLIMIT_CPU, (5, 5))
            # Limit address space (bytes) ~100MiB
            limit = 100 * 1024 * 1024
            resource.setrlimit(resource.RLIMIT_AS, (limit, limit))
        except (ImportError, OSError, ValueError) as e:
            _internal_logger.debug("Resource limits not applied: %s", e)

        _validate_script(script)

        exec_globals = {"__builtins__": _SAFE_BUILTINS_PROXY}
        exec_locals = dict(local_vars)

        # Execute primary script
        compiled_main = compile(script, "<main_script>", "exec")
        exec(compiled_main, exec_globals, exec_locals)
        exec_globals["__builtins__"] = _SAFE_BUILTINS_PROXY  # reâenforce safe builtins

        # Optional secondary script
        if secondary_path:
            sec_path = _validate_path(secondary_path)
            with open(sec_path, "r", encoding="utf-8") as f:
                secondary_script = f.read()
            _validate_script(secondary_script)
            compiled_sec = compile(secondary_script, sec_path, "exec")
            exec(compiled_sec, exec_globals, exec_locals)
            exec_globals["__builtins__"] = _SAFE_BUILTINS_PROXY

        # Retrieve and validate result
        result = exec_locals.get("result")
        if not _is_safe_value(result):
            raise TypeError("Result contains unsafe type")
        if not _result_size_ok(result):
            raise ValueError("Result size exceeds allowed limits")
        result_queue.put(("result", result))
    except Exception as exc:
        tb = "".join(traceback.format_exception_only(type(exc), exc))
        result_queue.put(("error", tb))


def run_script(
    local_vars: Dict[str, Any],
    script: str,
    secondary_path: Union[str, None] = None,
    timeout: int = 5,
):
    if not isinstance(local_vars, dict):
        raise TypeError("local_vars must be a dict")
    if not isinstance(script, str):
        raise TypeError("script must be a string")
    sanitized_locals = _sanitize_locals(local_vars)

    result_queue: multiprocessing.Queue = multiprocessing.Queue()
    proc = multiprocessing.Process(
        target=_worker,
        args=(script, secondary_path, sanitized_locals, result_queue),
    )
    proc.start()
    proc.join(timeout)

    if proc.is_alive():
        proc.terminate()
        proc.join()
        logging.error("Script execution timed out.")
        raise RuntimeError("Script execution timed out.")

    if result_queue.empty():
        logging.error("No result returned from script.")
        raise RuntimeError("Script execution failed without result.")

    status, payload = result_queue.get()
    if status == "result":
        return payload
    else:
        logging.error("An error occurred during script execution.")
        raise RuntimeError("Script execution failed.")


def _read_script_file(path: str) -> str:
    path = _validate_path(path)
    with open(path, "r", encoding="utf-8") as f:
        return f.read()


def main() -> None:
    parser = argparse.ArgumentParser(description="Secure script executor")
    parser.add_argument("script", help="Path to the primary Python script")
    parser.add_argument(
        "--secondary", help="Path to an optional secondary script", default=None
    )
    args = parser.parse_args()

    try:
        primary_code = _read_script_file(args.script)
        run_script({}, primary_code, args.secondary)
    except Exception:
        logging.error("Script execution failed.")
        sys.exit(1)


if __name__ == "__main__":
    main()

