def test_library_method(library_mock, method_name):
    """
    Validate and test a method of a library through PythonHandler.

    Args:
        library_mock: An object that mimics the target library. Must provide
            `expected_results` and `arg_limits` dictionaries.
        method_name (str): Name of the method to test.

    Returns:
        bool: True if all assertions pass.

    Raises:
        TypeError: If inputs are of incorrect type.
        ValueError: If inputs fail validation checks.
        AssertionError: If any test assertion fails.
        RuntimeError: For unexpected runtime errors.
    """
    import json

    def _is_json_serializable(obj):
        try:
            json.dumps(obj)
            return True
        except (TypeError, OverflowError):
            return False

    def _safe_compare(a, b):
        if type(a) is not type(b):
            return False
        if _is_json_serializable(a) and _is_json_serializable(b):
            try:
                return json.dumps(a, sort_keys=True) == json.dumps(b, sort_keys=True)
            except TypeError:
                # Fallback for nonâserializable structures
                pass
        return a is b

    # Input validation
    if not hasattr(library_mock, "expected_results") or not hasattr(library_mock, "arg_limits"):
        raise TypeError("library_mock must expose expected_results and arg_limits attributes")
    if not isinstance(method_name, str):
        raise TypeError("method_name must be a string")
    if not method_name.isidentifier():
        raise ValueError("method_name must be a valid identifier")
    if method_name != method_name.strip():
        raise ValueError("method_name contains leading/trailing whitespace")
    safe_method_name = method_name

    # Reject dunder or magic names
    if safe_method_name.startswith("__") or "__" in safe_method_name:
        raise ValueError(f"Disallowed method name '{safe_method_name}'")

    # Retrieve expected data
    expected_output = library_mock.expected_results.get(safe_method_name)
    arg_limits = library_mock.arg_limits.get(safe_method_name)
    if expected_output is None or arg_limits is None:
        raise ValueError(f"Missing test data for method '{safe_method_name}'")
    min_args, max_args = arg_limits

    # Create handler (assumes PythonHandler follows leastâprivilege design)
    try:
        handler = PythonHandler(library_mock, safe_method_name)
    except Exception as exc:
        raise RuntimeError("Failed to instantiate PythonHandler") from exc

    # Resolve method safely
    try:
        method = getattr(handler, safe_method_name)
    except AttributeError as exc:
        raise AssertionError(f"Handler does not expose method '{safe_method_name}'") from exc

    # Verify argument count limits
    try:
        from inspect import signature
        sig = signature(method)
        param_count = len(sig.parameters)
    except Exception as exc:
        raise RuntimeError("Unable to inspect method signature") from exc
    if not (min_args <= param_count <= max_args):
        raise AssertionError(
            f"Method '{safe_method_name}' argument count {param_count} outside expected range "
            f"[{min_args}, {max_args}]"
        )

    # Prepare arguments within limits (using simple placeholders)
    test_args = tuple(None for _ in range(param_count))

    # Execute method and compare result
    try:
        result = method(*test_args)
    except Exception as exc:
        raise AssertionError(f"Method '{safe_method_name}' raised an exception during test") from exc

    if not _safe_compare(result, expected_output):
        raise AssertionError(
            f"Method '{safe_method_name}' returned {result!r}, expected {expected_output!r}"
        )

    # All checks passed
    return True

import json
import logging
import socket
import urllib.parse
import ipaddress
import ssl
import http.client

logging.basicConfig(level=logging.INFO)
_logger = logging.getLogger(__name__)

_MAX_PAYLOAD_SIZE = 1 * 1024 * 1024  # 1â¯MiB
_MAX_RESPONSE_SIZE = 1 * 1024 * 1024  # 1â¯MiB
_ALLOWED_SCHEMES = {"https"}
_ALLOWED_METHODS = {"GET", "POST", "PUT", "DELETE", "PATCH", "HEAD", "OPTIONS"}
_DENY_HOSTNAMES = {
    "localhost",
    "127.0.0.1",
    "::1",
    "0.0.0.0",
    "255.255.255.255",
    "example",
    "example.com",
    "example.org",
    "example.net",
    "local",
    "intranet",
}


def _is_private_ip(address: str) -> bool:
    try:
        ip = ipaddress.ip_address(address)
        return (
            ip.is_private
            or ip.is_loopback
            or ip.is_link_local
            or ip.is_reserved
            or ip.is_multicast
        )
    except ValueError:
        return False


def _resolve_and_check_private(hostname: str) -> list[str]:
    """Resolve hostname and ensure no private IPs are returned."""
    if _is_private_ip(hostname):
        raise ValueError("URL resolves to a private or prohibited IP address")
    try:
        infos = socket.getaddrinfo(hostname, None)
    except socket.gaierror as exc:
        raise ValueError(f"Failed to resolve hostname: {exc}") from exc

    ips = []
    for _, _, _, _, sockaddr in infos:
        ip = sockaddr[0]
        if _is_private_ip(ip):
            raise ValueError("URL resolves to a private or prohibited IP address")
        ips.append(ip)
    if not ips:
        raise ValueError("Hostname could not be resolved to any IP address")
    return list(dict.fromkeys(ips))  # deduplicate while preserving order


def _is_denied_hostname(hostname: str) -> bool:
    """Return True if the hostname matches a denied name or any of its subâdomains."""
    lower = hostname.lower()
    for denied in _DENY_HOSTNAMES:
        denied = denied.lower()
        if lower == denied or lower.endswith("." + denied):
            return True
    return False


def _validate_url(url: str) -> str:
    if not isinstance(url, str):
        raise ValueError("URL must be a string")
    parsed = urllib.parse.urlparse(url)

    if parsed.scheme not in _ALLOWED_SCHEMES:
        raise ValueError("Only HTTPS URLs are allowed")
    if parsed.port and parsed.port != 443:
        raise ValueError("Nonâstandard ports are not allowed")
    if not parsed.netloc:
        raise ValueError("URL must have a network location")
    if parsed.username or parsed.password:
        raise ValueError("Credentials must not be included in the URL")

    hostname = parsed.hostname
    if not hostname:
        raise ValueError("URL must contain a hostname")

    # Disallow raw IP literals
    try:
        ipaddress.ip_address(hostname)
        raise ValueError("IP literals are not allowed in URLs")
    except ValueError:
        pass  # Not an IP address, continue

    if _is_denied_hostname(hostname):
        raise ValueError("Hostname is prohibited")
    _resolve_and_check_private(hostname)

    clean_url = urllib.parse.urlunparse(
        (
            parsed.scheme,
            parsed.netloc,
            parsed.path,
            parsed.params,
            parsed.query,
            parsed.fragment,
        )
    )
    return clean_url


class _IPHTTPSConnection(http.client.HTTPSConnection):
    """HTTPSConnection that connects to a specific IP while using the original hostname for SNI."""

    def __init__(self, host: str, ip: str, timeout: int, context: ssl.SSLContext):
        super().__init__(host, port=443, timeout=timeout, context=context, check_hostname=True)
        self._ip = ip

    def connect(self):
        self.sock = socket.create_connection((self._ip, self.port), self.timeout)
        if self._tunnel_host:
            self._tunnel()
        self.sock = self.context.wrap_socket(self.sock, server_hostname=self.host)


def _make_request(method: str, url: str, data: dict | None = None) -> dict:
    if method.upper() not in _ALLOWED_METHODS:
        raise ValueError(f"HTTP method '{method}' is not allowed")

    parsed = urllib.parse.urlparse(url)
    hostname = parsed.hostname
    if not hostname:
        raise ValueError("URL must contain a hostname")
    ip_list = _resolve_and_check_private(hostname)
    ip = ip_list[0]

    req_data = None
    headers = {"Accept": "application/json"}
    if data is not None:
        if not isinstance(data, dict):
            raise ValueError("Payload must be a dictionary")
        json_bytes = json.dumps(data, separators=(",", ":")).encode("utf-8")
        if len(json_bytes) > _MAX_PAYLOAD_SIZE:
            raise ValueError("Request payload exceeds maximum allowed size")
        req_data = json_bytes
        headers["Content-Type"] = "application/json"

    path = parsed.path or "/"
    if parsed.query:
        path += "?" + parsed.query

    ctx = ssl.create_default_context()
    conn = _IPHTTPSConnection(hostname, ip, timeout=10, context=ctx)

    try:
        conn.request(method.upper(), path, body=req_data, headers=headers)
        resp = conn.getresponse()
        if resp.status >= 400:
            raise urllib.error.HTTPError(url, resp.status, resp.reason, resp.headers, None)

        content_type = resp.getheader("Content-Type", "")
        if not content_type.startswith("application/json"):
            raise ValueError("Response Content-Type is not application/json")

        resp_body = resp.read(_MAX_RESPONSE_SIZE + 1)
        if len(resp_body) > _MAX_RESPONSE_SIZE:
            raise ValueError("Response size exceeds maximum allowed limit")
        if not resp_body:
            raise ValueError("Empty response")
        return json.loads(resp_body.decode("utf-8"))
    finally:
        conn.close()


def perform_requests(
    url: str,
    post_payload: dict,
    delete_payload: dict,
    expected_post_msg: str,
    expected_delete_msg: str,
) -> None:
    safe_url = _validate_url(url)

    post_response = _make_request("POST", safe_url, post_payload)
    if post_response.get("message") != expected_post_msg:
        raise AssertionError("Unexpected POST response message")

    delete_url = safe_url
    if delete_payload:
        query = urllib.parse.urlencode(delete_payload, doseq=True)
        delete_url = f"{safe_url}?{query}"

    delete_response = _make_request("DELETE", delete_url)
    if delete_response.get("message") != expected_delete_msg:
        raise AssertionError("Unexpected DELETE response message")

import os
