# Configure minimal logging
logging.basicConfig(level=logging.INFO, format='%(message)s', stream=sys.stderr)

SAFE_ENV = {
    "PATH": "/usr/sbin:/usr/bin:/sbin:/bin",
    "LANG": "C",
    "HOME": "/nonexistent",
}

# Whitelist of allowed executable basenames
COMMAND_WHITELIST = {
    "ls",
    "cat",
    "echo",
    "date",
    "whoami",
    "uname",
    "uptime",
    "id",
}

# Resolve absolute paths for allowed commands using the safe PATH
_ALLOWED_ABSOLUTE_PATHS = set()
for cmd in COMMAND_WHITELIST:
    path = shutil.which(cmd, path=SAFE_ENV["PATH"])
    if path:
        _ALLOWED_ABSOLUTE_PATHS.add(os.path.realpath(path))

MAX_JSON_SIZE = 2 * 1024 * 1024  # 2â¯MiB


def generic_exit(message: str) -> None:
    """Exit with a generic error message to avoid leaking details."""
    logging.error(message)
    sys.exit(1)


def limit_resources():
    """Set resource limits for subprocesses."""
    # Limit CPU time to 10 seconds
    resource.setrlimit(resource.RLIMIT_CPU, (10, 10))
    # Limit virtual memory to 100â¯MiB
    resource.setrlimit(resource.RLIMIT_AS, (100 * 1024 * 1024, 100 * 1024 * 1024))


def drop_privileges():
    """Drop root privileges securely."""
    if os.geteuid() != 0:
        return
    try:
        os.setgroups([])
        low_user = os.getenv("LOW_PRIV_USER", "nobody")
        try:
            pw = pwd.getpwnam(low_user)
        except KeyError:
            generic_exit("Unable to locate a lowâprivilege user account.")
        os.setgid(pw.pw_gid)
        os.setuid(pw.pw_uid)
        os.environ.clear()
        os.environ.update(SAFE_ENV)
    except OSError:
        generic_exit("Failed to drop privileges.")


def mask_command(command: str) -> str:
    """Mask possible credential arguments."""
    parts = command.split()
    masked = []
    for p in parts:
        if any(kw in p.lower() for kw in ("password=", "--password", "-p")):
            masked.append("[REDACTED]")
        else:
            masked.append(p)
    return " ".join(masked)


def safe_load_json(path: str):
    """Load and validate JSON from given file path."""
    if not hasattr(os, "O_NOFOLLOW"):
        generic_exit("Filesystem does not support O_NOFOLLOW; cannot safely open files.")
    flags = os.O_RDONLY | os.O_NOFOLLOW
    try:
        fd = os.open(path, flags)
    except OSError:
        generic_exit("Unable to open JSON file.")
    try:
        st = os.fstat(fd)
        if not stat.S_ISREG(st.st_mode):
            generic_exit("Provided path is not a regular file.")
        if st.st_size > MAX_JSON_SIZE:
            generic_exit("JSON file exceeds maximum allowed size.")
        with os.fdopen(fd, "r", encoding="utf-8") as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError):
        generic_exit("Failed to read or parse JSON file.")
    if not isinstance(data, dict):
        generic_exit("Invalid JSON format.")
    commands = data.get("commands")
    if not isinstance(commands, list):
        generic_exit("Missing or malformed 'commands' list.")
    validated = []
    for idx, entry in enumerate(commands, start=1):
        if not isinstance(entry, dict):
            generic_exit(f"Invalid command entry at index {idx}.")
        comment = entry.get("comment", "")
        command = entry.get("command")
        if not isinstance(comment, str) or not isinstance(command, str):
            generic_exit(f"Invalid types for comment/command at index {idx}.")
        if len(command) > 1024 or "�" in command:
            generic_exit(f"Command at index {idx} fails validation.")
        validated.append({"comment": comment, "command": command})
    return validated


def validate_arguments(exe: str, args: list) -> bool:
    """Enforce a strict argument policy."""
    # Allow arguments only for echo; otherwise reject any extra arguments
    if exe == "echo":
        # Prevent echoing potential passwords
        return all("/" not in a and not a.startswith("-") for a in args[1:])
    return len(args) == 1


def execute_commands(command_list, verbose, interactive):
