            continue
        if verbose:
            print("Output:")
            print(result.stdout.strip())
        if result.returncode != 0:
            logging.error(f"Command exited with status {result.returncode} on line {line_no}.")
        else:
            print("Command executed successfully.")
        if interactive:
            try:
                input("Press Enter to continue...")
            except EOFError:
                pass


def main():
    parser = argparse.ArgumentParser(description="Secure command executor")
    parser.add_argument("json_path", help="Path to JSON file containing commands")
    parser.add_argument("-v", "--verbose", action="store_true", help="Enable verbose output")
