CREATE OR REPLACE FUNCTION secure_insert_with_lock(p_lock_name TEXT)
RETURNS INTEGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, public
AS $$
DECLARE
    v_rows_affected INTEGER := 0;
    v_lock_key1 BIGINT;
    v_lock_key2 BIGINT;
    v_hash TEXT;
    v_full_name TEXT;
    secret_prefix CONSTANT TEXT := 's3cure_prefix_';
BEGIN
    -- Input validation
    IF p_lock_name IS NULL OR length(trim(p_lock_name)) = 0 THEN
        RAISE EXCEPTION 'Invalid lock name' USING ERRCODE = 'P0001';
    END IF;

    IF length(p_lock_name) > 64 THEN
        RAISE EXCEPTION 'Lock name too long (maximum 64 characters)' USING ERRCODE = 'P0001';
    END IF;

    IF NOT p_lock_name ~ '^[A-Za-z0-9_-]+$' THEN
        RAISE EXCEPTION 'Lock name contains invalid characters' USING ERRCODE = 'P0001';
    END IF;

    -- Authorization check
    IF NOT has_table_privilege(current_user, 'public.secure_demo', 'INSERT') THEN
        RAISE EXCEPTION 'Insufficient privileges to insert into secure_demo' USING ERRCODE = '42501';
    END IF;

    -- Combine secret prefix to avoid external lock name collisions
    v_full_name := secret_prefix || p_lock_name;

    -- Derive 128âbit advisory lock key from SHAâ256 hash
    SELECT pg_catalog.encode(pg_catalog.digest(v_full_name, 'sha256'), 'hex') INTO v_hash;

    SELECT
        ('x' || substr(v_hash, 1, 16))::bit(64)::bigint,
        ('x' || substr(v_hash, 17, 16))::bit(64)::bigint
    INTO v_lock_key1, v_lock_key2;

    -- Insert first two rows (no lock required)
    INSERT INTO public.secure_demo (name) VALUES ('Alice');
    GET DIAGNOSTICS v_rows_affected = ROW_COUNT;

    INSERT INTO public.secure_demo (name) VALUES ('Bob');
    GET DIAGNOSTICS v_rows_affected = v_rows_affected + ROW_COUNT;

    -- Acquire advisory lock for the third insert
    PERFORM pg_catalog.pg_advisory_xact_lock(v_lock_key1, v_lock_key2);

    -- Insert third row under lock
    INSERT INTO public.secure_demo (name) VALUES ('Alice');
    GET DIAGNOSTICS v_rows_affected = v_rows_affected + ROW_COUNT;

    RETURN v_rows_affected;
EXCEPTION
    WHEN OTHERS THEN
        RAISE;
END;
$$;

