class ConfigurationError(Exception):
    """Generic configuration error without leaking sensitive details."""

@dataclass(frozen=True)
class TestData:
    """Immutable test data holder."""
    name: str
    value: int

# ----- Validation helpers -----
def _validate_interval(value: Any) -> int:
    if isinstance(value, int) and 1 <= value <= 86400:
        return value
    raise ConfigurationError("Invalid interval value")

_allowed_path_dirs = (
    pathlib.Path("/usr/bin").resolve(),
    pathlib.Path("/opt/emc/bin").resolve(),
)

_common_passwords = {
    "password", "12345678", "qwerty", "letmein", "admin", "welcome",
    "123456789", "11111111", "iloveyou", "123123123"
}

_password_regex = re.compile(
    r"""^(?=.*[a-z])        # at least one lowercase
        (?=.*[A-Z])         # at least one uppercase
        (?=.*\d)            # at least one digit
        (?=.*[!@#$%^&*()_+=\-[\]{}|\;:'",.<>?/`~]) # at least one special
        .{12,}$""",
    re.VERBOSE,
)

def _hash_password(password: str) -> str:
    """Hash password with PBKDF2-HMAC-SHA256 and a random salt."""
    salt = os.urandom(16)
    dk = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt, 100_000)
    return f"{base64.b64encode(salt).decode()}:${base64.b64encode(dk).decode()}"

def _validate_password(password: Any) -> str:
    if not isinstance(password, str):
        raise ConfigurationError("Invalid password type")
    if len(password) < 12:
        raise ConfigurationError("Password must be at least 12 characters")
    if not _password_regex.match(password):
        raise ConfigurationError("Password does not meet complexity requirements")
    if password.lower() in _common_passwords:
        raise ConfigurationError("Password is too common")
    return _hash_password(password)

def _validate_path(path_str: Any) -> str:
    if not isinstance(path_str, str):
        raise ConfigurationError("Invalid path type")
    path = pathlib.Path(path_str).expanduser().resolve()
    if not path.is_absolute():
        raise ConfigurationError("Path must be absolute")
    if not any(path.is_relative_to(d) for d in _allowed_path_dirs):
        raise ConfigurationError("Executable path is not in an allowed directory")
    if not path.is_file():
        raise ConfigurationError("Path does not point to a file")
    if path.is_symlink():
        raise ConfigurationError("Executable must not be a symbolic link")
    if not os.access(path, os.X_OK):
        raise ConfigurationError("File is not executable")
    try:
        stat_info = path.stat()
    except OSError:
        raise ConfigurationError("Unable to stat the executable")
    if stat_info.st_uid != 0:
        raise ConfigurationError("Executable must be owned by root")
    if stat_info.st_mode & 0o22:
        raise ConfigurationError("Executable must not be writable by group or others")
    return str(path)

def _validate_username(username: Any) -> str:
    if not isinstance(username, str):
        raise ConfigurationError("Invalid username type")
    if not re.fullmatch(r"[A-Za-z0-9_.-]{1,64}", username):
        raise ConfigurationError("Invalid username format")
    return username

# ----- Main configuration function -----
def set_vnx_driver_config(raw_config: Dict[str, Any]) -> Tuple[Dict[str, Any], Mock, TestData]:
    """
    Sanitizes and stores configuration for an EMC VNX CLI driver.
    Returns a tuple of (sanitized_config, mock_config, test_data_instance).
    """
    try:
        # Validate intervals
        intervals_raw = raw_config.get("intervals", {})
        if not isinstance(intervals_raw, dict):
            raise ConfigurationError("Intervals must be a dictionary")
        intervals = {task: _validate_interval(val) for task, val in intervals_raw.items()}

        # Validate binary path
        naviseccli_path = _validate_path(raw_config.get("naviseccli_path", ""))

        # Validate credentials
        cred_raw = raw_config.get("credentials", {})
        if not isinstance(cred_raw, dict):
            raise ConfigurationError("Credentials must be a dictionary")
        username = _validate_username(cred_raw.get("username", ""))
        password_hash = _validate_password(cred_raw.get("password", ""))

        sanitized_config: Dict[str, Any] = {
            "intervals": intervals,
            "naviseccli_path": naviseccli_path,
            "credentials": {
                "username": username,
                "password_hash": password_hash,
            },
        }

        # Mock object exposing safe_get
        mock_config = Mock()
        mock_config.safe_get.side_effect = lambda key, default=None: sanitized_config.get(
            key, default
        )

        # Create test data instance
        test_data_instance = TestData(name="example_test", value=42)

        return sanitized_config, mock_config, test_data_instance

    except ConfigurationError as ce:
        logger.error("Configuration error occurred")
        raise ce
    except Exception as e:
        logger.error("Unexpected error during configuration")
        raise ConfigurationError("Failed to set configuration") from e

