import logging
import re
import socket
from urllib.parse import urlparse

import idna
import requests
from cryptography import x509
from cryptography.hazmat.primitives import serialization

# Configuration
MAX_RESPONSE_SIZE = 1 * 1024 * 1024  # 1 MiB
ALLOWED_CONTENT_TYPES = {
    "application/x-pem-file",
    "application/pkcs8",
}
TRUSTED_DOMAINS = {"example.com", "api.example.com"}

# Configure logger with minimal exposure
logger = logging.getLogger(__name__)
logger.addHandler(logging.NullHandler())


class PemAssemblyError(Exception):
    """Generic error for PEM assembly failures without leaking details."""


def _is_ip_private(host: str) -> bool:
    """Return True if the host string is an IP address that is private, loopback, or linkâlocal."""
    try:
        ip = ipaddress.ip_address(host)
        return ip.is_private or ip.is_loopback or ip.is_link_local
    except ValueError:
        return False


def _normalize_host(host: str) -> str:
    """Normalize Unicode hostnames to ASCII using IDNA (punycode)."""
    try:
        return idna.encode(host).decode("ascii")
    except idna.IDNAError as exc:
        raise PemAssemblyError("Invalid hostname.") from exc


def _host_allowed(host: str) -> bool:
    """Check if the normalized host matches the trusted domain allowâlist (exact or suffix)."""
    host_lc = host.lower()
    for domain in TRUSTED_DOMAINS:
        domain_lc = domain.lower()
        if host_lc == domain_lc or host_lc.endswith("." + domain_lc):
            return True
    return False


def _validate_https_url(url: str) -> None:
    """Validate that the URL is HTTPS, has no user info, does not contain a private IP literal,
    and belongs to an allowed domain."""
    if not isinstance(url, str):
        raise PemAssemblyError("Invalid URL format.")
    parsed = urlparse(url)

    if parsed.scheme.lower() != "https" or not parsed.netloc:
        raise PemAssemblyError("URL must be a valid HTTPS address.")

    if parsed.username or parsed.password:
        raise PemAssemblyError("URL must not contain user info.")

    host = parsed.hostname
    if not host:
        raise PemAssemblyError("URL hostname could not be determined.")

    host = _normalize_host(host)

    if _is_ip_private(host):
        raise PemAssemblyError("URL points to a prohibited private address.")

    if TRUSTED_DOMAINS and not _host_allowed(host):
        raise PemAssemblyError("URL domain is not in the allowed list.")


def _verify_public_ip(response: requests.Response) -> None:
    """After the TLS connection is established, ensure the remote IP is not private."""
    try:
        raw = getattr(response, "raw", None)
        if raw is None:
            raise PemAssemblyError("Unable to access raw socket.")

        # urllib3 (used by requests) stores the connection in raw._connection
        conn = getattr(raw, "_connection", None)
        if conn and hasattr(conn, "sock"):
            peer_ip = conn.sock.getpeername()[0]
        else:
            # Fallback for newer urllib3 versions
            fp = getattr(raw, "_fp", None)
            if fp and hasattr(fp, "fp") and hasattr(fp.fp, "raw"):
                inner_sock = getattr(fp.fp.raw, "_sock", None)
                if inner_sock:
                    peer_ip = inner_sock.getpeername()[0]
                else:
                    raise PemAssemblyError("Unable to determine peer IP.")
            else:
                raise PemAssemblyError("Unable to determine peer IP.")

        ip = ipaddress.ip_address(peer_ip)
        if ip.is_private or ip.is_loopback or ip.is_link_local:
            raise PemAssemblyError("Fetched resource resolved to a prohibited private address.")
    except Exception as exc:
        raise PemAssemblyError("Unable to verify remote address.") from exc


def _fetch_resource(url: str) -> bytes:
    """Fetch a resource over HTTPS with strict size, contentâtype, and SSRF protections."""
    try:
        with requests.get(
            url,
            timeout=10,
            verify=True,
            stream=True,
            allow_redirects=False,
            headers={"User-Agent": "pem-assembler/1.0"},
        ) as response:
            response.raise_for_status()
            _verify_public_ip(response)

            content_type = response.headers.get("Content-Type", "").split(";")[0].strip().lower()
            if content_type not in ALLOWED_CONTENT_TYPES:
                raise PemAssemblyError("Unexpected ContentâType for fetched resource.")

            content_length = response.headers.get("Content-Length")
            if content_length is not None:
                try:
                    if int(content_length) > MAX_RESPONSE_SIZE:
                        raise PemAssemblyError("Resource exceeds maximum allowed size.")
                except ValueError:
                    pass  # Ignore malformed Content-Length; size will be enforced while streaming

            data = bytearray()
            for chunk in response.iter_content(chunk_size=8192):
                if not chunk:
                    continue
                data.extend(chunk)
                if len(data) > MAX_RESPONSE_SIZE:
                    raise PemAssemblyError("Resource exceeds maximum allowed size during download.")

            if not data.startswith(b"-----BEGIN"):
                raise PemAssemblyError("Fetched resource does not appear to be PEM formatted.")
            return bytes(data)
    except requests.RequestException as exc:
        raise PemAssemblyError("Unable to retrieve required resource.") from exc


def _verify_key_matches_certificate(private_key_bytes: bytes, certificate_bytes: bytes) -> None:
    """Ensure the private key corresponds to the public key in the certificate and meets strength requirements."""
    try:
        private_key = serialization.load_pem_private_key(
            private_key_bytes,
            password=None,
        )
    except Exception as exc:
        raise PemAssemblyError("Invalid private key format.") from exc

    try:
        certificate = x509.load_pem_x509_certificate(certificate_bytes)
    except Exception as exc:
        raise PemAssemblyError("Invalid certificate format.") from exc

    # Enforce key size / curve strength
    if hasattr(private_key, "key_size"):
        if private_key.key_size < 2048:
            raise PemAssemblyError("Private key size is insufficient.")
    elif hasattr(private_key, "curve"):
        if private_key.curve.name not in {"secp256r1", "secp384r1"}:
            raise PemAssemblyError("Elliptic curve is not allowed.")
    else:
        raise PemAssemblyError("Unsupported private key type.")

    private_public = private_key.public_key()
    cert_public = certificate.public_key()

    if hasattr(private_public, "public_numbers") and hasattr(cert_public, "public_numbers"):
        if private_public.public_numbers() != cert_public.public_numbers():
            raise PemAssemblyError("Private key does not match certificate.")
    else:
        raise PemAssemblyError("Unsupported key type for verification.")


def _pem_delimiter_check(data: bytes, label: str) -> None:
    """Validate that PEM data contains proper BEGIN/END delimiters using a strict regex."""
    pattern = re.compile(
        rb"-----BEGIN [A-Z ]+-----?
(?:.+?
)*?-----END [A-Z ]+-----?
?",
        re.DOTALL,
    )
    if not pattern.search(data):
        raise PemAssemblyError(f"{label} content is not valid PEM format.")


def assemble_pem_from_oauth(oauth_request: dict) -> str:
    """
    Assemble a PEM containing a private key and its matching certificate.

    Expected oauth_request keys:
        - 'private_key_url': HTTPS URL pointing to the PEMâencoded private key.
        - 'certificate_url': HTTPS URL pointing to the PEMâencoded certificate.

    Returns:
        A string with the combined PEM content.

    Raises:
        PemAssemblyError on validation or fetch failures.
    """
    try:
        private_key_url = oauth_request.get("private_key_url")
        certificate_url = oauth_request.get("certificate_url")
        if not private_key_url or not certificate_url:
            raise PemAssemblyError("Missing required URLs.")

        _validate_https_url(private_key_url)
        _validate_https_url(certificate_url)

        private_key_bytes = _fetch_resource(private_key_url)
        certificate_bytes = _fetch_resource(certificate_url)

        _pem_delimiter_check(private_key_bytes, "Private key")
        _pem_delimiter_check(certificate_bytes, "Certificate")

        _verify_key_matches_certificate(private_key_bytes, certificate_bytes)

        combined = private_key_bytes.rstrip(b"
") + b"
" + certificate_bytes.lstrip(b"
")
        return combined.decode("utf-8")
    except PemAssemblyError:
        raise
    except Exception as exc:
        logger.debug("Unexpected error during PEM assembly: %s", exc)
        raise PemAssemblyError("Failed to assemble PEM.") from exc

import subprocess
import logging
import os
import shutil
from pathlib import Path

logging.basicConfig(level=logging.ERROR, format='%(asctime)s %(levelname)s')


def _is_safe_executable(path: Path) -> bool:
    try:
        if not (path.is_file() and path.is_absolute()):
            return False
        if path.is_symlink():
            resolved = path.resolve()
            if not resolved.is_file() or not resolved.is_absolute():
                return False
            path = resolved
        stat = path.stat()
        if stat.st_uid != 0:
            return False
        if bool(stat.st_mode & 0o002):
            return False
        return True
    except Exception:
        return False


def _resolve_ps_executable() -> Path:
    primary = Path("/bin/ps")
    if _is_safe_executable(primary):
        return primary
    safe_path_env = "/bin:/usr/bin"
    ps_path = shutil.which("ps", path=safe_path_env)
    if ps_path:
        candidate = Path(ps_path).resolve()
        if _is_safe_executable(candidate):
            return candidate
    raise FileNotFoundError("Secure 'ps' executable not found.")


_PS_EXECUTABLE = _resolve_ps_executable()


def get_process_command(pid):
    """
    Retrieve the command line of a process given its PID.
    """
    try:
        pid_int = int(pid)
    except (TypeError, ValueError) as exc:
        raise ValueError("PID must be an integer.") from exc
    if pid_int <= 0:
        raise ValueError("PID must be a positive integer.")

    try:
        result = subprocess.run(
            [str(_PS_EXECUTABLE), "-p", str(pid_int), "-o", "command="],
            stdout=subprocess.PIPE,
            stderr=subprocess.DEVNULL,
            text=True,
            timeout=5,
            check=False,
            env={},  # empty environment to avoid inheritance of malicious vars
        )
        if result.returncode != 0:
            logging.error("ps command failed with return code %s.", result.returncode)
            return None
        command = result.stdout.strip()
        return command if command else None
    except subprocess.TimeoutExpired:
        logging.error("ps command timed out.")
    except FileNotFoundError:
        logging.error("ps executable not found.")
    except Exception as e:
        logging.error("Failed to retrieve process command: %s", e)
    return None

