_MAX_TEMPLATE_LENGTH = 10_000
_MAX_TOKENS = 1_000
_MAX_VAR_NAME_LENGTH = 64
_ALLOWED_CHARS_PATTERN = re.compile(r'^[\w\s\.\-\$\{\}]*$')
_TOKEN_REGEX = re.compile(r'\$\{(?P<name>[A-Za-z_][A-Za-z0-9_\.]*)\}')


