def _pop_token(tokens):
    if not tokens:
        raise SyntaxError("Unexpected end of template")
    return tokens.pop(0)


def _is_primitive(val):
    return isinstance(val, (str, int, float, bool, type(None)))


def _safe_str(val):
    if _is_primitive(val):
        return str(val)
    raise TypeError("Nonâprimitive values are not allowed in template rendering")


def _html_encoder(text: str) -> str:
    return html.escape(text, quote=True)


def _sql_encoder(text: str) -> str:
    # Very basic SQL escaping; for real use, rely on parameterised queries
    return text.replace("'", "''")


def _shell_encoder(text: str) -> str:
    return shlex.quote(text)


_ENCODERS: Dict[str, Callable[[str], str]] = {
    "html": _html_encoder,
    "sql": _sql_encoder,
    "shell": _shell_encoder,
}


def compile_template(template: str, *, mode: str = "html"):
    """
    Compile a simple template string into a safe rendering function.

    Parameters
    ----------
    template: str
        Template containing `${var}` placeholders.
    mode: str, optional
        Encoding mode for substituted values. Supported: 'html', 'sql', 'shell'.
        Defaults to 'html'.
    """
    if not isinstance(template, str):
        raise TypeError("Template must be a string")

    if len(template) > _MAX_TEMPLATE_LENGTH:
        raise ValueError("Template length exceeds allowed limit")

    if not _ALLOWED_CHARS_PATTERN.fullmatch(template):
        raise ValueError("Template contains invalid characters")

    if mode not in _ENCODERS:
        raise ValueError(f"Unsupported encoding mode: {mode}")

    encoder = _ENCODERS[mode]

    raw_tokens = []
    pos = 0
    for m in _TOKEN_REGEX.finditer(template):
        if len(m.group('name')) > _MAX_VAR_NAME_LENGTH:
            raise ValueError(f"Variable name '{m.group('name')}' exceeds maximum length")
        if m.start() > pos:
            raw_tokens.append(('LIT', template[pos:m.start()]))
        raw_tokens.append(('VAR', m.group('name')))
        pos = m.end()
    if pos < len(template):
        raw_tokens.append(('LIT', template[pos:]))

    if len(raw_tokens) > _MAX_TOKENS:
        raise ValueError("Template contains too many tokens")

    def render(context: Dict[str, Any]):
        if not isinstance(context, dict):
            raise TypeError("Context must be a dictionary")
        parts = []
        tokens = list(raw_tokens)  # copy to avoid mutation side-effects
        while tokens:
            token_type, token_value = _pop_token(tokens)
            if token_type == 'LIT':
                parts.append(token_value)
            elif token_type == 'VAR':
                raw = _safe_str(context.get(token_value, ''))
                parts.append(encoder(raw))
            else:
                raise SyntaxError(f"Unsupported token type: {token_type}")
        return ''.join(parts)

    return render

