import gymnasium as gym
from gymnasium import Wrapper
from gymnasium.vector import SyncVectorEnv

try:
    import tensorflow as tf
except Exception:
    tf = None  # TensorFlow is optional; GPU configuration will be skipped if unavailable

# Configure a minimal logger
logger = logging.getLogger(__name__)
if not logger.handlers:
    handler = logging.StreamHandler()
    formatter = logging.Formatter("%(asctime)s - %(levelname)s - %(message)s")
    handler.setFormatter(formatter)
    logger.addHandler(handler)
    logger.setLevel(logging.INFO)

# --------------------------------------------------------------------------- #
# Configuration
# --------------------------------------------------------------------------- #

# Explicit allowâlist of environment IDs that are considered safe.
ALLOWED_ENV_IDS = {
    "CartPole-v1",
    "MountainCar-v0",
    "Acrobot-v1",
    # add other vetted ids here
}

# Snapshot of the registry at import time to prevent later mutations.
_STATIC_REGISTRY: Dict[str, gym.envs.registration.EnvSpec] = {
    env_id: gym.registry[env_id]
    for env_id in ALLOWED_ENV_IDS
    if env_id in gym.registry
}


# --------------------------------------------------------------------------- #
# Helper functions
# --------------------------------------------------------------------------- #


def _enable_gpu_memory_growth() -> None:
    """Enable GPU memory growth if TensorFlow is available."""
    if tf is None:
        logger.info("TensorFlow not installed; skipping GPU configuration.")
        return

    try:
        gpus = tf.config.experimental.list_physical_devices("GPU")
        for gpu in gpus:
            tf.config.experimental.set_memory_growth(gpu, True)
        if gpus:
            logger.info("Enabled GPU memory growth for %d GPU(s).", len(gpus))
    except Exception as e:
        logger.warning("Failed to set GPU memory growth: %s", str(e))


class CustomRewardWrapper(Wrapper):
    """Wrap an environment to modify its reward according to provided parameters."""

    def __init__(self, env: gym.Env, params: Dict[str, Any]) -> None:
        super().__init__(env)
        self.scale: float = float(params.get("scale", 1.0))
        self.offset: float = float(params.get("offset", 0.0))

    def step(self, action):
        obs, reward, terminated, truncated, info = self.env.step(action)
        if isinstance(reward, (int, float)):
            try:
                reward = reward * self.scale + self.offset
            except Exception as e:
                logger.debug("Reward scaling failed: %s", e)
        else:
            logger.debug("Reward %s is non-numeric; leaving unchanged.", reward)
        return obs, reward, terminated, truncated, info


def _validate_env_id(env_id: str) -> str:
    """Validate the environment ID against a safe pattern, whitelist, and static registry."""
    if not isinstance(env_id, str):
        raise ValueError("Environment ID must be a string.")

    pattern = re.compile(r"^[A-Za-z0-9_/\-]+$", re.ASCII)
    if not pattern.fullmatch(env_id):
        raise ValueError("Environment ID contains invalid characters.")

    if env_id not in ALLOWED_ENV_IDS:
        raise ValueError(f"Environment '{env_id}' is not in the allowed list.")

    if env_id not in _STATIC_REGISTRY:
        raise ValueError("Requested environment is not registered in the static whitelist.")
    return env_id


def _validate_num_envs(num: int) -> int:
    """Ensure the number of environments is a reasonable positive integer."""
    if not isinstance(num, int):
        raise ValueError("num_envs must be an integer.")
    if num <= 0:
        raise ValueError("num_envs must be greater than zero.")
    if num > 64:
        raise ValueError("num_envs exceeds the allowed maximum of 64.")
    return num


def _validate_reward_params(params: Optional[dict]) -> Optional[dict]:
    """Validate and sanitize reward parameters."""
    if params is None:
        return None
    if not isinstance(params, dict):
        raise ValueError("reward_params must be a dictionary.")
    allowed_keys = {"scale", "offset"}
    for key in params:
        if key not in allowed_keys:
            raise ValueError(f"Unsupported reward parameter: {key}")
    sanitized: Dict[str, float] = {}
    for key in allowed_keys:
        if key in params:
            try:
                sanitized[key] = float(params[key])
            except (TypeError, ValueError):
                raise ValueError(f"Reward parameter '{key}' must be numeric.")
    return sanitized


def _safe_import_entry_point(entry_point: str) -> None:
    """
    Verify that the entry point module can be imported from a trusted package.
    The module's package name must start with 'gymnasium'.
    """
    module_path = entry_point.split(":")[0]
    try:
        module = importlib.import_module(module_path)
    except Exception as e:
        raise ImportError(f"Cannot import module '{module_path}': {e}") from e

    pkg_name = getattr(module, "__package__", "")
    if not pkg_name.startswith("gymnasium"):
        raise ImportError(
            f"Environment module '{module_path}' is not within the trusted 'gymnasium' package."
        )


def _sanitize_for_logging(value: str) -> str:
    """Remove control characters that could corrupt log files."""
    return re.sub(r"[\x00-\x1F\x7F]", "", value)


def configure_rl_environment(
    env_id: str,
    num_envs: int = 1,
    reward_params: Optional[dict] = None,
) -> SyncVectorEnv:
    """
    Configure a deep reinforcement learning environment.

    Parameters
    ----------
    env_id : str
        Identifier of the Gymnasium environment.
    num_envs : int, optional
        Number of parallel environments to create.
    reward_params : dict, optional
        Parameters for custom reward shaping (e.g., {"scale": 0.5, "offset": 1.0}).

    Returns
    -------
    SyncVectorEnv
        A vectorized environment ready for training.

    Raises
    ------
    ValueError
        If any of the inputs are invalid.
    RuntimeError
        If environment creation fails.
    """
    _enable_gpu_memory_growth()
    safe_env_id = _validate_env_id(env_id)
    safe_num = _validate_num_envs(num_envs)
    safe_reward_params = _validate_reward_params(reward_params)

    env_spec = _STATIC_REGISTRY[safe_env_id]
    _safe_import_entry_point(env_spec.entry_point)

    def make_env_factory(_: int) -> Callable[[], gym.Env]:
        def _factory() -> gym.Env:
            try:
                env = gym.make(safe_env_id)
            except gym.error.Error as e:
                logger.error("Gym error while creating environment '%s': %s", safe_env_id, e)
                raise RuntimeError(f"Could not create environment '{safe_env_id}'.") from e
            except Exception as e:
                logger.error("Unexpected error while creating environment '%s': %s", safe_env_id, e)
                raise
            if safe_reward_params:
                env = CustomRewardWrapper(env, safe_reward_params)
            return env
        return _factory

    env_fns: List[Callable[[], gym.Env]] = [make_env_factory(i) for i in range(safe_num)]
    try:
        vector_env = SyncVectorEnv(env_fns)
    except Exception as e:
        logger.error("Failed to create SyncVectorEnv: %s", e)
        raise RuntimeError("Vector environment configuration error.") from e

    log_env_id = _sanitize_for_logging(safe_env_id)
    logger.info(
        "Created vectorized environment '%s' with %d instance(s).",
        log_env_id,
        safe_num,
    )
    return vector_env

