import inspect
import types
import weakref
import functools

# Store modification metadata without polluting the object namespace
_secure_modifications_store = weakref.WeakKeyDictionary()


def secure_modify_object_setters(obj):
    """
    Wraps all instance methods whose name starts with ``Set`` on a userâdefined object.
    Each wrapper validates the incoming value using the corresponding ``Get`` method
    before delegating to the original setter.  Modification metadata is kept in a
    private WeakKeyDictionary to avoid attribute clashes.
    """
    if obj is None:
        raise ValueError("Object must not be None")

    # Reject builtâin types and ensure we have a proper userâdefined instance
    if not isinstance(obj, object) or obj.__class__.__module__ == "builtins":
        raise TypeError("Unsupported object type")

    # Prepare metadata container for this instance
    if obj not in _secure_modifications_store:
        _secure_modifications_store[obj] = {}

    cls = obj.__class__

    # Iterate over functions defined on the class (skip descriptors, static/class methods)
    for name, func in inspect.getmembers(cls, predicate=inspect.isfunction):
        if not name.startswith("Set"):
            continue

        suffix = name[3:]  # part after 'Set'
        get_name = f"Get{suffix}"
        # Verify that a corresponding getter exists on the instance
        getter = getattr(obj, get_name, None)
        if not callable(getter):
            continue

        original_set = func  # unbound function from the class

        @functools.wraps(original_set)
        def wrapper(self, value, _orig_set=original_set, _getter_name=get_name):
            # Basic input validation â reject None values
            if value is None:
                raise ValueError(f"Setter '{name}' received an invalid None value")

            # Resolve the getter on the current instance (allows later overrides)
            getter_method = getattr(self, _getter_name, None)
            if not callable(getter_method):
                # If the getter disappears, treat as if no current value exists
                current = None
            else:
                try:
                    current = getter_method()
                except Exception:
                    # Swallow unexpected getter errors; treat as no current value
                    current = None

            # Optional type consistency check when a current value exists
            if current is not None and not isinstance(value, type(current)):
                raise TypeError(
                    f"Type of value ({type(value).__name__}) does not match existing "
                    f"attribute type ({type(current).__name__}) for setter '{name}'"
                )

            # Delegate to the original setter
            return _orig_set(self, value)

        # Bind the wrapper to the instance
        try:
            object.__setattr__(obj, name, types.MethodType(wrapper, obj))
        except Exception as exc:
            raise RuntimeError(f"Failed to replace setter '{name}'") from exc
        else:
            _secure_modifications_store[obj][name] = {"wrapped": True, "original": original_set}

    return obj

import os
import re
import pathlib
import defusedxml.ElementTree as ET
from typing import Any, Dict

_ALLOWED_AUTH_METHODS = {"none", "chap", "mutual"}
_BASE_VOLUME_DIR = pathlib.Path("/var/lib/libvirt/images").resolve()
_UUID_RE = re.compile(
    r"^[0-9a-fA-F]{8}-"
    r"[0-9a-fA-F]{4}-"
    r"[0-9a-fA-F]{4}-"
    r"[0-9a-fA-F]{4}-"
    r"[0-9a-fA-F]{12}$"
)


def _validate_string(name: str, value: Any, max_len: int = 256) -> str:
    if not isinstance(value, str):
        raise ValueError(f"{name}: expected a string")
    stripped = value.strip()
    if not stripped:
        raise ValueError(f"{name}: value cannot be empty")
    if len(stripped) > max_len:
        raise ValueError(f"{name}: exceeds maximum length of {max_len}")
    return stripped


def _is_relative_to(path: pathlib.Path, base: pathlib.Path) -> bool:
    try:
        path.relative_to(base)
        return True
    except ValueError:
        return False


def _validate_device_path(path: Any) -> str:
    path_str = _validate_string("device_path", path, 1024)

    if os.path.isabs(path_str):
        raise ValueError("device_path must be a relative path")
    if ".." in pathlib.PurePosixPath(path_str).parts:
        raise ValueError("device_path must not contain parent directory references")

    allowed_chars = set(
        "/._-ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"
    )
    if any(ch not in allowed_chars for ch in path_str):
        raise ValueError("device_path contains illegal characters")

    resolved_path = (_BASE_VOLUME_DIR / path_str).resolve()
    if not _is_relative_to(resolved_path, _BASE_VOLUME_DIR):
        raise ValueError("device_path resolves outside of allowed directory")

    return str(resolved_path.relative_to(_BASE_VOLUME_DIR))


def _validate_positive_int(name: str, value: Any, max_value: int = 10**12) -> str:
    s = _validate_string(name, value)
    if not s.isdigit():
        raise ValueError(f"{name}: must be a positive integer")
    iv = int(s)
    if iv <= 0 or iv > max_value:
        raise ValueError(f"{name}: must be >0 and <= {max_value}")
    return s


def _validate_qos(qos: Any) -> Dict[str, str]:
    if not isinstance(qos, dict):
        raise ValueError("qos_specs must be a dict")
    total = _validate_positive_int("total_bytes_sec", qos.get("total_bytes_sec"))
    iops = _validate_positive_int("read_iops_sec", qos.get("read_iops_sec"))
    return {"total_bytes_sec": total, "read_iops_sec": iops}


def _validate_uuid(name: str, value: Any) -> str:
    s = _validate_string(name, value, 128)
    if not _UUID_RE.fullmatch(s):
        raise ValueError(f"{name}: must be a valid UUID")
    return s.lower()


def _validate_auth(auth: Any) -> Dict[str, str]:
    if not isinstance(auth, dict):
        raise ValueError("auth must be a dict")
    method = _validate_string("auth.method", auth.get("method"))
    if method not in _ALLOWED_AUTH_METHODS:
        raise ValueError("Unsupported authentication method")
    username = _validate_string("auth.username", auth.get("username"))

    password = auth.get("password")
    secret_uuid = auth.get("secret_uuid")

    if password is not None and secret_uuid is not None:
        raise ValueError("Provide either password or secret_uuid, not both")
    if password is not None:
        raise ValueError(
            "Embedding plaintext passwords is insecure; provide a secret_uuid referencing a libvirt secret"
        )
    if secret_uuid is None:
        raise ValueError("Either password or secret_uuid must be provided for authentication")

    secret_uuid = _validate_uuid("auth.secret_uuid", secret_uuid)

    return {"method": method, "username": username, "secret_uuid": secret_uuid}


def open_secure_device_path(
    path: Any,
    flags: int = os.O_RDONLY,
    mode: int = 0o640,
) -> int:
    """
    Validate the device path and open the file atomically without following symlinks.
    Returns a file descriptor.
    """
    rel_path = _validate_device_path(path)
    full_path = (_BASE_VOLUME_DIR / rel_path).resolve()
    if not _is_relative_to(full_path, _BASE_VOLUME_DIR):
        raise ValueError("Resolved path escaped allowed directory")
    fd = os.open(
        str(full_path),
        flags | getattr(os, "O_NOFOLLOW", 0),
        mode,
    )
    return fd


def build_libvirt_volume_xml(params: Dict[str, Any]) -> str:
    if not isinstance(params, dict):
        raise ValueError("Input must be a dictionary")

    try:
        device_path = _validate_device_path(params["device_path"])
        qos = _validate_qos(params["qos_specs"])
        auth = _validate_auth(params["auth"])
    except KeyError as e:
        raise ValueError(f"Missing required key: {e.args[0]}") from None

    volume = ET.Element("volume")

    target = ET.SubElement(volume, "target")
    path_elem = ET.SubElement(target, "path")
    path_elem.text = device_path

    qos_elem = ET.SubElement(volume, "qos")
    total_elem = ET.SubElement(qos_elem, "total_bytes_sec")
    total_elem.text = qos["total_bytes_sec"]
    iops_elem = ET.SubElement(qos_elem, "read_iops_sec")
    iops_elem.text = qos["read_iops_sec"]

    auth_elem = ET.SubElement(volume, "auth", method=auth["method"])
    user_elem = ET.SubElement(auth_elem, "username")
    user_elem.text = auth["username"]
    secret_elem = ET.SubElement(
        auth_elem,
        "secret",
        type="password",
        uuid=auth["secret_uuid"],
    )

    return ET.tostring(volume, encoding="unicode", method="xml")

