import argparse
import json
import logging
import os
import pathlib
import re
import sys
from typing import Any, Callable, Dict, List

# Configure logger only if no handlers are present to avoid interfering with host applications
if not logging.getLogger().handlers:
    logging.basicConfig(
        level=logging.WARNING,
        format="%(asctime)s %(levelname)s %(message)s",
        handlers=[logging.StreamHandler(sys.stderr)],
    )
logger = logging.getLogger(__name__)

# Internal storage for configuration values and their provenance
_config: Dict[str, Any] = {}
_source: Dict[str, str] = {}
_handlers: List[Callable[[str, Any, str], None]] = []

# Regular expression for a safe configuration key: letters, digits, underscore, not starting with a digit
_KEY_PATTERN = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

# Directory that is allowed to contain configuration files
_ALLOWED_CONFIG_DIR = pathlib.Path(__file__).resolve().parent / "config"

# Maximum allowed configuration file size (1 MiB)
_MAX_CONFIG_SIZE = 1 * 1024 * 1024


def _is_valid_key(key: str) -> bool:
    return isinstance(key, str) and bool(_KEY_PATTERN.fullmatch(key))


def register_handler(handler: Callable[[str, Any, str], None]) -> None:
    """Register a callable to receive broadcasted configuration items."""
    if callable(handler):
        _handlers.append(handler)
    else:
        logger.warning(
            "Attempted to register a non-callable handler",
            extra={"source": "handler_registration", "object_id": str(handler)},
        )
        raise TypeError("Handler must be callable")


def _broadcast(name: str, value: Any, src: str) -> None:
    """Notify all registered handlers about a configuration retrieval."""
    for h in _handlers:
        try:
            h(name, value, src)
        except Exception:
            # Do not expose potentially sensitive value or full traceback
            logger.error(
                "Handler raised an exception while processing configuration key",
                extra={"source": "handler", "object_id": name},
                exc_info=False,
            )


def _is_path_allowed(path: pathlib.Path) -> bool:
    """Ensure the resolved path is inside the allowed configuration directory."""
    try:
        return path.is_relative_to(_ALLOWED_CONFIG_DIR)
    except AttributeError:
        # For Python <3.9 fallback
        try:
            path.relative_to(_ALLOWED_CONFIG_DIR)
            return True
        except ValueError:
            return False


def _load_file(path_str: str) -> None:
    """Load configuration from a JSON file, storing provenance as 'file'."""
    try:
        path = pathlib.Path(path_str).resolve(strict=True)

        # Restrict to allowed directory
        if not _is_path_allowed(path):
            raise PermissionError(f"Configuration file {path} is outside the allowed directory")

        # Verify file ownership matches the current user
        stat_info = path.stat()
        if stat_info.st_uid != os.getuid():
            raise PermissionError(f"Configuration file {path} is not owned by the current user")

        # Enforce maximum file size
        if stat_info.st_size > _MAX_CONFIG_SIZE:
            raise ValueError(f"Configuration file {path} exceeds maximum allowed size")

        if not path.is_file():
            raise FileNotFoundError(f"{path} is not a regular file")

        with path.open("r", encoding="utf-8") as f:
            try:
                data = json.load(f)
            except json.JSONDecodeError as jde:
                raise ValueError(f"Invalid JSON in configuration file {path}: {jde}") from jde

            if not isinstance(data, dict):
                raise ValueError("Configuration file must contain a JSON object at top level")

            for k, v in data.items():
                if _is_valid_key(k):
                    _config[k] = v
                    _source[k] = f"file:{path.name}"
                else:
                    logger.warning(
                        f"Ignored invalid configuration key from file: {k}",
                        extra={"source": "file", "object_id": k},
                    )
    except Exception as exc:
        logger.error(
            f"Failed to load configuration file '{path_str}': {exc}",
            extra={"source": "file_load", "object_id": path_str},
            exc_info=False,
        )
        # Swallow exception to avoid leaking internal details


def _parse_cli_overrides(overrides: List[str]) -> None:
    """Parse --set key=value arguments, storing provenance as 'cli'."""
    for item in overrides:
        if "=" not in item:
            logger.warning(
                f"Ignored malformed override argument: {item}",
                extra={"source": "cli", "object_id": item},
            )
            continue
        key, value = item.split("=", 1)
        key = key.strip()
        value = value.strip()
        if _is_valid_key(key):
            _config[key] = value
            _source[key] = "cli"
        else:
            logger.warning(
                f"Ignored invalid override key: {key}",
                extra={"source": "cli", "object_id": key},
            )


def _initialize_configuration() -> None:
    """Read command-line arguments and optional configuration file."""
    parser = argparse.ArgumentParser(add_help=False)
    parser.add_argument(
        "--config-file",
        type=str,
        help="Path to JSON configuration file (must reside in the allowed config directory)",
    )
    parser.add_argument(
        "--set",
        action="append",
        default=[],
        help="Override configuration entries in key=value form",
    )
    args, _ = parser.parse_known_args()

    if args.config_file:
        _load_file(args.config_file)

    if args.set:
        _parse_cli_overrides(args.set)


# Load configuration at import time
_initialize_configuration()


def get_config(name: str) -> Any:
    """
    Retrieve a configuration value by name.

    Logs a warning with the source of the value and broadcasts the item
    to any registered handlers.
    """
    if not _is_valid_key(name):
        logger.warning(
            "Invalid configuration name requested",
            extra={"source": "validation", "object_id": str(name)},
        )
        raise ValueError("Invalid configuration name")

    value = _config.get(name)
    src = _source.get(name, "default")
    logger.warning(
        f"Configuration item accessed: {name}",
        extra={"source": src, "object_id": name},
    )
    _broadcast(name, value, src)
    return value

