logging.basicConfig(level=logging.INFO, format='[%(levelname)s] %(message)s')

BASE_DIR = pathlib.Path(os.getenv('EXTRACTOR_BASE', '/opt/extractor')).resolve()
if not (
    BASE_DIR.is_dir()
    and os.access(BASE_DIR, os.W_OK)
    and (BASE_DIR.stat().st_mode & 0o002) == 0
):
    raise RuntimeError("Base directory must be a secure, non-world-writable directory")

QUARANTINE_DIR = (BASE_DIR / 'quarantine').resolve()
MAX_TOTAL_SIZE = 500 * 1024 * 1024  # 500â¯MiB
MAX_FILES = 10_000
DOWNLOAD_TIMEOUT = 30  # seconds
MARKER_NAME = '.extracted'
COMPRESSION_RATIO_LIMIT = 10  # max allowed uncompressed/compressed ratio


def is_private_ip(ip: str) -> bool:
    try:
        addr = ipaddress.ip_address(ip)
        return (
            addr.is_private
            or addr.is_loopback
            or addr.is_link_local
            or addr.is_reserved
            or addr.is_multicast
        )
    except ValueError:
        return False


def resolve_and_check(hostname: str) -> List[str]:
    """Resolve hostname once and ensure all returned IPs are public."""
    try:
        infos = socket.getaddrinfo(hostname, None, family=socket.AF_UNSPEC, type=socket.SOCK_STREAM)
    except socket.gaierror as exc:
        raise RuntimeError(f"DNS resolution failed for {hostname}: {exc}") from exc
    ips = []
    for _, _, _, _, sockaddr in infos:
        ip = sockaddr[0]
        if is_private_ip(ip):
            raise RuntimeError(f"Resolved private IP {ip} for hostname {hostname}")
        ips.append(ip)
    if not ips:
        raise RuntimeError(f"No IP addresses resolved for {hostname}")
    return ips


def is_valid_url(url: str) -> bool:
    try:
        parsed = urllib.parse.urlparse(url)
        if parsed.scheme.lower() != 'https':
            return False
        if not parsed.hostname:
            return False
        if parsed.username or parsed.password:
            return False
        try:
            ipaddress.ip_address(parsed.hostname)
            # hostname is an IP literal
            if is_private_ip(parsed.hostname):
                return False
        except ValueError:
            # hostname is not an IP, resolve it
            resolve_and_check(parsed.hostname)
        return True
    except Exception:
        return False


def sanitize_path(path: pathlib.Path) -> pathlib.Path:
    return path.expanduser().resolve()


def compute_sha256(file_path: pathlib.Path) -> str:
    h = hashlib.sha256()
    with file_path.open('rb') as f:
        for chunk in iter(lambda: f.read(8192), b''):
            h.update(chunk)
    return h.hexdigest()


class NoRedirectHandler(urllib.request.HTTPRedirectHandler):
    def redirect_request(self, req, fp, code, msg, hdrs, newurl):
        raise urllib.error.HTTPError(req.full_url, code, "Redirect blocked", hdrs, fp)


def download_file(url: str, dest: pathlib.Path) -> None:
    parsed = urllib.parse.urlparse(url)
    hostname = parsed.hostname
    if not hostname:
        raise RuntimeError("URL has no hostname")
    ips = resolve_and_check(hostname)
    ip = ips[0]
    netloc = ip
    if parsed.port:
        netloc += f":{parsed.port}"
    url_ip = parsed._replace(netloc=netloc).geturl()
    headers = {'Host': hostname}
    ctx = ssl.create_default_context()
    ctx.check_hostname = False
    req = urllib.request.Request(url_ip, headers=headers)
    opener = urllib.request.build_opener(NoRedirectHandler())
    with opener.open(req, timeout=DOWNLOAD_TIMEOUT, context=ctx) as response:
        total_downloaded = 0
        with dest.open('wb') as out_file:
            while True:
                chunk = response.read(8192)
                if not chunk:
                    break
                total_downloaded += len(chunk)
                if total_downloaded > MAX_TOTAL_SIZE:
                    raise RuntimeError('Downloaded data exceeds allowed limit')
                out_file.write(chunk)


def is_path_within(base: pathlib.Path, target: pathlib.Path) -> bool:
    try:
        target.resolve().relative_to(base.resolve())
        return True
    except ValueError:
        return False


def safe_join_no_symlink(base: pathlib.Path, parts: List[str]) -> pathlib.Path:
    target = base
    for part in parts:
        target = target / part
        try:
            if target.is_symlink():
                raise RuntimeError('Symlink detected in extraction path')
        except OSError:
            # path may not exist yet; lstat will fail, treat as safe (no symlink)
            pass
    return target


def enforce_permissions(root: pathlib.Path) -> None:
    for p in root.rglob('*'):
        try:
            if p.is_file():
                p.chmod(0o600)
            elif p.is_dir():
                p.chmod(0o700)
        except OSError:
            pass


def safe_extract_zip(zip_path: pathlib.Path, extract_to: pathlib.Path) -> None:
    with zipfile.ZipFile(zip_path, 'r') as zf:
        infos = zf.infolist()
        total_uncompressed = sum(info.file_size for info in infos)
        if total_uncompressed > MAX_TOTAL_SIZE or len(infos) > MAX_FILES:
            raise RuntimeError('Zip archive exceeds size or file count limits')
        if total_uncompressed > sum(info.compress_size for info in infos) * COMPRESSION_RATIO_LIMIT:
            raise RuntimeError('Zip archive compression ratio exceeds safe limit')
        temp_dir = pathlib.Path(tempfile.mkdtemp(dir=extract_to))
        try:
            for info in infos:
                member_path = pathlib.Path(info.filename)
                if member_path.is_absolute() or '..' in member_path.parts:
                    raise RuntimeError('Unsafe zip entry detected')
                is_symlink = ((info.external_attr >> 16) & 0o120000) == 0o120000
                if is_symlink:
                    raise RuntimeError('Symlink entries are not allowed in zip archives')
                target_path = safe_join_no_symlink(temp_dir, list(member_path.parts))
                if info.is_dir():
                    target_path.mkdir(parents=True, exist_ok=True)
                    continue
                target_path.parent.mkdir(parents=True, exist_ok=True)
                with zf.open(info, 'r') as source, target_path.open('wb') as dest:
                    shutil.copyfileobj(source, dest, length=8192)
            for item in temp_dir.iterdir():
                dest = extract_to / item.name
                if dest.exists():
                    if dest.is_dir():
                        shutil.rmtree(dest)
                    else:
                        dest.unlink()
                shutil.move(str(item), str(dest))
        finally:
            shutil.rmtree(temp_dir, ignore_errors=True)
        enforce_permissions(extract_to)


def safe_extract_tar(tar_path: pathlib.Path, extract_to: pathlib.Path) -> None:
    with tarfile.open(tar_path, 'r:*') as tf:
        members = tf.getmembers()
        total_uncompressed = sum(m.size for m in members)
        if total_uncompressed > MAX_TOTAL_SIZE or len(members) > MAX_FILES:
            raise RuntimeError('Tar archive exceeds size or file count limits')
        if total_uncompressed > MAX_TOTAL_SIZE * COMPRESSION_RATIO_LIMIT:
            raise RuntimeError('Tar archive compression ratio exceeds safe limit')
        temp_dir = pathlib.Path(tempfile.mkdtemp(dir=extract_to))
        try:
            for member in members:
                member_path = pathlib.Path(member.name)
                if member_path.is_absolute() or '..' in member_path.parts:
                    raise RuntimeError('Unsafe tar entry detected')
                if member.ischr() or member.isblk() or member.isfifo() or member.issym() or member.islnk():
                    raise RuntimeError('Unsupported tar entry type')
                target_path = safe_join_no_symlink(temp_dir, list(member_path.parts))
                if member.isdir():
                    target_path.mkdir(parents=True, exist_ok=True)
                    continue
                target_path.parent.mkdir(parents=True, exist_ok=True)
                extracted_file = tf.extractfile(member)
                if extracted_file is None:
                    continue
                with extracted_file as source, target_path.open('wb') as dest:
                    shutil.copyfileobj(source, dest, length=8192)
            for item in temp_dir.iterdir():
                dest = extract_to / item.name
                if dest.exists():
                    if dest.is_dir():
                        shutil.rmtree(dest)
                    else:
                        dest.unlink()
                shutil.move(str(item), str(dest))
        finally:
            shutil.rmtree(temp_dir, ignore_errors=True)
        enforce_permissions(extract_to)


def marker_path(target_dir: pathlib.Path) -> pathlib.Path:
    return target_dir / MARKER_NAME


def marker_is_valid(target_dir: pathlib.Path, archive_path: pathlib.Path) -> bool:
    mp = marker_path(target_dir)
    if not mp.is_file():
        return False
    try:
        expected = mp.read_text(encoding='utf-8').strip()
        actual = compute_sha256(archive_path)
        return expected == actual
    except Exception:
        return False


def ensure_quarantine_dir() -> None:
    QUARANTINE_DIR.mkdir(parents=True, exist_ok=True)


def main() -> None:
    if len(sys.argv) != 3:
        logging.error('Usage: script.py <url> <target_directory>')
        sys.exit(1)

    url = sys.argv[1].strip()
    target_dir = pathlib.Path(sys.argv[2])

    if not is_valid_url(url):
        logging.error('Invalid URL')
        sys.exit(1)

    try:
        target_dir = sanitize_path(target_dir)
        if not is_path_within(BASE_DIR, target_dir):
            logging.error('Target directory is outside the allowed base directory')
            sys.exit(1)
        target_dir.mkdir(parents=True, exist_ok=True)
    except Exception:
        logging.error('Invalid target directory')
        sys.exit(1)

    filename = pathlib.Path(urllib.parse.urlparse(url).path).name
    if not filename:
        logging.error('Cannot determine filename from URL')
        sys.exit(1)

    compressed_path = target_dir / filename

    if not compressed_path.is_file():
        try:
            download_file(url, compressed_path)
        except RuntimeError as e:
            logging.error(f'Download failed: {e}')
            sys.exit(1)
        except Exception as e:
            logging.error(f'Unexpected download error: {e}')
            sys.exit(1)
    else:
        logging.info('Compressed file already exists, skipping download')

    extraction_successful = False
    if not marker_is_valid(target_dir, compressed_path):
        try:
            if zipfile.is_zipfile(compressed_path):
                safe_extract_zip(compressed_path, target_dir)
            elif tarfile.is_tarfile(compressed_path):
                safe_extract_tar(compressed_path, target_dir)
            else:
                logging.error('Unsupported archive format')
                sys.exit(1)

            try:
                hash_value = compute_sha256(compressed_path)
                marker_path(target_dir).write_text(hash_value, encoding='utf-8')
            except Exception as e:
                logging.warning(f'Failed to write marker file: {e}')

            logging.info('Extraction completed')
            extraction_successful = True
        except Exception as e:
            logging.error(f'Extraction failed: {e}')
            extraction_successful = False
    else:
        logging.info('Extraction already performed, skipping')
        extraction_successful = True

    if compressed_path.is_file():
        if extraction_successful:
            try:
                compressed_path.unlink()
                logging.info('Removed compressed file')
            except Exception:
                logging.warning('Could not delete compressed file')
        else:
            try:
                ensure_quarantine_dir()
                quarantine_path = QUARANTINE_DIR / compressed_path.name
                shutil.move(str(compressed_path), str(quarantine_path))
                logging.info(f'Quarantined compressed file at {quarantine_path}')
            except Exception:
                logging.warning('Could not quarantine compressed file')
    sys.exit(0)


if __name__ == '__main__':
    main()

