import os
import re
import sqlite3
from typing import List, Dict


class TableRowCountError(Exception):
    """Generic error for table row count validation."""


def _validate_db_path(db_path: str) -> str:
    if not isinstance(db_path, str) or not db_path:
        raise TableRowCountError("Invalid database path.")
    if os.path.isabs(db_path):
        raise TableRowCountError("Invalid database path.")
    if re.search(r"[?&#]", db_path):
        raise TableRowCountError("Invalid database path.")
    norm = os.path.normpath(db_path)
    if norm.startswith("..") or f"..{os.path.sep}" in norm:
        raise TableRowCountError("Invalid database path.")
    base_dir = os.path.realpath(os.getcwd())
    full_path = os.path.realpath(os.path.join(base_dir, norm))
    if not full_path.startswith(base_dir + os.path.sep):
        raise TableRowCountError("Invalid database path.")
    return full_path


_TABLE_NAME_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")


def _validate_table_names(tables: List[str]) -> None:
    if not isinstance(tables, (list, tuple)) or not tables:
        raise TableRowCountError("Invalid table list.")
    for name in tables:
        if not isinstance(name, str) or not _TABLE_NAME_RE.fullmatch(name):
            raise TableRowCountError("Invalid table name.")


def _quote_identifier(conn: sqlite3.Connection, identifier: str) -> str:
    escaped = identifier.replace('"', '""')
    return f'"{escaped}"'


def _fetch_schema(cursor: sqlite3.Cursor, table: str) -> List[tuple]:
    quoted = _quote_identifier(cursor.connection, table)
    cursor.execute(f"PRAGMA table_info({quoted})")
    return cursor.fetchall()


def get_table_row_counts(db_path: str, tables: List[str]) -> Dict[str, int]:
    """
    Returns a mapping of table name to row count for the given tables.
    Raises TableRowCountError on validation failures.
    """
    safe_path = _validate_db_path(db_path)
    _validate_table_names(tables)

    try:
        uri = f"file:{safe_path}?mode=ro"
        conn = sqlite3.connect(uri, timeout=5.0, uri=True)
    except sqlite3.Error as exc:
        raise TableRowCountError("Unable to open database.") from exc

    try:
        with conn:
            cursor = conn.cursor()

            # Build a safe IN clause using only parameter placeholders.
            placeholders = ",".join("?" for _ in tables)
            query = (
                "SELECT name FROM sqlite_master WHERE type='table' AND name IN ("
                + placeholders
                + ")"
            )
            cursor.execute(query, tables)

            existing = {row[0] for row in cursor.fetchall()}
            if set(tables) - existing:
                raise TableRowCountError("Requested tables are unavailable.")

            reference_schema = _fetch_schema(cursor, tables[0])
            for tbl in tables[1:]:
                if _fetch_schema(cursor, tbl) != reference_schema:
                    raise TableRowCountError("Table schemas do not match.")

            counts: Dict[str, int] = {}
            for tbl in tables:
                quoted_tbl = _quote_identifier(conn, tbl)
                cursor.execute("SELECT COUNT(*) FROM " + quoted_tbl)
                row = cursor.fetchone()
                if row is None:
                    raise TableRowCountError("Failed to retrieve row count.")
                count = row[0]
                if count == 0:
                    raise TableRowCountError("One of the tables contains zero rows.")
                counts[tbl] = count

            return counts
    finally:
        conn.close()

import os
import re
import shutil
import subprocess
import logging
import hashlib
from typing import List, Sequence

logging.basicConfig(level=logging.WARNING)
logger = logging.getLogger(__name__)

_TRUSTED_AMIXER = "/usr/bin/amixer"
_TRUSTED_AMIXER_HASH = "d2c0e0c1f9a0e5b4c6d8f7e9a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0"  # placeholder; replace with actual SHAâ256
_ALLOWED_COMMANDS = {_TRUSTED_AMIXER}
_VOLUME_CHANGE_REGEX = re.compile(r"^(?:[0-9]|[1-9][0-9]|100)%[+-]$")

def _verify_binary_hash(path: str) -> None:
    """Verify that the binary at *path* matches the expected SHAâ256 hash."""
    try:
        with open(path, "rb") as f:
            digest = hashlib.sha256(f.read()).hexdigest()
        if digest.lower() != _TRUSTED_AMIXER_HASH.lower():
            raise ValueError(f"Hash mismatch for trusted binary '{path}'")
    except OSError as exc:
        raise ValueError(f"Unable to read trusted binary '{path}': {exc}") from exc

# Verify at import time
_verify_binary_hash(_TRUSTED_AMIXER)

def _resolve_executable(executable: str) -> str:
    """
    Resolve a command name to an absolute path and verify it matches the trusted location.
    """
    if os.path.isabs(executable):
        resolved = os.path.realpath(executable)
    else:
        resolved = shutil.which(executable)
        if resolved is None:
            raise ValueError(f"Executable '{executable}' not found in PATH")
        resolved = os.path.realpath(resolved)
    if resolved != _TRUSTED_AMIXER:
        raise ValueError(f"Executable '{executable}' is not the trusted amixer")
    return resolved

def _validate_cmd(cmd: Sequence[str]) -> List[str]:
    """
    Validate that the command is a nonâempty list/tuple of strings,
    the executable resolves to the trusted amixer, and the arguments
    conform to the expected patterns.
    """
    if not isinstance(cmd, (list, tuple)):
        raise ValueError("Command must be a list or tuple")
    if not cmd:
        raise ValueError("Command list cannot be empty")
    if not all(isinstance(part, str) for part in cmd):
        raise ValueError("All command arguments must be strings")

    executable = _resolve_executable(cmd[0])
    if executable not in _ALLOWED_COMMANDS:
        raise ValueError(f"Executable '{executable}' is not allowed")

    # Argument pattern validation
    if len(cmd) < 3:
        raise ValueError("Insufficient command arguments")
    if cmd[1] == "get":
        if cmd[2] != "Master" or len(cmd) != 3:
            raise ValueError("Invalid arguments for 'get'")
    elif cmd[1] == "set":
        if cmd[2] != "Master" or len(cmd) != 4:
            raise ValueError("Invalid arguments for 'set'")
        if not _VOLUME_CHANGE_REGEX.fullmatch(cmd[3]):
            raise ValueError("Invalid volume change argument")
    else:
        raise ValueError("Unsupported amixer operation")

    # Return command with resolved absolute path (still a string)
    return [executable] + list(cmd[1:])

def _open_executable_fd(path: str) -> int:
    """Open the trusted executable and return a file descriptor bound to it."""
    flags = os.O_RDONLY
    if hasattr(os, "O_PATH"):
        flags |= os.O_PATH
    return os.open(path, flags)

def _run_cmd(cmd: Sequence[str]) -> str:
    """
    Execute a validated command safely and return its stdout.
    Returns an empty string on any error.
    """
    try:
        validated_cmd = _validate_cmd(cmd)
        exe_path = validated_cmd[0]
        fd = _open_executable_fd(exe_path)
        try:
            fd_path = f"/proc/self/fd/{fd}"
            exec_cmd = [fd_path] + validated_cmd[1:]
            safe_env = {"PATH": "/usr/bin", "LANG": "C", "LC_ALL": "C"}
            result = subprocess.run(
                exec_cmd,
                capture_output=True,
                text=True,
                check=True,
                env=safe_env,
                close_fds=False,
            )
            return result.stdout
        finally:
            os.close(fd)
    except (subprocess.CalledProcessError, OSError, ValueError) as exc:
        logger.warning("Command execution failed: %s", exc)
        return ""

def _get_current_volume() -> int:
    output = _run_cmd(["amixer", "get", "Master"])
    match = re.search(r"\[(\d+)%\]", output)
    if match:
        try:
            return int(match.group(1))
        except ValueError:
            logger.warning("Failed to parse volume from output")
    return 0

def _set_volume(change: str) -> None:
    """
    Adjust the master volume.
    `change` must match the pattern like "5%+" or "5%-".
    """
    if not isinstance(change, str) or not _VOLUME_CHANGE_REGEX.fullmatch(change):
        raise ValueError("Invalid volume change format")
    _run_cmd(["amixer", "set", "Master", change])

def adjust_volume(direction: str) -> str:
    """
    Adjust system master volume.

    Parameters:
        direction: "up" or "down" (caseâinsensitive).

    Returns:
        New volume level as a string, e.g., "75%". Returns an empty
        string on error.
    """
    if not isinstance(direction, str):
        return ""
    dir_clean = direction.strip().lower()
    if dir_clean not in ("up", "down"):
        return ""

    step = "5%+" if dir_clean == "up" else "5%-"

    try:
        _set_volume(step)
    except ValueError as exc:
        logger.warning("Volume set failed: %s", exc)
        return ""

    new_volume = _get_current_volume()
    return f"{new_volume}%" if new_volume >= 0 else ""

