import scrapy
import requests
from scrapy.exceptions import DropItem
from scrapy.utils.project import get_project_settings

logger = logging.getLogger(__name__)
logger.setLevel(logging.INFO)

# Environment variables for sensitive data
QUANDL_API_KEY = os.getenv("QUANDL_API_KEY")
QUANDL_DATABASE_CODE = os.getenv("QUANDL_DATABASE_CODE")
QUANDL_DATASET_CODE = os.getenv("QUANDL_DATASET_CODE")

if not all([QUANDL_API_KEY, QUANDL_DATABASE_CODE, QUANDL_DATASET_CODE]):
    raise RuntimeError("Required Quandl environment variables are not set.")

# Validate database and dataset codes against a whitelist
CODE_PATTERN = re.compile(r"^[A-Za-z0-9_-]+$")
if not CODE_PATTERN.fullmatch(QUANDL_DATABASE_CODE):
    raise ValueError(f"Invalid QUANDL_DATABASE_CODE: {QUANDL_DATABASE_CODE}")
if not CODE_PATTERN.fullmatch(QUANDL_DATASET_CODE):
    raise ValueError(f"Invalid QUANDL_DATASET_CODE: {QUANDL_DATASET_CODE}")

ISO_DATE_RE = re.compile(r"^\d{4}-\d{2}-\d{2}$")


def safe_date(value: str) -> str:
    """Validate date string against ISO format."""
    if not ISO_DATE_RE.match(value):
        raise ValueError(f"Invalid date format: {value}")
    datetime.strptime(value, "%Y-%m-%d")
    return value


def safe_float(value: Any) -> float:
    """Convert value to a finite float."""
    try:
        num = float(value)
    except (TypeError, ValueError) as e:
        raise ValueError(f"Invalid numeric value: {value}") from e
    if not math.isfinite(num):
        raise ValueError(f"Non-finite numeric value: {value}")
    return num


class QuandlPipeline:
    """Scrapy pipeline that uploads items to a Quandl dataset."""

    def __init__(self):
        self.session = requests.Session()
        self.session.headers.update({
            "Content-Type": "application/json",
            "Accept": "application/json",
            "Authorization": f"Bearer {QUANDL_API_KEY}",
        })
        self.upload_url = (
            f"https://data.nasdaq.com/api/v3/datasets/"
            f"{QUANDL_DATABASE_CODE}/{QUANDL_DATASET_CODE}/data.json"
        )

    def process_item(self, item: Dict[str, Any], spider: scrapy.Spider) -> Dict[str, Any]:
        try:
            date = safe_date(item.get("date", ""))
            value = safe_float(item.get("value"))
        except Exception as exc:
            raise DropItem(f"Item validation failed: {exc}") from exc

        payload = {
            "data": [
                {
                    "date": date,
                    "value": value
                }
            ]
        }

        try:
            response = self.session.post(
                self.upload_url,
                data=json.dumps(payload),
                timeout=10
            )
            response.raise_for_status()
            logger.info("Successfully uploaded data for %s", date)
        except requests.RequestException as exc:
            # Log without exposing sensitive URL or credentials
            status = getattr(exc.response, "status_code", "N/A")
            logger.error(
                "Failed to upload data to Quandl (status: %s).",
                status
            )
        return item

    def close_spider(self, spider: scrapy.Spider) -> None:
        self.session.close()


class ExampleSpider(scrapy.Spider):
    name = "example_spider"
    allowed_domains = ["example.com"]
    start_urls = ["https://www.example.com/data"]

    custom_settings = {
        "ITEM_PIPELINES": {
            "__main__.QuandlPipeline": 300
        },
        "ROBOTSTXT_OBEY": True,
        "DOWNLOAD_TIMEOUT": 15,
        "RETRY_ENABLED": True,
        "RETRY_TIMES": 2,
        "LOG_LEVEL": "INFO",
    }

    def parse(self, response: scrapy.http.Response):
        """
        Parses the response and yields items with `date` and `value` fields.
        Adjust selectors to match the target website structure.
        """
        rows = response.xpath("//table[@id='data-table']/tbody/tr")
        for row in rows:
            date_raw = row.xpath("./td[1]/text()").get()
            value_raw = row.xpath("./td[2]/text()").get()

            if not date_raw or not value_raw:
                continue

            date_clean = date_raw.strip()
            value_clean = value_raw.strip().replace(",", "")

            yield {
                "date": date_clean,
                "value": value_clean,
            }

