            cls.access_token = get_env('COINBASE_ACCESS_TOKEN')
            cls.refresh_token = get_env('COINBASE_REFRESH_TOKEN')
        except ValueError as exc:
            logger.error("Configuration error: %s", exc)
            raise

        cls.client = Client(
            access_token=cls.access_token,
            refresh_token=cls.refresh_token,
            client_id=cls.client_id,
            client_secret=cls.client_secret,
        )

    def test_delete_test_account(self) -> None:
        try:
            accounts = self.client.get_accounts()
        except CoinbaseAPIError:
            self.fail("Unable to list Coinbase accounts.")
        except Exception as exc:
            logger.exception("Unexpected error while listing accounts.")
            self.fail("Unexpected error occurred.")

        test_account = None
        for account in getattr(accounts, "data", []):
            name = getattr(account, "name", "")
            if isinstance(name, str) and name == "Test Account":
                test_account = account
                break

        if not test_account:
            self.skipTest("Test account not found; nothing to delete.")
            return

        try:
            self.client.delete_account(test_account.id)
        except CoinbaseAPIError:
            self.fail("Account deletion failed.")
        except Exception as exc:
            logger.exception("Unexpected error during account deletion.")
            self.fail("Unexpected error occurred during deletion.")

        try:
            accounts_after = self.client.get_accounts()
        except CoinbaseAPIError:
            self.fail("Unable to verify account deletion.")
        except Exception as exc:
            logger.exception("Unexpected error while verifying deletion.")
            self.fail("Unexpected error occurred during verification.")

        remaining_ids = {getattr(acct, "id", None) for acct in getattr(accounts_after, "data", [])}
        self.assertNotIn(test_account.id, remaining_ids, "Deleted account still present after deletion attempt.")

