import ast
import operator
import logging
from typing import Any, Callable, Dict, List, Tuple

logger = logging.getLogger(__name__)


class LockEvaluationError(Exception):
    """Custom exception for lock evaluation errors."""


class SafeEvaluator(ast.NodeVisitor):
    """
    Evaluates a restricted subset of Python expressions safely.
    Only allows:
        - literals (str, int, float, bool, None)
        - containers (list, tuple, dict) of allowed literals
        - boolean operations (and, or, not) with shortâcircuit semantics
        - comparisons (==, !=, <, <=, >, >=, is, is not, in, not in)
        - calls to whitelisted functions
    """

    _allowed_cmpops = {
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.Is: operator.is_,
        ast.IsNot: operator.is_not,
        ast.In: lambda a, b: a in b,
        ast.NotIn: lambda a, b: a not in b,
    }

    _allowed_unaryops = {
        ast.Not: operator.not_,
    }

    def __init__(self, functions: Dict[str, Callable[..., Any]]) -> None:
        self._functions = functions

    def evaluate(self, node: ast.AST) -> Any:
        return self.visit(node)

    def visit_Expression(self, node: ast.Expression) -> Any:
        return self.visit(node.body)

    def visit_Constant(self, node: ast.Constant) -> Any:
        if not isinstance(node.value, (str, int, float, bool, type(None))):
            raise LockEvaluationError(f"Unsupported literal type: {type(node.value).__name__}")
        return node.value

    def visit_Name(self, node: ast.Name) -> Any:
        if node.id in self._functions:
            return self._functions[node.id]
        raise LockEvaluationError(f"Unauthorized name '{node.id}' used in lock definition.")

    def visit_Call(self, node: ast.Call) -> Any:
        func = self.visit(node.func)
        if not callable(func):
            raise LockEvaluationError("Attempted to call a non-callable object.")
        args = [self.visit(arg) for arg in node.args]
        keywords = {kw.arg: self.visit(kw.value) for kw in node.keywords if kw.arg}
        return func(*args, **keywords)

    def visit_List(self, node: ast.List) -> List[Any]:
        return [self.visit(elt) for elt in node.elts]

    def visit_Tuple(self, node: ast.Tuple) -> Tuple[Any, ...]:
        return tuple(self.visit(elt) for elt in node.elts)

    def visit_Dict(self, node: ast.Dict) -> Dict[Any, Any]:
        return {self.visit(k): self.visit(v) for k, v in zip(node.keys, node.values)}

    def visit_BoolOp(self, node: ast.BoolOp) -> Any:
        if isinstance(node.op, ast.And):
            result = True
            for value in node.values:
                operand = bool(self.visit(value))
                result = result and operand
                if not result:
                    break
            return result
        elif isinstance(node.op, ast.Or):
            result = False
            for value in node.values:
                operand = bool(self.visit(value))
                result = result or operand
                if result:
                    break
            return result
        else:
            raise LockEvaluationError(f"Unsupported boolean operator {type(node.op).__name__}.")

    def visit_UnaryOp(self, node: ast.UnaryOp) -> Any:
        op_type = type(node.op)
        if op_type not in self._allowed_unaryops:
            raise LockEvaluationError(f"Unsupported unary operator {op_type.__name__}.")
        operand = self.visit(node.operand)
        return self._allowed_unaryops[op_type](operand)

    def visit_Compare(self, node: ast.Compare) -> Any:
        left = self.visit(node.left)
        for op, comparator in zip(node.ops, node.comparators):
            op_type = type(op)
            if op_type not in self._allowed_cmpops:
                raise LockEvaluationError(f"Unsupported comparison operator {op_type.__name__}.")
            right = self.visit(comparator)
            if not self._allowed_cmpops[op_type](left, right):
                return False
            left = right
        return True

    def generic_visit(self, node: ast.AST) -> Any:
        raise LockEvaluationError(f"Unsupported syntax {type(node).__name__} in lock definition.")


def parse_and_evaluate_lock(
    lock_str: str,
    function_defs: List[Tuple[str, List[Any], Dict[str, Any]]],
) -> Tuple[Any, List[str]]:
    """
    Parses and safely evaluates a lock definition string.

    Args:
        lock_str: The string containing the lock expression.
        function_defs: List of tuples (name, args, kwargs) defining
                      callable stubs available inside the expression.

    Returns:
        A tuple (result, warnings). ``result`` is the evaluated value,
        ``warnings`` is a list of any nonâcritical issues discovered.

    Raises:
        LockEvaluationError: For syntax errors, unauthorized constructs,
                             or runtime errors during evaluation.
    """
    if not isinstance(lock_str, str):
        raise LockEvaluationError("Lock definition must be a string.")

    warnings: List[str] = []

    # Build a safe function registry
    function_registry: Dict[str, Callable[..., Any]] = {}

    for name, args, kwargs in function_defs:
        if not isinstance(name, str):
            warnings.append(f"Ignoring function with nonâstring name: {name}")
            continue

        safe_args = list(args) if isinstance(args, (list, tuple)) else []
        safe_kwargs = dict(kwargs) if isinstance(kwargs, dict) else {}

        def _make_callable(func_name: str, predef_args: List[Any], predef_kwargs: Dict[str, Any]) -> Callable[..., Any]:
            def _callable(*call_args: Any, **call_kwargs: Any) -> Any:
                if call_args or call_kwargs:
                    raise LockEvaluationError(f"Function '{func_name}' does not accept runtime arguments.")
                return {
                    "name": func_name,
                    "args": predef_args,
                    "kwargs": predef_kwargs,
                }
            return _callable

        function_registry[name] = _make_callable(name, safe_args, safe_kwargs)

    # Parse and validate the expression syntax
    try:
        parsed_ast = ast.parse(lock_str, mode="eval")
    except SyntaxError as exc:
        raise LockEvaluationError(f"Syntax error in lock definition: {exc.msg}") from exc

    # Evaluate safely
    evaluator = SafeEvaluator(function_registry)
    try:
        result = evaluator.evaluate(parsed_ast)
    except Exception as exc:
        logger.exception("Error evaluating lock definition")
        raise LockEvaluationError("Error evaluating lock definition") from exc

    return result, warnings

