# Absolute path to the trusted pactl binary
_PACTL_PATH = shutil.which('pactl') or '/usr/bin/pactl'
if not _PACTL_PATH or not os.path.isabs(_PACTL_PATH):
    raise RuntimeError("Trusted pactl binary not found.")

# Lockedâdown environment for subprocess calls
_SAFE_ENV = {'PATH': os.path.dirname(_PACTL_PATH)}

# Whitelisted full command argument sequences
_ALLOWED_COMMANDS = {
    ('pactl', 'get-sink-volume', '@DEFAULT_SINK@'),
    ('pactl', 'set-sink-volume', '@DEFAULT_SINK@', '+5%'),
    ('pactl', 'set-sink-volume', '@DEFAULT_SINK@', '-5%'),
}

_TIMEOUT_SECONDS = 5  # reasonable timeout for pactl invocations


def _validate_args(args):
    """Validate that args exactly matches an allowed command sequence."""
    if not isinstance(args, (list, tuple)):
        raise ValueError("Command arguments must be a list or tuple.")
    if not args:
        raise ValueError("Command arguments cannot be empty.")
    for i, arg in enumerate(args):
        if not isinstance(arg, str):
            raise ValueError(f"Argument {i} is not a string.")
        if not arg:
            raise ValueError(f"Argument {i} is an empty string.")
    if tuple(args) not in _ALLOWED_COMMANDS:
        raise ValueError(f"Command sequence {args} is not allowed.")
    return list(args)  # subprocess.run expects a mutable sequence


def _run_command(args):
    """Run a whitelisted command safely without using a shell."""
    try:
        safe_args = _validate_args(args)
        # Replace the first argument ('pactl') with the absolute, trusted path
        final_args = [_PACTL_PATH] + safe_args[1:]
        result = subprocess.run(
            final_args,
            capture_output=True,
            text=True,
            check=True,
            timeout=_TIMEOUT_SECONDS,
            env=_SAFE_ENV,
        )
        return result.stdout
    except (subprocess.CalledProcessError, OSError, ValueError, subprocess.TimeoutExpired):
        return None


def _get_current_volume():
    """Retrieve the current sink volume as a percentage string."""
    output = _run_command(['pactl', 'get-sink-volume', '@DEFAULT_SINK@'])
    if not output:
        return "unknown"
    for token in output.split():
        if token.endswith('%'):
            return token
    return "unknown"


def _adjust_volume(direction):
    """Adjust volume up or down by a fixed step."""
    step = '+5%' if direction == 'up' else '-5%'
    _run_command(['pactl', 'set-sink-volume', '@DEFAULT_SINK@', step])


def adjust_volume(command):
    """
    Adjust system volume based on command ('up' or 'down') and return current volume level.
    Returns volume as a string (e.g., '45%') or 'unknown' on error.
    """
    if not isinstance(command, str):
        return _get_current_volume()
    cmd = command.strip().lower()
    if cmd not in ('up', 'down'):
        return _get_current_volume()
    _adjust_volume(cmd)
    return _get_current_volume()

