import re
import hashlib
from typing import Dict, Any


_MAX_DEVICE_ID_LENGTH = 256
_DEVICE_ID_PATTERN = re.compile(r"^[A-Za-z0-9_\-]+$")


def create_fake_switch_and_get_port_tags(device_id: str) -> Dict[str, Any]:
    """
    Creates a mock switch with a single port and returns a copy of the port's tags,
    including a VM ID derived from the provided device_id.

    Args:
        device_id (str): Identifier of the device. Must be a nonâempty string
                         containing only alphanumeric characters, hyphens, or underscores.

    Returns:
        dict: Dictionary containing port tags, e.g., {"vm_id": "..."}.

    Raises:
        ValueError: If the device_id is invalid.
        RuntimeError: For unexpected errors without leaking internal details.
    """
    try:
        # Input validation
        if not isinstance(device_id, str):
            raise ValueError("device_id must be a string.")
        cleaned_id = device_id.strip()
        if not cleaned_id:
            raise ValueError("device_id cannot be empty or only whitespace.")
        if len(cleaned_id) > _MAX_DEVICE_ID_LENGTH:
            raise ValueError(
                f"device_id exceeds maximum allowed length of {_MAX_DEVICE_ID_LENGTH}."
            )
        if not _DEVICE_ID_PATTERN.fullmatch(cleaned_id):
            raise ValueError("device_id contains invalid characters.")

        # Generate VM ID using a cryptographic hash (SHAâ256) and truncate for readability
        vm_id = hashlib.sha256(cleaned_id.encode("utf-8")).hexdigest()[:32]

        # Build a mock switch and its port
        fake_switch = {
            "switch_id": f"switch_{cleaned_id}",
            "ports": [
                {
                    "port_id": f"port_{cleaned_id}",
                    "tags": {"vm_id": vm_id},
                }
            ],
        }

        # Retrieve tags from the first (and only) port and return a copy
        port_tags = fake_switch["ports"][0]["tags"]
        return dict(port_tags)

    except ValueError:
        raise
    except Exception as exc:
        raise RuntimeError("Failed to generate port tags.") from exc

import os
import shutil
import subprocess
import tempfile
import time
import select
from typing import List

# Configuration constants
BLOCKED_SHELLS = {"sh", "bash", "cmd", "cmd.exe", "powershell", "pwsh"}
MAX_ARG_LEN = 4096
MAX_ARG_COUNT = 256
MAX_OUTPUT_SIZE = 10 * 1024 * 1024  # 10 MB
SAFE_PATH = "/usr/sbin:/usr/bin:/sbin:/bin"


class CommandResultError(RuntimeError):
    """Raised when a command's exit status does not match the expected outcome."""
    pass


def _is_blocked_path(path: str) -> bool:
    """
    Return True if the file at *path* is a blocked shell or a script whose interpreter is blocked.
    """
    try:
        with open(path, "rb") as f:
            first_line = f.readline()
        if first_line.startswith(b"#!"):
            interpreter = first_line[2:].strip().split(b" ")[0]
            interpreter_basename = os.path.basename(interpreter).decode(errors="ignore").lower()
            if interpreter_basename in BLOCKED_SHELLS:
                return True
    except OSError:
        pass
    return os.path.basename(path).lower() in BLOCKED_SHELLS


def _is_blocked(executable: str) -> bool:
    """
    Resolve *executable* using the safe PATH and determine if it is blocked.
    """
    resolved = shutil.which(executable, path=SAFE_PATH) or executable
    return _is_blocked_path(resolved)


def _validate_command(command: List[str]) -> None:
    if not isinstance(command, list) or not command:
        raise ValueError("command must be a nonâempty list")
    if len(command) > MAX_ARG_COUNT:
        raise ValueError(f"command contains too many arguments (max {MAX_ARG_COUNT})")
    for part in command:
        if not isinstance(part, str) or not part:
            raise ValueError("each command part must be a nonâempty string")
        if any(ord(c) < 32 for c in part):
            raise ValueError("command parts contain control characters")
        if len(part) > MAX_ARG_LEN:
            raise ValueError("command part exceeds maximum allowed length")
    if _is_blocked(command[0]):
        raise ValueError(f"execution of shell or blocked interpreter '{command[0]}' is not allowed")


def _validate_timeout(timeout: int) -> None:
    if not isinstance(timeout, int) or timeout <= 0:
        raise ValueError("timeout must be a positive integer")


def _resolve_executable(executable: str) -> str:
    """
    Resolve *executable* against SAFE_PATH, ensure it is within allowed directories,
    executable, and not blocked.
    """
    resolved = shutil.which(executable, path=SAFE_PATH) or executable
    if not os.path.isabs(resolved):
        resolved = os.path.abspath(resolved)

    if not os.path.isfile(resolved) or not os.access(resolved, os.X_OK):
        raise RuntimeError("executable not found or not executable")

    # Verify the executable resides in one of the SAFE_PATH directories
    allowed_dirs = [os.path.abspath(p) for p in SAFE_PATH.split(os.pathsep) if p]
    exec_dir = os.path.abspath(os.path.dirname(resolved))
    if not any(exec_dir == d or exec_dir.startswith(d + os.sep) for d in allowed_dirs):
        raise RuntimeError("executable is not located in a safe directory")

    if _is_blocked_path(resolved):
        raise ValueError(f"execution of blocked interpreter '{resolved}' is not allowed")

    return resolved


def _read_streams_with_limit(proc: subprocess.Popen, timeout: int) -> tuple[bytes, bytes]:
    """
    Read stdout and stderr from *proc* incrementally, enforcing MAX_OUTPUT_SIZE and timeout.
    """
    stdout_chunks = []
    stderr_chunks = []
    total = 0
    start = time.time()
    while True:
        remaining = timeout - (time.time() - start)
        if remaining <= 0:
            proc.kill()
            raise RuntimeError("command timed out")
        rlist, _, _ = select.select([proc.stdout, proc.stderr], [], [], remaining)
        if not rlist:
            continue
        for stream in rlist:
            data = stream.read(8192)
            if not data:
                continue
            total += len(data)
            if total > MAX_OUTPUT_SIZE:
                proc.kill()
                raise RuntimeError("command output exceeds allowed size")
            if stream is proc.stdout:
                stdout_chunks.append(data)
            else:
                stderr_chunks.append(data)
        if proc.poll() is not None:
            # Process finished; drain remaining data
            remaining_stdout = proc.stdout.read()
            remaining_stderr = proc.stderr.read()
            for data in (remaining_stdout, remaining_stderr):
                if data:
                    total += len(data)
                    if total > MAX_OUTPUT_SIZE:
                        proc.kill()
                        raise RuntimeError("command output exceeds allowed size")
            if remaining_stdout:
                stdout_chunks.append(remaining_stdout)
            if remaining_stderr:
                stderr_chunks.append(remaining_stderr)
            break
    return b"".join(stdout_chunks), b"".join(stderr_chunks)


def run_command(command: List[str], expect_success: bool, timeout: int = 30) -> None:
    """
    Execute a command safely and verify its result.

    :param command: Command and arguments as a list of strings.
    :param expect_success: True if the command is expected to exit with 0.
    :param timeout: Maximum seconds to wait for the command.
    :raises ValueError: If the input is invalid.
    :raises CommandResultError: If the command outcome does not match expectation.
    :raises RuntimeError: If execution fails, times out, or output is too large.
    """
    _validate_command(command)
    _validate_timeout(timeout)

    safe_env = {
        "PATH": SAFE_PATH,
        "HOME": os.environ.get("HOME", ""),
        "LANG": os.environ.get("LANG", ""),
        "LC_ALL": os.environ.get("LC_ALL", ""),
    }

    # Resolve and validate the executable
    resolved_exe = _resolve_executable(command[0])
    pre_stat = os.stat(resolved_exe)

    # Prepare command with absolute executable path
    exec_command = list(command)
    exec_command[0] = resolved_exe

    # Use a temporary safe working directory
    safe_cwd = tempfile.mkdtemp(prefix="cmdrun_")
    try:
        proc = subprocess.Popen(
            exec_command,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            env=safe_env,
            cwd=safe_cwd,
        )
        try:
            stdout, stderr = _read_streams_with_limit(proc, timeout)
        except Exception:
            proc.kill()
            raise

        # Verify the executable wasn't swapped (TOCTOU protection)
        post_stat = os.stat(resolved_exe)
        if pre_stat.st_ino != post_stat.st_ino or pre_stat.st_mtime != post_stat.st_mtime:
