    # Preâvalidate the path
    pre_stat = os.lstat(abs_path)
    if stat.S_ISLNK(pre_stat.st_mode):
        raise OSError(errno.ELOOP, "Symlink encountered", abs_path)
    if not stat.S_ISDIR(pre_stat.st_mode):
        raise NotADirectoryError(f"Path is not a directory: {abs_path}")

