    flags = 0
    if hasattr(os, "O_PATH"):
        flags |= os.O_PATH
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW
    if hasattr(os, "O_DIRECTORY"):
        flags |= os.O_DIRECTORY

    # Fallback to O_RDONLY + O_DIRECTORY if no special flags are present
    if flags == 0:
        flags = os.O_RDONLY
