        post_stat = os.fstat(fd)

        # Verify that the opened descriptor points to the same inode/device
        if (pre_stat.st_ino != post_stat.st_ino) or (pre_stat.st_dev != post_stat.st_dev):
            os.close(fd)
            raise OSError(errno.ELOOP, "Path changed during open (potential race)", abs_path)

