        if not (hasattr(os, "O_NOFOLLOW") and (flags & os.O_NOFOLLOW)):
            if stat.S_ISLNK(post_stat.st_mode):
                os.close(fd)
                raise OSError(errno.ELOOP, "Symlink encountered after open", abs_path)

        if not stat.S_ISDIR(post_stat.st_mode):
            os.close(fd)
            raise NotADirectoryError(f"Path is not a directory after open: {abs_path}")

    except Exception:
        os.close(fd)
