    if not isinstance(uri, str) or not uri:
        raise ValueError("MongoDB URI must be a non-empty string.")
    if not (uri.startswith("mongodb://") or uri.startswith("mongodb+srv://")):
        raise ValueError("Unsupported MongoDB URI scheme.")
    # Enforce TLS usage; pymongo will negotiate TLS if `tls=True`
    # No further validation needed here; connection parameters enforce it.


def manage_collections(
    mongo_uri: str,
    db_name: str,
    new_collection: str,
    collections_to_drop: List[str],
    document: Dict[str, Any],
) -> bool:
    _validate_mongo_uri(mongo_uri)
    db_name = _sanitize_db_name(db_name)

    new_collection = _sanitize_collection_name(new_collection)
    collections_to_drop = [_sanitize_collection_name(c) for c in collections_to_drop]
    document = _sanitize_document(document)

    client = None
    try:
        client = MongoClient(
            mongo_uri,
            serverSelectionTimeoutMS=5000,
            tls=True,
            tlsAllowInvalidCertificates=False,
        )
        client.admin.command("ping")  # Validate connection early
        db = client[db_name]

        for coll_name in collections_to_drop:
            if coll_name in db.list_collection_names():
                db.drop_collection(coll_name)
                logger.info("Dropped collection: %s", coll_name)

        if new_collection not in db.list_collection_names():
            db.create_collection(new_collection)
            logger.info("Created collection: %s", new_collection)

        db[new_collection].insert_one(document)
        logger.info("Inserted document into %s", new_collection)

        return True
    except (errors.PyMongoError, ValueError) as exc:
        logger.error("Database operation failed: %s", exc)
        return False
    finally:
        if client:
            client.close()

