import shutil
import subprocess
import sys
from collections import defaultdict
from hashlib import sha256

# SHAâ256 hash (64 hex characters)
_HASH_RE = re.compile(r"^[a-f0-9]{64}$", re.IGNORECASE)
_KNOWN_HG_HASH = None  # Set to the expected SHAâ256 hash of the trusted hg binary if desired

_MAX_COMMITS = 1_000_000  # safeguard against unbounded memory usage


def _resolve_repo_path(path: str) -> str:
    if not isinstance(path, str):
        raise ValueError("Repository path must be a string")
    abs_path = os.path.abspath(path)
    real_path = os.path.realpath(abs_path)
    if not os.path.isdir(real_path):
        raise ValueError("Repository path is not a directory")
    hg_dir = os.path.join(real_path, ".hg")
    if not os.path.isdir(hg_dir):
        raise ValueError("Directory does not appear to be a Mercurial repository")
    return real_path


def _verify_binary(path: str) -> tuple[str, tuple[int, int]]:
    if not os.path.isfile(path):
        raise FileNotFoundError(f"hg binary not found at {path}")
    if not os.access(path, os.X_OK):
        raise PermissionError(f"hg binary at {path} is not executable")
    if _KNOWN_HG_HASH:
        h = sha256()
        with open(path, "rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                h.update(chunk)
        if h.hexdigest() != _KNOWN_HG_HASH:
            raise ValueError("hg binary hash mismatch")
    abs_path = os.path.abspath(path)
    st = os.stat(abs_path)
    return abs_path, (st.st_dev, st.st_ino)


def _find_hg_binary() -> tuple[str, tuple[int, int]]:
    preferred = "/usr/bin/hg"
    if os.path.isfile(preferred) and os.access(preferred, os.X_OK):
        return _verify_binary(preferred)
    hg_path = shutil.which("hg", path="/usr/bin")
    if not hg_path:
        raise FileNotFoundError("hg executable not found in trusted locations")
    return _verify_binary(hg_path)


def run_hg_log(repo_path: str):
    hg_binary, expected_stat = _find_hg_binary()
    hg_cmd = [
        hg_binary,
        "log",
        "-R",
        repo_path,
        "-r",
        "sort(all(), date)",
        "--template",
        "{node} {p1node} {p2node}
",
    ]
    safe_env = {"PATH": "/usr/bin", "LANG": "C", "LC_ALL": "C"}

    def _preexec():
        try:
            st = os.stat(hg_binary)
            if (st.st_dev, st.st_ino) != expected_stat:
                os._exit(127)
        except Exception:
            os._exit(127)

    try:
        with subprocess.Popen(
            hg_cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            env=safe_env,
            cwd=repo_path,
            close_fds=True,
            preexec_fn=_preexec,
        ) as proc:
            _resolve_repo_path(repo_path)
            for line in proc.stdout:
                yield line.rstrip("
")
            _, err = proc.communicate()
            if proc.returncode != 0:
                sys.stderr.write(f"hg log failed: {err.strip()}
")
                sys.exit(1)
    except FileNotFoundError:
        sys.stderr.write("hg executable not found or not executable.
")
        sys.exit(1)
    except subprocess.SubprocessError as e:
        sys.stderr.write(f"Subprocess error: {e}
")
        sys.exit(1)


def parse_commit_lines(lines):
    commits = {}
    children = defaultdict(set)
    for line in lines:
        parts = line.strip().split()
        if not parts:
            continue
        node = parts[0]
        if not _HASH_RE.fullmatch(node):
            continue
        parents = [p for p in parts[1:] if p and _HASH_RE.fullmatch(p)]
        commits[node] = parents
        for p in parents:
            children[p].add(node)
    return commits, children


def calculate_branch_counts(commits):
    heads = set()
    branch_counts = {}
    for commit in commits:
        for parent in commits[commit]:
            if parent in heads:
                heads.remove(parent)
        heads.add(commit)
        branch_counts[commit] = len(heads)
    return branch_counts


def main():
    parser = argparse.ArgumentParser(
        description="Calculate branch count per commit in a Mercurial repository."
    )
    parser.add_argument("repo_path", help="Path to the Mercurial repository")
    args = parser.parse_args()
    try:
        repo_path = _resolve_repo_path(args.repo_path)
    except ValueError as ve:
        sys.stderr.write(str(ve) + "
")
        sys.exit(1)

    commits_dict = {}
    for line in run_hg_log(repo_path):
        temp_commits, _ = parse_commit_lines([line])
        commits_dict.update(temp_commits)
        if len(commits_dict) > _MAX_COMMITS:
            sys.stderr.write("Repository contains too many commits to process safely.
")
            sys.exit(1)

    branch_counts = calculate_branch_counts(commits_dict)

    for commit in commits_dict:
        print(f"{commit} {branch_counts[commit]}")


