from iminuit import Minuit

_MAX_ITEMS = 10_000  # reasonable limit to mitigate DoS attacks


def create_minuit(
    param_dict: Dict[str, Any],
    exclusions: List[int],
    centroids: List[float]
) -> Minuit:
    """
    Create a Minuit instance, set its parameters from ``param_dict`` and
    assign a filtered list of values based on ``exclusions`` and ``centroids``.
    """
    # Basic type validation
    if not isinstance(param_dict, dict):
        raise TypeError("param_dict must be a dictionary")
    if not isinstance(exclusions, list):
        raise TypeError("exclusions must be a list")
    if not isinstance(centroids, list):
        raise TypeError("centroids must be a list")

    if len(param_dict) > _MAX_ITEMS:
        raise ValueError("param_dict contains too many items")
    if len(exclusions) > _MAX_ITEMS:
        raise ValueError("exclusions list is too large")
    if len(centroids) > _MAX_ITEMS:
        raise ValueError("centroids list is too large")

    if not all(isinstance(i, int) for i in exclusions):
        raise TypeError("exclusions must contain only integers")
    if not all(isinstance(v, (int, float)) for v in centroids):
        raise TypeError("centroids must contain only numeric values")
    if not all(math.isfinite(v) for v in centroids):
        raise ValueError("centroids must contain finite numeric values")

    # Validate exclusions indices
    if any(i < 0 or i >= len(centroids) for i in exclusions):
        raise ValueError("exclusions contain indices out of range")
    if len(set(exclusions)) != len(exclusions):
        raise ValueError("exclusions contain duplicate indices")

    # Initialise a dummy Minuit; actual function can be a simple lambda
    minuit = Minuit(lambda *args: 0.0)

    # Safe attribute assignment
    identifier_pattern = re.compile(r"^[A-Za-z][A-Za-z0-9_]*$")
    for name, value in param_dict.items():
        if not isinstance(name, str) or not identifier_pattern.fullmatch(name):
            raise ValueError(f"Invalid parameter name: {name}")
        if not isinstance(value, (int, float)):
            raise ValueError(f"Parameter '{name}' must be a numeric type")
        if not math.isfinite(value):
            raise ValueError(f"Parameter '{name}' must be a finite number")
        setattr(minuit, name, value)

    # Build the filtered values list
    filtered_values = [
        centroids[i] for i in range(len(centroids)) if i not in exclusions
    ]

    # Verify filtered list contains only finite numbers
    if not all(isinstance(v, (int, float)) and math.isfinite(v) for v in filtered_values):
        raise ValueError("Filtered values contain nonânumeric or nonâfinite entries")

    # Direct assignment without exec
    minuit.values = filtered_values

    return minuit

