def _sanitize_tcp_layer(tcp_layer: TCP) -> None:
    try:
        win_val = int(tcp_layer.window) if tcp_layer.window is not None else 8192
    except Exception:
        win_val = 8192
    tcp_layer.window = max(0, min(win_val, 65535))
