# Trusted locations for the samtools executable
_TRUSTED_SAMTOOLS_DIRS = ("/usr/bin", "/usr/local/bin")
# Maximum amount of output (in bytes) to read from samtools
_MAX_OUTPUT_SIZE = 10 * 1024 * 1024  # 10â¯MiB


def _find_samtools() -> str:
    """Locate a trusted samtools executable with strict verification."""
    samtools_path = shutil.which("samtools")
    if not samtools_path:
        raise FileNotFoundError("Required executable 'samtools' not found in PATH.")

    # Open the executable securely to avoid TOCTOU races
    flags = (
        os.O_PATH | os.O_NOFOLLOW | os.O_CLOEXEC
        if hasattr(os, "O_PATH")
        else os.O_RDONLY | os.O_NOFOLLOW | os.O_CLOEXEC
    )
    try:
        fd = os.open(samtools_path, flags)
    except OSError as exc:
        raise PermissionError("Unable to open samtools executable securely.") from exc

    try:
        st = os.fstat(fd)
        if not stat.S_ISREG(st.st_mode):
            raise PermissionError("samtools is not a regular file.")
        if not (st.st_mode & stat.S_IXUSR):
            raise PermissionError("samtools is not executable by its owner.")
        if st.st_mode & (stat.S_IWGRP | stat.S_IWOTH):
            raise PermissionError("samtools is writable by group or others.")
        if st.st_uid != 0:
            raise PermissionError("samtools must be owned by root.")
        # Resolve the real path from the file descriptor
        if os.path.isdir("/proc/self/fd"):
            real_path = os.readlink(f"/proc/self/fd/{fd}")
        else:
            real_path = os.path.realpath(samtools_path)

        # Ensure the resolved path is inside a trusted directory
        inside_trusted = any(
            os.path.commonpath([real_path, os.path.abspath(dir_path)])
            == os.path.abspath(dir_path)
            for dir_path in _TRUSTED_SAMTOOLS_DIRS
        )
        if not inside_trusted:
            raise PermissionError("samtools executable is not located in a trusted directory.")
    finally:
        os.close(fd)

    return samtools_path


def read_bam_without_header(bam_path: str) -> List[str]:
    """Read a BAM file with samtools, returning alignment lines without the SAM header."""
    if not isinstance(bam_path, str):
        raise TypeError("bam_path must be a string.")
    if "�" in bam_path:
        raise ValueError("Invalid file name: null byte detected.")

    path = Path(bam_path).expanduser()
    if not path.is_absolute():
        raise ValueError("Path must be absolute.")
    if path.suffix.lower() != ".bam":
        raise ValueError("File does not have a .bam extension.")

    # Open the file securely, preventing TOCTOU and symlink attacks
    try:
        fd = os.open(str(path), os.O_RDONLY | os.O_NOFOLLOW)
    except OSError as exc:
        raise FileNotFoundError(f"Unable to open file: {path}") from exc

    try:
        st = os.fstat(fd)
        if not stat.S_ISREG(st.st_mode):
            raise ValueError("Specified path is not a regular file.")
        if st.st_uid != os.getuid():
            raise PermissionError("BAM file is not owned by the current user.")
        if st.st_mode & (stat.S_IWGRP | stat.S_IWOTH):
            raise PermissionError("BAM file is writable by group or others.")
    except Exception:
        os.close(fd)
        raise

    samtools_exe = _find_samtools()
    cmd = [samtools_exe, "view", "-"]

    # Provide a minimal, sanitized environment
    safe_env = {
        "PATH": "/usr/bin:/bin",
        "LD_PRELOAD": "",
        "LD_LIBRARY_PATH": "",
        "PYTHONPATH": "",
        "IFS": "",
        "TMPDIR": "/tmp",
    }

    try:
        proc = subprocess.Popen(
            cmd,
            stdin=fd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            errors="replace",
            env=safe_env,
        )
    except Exception as exc:
        os.close(fd)
        raise RuntimeError("Failed to start samtools process.") from exc

    lines: List[str] = []
    total_bytes = 0

    try:
        if proc.stdout is None:
            raise RuntimeError("Failed to capture samtools output.")
        for raw_line in proc.stdout:
            line_bytes = len(raw_line.encode())
            if total_bytes + line_bytes > _MAX_OUTPUT_SIZE:
                proc.kill()
                raise RuntimeError("samtools output exceeds allowed size.")
            total_bytes += line_bytes
            lines.append(raw_line.rstrip("
"))
        proc.stdout.close()

        proc.wait(timeout=30)

        err_msg = proc.stderr.read() if proc.stderr else ""
        if proc.returncode != 0:
            raise RuntimeError(f"samtools failed: {err_msg.strip()}")
    finally:
        if proc.stderr:
            proc.stderr.close()
        os.close(fd)

    return lines

