import subprocess
import shutil
import hashlib
import ipaddress
import logging
import socket
import re
from typing import Optional

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

_MAX_DOWNLOAD_BYTES = 100 * 1024 * 1024  # 100â¯MiB
_MAX_EXTRACTED_FILES = 10_000
_MAX_UNCOMPRESSED_SIZE = 500 * 1024 * 1024  # 500â¯MiB
_DOWNLOAD_TIMEOUT = 30  # seconds
_MAX_REDIRECTS = 5
_NON_PUBLIC_NETWORKS = [
    ipaddress.ip_network("10.0.0.0/8"),
    ipaddress.ip_network("172.16.0.0/12"),
    ipaddress.ip_network("192.168.0.0/16"),
    ipaddress.ip_network("127.0.0.0/8"),
    ipaddress.ip_network("169.254.0.0/16"),
    ipaddress.ip_network("::1/128"),
    ipaddress.ip_network("fc00::/7"),
]

SAFE_INSTALL_ROOT = os.getenv("SAFE_INSTALL_ROOT", "/opt/myapp")
_SCRIPT_NAME_REGEX = re.compile(r"^[A-Za-z0-9._-]+$")


def _is_private_ip(host: str) -> bool:
    try:
        ip = ipaddress.ip_address(host)
        return any(ip in net for net in _NON_PUBLIC_NETWORKS)
    except ValueError:
        return False


def _resolve_host_ips(host: str) -> list[ipaddress.IPv4Address | ipaddress.IPv6Address]:
    try:
        infos = socket.getaddrinfo(host, None, proto=socket.IPPROTO_TCP)
        return [ipaddress.ip_address(info[4][0]) for info in infos]
    except socket.gaierror as exc:
        raise ValueError(f"Unable to resolve host {host!r}: {exc}") from exc


def _is_safe_path(base_path: str, target_path: str) -> bool:
    base = os.path.abspath(base_path)
    target = os.path.abspath(target_path)
    return target == base or target.startswith(base + os.sep)


def _NoRedirectHandler(urllib.request.HTTPRedirectHandler):
    def redirect_request(self, req, fp, code, msg, hdrs, newurl):
        raise urllib.error.HTTPError(
            req.full_url, code, f"Redirect blocked to {newurl}", hdrs, fp
        )


def _validate_url(url: str) -> urllib.parse.ParseResult:
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme not in ("http", "https"):
        raise ValueError("URL must use http or https.")
    if not parsed.netloc:
        raise ValueError("URL must have a network location.")
    host = parsed.hostname
    if host is None:
        raise ValueError("URL hostname could not be determined.")
    for ip in _resolve_host_ips(host):
        if any(ip in net for net in _NON_PUBLIC_NETWORKS):
            raise ValueError("URL resolves to a disallowed private network address.")
    return parsed


def _post_connection_ip_check(response: urllib.responseaddinfourl) -> None:
    final_url = response.geturl()
    parsed = urllib.parse.urlparse(final_url)
    host = parsed.hostname
    if host is None:
        raise ValueError("Final URL has no hostname.")
    for ip in _resolve_host_ips(host):
        if any(ip in net for net in _NON_PUBLIC_NETWORKS):
            raise ValueError("Final connection resolved to a private network address.")


def _download_to_file(url: str, dest_path: str) -> None:
    opener = urllib.request.build_opener(_NoRedirectHandler)
    current_url = url
    for _ in range(_MAX_REDIRECTS + 1):
        _validate_url(current_url)
        try:
            with opener.open(current_url, timeout=_DOWNLOAD_TIMEOUT) as response:
                _post_connection_ip_check(response)
                if 300 <= response.getcode() < 400:
                    raise urllib.error.HTTPError(
                        current_url,
                        response.getcode(),
                        "Unexpected redirect",
                        response.headers,
                        None,
                    )
                total = 0
                fd = os.open(dest_path, os.O_WRONLY | os.O_CREAT | os.O_EXCL, 0o600)
                try:
                    with os.fdopen(fd, "wb") as out_file:
                        while True:
                            chunk = response.read(8192)
                            if not chunk:
                                break
                            total += len(chunk)
                            if total > _MAX_DOWNLOAD_BYTES:
                                raise ValueError("Download exceeds maximum allowed size.")
                            out_file.write(chunk)
                finally:
                    # fd is closed by fdopen context; no extra close needed
                    pass
                return
        except urllib.error.HTTPError as e:
            if e.code in (301, 302, 303, 307, 308):
                location = e.headers.get("Location")
                if not location:
                    raise ValueError("Redirect response missing Location header.") from e
                current_url = urllib.parse.urljoin(current_url, location)
                continue
            raise
    raise ValueError("Too many redirects while downloading.")


def _check_tar_member(member: tarfile.TarInfo, extract_dir: str) -> None:
    member_path = os.path.join(extract_dir, member.name)
    if not _is_safe_path(extract_dir, member_path):
        raise RuntimeError("Archive contains unsafe paths.")
    if member.islnk() or member.issym():
        raise RuntimeError("Archive contains disallowed symlink entries.")
    final_path = os.path.realpath(member_path)
    if not _is_safe_path(extract_dir, final_path):
        raise RuntimeError("Symlink resolves outside extraction directory.")


def _check_zip_member(zinfo: zipfile.ZipInfo, extract_dir: str) -> None:
    member_path = os.path.join(extract_dir, zinfo.filename)
    if not _is_safe_path(extract_dir, member_path):
        raise RuntimeError("Archive contains unsafe paths.")
    if (zinfo.external_attr >> 16) & stat.S_IFMT() == stat.S_IFLNK:
        raise RuntimeError("Archive contains disallowed symlink entries.")
    final_path = os.path.realpath(member_path)
    if not _is_safe_path(extract_dir, final_path):
        raise RuntimeError("Symlink resolves outside extraction directory.")


def _secure_write(path: str, data_iter) -> None:
    os.makedirs(os.path.dirname(path), mode=0o750, exist_ok=True)
    fd = os.open(path, os.O_WRONLY | os.O_CREAT | os.O_EXCL, 0o600)
    try:
        with os.fdopen(fd, "wb") as dst:
            for chunk in data_iter:
                dst.write(chunk)
    finally:
        # fd closed by fdopen; nothing else
        pass
    st = os.lstat(path)
    if st.st_nlink != 1:
        raise RuntimeError("Hard link detected in extracted file.")
    if not _is_safe_path(os.path.dirname(path), os.path.realpath(path)):
        raise RuntimeError("Extracted file resolved outside target directory.")


def _extract_archive(archive_path: str, extract_dir: str) -> None:
    lower_name = archive_path.lower()
    extracted_files = 0
    total_uncompressed = 0

    if lower_name.endswith(".zip"):
        with zipfile.ZipFile(archive_path, "r") as zf:
            for zinfo in zf.infolist():
                _check_zip_member(zinfo, extract_dir)
                extracted_files += 1
                if extracted_files > _MAX_EXTRACTED_FILES:
                    raise RuntimeError("Archive contains too many files.")
                target_path = os.path.join(extract_dir, zinfo.filename)
                if zinfo.is_dir():
                    os.makedirs(target_path, mode=0o750, exist_ok=True)
                    continue
                with zf.open(zinfo, "r") as src:
                    def chunks():
                        while True:
                            data = src.read(8192)
                            if not data:
                                break
                            nonlocal total_uncompressed
                            total_uncompressed += len(data)
                            if total_uncompressed > _MAX_UNCOMPRESSED_SIZE:
                                raise RuntimeError("Archive exceeds allowed uncompressed size.")
                            yield data
                    _secure_write(target_path, chunks())
    elif lower_name.endswith((".tar.gz", ".tgz")):
        with tarfile.open(archive_path, "r:gz") as tf:
            for member in tf.getmembers():
                _check_tar_member(member, extract_dir)
                extracted_files += 1
                if extracted_files > _MAX_EXTRACTED_FILES:
                    raise RuntimeError("Archive contains too many files.")
                member_path = os.path.join(extract_dir, member.name)
                if member.isdir():
                    os.makedirs(member_path, mode=0o750, exist_ok=True)
                    continue
                if member.isreg():
                    src_f = tf.extractfile(member)
                    if src_f is None:
                        raise RuntimeError("Failed to extract file from tar archive.")
                    def chunks():
                        while True:
                            data = src_f.read(8192)
                            if not data:
                                break
                            nonlocal total_uncompressed
                            total_uncompressed += len(data)
                            if total_uncompressed > _MAX_UNCOMPRESSED_SIZE:
                                raise RuntimeError("Archive exceeds allowed uncompressed size.")
                            yield data
                    _secure_write(member_path, chunks())
                else:
                    raise RuntimeError("Unsupported tar entry type.")
    else:
        raise ValueError("Unsupported archive format.")


def _drop_privileges():
    if os.name != "posix":
        return
    if os.getuid() != 0:
        return
    try:
        import pwd
        import grp
        nobody_uid = pwd.getpwnam("nobody").pw_uid
        nobody_gid = grp.getgrnam("nogroup").gr_gid
        os.setgid(nobody_gid)
        os.setuid(nobody_uid)
    except Exception as e:
        raise RuntimeError(f"Unable to drop privileges: {e}") from e


def _run_configuration(script_path: str, working_dir: str) -> None:
    if not os.path.isfile(script_path):
        raise FileNotFoundError("Configuration script not found.")
    st = os.stat(script_path)
    forbidden_bits = stat.S_IWOTH | stat.S_ISUID | stat.S_ISGID
    if st.st_mode & forbidden_bits:
        raise PermissionError("Configuration script must not be world-writable or setuid/setgid.")
    cmd = [sys.executable, script_path] if script_path.endswith(".py") else [script_path]
    result = subprocess.run(
        cmd,
        cwd=working_dir,
        check=False,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        preexec_fn=_drop_privileges,
        text=True,
        close_fds=True,
        env={"PATH": os.getenv("PATH", "")},
    )
    if result.returncode != 0:
        logger.error(f"Configuration script failed: {result.stderr}")
        raise RuntimeError("Configuration script execution failed.")
    else:
        logger.info(f"Configuration script output: {result.stdout}")


def _install_contents(source_dir: str, target_dir: str) -> None:
    if not os.path.isdir(source_dir):
        raise NotADirectoryError("Source directory does not exist.")
    os.makedirs(target_dir, mode=0o750, exist_ok=True)
    for root, dirs, files in os.walk(source_dir):
        rel_path = os.path.relpath(root, source_dir)
        dest_root = os.path.join(target_dir, rel_path) if rel_path != "." else target_dir
        os.makedirs(dest_root, mode=0o750, exist_ok=True)
        for d in dirs:
            dest_path = os.path.join(dest_root, d)
            os.makedirs(dest_path, mode=0o750, exist_ok=True)
        for f in files:
            src_path = os.path.join(root, f)
            dest_path = os.path.join(dest_root, f)
            shutil.copy2(src_path, dest_path)
            os.chmod(dest_path, 0o640)


def _validate_config_script_name(name: str) -> str:
    base = os.path.basename(name)
    if base != name or os.path.sep in name:
        raise ValueError("Invalid configuration script name.")
    if not _SCRIPT_NAME_REGEX.fullmatch(base):
        raise ValueError("Configuration script name contains illegal characters.")
    return base


def _validate_target_dir(target_dir: str) -> str:
    abs_target = os.path.abspath(target_dir)
    safe_root = os.path.abspath(SAFE_INSTALL_ROOT)
    if not abs_target.startswith(safe_root + os.sep):
        raise ValueError(f"Target directory must be inside {SAFE_INSTALL_ROOT}")
    if os.path.islink(abs_target):
        raise ValueError("Target directory must not be a symlink.")
    return abs_target


def download_and_install(
    url: str,
    target_dir: str,
    config_script: str = "configure.sh",
    expected_hash: Optional[str] = None,
) -> None:
    if expected_hash is None:
        raise ValueError("Integrity hash (expected_hash) is required.")
    try:
        _validate_url(url)
        config_script = _validate_config_script_name(config_script)
        target_dir = _validate_target_dir(target_dir)

        with tempfile.TemporaryDirectory() as tmp_dir:
            archive_path = os.path.join(tmp_dir, "downloaded_archive")
            _download_to_file(url, archive_path)

            sha256 = hashlib.sha256()
            with open(archive_path, "rb") as f:
                for chunk in iter(lambda: f.read(8192), b""):
                    sha256.update(chunk)
            if sha256.hexdigest().lower() != expected_hash.lower():
                raise RuntimeError("Downloaded archive failed integrity check.")

            extract_dir = os.path.join(tmp_dir, "extracted")
            os.makedirs(extract_dir, mode=0o750, exist_ok=True)
            _extract_archive(archive_path, extract_dir)

            script_path = os.path.join(extract_dir, config_script)
            if not os.path.isfile(script_path):
                raise FileNotFoundError("Specified configuration script not found in archive.")
            _run_configuration(script_path, extract_dir)

            _install_contents(extract_dir, target_dir)

    except Exception as exc:
        raise RuntimeError("Failed to complete installation.") from exc

