# Strictly safe binaries â utilities that cannot invoke external commands.
ALLOWED_COMMANDS = {"printf"}  # extend only with utilities proven safe

# Mapping of commands to arguments that would permit execution of external code.
PROHIBITED_ARGS = {
    "awk": {"-e", "-f", "--eval"},
    "grep": {"-e", "-f"},
    "cat": set(),
    "ls": set(),
    "printf": set(),
    # "sed" removed from whitelist; not needed.
    "echo": set(),
}

