TRUSTED_PATH = "/usr/bin:/bin"
TRUSTED_DIRS = tuple(os.path.abspath(p) for p in TRUSTED_PATH.split(":"))


class SecureCommandError(RuntimeError):
    """Exception raised for errors during secure command execution."""


def _drop_privileges() -> None:
    """Drop privileges to the 'nobody' user if running as root."""
    if os.geteuid() != 0:
        return
