    if not cmd_list:
        raise ValueError("Command must contain at least one argument.")

    for arg in cmd_list:
        if not isinstance(arg, str):
            raise TypeError("All command arguments must be strings.")
        if "�" in arg:
            raise ValueError("Command arguments must not contain null bytes.")
        if not arg:
            raise ValueError("Command arguments must not be empty strings.")

    executable = cmd_list[0]
    exe_name = os.path.basename(executable)

    if exe_name not in ALLOWED_COMMANDS:
        raise SecureCommandError(f"Executable '{exe_name}' is not permitted.")

    prohibited = PROHIBITED_ARGS.get(exe_name, set())
    for arg in cmd_list[1:]:
