import argparse
import base64
import json
import logging
import os
import re
import stat
import subprocess
import sys
import shutil
from getpass import getpass

# Optional cryptography import for encryption support
try:
    from cryptography.fernet import Fernet, InvalidToken
    from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC
    from cryptography.hazmat.primitives import hashes
    from cryptography.hazmat.backends import default_backend
    CRYPTO_AVAILABLE = True
except Exception:  # pragma: no cover
    CRYPTO_AVAILABLE = False

# Configure logging
logging.basicConfig(
    level=logging.ERROR,
    format='%(asctime)s %(levelname)s: %(message)s',
    handlers=[logging.StreamHandler(sys.stderr)]
)

ALLOWED_STATES = {"on", "off", "reset", "status"}
USERNAME_PATTERN = re.compile(r'^[A-Za-z0-9._-]{1,32}$')
BASE_CRED_DIR = os.path.abspath(os.path.expanduser("~/.ipmi"))
DEFAULT_SALT = b'ipmi_tool_salt'  # fallback static salt for backward compatibility
ALLOWED_IPMITOOL_DIRS = (
    "/usr/sbin",
    "/usr/bin",
    "/sbin",
    "/bin",
)


def ensure_cred_dir():
    os.makedirs(BASE_CRED_DIR, mode=0o700, exist_ok=True)
    st = os.stat(BASE_CRED_DIR)
    if (st.st_mode & 0o777) != 0o700 or st.st_uid != os.getuid():
        logging.error("Credentials directory %s must have mode 0700 and be owned by the current user.", BASE_CRED_DIR)
        sys.exit(1)


def mask_password(pw: str) -> str:
    return '*' * len(pw) if pw else ''


def validate_ip(ip_str: str) -> str:
    try:
        import ipaddress
        ipaddress.ip_address(ip_str)
        return ip_str
    except Exception:
        raise argparse.ArgumentTypeError(f"Invalid IP address: {ip_str}")


def validate_username(username: str) -> str:
    if not USERNAME_PATTERN.fullmatch(username):
        raise argparse.ArgumentTypeError("Username contains invalid characters.")
    if len(username) > 32:
        raise argparse.ArgumentTypeError("Username exceeds maximum length of 32 characters.")
    return username


def validate_state(state: str) -> str:
    if state.lower() not in ALLOWED_STATES:
        raise argparse.ArgumentTypeError(
            f"Power state must be one of {', '.join(ALLOWED_STATES)}."
        )
    return state.lower()


def is_path_inside_base(path: str, base: str) -> bool:
    real_path = os.path.realpath(path)
    real_base = os.path.realpath(base)
    return real_path == real_base or real_path.startswith(real_base + os.sep)


def is_secure_file(path: str) -> bool:
    try:
        st = os.stat(path)
        if not stat.S_ISREG(st.st_mode):
            return False
        if st.st_uid != os.getuid():
            return False
        if (st.st_mode & 0o777) > 0o600:
            return False
        return True
    except OSError:
        return False


def get_fernet_from_passphrase(passphrase: str, salt: bytes) -> Fernet:
    if not CRYPTO_AVAILABLE:
        raise RuntimeError("Cryptography library is not available for encryption.")
    kdf = PBKDF2HMAC(
        algorithm=hashes.SHA256(),
        length=32,
        salt=salt,
        iterations=100_000,
        backend=default_backend()
    )
    key = base64.urlsafe_b64encode(kdf.derive(passphrase.encode()))
    return Fernet(key)


def decrypt_password(enc: str, fernet: Fernet) -> str:
    try:
        decrypted = fernet.decrypt(enc.encode())
        return decrypted.decode()
    except InvalidToken as exc:
        raise InvalidToken("Failed to decrypt password.") from exc


def load_credentials_file(path: str, fernet: Fernet | None) -> dict:
    if not os.path.isfile(path):
        logging.error("Credentials file not found.")
        return {}
    if not is_secure_file(path):
        logging.error("Credentials file permissions are too permissive (must be mode 0600, owned by you, regular file).")
        return {}
    try:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
            if not isinstance(data, dict):
                logging.error("Invalid credentials file format.")
                return {}
            # Expect optional topâlevel "_salt" field (base64)
            salt = DEFAULT_SALT
            if "_salt" in data:
                try:
                    salt = base64.urlsafe_b64decode(data["_salt"])
                except Exception:
                    logging.error("Invalid salt encoding in credentials file.")
                    return {}
                # If a fernet is needed, recreate it with this salt and env passphrase
                if fernet is None:
                    passphrase = os.getenv("IPMI_KEY_PASSPHRASE")
                    if not passphrase:
                        logging.error("Encrypted credentials require IPMI_KEY_PASSPHRASE environment variable.")
                        return {}
                    fernet = get_fernet_from_passphrase(passphrase, salt)

            if fernet:
                for ip_cfg in data.values():
                    if not isinstance(ip_cfg, dict):
                        continue
                    pwd = ip_cfg.get("password")
                    if isinstance(pwd, str):
                        try:
                            ip_cfg["password"] = decrypt_password(pwd, fernet)
                        except InvalidToken:
                            logging.error("Failed to decrypt password for IP %s.", ip_cfg.get("ip", "unknown"))
                            return {}
            return data
    except Exception:
        logging.error("Failed to read credentials file.")
        return {}


def resolve_ipmitool_path() -> str:
    binary = shutil.which("ipmitool")
    if not binary:
        logging.error("ipmitool not found on this system.")
        sys.exit(1)
    if not any(os.path.commonpath([binary, d]) == d for d in ALLOWED_IPMITOOL_DIRS):
        logging.error("ipmitool located at %s is not in an allowed directory.", binary)
        sys.exit(1)
    return binary


def build_command(ip: str, user: str, state: str) -> list:
    return [
        resolve_ipmitool_path(),
        "-I", "lanplus",
        "-H", ip,
        "-U", user,
        "-f", "-",
        "chassis", "power", state
    ]


def zero_bytearray(barr: bytearray):
    for i in range(len(barr)):
        barr[i] = 0


def main() -> None:
    ensure_cred_dir()
    parser = argparse.ArgumentParser(description="Remote IPMI power control")
    parser.add_argument("--ip", required=True, type=validate_ip, help="Target device IP address")
    parser.add_argument("--user", help="Username for IPMI")
    parser.add_argument("--password", help="Password for IPMI (will prompt if omitted)")
    parser.add_argument(
        "--state",
        required=True,
        type=validate_state,
        help="Desired power state (on, off, reset, status)",
    )
    parser.add_argument(
        "--cred-file",
        help="Path to JSON file with stored credentials",
    )
    args = parser.parse_args()

    fernet = None
    # Decryption key will be obtained lazily from env if needed

    credentials = {}
    if args.cred_file:
        if not is_path_inside_base(args.cred_file, BASE_CRED_DIR):
            logging.error("Credentials file path must be inside %s", BASE_CRED_DIR)
            sys.exit(1)
        credentials = load_credentials_file(args.cred_file, fernet)

    # Resolve credentials hierarchy: command line > cred file > interactive prompt
    username = args.user
    password = args.password

    if not username and args.ip in credentials:
        username = credentials[args.ip].get("user")
    if not password and args.ip in credentials:
        password = credentials[args.ip].get("password")

    if not username:
        logging.error("Username is required.")
        sys.exit(1)

    try:
        username = validate_username(username)
    except argparse.ArgumentTypeError as e:
        logging.error(str(e))
        sys.exit(1)

    if not password:
        try:
            password = getpass(prompt="IPMI Password: ")
        except Exception:
            logging.error("Failed to read password.")
            sys.exit(1)

    command = build_command(args.ip, username, args.state)

    print("Executing command:", " ".join(command))

    pwd_bytes = bytearray(password.encode('utf-8'))
    password = None  # remove immutable reference

    try:
        proc = subprocess.Popen(
            command,
            stdin=subprocess.PIPE,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=False,
            close_fds=True,
            start_new_session=True,
        )
        stdout, stderr = proc.communicate(input=pwd_bytes + b'
')
        returncode = proc.returncode
    except FileNotFoundError:
        logging.error("ipmitool not found on this system.")
        sys.exit(1)
    except Exception:
        logging.error("An unexpected error occurred while executing the command.")
        sys.exit(1)
    finally:
        zero_bytearray(pwd_bytes)
        del pwd_bytes

    if returncode != 0:
        logging.error("Command failed with exit code %s.", returncode)
        if stderr:
            logging.error("Error output: %s", stderr.decode(errors='ignore').strip())
        sys.exit(1)

    if stdout:
        print(stdout.decode(errors='ignore').strip())


if __name__ == "__main__":
    main()

