import json
import re
import urllib.parse
from pathlib import Path
from typing import Any, Dict, Iterator, Optional, Union

import boto3
from botocore.config import Config
from botocore.exceptions import BotoCoreError, ClientError


class SecureInputReaderError(Exception):
    """Base exception for SecureInputReader."""


class InputNotFoundError(SecureInputReaderError):
    """Raised when the requested input cannot be found."""


class ValidationError(SecureInputReaderError):
    """Raised when validation of input parameters fails."""


class SecureInputReader:
    _FILE = "file"
    _BUCKET = "bucket"
    _BUCKET_NAME_REGEX = re.compile(r"^[a-z0-9.\-]{3,255}$")
    _BUCKET_KEY_REGEX = re.compile(r"^[^\s]{1,1024}$")
    _DEFAULT_ROOT = Path.cwd().resolve()  # retained for backward compatibility

    def __init__(
        self,
        source_type: str,
        location: str,
        fail_on_missing: bool = False,
        *,
        aws_region: Optional[str] = None,
        aws_profile: Optional[str] = None,
        allowed_root: Optional[Path] = None,
    ) -> None:
        self.source_type = source_type.lower()
        if self.source_type not in (self._FILE, self._BUCKET):
            raise ValidationError(f"Invalid source_type: {source_type}")

        self.fail_on_missing = bool(fail_on_missing)
        self._allowed_root = (allowed_root or self._DEFAULT_ROOT).resolve()

        if self.source_type == self._FILE:
            self.file_path = self._validate_and_resolve_path(location)
            self.s3_client = None
            self.bucket_name = None
            self.object_key = None
        else:
            bucket, key = self._parse_bucket_location(location)
            self.bucket_name = bucket
            self.object_key = key
            self.file_path = None
            self.s3_client = self._create_s3_client(aws_region, aws_profile)

    def _validate_and_resolve_path(self, path_str: str) -> Path:
        path = Path(path_str).expanduser().resolve()
        if not path.is_absolute():
            raise ValidationError("File path must be absolute after resolution.")
        try:
            path.relative_to(self._allowed_root)
        except ValueError:
            raise ValidationError(
                f"File path must be within allowed directory: {self._allowed_root}"
            )
        if not path.is_file():
            raise ValidationError(f"Path is not a file: {path}")
        return path

    @classmethod
    def _parse_bucket_location(cls, location: str) -> tuple[str, str]:
        if "/" not in location:
            raise ValidationError("Bucket location must be in the form 'bucket/key'.")
        bucket, key = location.split("/", 1)
        if not bucket or not key:
            raise ValidationError("Bucket name and key must be nonâempty.")
        if not cls._BUCKET_NAME_REGEX.fullmatch(bucket):
            raise ValidationError(f"Invalid bucket name: {bucket}")
        if "\" in key:
            raise ValidationError("Bucket key must not contain backslashes.")
        if not cls._BUCKET_KEY_REGEX.fullmatch(key):
            raise ValidationError(f"Invalid bucket key: {key}")

        # Decode potential URLâencoded characters before traversal checks
        decoded_key = urllib.parse.unquote(key)

        if ".." in decoded_key or decoded_key.startswith("/") or decoded_key.startswith("\"):
            raise ValidationError("Bucket key must not contain path traversal sequences.")
        return bucket, key

    @staticmethod
    def _create_s3_client(region: Optional[str], profile: Optional[str]) -> Any:
        session_kwargs: Dict[str, Any] = {}
        if profile:
            session_kwargs["profile_name"] = profile
        session = boto3.Session(**session_kwargs)
        config = Config(
            retries={"max_attempts": 3, "mode": "standard"},
            read_timeout=30,
            connect_timeout=30,
        )
        client_kwargs: Dict[str, Any] = {"config": config, "verify": True}
        if region:
            client_kwargs["region_name"] = region
        return session.client("s3", **client_kwargs)

    @staticmethod
    def _extract_error_code(exc: Exception) -> Optional[str]:
        if isinstance(exc, ClientError):
            return exc.response.get("Error", {}).get("Code")
        resp = getattr(exc, "response", None)
        if isinstance(resp, dict):
            return resp.get("Error", {}).get("Code")
        return None

    def __iter__(self) -> Iterator[bytes]:
        if self.source_type == self._FILE:
            return self._file_iterator()
        return self._bucket_iterator()

    def _file_iterator(self) -> Iterator[bytes]:
        try:
            with self.file_path.open("rb") as f:
                for chunk in iter(lambda: f.read(8192), b""):
                    yield chunk
        except FileNotFoundError:
            if self.fail_on_missing:
                raise InputNotFoundError(f"File not found: {self.file_path}") from None
        except OSError as exc:
            raise SecureInputReaderError("Error reading file.") from exc

    def _bucket_iterator(self) -> Iterator[bytes]:
        try:
            response = self.s3_client.get_object(
                Bucket=self.bucket_name, Key=self.object_key
            )
            body = response["Body"]
            for chunk in iter(lambda: body.read(8192), b""):
                yield chunk
        except (ClientError, BotoCoreError) as exc:
            error_code = self._extract_error_code(exc)
            if error_code in ("NoSuchKey", "NoSuchBucket"):
                if self.fail_on_missing:
                    raise InputNotFoundError(
                        f"S3 object not found: s3://{self.bucket_name}/{self.object_key}"
                    ) from None
            raise SecureInputReaderError("Error accessing S3 object.") from exc

    @classmethod
    def from_json(cls, json_str: str) -> "SecureInputReader":
        try:
            data = json.loads(json_str)
        except json.JSONDecodeError as exc:
            raise ValidationError("Invalid JSON.") from exc

        if not isinstance(data, dict):
            raise ValidationError("JSON must represent an object.")

        required_keys = {"source_type", "location"}
        missing = required_keys - data.keys()
        if missing:
            raise ValidationError(f"Missing required fields: {', '.join(missing)}")

        return cls(
            source_type=data["source_type"],
            location=data["location"],
