def safe_write_list(file_path, items):
    parent = os.path.dirname(file_path)

    try:
        os.makedirs(parent, mode=0o700, exist_ok=True)
    except OSError:
        _error('Unable to create output directory')

    try:
        parent_fd = os.open(
            parent,
            os.O_RDONLY | os.O_DIRECTORY | getattr(os, 'O_NOFOLLOW', 0)
        )
    except OSError:
        _error('Output directory validation failed (open)')

    try:
        os.fchmod(parent_fd, 0o700)
    except OSError:
        os.close(parent_fd)
        _error('Failed to set permissions on output directory')

    flags = (
        os.O_CREAT
        | os.O_WRONLY
        | os.O_TRUNC
        | getattr(os, 'O_NOFOLLOW', 0)
        | getattr(os, 'O_EXCL', 0)
    )
    mode = 0o600

    try:
        fd = os.openat(parent_fd, os.path.basename(file_path), flags, mode)
    except AttributeError:
        fd = os.open(file_path, flags, mode)
    except OSError:
        os.close(parent_fd)
        _error('Unable to open output file')

    os.close(parent_fd)

    try:
        with os.fdopen(fd, 'w', encoding='utf-8') as f:
            for item in items:
                safe_item = item.replace('
', '\n').replace('', '\r')
                f.write(safe_item + '
')
    except OSError:
        _error('Unable to write to output file')

def collect_python_files(root_path):
    try:
        root_fd = os.open(root_path, os.O_RDONLY | os.O_DIRECTORY)
    except OSError:
        _error('Cannot open directory')

    count = 0
    try:
        for dirpath, dirnames, filenames in os.fwalk(root_fd):
            filtered = []
            for d in dirnames:
                if d.startswith('.'):
                    continue
                full = os.path.join(dirpath, d)
                try:
                    if os.path.islink(full):
                        continue
                except OSError:
                    continue
                filtered.append(d)
            dirnames[:] = filtered

            for name in filenames:
                if not name.endswith('.py'):
                    continue
                full_path = os.path.join(dirpath, name)
                try:
                    fd = os.open(full_path, os.O_RDONLY | getattr(os, 'O_NOFOLLOW', 0))
                    st = os.fstat(fd)
                    os.close(fd)
