    level=logging.WARNING,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler()],
)
logger = logging.getLogger(__name__)

# Allow typical credential characters, max 128 chars
_CRED_PATTERN = re.compile(r"^[\w!@#$%^&*()\-\+=]{1,128}$")
# Hostname must contain only DNSâcompatible characters
_HOSTNAME_RE = re.compile(r"^[A-Za-z0-9.-]+$")

_ALERT_REGEX = re.compile(
    r'<div[^>]*class=["'][^"']*alert[^"']*["']', re.IGNORECASE
)


def _validate_input(value: str, name: str) -> str:
    if not isinstance(value, str):
        raise ValueError(f"{name} must be a string")
    if not value:
        raise ValueError(f"{name} cannot be empty")
    if not _CRED_PATTERN.fullmatch(value):
        raise ValueError(f"{name} contains illegal characters")
    return value


def _validate_base_url(url: str) -> str:
    """
    Validate base URL and return a cleaned URL in the form ``scheme://host``.
    Reject URLs with user info, path, query, fragment, or any private IPs.
    The hostname must consist only of DNSâcompatible characters.
    """
    if not isinstance(url, str):
        raise ValueError("base_url must be a string")
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme not in ("http", "https"):
        raise ValueError("base_url must start with http:// or https://")
    if not parsed.netloc:
        raise ValueError("base_url must contain a host")
    if parsed.username or parsed.password:
        raise ValueError("base_url must not contain user info")
    if any([parsed.path, parsed.params, parsed.query, parsed.fragment]):
        raise ValueError(
            "base_url must not contain path, query, params, or fragment"
        )

    host = parsed.hostname
    if host is None:
        raise ValueError("Unable to extract hostname from base_url")
    if not _HOSTNAME_RE.fullmatch(host):
        raise ValueError("base_url contains an invalid hostname")

    try:
        addr_info = socket.getaddrinfo(host, None, proto=socket.IPPROTO_TCP)
    except socket.gaierror as exc:
        raise ValueError(
            f"Unable to resolve host '{host}': {exc}"
        ) from exc

    public_found = False
    for family, _, _, _, sockaddr in addr_info:
        ip_str = sockaddr[0]
        try:
            ip_obj = ipaddress.ip_address(ip_str)
        except ValueError:
            continue
        if (
            ip_obj.is_private
            or ip_obj.is_loopback
            or ip_obj.is_link_local
            or ip_obj.is_reserved
            or ip_obj.is_multicast
            or ip_obj.is_unspecified
        ):
            continue
        public_found = True
        break

    if not public_found:
        raise ValueError(
            "base_url does not resolve to any public IP address"
        )

    cleaned_url = f"{parsed.scheme}://{host}"
    return cleaned_url.rstrip("/")


def _safe_post(
    session: Session,
    url: str,
    data: Dict[str, Any],
    verify: Any,
) -> Optional[Response]:
    try:
        resp = session.post(
            url,
            data=data,
            timeout=10,
            verify=verify,
            allow_redirects=False,
        )
        return resp
    except requests.RequestException as exc:
        logger.error(
            "Network error during POST to %s: %s", url, type(exc).__name__
        )
        logger.debug("Exception detail: %s", exc)
        return None


def _safe_get(
    session: Session,
    url: str,
    verify: Any,
) -> Optional[Response]:
    try:
        resp = session.get(
            url,
            timeout=10,
            verify=verify,
            allow_redirects=False,
        )
        return resp
    except requests.RequestException as exc:
        logger.error(
            "Network error during GET to %s: %s", url, type(exc).__name__
        )
        logger.debug("Exception detail: %s", exc)
        return None


def test_login(
    base_url: str,
    username: str,
    password: str,
    ca_bundle: Optional[str] = None,
) -> bool:
    try:
        cleaned_base = _validate_base_url(base_url)
    except ValueError as ve:
        logger.error("Base URL validation failed: %s", ve)
        return False

    try:
        username = _validate_input(username, "username")
        password = _validate_input(password, "password")
    except ValueError as ve:
        logger.error("Input validation failed: %s", ve)
        return False

    login_url = f"{cleaned_base}/login"
    logout_url = f"{cleaned_base}/logout"

    verify_opt = ca_bundle if ca_bundle is not None else True

    with requests.Session() as session:
        login_resp = _safe_post(
            session,
            login_url,
            data={"username": username, "password": password},
            verify=verify_opt,
        )
        if login_resp is None:
            return False
        if login_resp.status_code not in (200, 302):
            logger.info("Login failed with status %s", login_resp.status_code)
            return False
        if login_resp.is_redirect:
            logger.info("Unexpected redirect on login response")
            return False

        logout_resp = _safe_get(session, logout_url, verify=verify_opt)
        if logout_resp is None:
            return False
        if logout_resp.status_code != 200:
            logger.info("Logout failed with status %s", logout_resp.status_code)
            return False
        if logout_resp.is_redirect:
            logger.info("Unexpected redirect on logout response")
            return False

        if not _ALERT_REGEX.search(logout_resp.text):
            logger.info("Alert message not found on logout page")
            return False

    return True

import os
import logging
import shutil
from pathlib import Path
from typing import Union

# Configuration
ALLOWED_ROOT = Path("/var/app/data").resolve()  # Adjust as needed
MAX_COPY_SIZE = 1 * 1024 * 1024 * 1024  # 1â¯GiB
MAX_DEPTH = 20

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


def _sanitize_path(p: Union[str, Path], *, must_exist: bool = False) -> Path:
    if not isinstance(p, (str, Path)):
        raise TypeError("Path must be a string or Path object")
    try:
        path_obj = Path(p).expanduser().resolve(strict=must_exist)
    except Exception as e:
        raise ValueError("Invalid path") from e
    return path_obj


def _is_within_allowed_root(p: Path) -> bool:
    try:
        return p.is_relative_to(ALLOWED_ROOT)
    except AttributeError:  # Python <3.9 fallback
        return str(p).startswith(str(ALLOWED_ROOT) + os.sep)


def _validate_no_dash(p: Path) -> None:
    for part in p.parts:
        if part.startswith("-"):
            raise ValueError(f"Path component '{part}' starts with a dash '-' which is not allowed")


def _copy_tree(src: Path, dst: Path, current_depth: int = 0, total_copied: int = 0) -> int:
    if current_depth > MAX_DEPTH:
        raise ValueError("Directory depth exceeds allowed limit")
    try:
        entries = list(os.scandir(src))
    except OSError as e:
        raise ValueError(f"Unable to read directory '{src}': {e}") from e

    for entry in entries:
        entry_path = Path(entry.path)
        dest_path = dst / entry.name

        if entry.is_symlink():
            raise ValueError(f"Symlink detected in source tree: {entry_path}")

        if entry.is_dir(follow_symlinks=False):
            dest_path.mkdir(parents=True, exist_ok=True)
            total_copied = _copy_tree(entry_path, dest_path, current_depth + 1, total_copied)
        elif entry.is_file(follow_symlinks=False):
            try:
                size = entry.stat().st_size
            except OSError:
                continue
            if total_copied + size > MAX_COPY_SIZE:
                raise ValueError("Total size exceeds allowed limit")
            shutil.copyfile(entry_path, dest_path)
            total_copied += size
        else:
            # Skip other types (e.g., sockets, FIFOs)
            continue
    return total_copied


def copy_directory(source, destination):
    """
    Safely copy an entire directory from source to destination.
    Performs strict path validation, size/depth limits, and copies files
    without preserving ownership or executing external commands.
    """
    try:
        src_path = _sanitize_path(source, must_exist=True)
        dst_path = _sanitize_path(destination, must_exist=False)

        _validate_no_dash(src_path)
        _validate_no_dash(dst_path)

        if not _is_within_allowed_root(src_path):
            logger.error("Source path is outside the permitted directory")
            return
        if not _is_within_allowed_root(dst_path):
            logger.error("Destination path is outside the permitted directory")
            return

        if not src_path.is_dir():
            logger.error("Source is not a directory")
            return

        # Resolve destination (may not exist yet) and re-check root
        resolved_dst = dst_path.resolve(strict=False)
        if not _is_within_allowed_root(resolved_dst):
            logger.error("Resolved destination path is outside the permitted directory")
            return

        resolved_dst.mkdir(parents=True, exist_ok=True)

        logger.info("Starting safe copy operation")
        try:
            _copy_tree(src_path, resolved_dst)
        except ValueError as ve:
            logger.error(str(ve))
            return

        logger.info("Copy operation completed successfully")
    except Exception as exc:
        logger.error("An unexpected error occurred during copy operation")
        logger.debug("Exception details:", exc_info=exc)

