                sha256 = entry.get("sha256")
                if rel_path and sha256:
                    abs_path = os.path.realpath(os.path.join(ALLOWED_BASE_DIR, rel_path))
                    _TRUSTED_MODULE_HASHES[abs_path] = sha256.lower()
    except Exception as exc:
        raise RuntimeError(f"Failed to load module manifest: {exc}") from exc

def _is_path_within_allowed(abs_path: str) -> bool:
    """Return True if abs_path is inside ALLOWED_BASE_DIR."""
    try:
        common = os.path.commonpath([abs_path, ALLOWED_BASE_DIR])
        return common == ALLOWED_BASE_DIR
    except ValueError:
        return False

def _compute_sha256(fd: int) -> str:
    """Compute SHAâ256 of file referenced by fd without following symlinks."""
    sha256 = hashlib.sha256()
    os.lseek(fd, 0, os.SEEK_SET)
    while True:
        chunk = os.read(fd, 8192)
        if not chunk:
            break
        sha256.update(chunk)
    return sha256.hexdigest()

def _validate_file(fd: int, abs_path: str) -> None:
    """Validate that the opened descriptor points to a regular, sizeâlimited, nonâhardâlinked file inside the allowed dir."""
    st = os.fstat(fd)
    if not stat.S_ISREG(st.st_mode):
        raise ValueError("Requested path is not a regular file.")
    if st.st_nlink != 1:
        raise ValueError("Hard links are not allowed.")
    if st.st_size > MAX_MODULE_SIZE:
        raise ValueError("File size exceeds the permitted limit.")
    fd_path = os.readlink(f"/proc/self/fd/{fd}")
    fd_abs_path = os.path.abspath(os.path.realpath(fd_path))
    if not _is_path_within_allowed(fd_abs_path):
        raise ValueError("Access to the requested file is not allowed after opening.")

def _verify_trust(abs_path: str, fd: int) -> None:
    """Ensure the file matches a trusted hash if a manifest is present."""
    if not _TRUSTED_MODULE_HASHES:
        raise ValueError("No trusted module manifest configured.")
    trusted_hash = _TRUSTED_MODULE_HASHES.get(abs_path)
    if not trusted_hash:
        raise ValueError("File is not listed in the trusted manifest.")
    actual_hash = _compute_sha256(fd)
    if actual_hash.lower() != trusted_hash:
        raise ValueError("File integrity check failed.")

def load_python_module(file_path: str, module_name: Optional[str] = None) -> ModuleType:
    """
    Securely load a trusted Python module from a given file path.

    Args:
        file_path: Path to the Python source file.
        module_name: Optional explicit name for the module.

    Returns:
        The loaded module object.

    Raises:
        ValueError: If validation fails or the module cannot be loaded.
    """
    if not isinstance(file_path, str):
        raise ValueError("Invalid file path type.")

    abs_path = os.path.abspath(os.path.realpath(file_path))

    if not _is_path_within_allowed(abs_path):
        raise ValueError("Access to the requested file is not allowed.")

    if not abs_path.lower().endswith(".py"):
        raise ValueError("Only Python (.py) files are permitted.")

    try:
        fd = os.open(abs_path, os.O_RDONLY | os.O_NOFOLLOW)
    except OSError as exc:
        raise ValueError("Unable to open the requested file safely.") from exc

    try:
        _validate_file(fd, abs_path)
        _verify_trust(abs_path, fd)
    finally:
        os.close(fd)

    if module_name:
        if not MODULE_NAME_PATTERN.fullmatch(module_name):
            raise ValueError("Provided module name is invalid.")
        safe_name = module_name
    else:
        safe_name = os.path.splitext(os.path.basename(abs_path))[0]
        if not MODULE_NAME_PATTERN.fullmatch(safe_name):
            raise ValueError("Derived module name is invalid.")

    spec = importlib.util.spec_from_file_location(safe_name, abs_path)
    if spec is None or spec.loader is None:
        raise ValueError("Unable to construct module specification.")

    module = importlib.util.module_from_spec(spec)
    try:
        spec.loader.exec_module(module)  # type: ignore
    except Exception:
        logger.error("Failed to load module.")
        raise ValueError("Unable to load the requested module.") from None

    return module

import math

MAX_GB = 10_000  # Upper bound to prevent excessive memory usage


def gb_to_kib(gb: float) -> str:
    """Convert gigabytes to kibibytes and return a formatted string."""
    if isinstance(gb, bool):
        raise ValueError("Invalid size")
    try:
        value = float(gb)
    except (TypeError, ValueError):
        raise ValueError("Invalid size")
    if not math.isfinite(value) or value < 0:
        raise ValueError("Invalid size")
    if value > MAX_GB:
        raise ValueError("Invalid size")
    kib = int(value * 1024 * 1024)
    return f"{kib} KiB"

import os
import stat
import tarfile
import logging
import errno
from pathlib import Path

_logger = logging.getLogger(__name__)

MAX_TOTAL_SIZE = 10 * 1024**3       # 10â¯GiB total extraction limit
MAX_FILE_SIZE = 500 * 1024**2      # 500â¯MiB per file limit
MAX_MEMBER_COUNT = 100_000        # Maximum number of members to extract

# --------------------------------------------------------------------------- #
# Helper functions                                                          #
# --------------------------------------------------------------------------- #

def _is_safe_path(base_path: Path, target_path: Path) -> bool:
    """
    Verify that ``target_path`` is inside ``base_path`` without traversing symlinks
    and without using ``..`` components.
    """
    try:
        base_resolved = base_path.resolve(strict=True)
        target_resolved = target_path.resolve(strict=False)

        # must be a subâpath of base
        target_resolved.relative_to(base_resolved)

        # disallow any ``..`` components after the relative conversion
        rel = target_resolved.relative_to(base_resolved)
        if ".." in rel.parts:
            return False

        # reject any existing component that is a symlink (excluding the final
        # component which may not exist yet)
        for parent in (base_resolved, *target_resolved.parents):
            if parent.exists() and parent.is_symlink():
                return False
        return True
    except Exception:
        return False


def _validate_tarball(tar_path: Path) -> None:
    """Validate the tarball path and permissions."""
    if not tar_path.is_file():
        raise ValueError("Tarball must be an existing regular file")
    if tar_path.is_symlink():
        raise ValueError("Symlinks are not allowed for tarball")
    mode = tar_path.stat().st_mode
    if mode & (stat.S_IWOTH | stat.S_IWGRP):
        raise PermissionError("Tarball must not be world- or group-writable")
    name = tar_path.name.lower()
    if not (name.endswith('.tar') or name.endswith('.tar.gz') or name.endswith('.tgz')):
        raise ValueError("Unsupported tarball format; expected .tar, .tar.gz, or .tgz")


def _open_tarball_atomic(tar_path: Path):
    """Open tarball without following symlinks and validate its status atomically."""
    fd = os.open(tar_path, os.O_RDONLY | os.O_NOFOLLOW)
    try:
        st = os.fstat(fd)
        if not stat.S_ISREG(st.st_mode):
            raise ValueError("Tarball must be a regular file")
        if st.st_mode & (stat.S_IWOTH | stat.S_IWGRP):
            raise PermissionError("Tarball must not be world- or group-writable")
        return os.fdopen(fd, "rb")
    except Exception:
        os.close(fd)
        raise


def _ensure_destination(dest_dir: Path) -> None:
    """Create destination directory if needed and reject if it is a symlink or insecure."""
    try:
        st = dest_dir.lstat()
        if stat.S_ISLNK(st.st_mode):
            raise ValueError("Destination directory must not be a symlink")
        if not dest_dir.is_dir():
            raise ValueError("Destination exists and is not a directory")
        # Ensure existing directory is not group/other writable
        if st.st_mode & (stat.S_IWOTH | stat.S_IWGRP):
            raise PermissionError("Destination directory must not be world- or group-writable")
    except FileNotFoundError:
        parent_fd = os.open(dest_dir.parent, os.O_RDONLY | os.O_DIRECTORY | os.O_NOFOLLOW)
        try:
            os.mkdir(dest_dir.name, mode=0o700, dir_fd=parent_fd)
        finally:
            os.close(parent_fd)

        if dest_dir.is_symlink():
            raise ValueError("Destination directory resolved to a symlink after creation")
    # Ensure the directory has strict permissions
    os.chmod(dest_dir, 0o700)


def _open_file_secure(parent_fd: int, filename: str):
    """Create a regular file securely using O_NOFOLLOW|O_EXCL with restrictive mode."""
    flags = (
        os.O_WRONLY
        | os.O_CREAT
        | os.O_EXCL
        | os.O_NOFOLLOW
    )
    fd = os.open(filename, flags, 0o600, dir_fd=parent_fd)
    return os.fdopen(fd, "wb")


def _make_dirs_secure(dest_dir: Path, relative_path: Path):
    """
    Ensure that all directories in ``relative_path`` exist under ``dest_dir``,
    creating them atomically and rejecting symlinks.
    """
    current_path = dest_dir
    for part in relative_path.parts:
        current_path = current_path / part
        try:
            st = current_path.lstat()
            if stat.S_ISLNK(st.st_mode):
                raise ValueError(f"Symlink encountered in path component: {current_path}")
            if not stat.S_ISDIR(st.st_mode):
                raise ValueError(f"Nonâdirectory component exists where a directory is required: {current_path}")
            if st.st_mode & (stat.S_IWOTH | stat.S_IWGRP):
                raise PermissionError(f"Directory {current_path} must not be group/other writable")
        except FileNotFoundError:
            parent_fd = os.open(current_path.parent, os.O_RDONLY | os.O_DIRECTORY | os.O_NOFOLLOW)
            try:
                os.mkdir(part, mode=0o700, dir_fd=parent_fd)
            finally:
                os.close(parent_fd)

            if current_path.is_symlink():
                raise ValueError(f"Directory creation resulted in symlink: {current_path}")
            os.chmod(current_path, 0o700)


# --------------------------------------------------------------------------- #
# Public API                                                                 #
# --------------------------------------------------------------------------- #

def extract_secure_tar(tar_path_str: str, dest_dir_str: str) -> None:
    tar_path = Path(tar_path_str)
    dest_dir = Path(dest_dir_str)

    try:
        _validate_tarball(tar_path)
        _ensure_destination(dest_dir)

        with _open_tarball_atomic(tar_path) as fileobj:
            with tarfile.open(fileobj=fileobj, mode="r:*") as tar:
                total_extracted = 0
                member_count = 0

                for member in tar.getmembers():
                    member_count += 1
                    if member_count > MAX_MEMBER_COUNT:
                        raise ValueError("Archive contains too many members")

                    member_path = dest_dir / member.name

                    if not _is_safe_path(dest_dir, member_path):
                        raise ValueError(f"Unsafe extraction path detected: {member.name}")

                    if member.isdir():
                        _make_dirs_secure(dest_dir, Path(member.name))
                        continue

                    if member.isreg():
                        if member.size > MAX_FILE_SIZE:
                            raise ValueError(f"File too large: {member.name}")
                        total_extracted += member.size
                        if total_extracted > MAX_TOTAL_SIZE:
                            raise ValueError("Extraction would exceed total allowed size")

                        parent_rel = Path(member.name).parent
                        if parent_rel != Path('.'):
                            _make_dirs_secure(dest_dir, parent_rel)

                        parent_fd = os.open(dest_dir / parent_rel, os.O_RDONLY | os.O_DIRECTORY | os.O_NOFOLLOW)
                        try:
                            with _open_file_secure(parent_fd, Path(member.name).name) as dst:
                                src = tar.extractfile(member)
                                if src is None:
                                    raise ValueError(f"Failed to extract file object for {member.name}")
                                while True:
                                    chunk = src.read(1024 * 1024)
                                    if not chunk:
                                        break
                                    dst.write(chunk)
                        finally:
                            os.close(parent_fd)
                        continue

                    _logger.warning(
                        "Ignored unsupported tar member: %s (type=%s)",
                        member.name,
                        member.type,
                    )
    except Exception as exc:
        _logger.exception(f"Failed to extract tarball: {tar_path.name}")
        raise OSError("Extraction failed") from exc

CREATE OR REPLACE FUNCTION rename_and_add_column(
