                         'text|' ||
                         'boolean|' ||
                         'date|' ||
                         'timestamp(\s+(without|with)\s+time\s+zone)?|' ||
                         'time(\s+(without|with)\s+time\s+zone)?|' ||
                         'bytea' ||
                         ')$';
    v_default_regex  TEXT := '^(NULL|TRUE|FALSE|\d+(\.\d+)?|'[^']*'|'(?:[^']|'')*')$';
