    -- Normalise schema name
    -----------------------------------------------------------------------
    IF p_schema_name IS NULL OR p_schema_name = '' THEN
        p_schema_name := current_schema;
    END IF;

    -----------------------------------------------------------------------
    -- Basic nonâempty checks
    -----------------------------------------------------------------------
    IF p_schema_name IS NULL OR p_schema_name = '' THEN
        RAISE EXCEPTION 'Invalid schema name';
    END IF;
    IF p_table_name IS NULL OR p_table_name = '' THEN
        RAISE EXCEPTION 'Invalid table name';
    END IF;
    IF p_old_col IS NULL OR p_old_col = '' THEN
        RAISE EXCEPTION 'Invalid old column name';
    END IF;
    IF p_new_col IS NULL OR p_new_col = '' THEN
        RAISE EXCEPTION 'Invalid new column name';
    END IF;
    IF p_new_col_def IS NULL OR p_new_col_def = '' THEN
        RAISE EXCEPTION 'Invalid column definition';
    END IF;

    -----------------------------------------------------------------------
    -- Identifier validation (unquoted identifiers only)
    -----------------------------------------------------------------------
    IF p_schema_name !~ '^[a-zA-Z_][a-zA-Z0-9_]*$' THEN
        RAISE EXCEPTION 'Invalid schema name';
    END IF;
    IF p_table_name  !~ '^[a-zA-Z_][a-zA-Z0-9_]*$' THEN
        RAISE EXCEPTION 'Invalid table name';
    END IF;
    IF p_old_col    !~ '^[a-zA-Z_][a-zA-Z0-9_]*$' THEN
        RAISE EXCEPTION 'Invalid old column name';
    END IF;
    IF p_new_col    !~ '^[a-zA-Z_][a-zA-Z0-9_]*$' THEN
        RAISE EXCEPTION 'Invalid new column name';
    END IF;

    -----------------------------------------------------------------------
    -- Disallow system schemas
    -----------------------------------------------------------------------
    IF lower(p_schema_name) = ANY (ARRAY['pg_catalog','information_schema','pg_toast']) THEN
        RAISE EXCEPTION 'Operation not allowed on system schema %', p_schema_name;
    END IF;

    -----------------------------------------------------------------------
    -- Verify table existence
    -----------------------------------------------------------------------
    IF NOT EXISTS (
        SELECT 1
        FROM pg_class c
        JOIN pg_namespace n ON n.oid = c.relnamespace
        WHERE n.nspname = p_schema_name
          AND c.relname = p_table_name
          AND c.relkind = 'r'
