    -- Privilege checks for caller
    -----------------------------------------------------------------------
    IF NOT has_table_privilege(
            current_user,
            format('%I.%I', p_schema_name, p_table_name),
            'ALTER, SELECT, INSERT, UPDATE, DELETE'
       ) THEN
        RAISE EXCEPTION 'Insufficient privileges to alter table %.%', p_schema_name, p_table_name;
    END IF;

    -----------------------------------------------------------------------
    -- Parse and validate column definition
    -----------------------------------------------------------------------
    IF position('DEFAULT' IN upper(p_new_col_def)) > 0 THEN
        v_has_default := TRUE;
        v_type_def := trim(split_part(p_new_col_def, 'DEFAULT', 1));
        v_default  := trim(split_part(p_new_col_def, 'DEFAULT', 2));
        IF v_default = '' THEN
            RAISE EXCEPTION 'DEFAULT clause requires a literal value';
        END IF;
    ELSE
        v_type_def := trim(p_new_col_def);
    END IF;

    IF lower(v_type_def) !~ v_type_regex THEN
        RAISE EXCEPTION 'Column type % is not allowed or has unsupported modifiers', v_type_def;
    END IF;

    IF v_has_default THEN
        IF lower(v_default) !~ v_default_regex THEN
            RAISE EXCEPTION 'DEFAULT value % is not a simple literal', v_default;
        END IF;
    END IF;

    -----------------------------------------------------------------------
    -- Generate a unique temporary column name
    -----------------------------------------------------------------------
    LOOP
        v_tmp_col_name := p_new_col || '_old_' || to_char(clock_timestamp(),'YYYYMMDD_HH24MISSUS') ||
                          '_' || floor(random()*1000)::text;
        EXIT WHEN NOT EXISTS (
            SELECT 1
            FROM information_schema.columns
            WHERE table_schema = p_schema_name
              AND table_name   = p_table_name
              AND column_name  = v_tmp_col_name
        );
    END LOOP;

    -----------------------------------------------------------------------
    -- Rename the existing column to the temporary name
    -----------------------------------------------------------------------
    v_sql := format(
        'ALTER TABLE %I.%I RENAME COLUMN %I TO %I',
        p_schema_name, p_table_name, p_old_col, v_tmp_col_name
    );
    EXECUTE v_sql;

    -----------------------------------------------------------------------
    -- Add the new column with validated definition
    -----------------------------------------------------------------------
    v_sql := format(
        'ALTER TABLE %I.%I ADD COLUMN %I %s%s',
        p_schema_name,
        p_table_name,
        p_new_col,
        v_type_def,
        CASE
            WHEN v_has_default THEN ' DEFAULT ' || v_default
            ELSE ''
        END
    );
    EXECUTE v_sql;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Operation failed: %', SQLERRM;
END;
$$ LANGUAGE plpgsql SECURITY INVOKER;

