import re
import builtins
import logging
import unicodedata
from types import MappingProxyType
from typing import Any, Callable, Mapping, Sequence

_logger = logging.getLogger(__name__)

# Define a static, immutable whitelist of safe functions
_SAFE_FUNCTIONS: Mapping[str, Callable] = MappingProxyType({
    "len": len,
    "sum": sum,
    "max": max,
    "min": min,
    "sorted": sorted,
    "abs": abs,
    "round": round,
})

# Expanded blacklist of substrings considered unsafe
_UNSAFE_SUBSTRINGS = (
    ";", "&&", "|", "`", "$(", "${", "�", "..",
    ">", "<", "&", "||", "
", "", "	", "%", "$", "!",
)

def _is_safe_value(value: Any) -> bool:
    """Recursively verify that a value does not contain obviously unsafe content."""
    # Reject subclasses of str by requiring an exact type match
    if type(value) is str:
        # Normalise Unicode to a canonical form before scanning
        normalized = unicodedata.normalize("NFKC", value)
        return not any(sub in normalized for sub in _UNSAFE_SUBSTRINGS)
    if isinstance(value, (int, float, bool, type(None))):
        return True
    if isinstance(value, (list, tuple, set)):
        return all(_is_safe_value(item) for item in value)
    if isinstance(value, dict):
        return all(
            isinstance(k, str) and _is_safe_value(k) and _is_safe_value(v)
            for k, v in value.items()
        )
    # Disallow complex or executable objects
    return False


def safe_execute(
    func_name: str,
    args: Sequence[Any] | None = None,
    kwargs: dict[str, Any] | None = None,
    allowed_functions: dict[str, Callable] | None = None,
) -> Any:
    # Validate function name format (no leading underscore) and reject builtâins
    if not isinstance(func_name, str):
        raise TypeError("Function name must be a string")
    if not re.fullmatch(r"[A-Za-z][A-Za-z0-9_]*", func_name):
        raise ValueError("Invalid function name")
    if func_name.startswith("_") or func_name in dir(builtins):
        raise ValueError("Function name is not permitted")

    # Normalise argument containers
    args = () if args is None else args
    kwargs = {} if kwargs is None else kwargs

    if not isinstance(args, (list, tuple)):
        raise TypeError("args must be a list or tuple")
    if not isinstance(kwargs, dict):
        raise TypeError("kwargs must be a dict")

    # Build a validated whitelist combining the static safe set with any callerâsupplied entries
    whitelist: dict[str, Callable] = dict(_SAFE_FUNCTIONS)
    if allowed_functions is not None:
        if not isinstance(allowed_functions, dict):
            raise TypeError("allowed_functions must be a dict")
        for name, func in allowed_functions.items():
            # Only accept entries that match the static safe list exactly
            if name in _SAFE_FUNCTIONS and func is _SAFE_FUNCTIONS[name]:
                whitelist[name] = func

    # Retrieve the callable
    func = whitelist.get(func_name)
    if not callable(func):
        raise ValueError("Function not allowed or not callable")

    # Perâargument sanitisation
    if not all(_is_safe_value(a) for a in args):
        raise ValueError("One or more positional arguments contain unsafe data")
    if not all(_is_safe_value(v) for v in kwargs.values()):
