import re
from typing import Dict, Any

_logger = logging.getLogger(__name__)

# Length limits
MAX_KEY_LEN = 128
MAX_VAL_LEN = 4096

# Key whitelist: uppercase letters, digits, underscore
_KEY_PATTERN = re.compile(r'^[A-Z0-9_]+$')

# Value patterns per context
_URL_PATTERN = re.compile(r'^[A-Za-z0-9:/?&=._~%+\-#]+$')
_GENERIC_PATTERN = re.compile(r'^[A-Za-z0-9._-]+$')

# Characters that are not allowed in values (control chars)
_CONTROL_CHARS = ''.join(chr(i) for i in range(0, 32) if i not in (9, 10, 13))


def _is_str(obj: Any) -> bool:
    return isinstance(obj, str)


def _validate_length(name: str, value: str, max_len: int) -> None:
    if len(value) > max_len:
        raise ValueError(f"{name} exceeds maximum length of {max_len}")


def _sanitize_key(key: str) -> str:
    clean = key.strip()
    _validate_length("Environment variable key", clean, MAX_KEY_LEN)
    if not _KEY_PATTERN.fullmatch(clean):
        raise ValueError(f"Invalid characters in environment variable key: {clean!r}")
    return clean


def _sanitize_value(key: str, value: str) -> str:
    # Remove NUL and other control characters
    clean = value.strip().replace("�", "")
    clean = clean.translate({ord(c): None for c in _CONTROL_CHARS})

    _validate_length(f"Value for {key}", clean, MAX_VAL_LEN)

    # Choose pattern based on known key semantics
    pattern = _URL_PATTERN if key in {"OS_AUTH_URL", "ST_AUTH"} else _GENERIC_PATTERN

    if not pattern.fullmatch(clean):
        raise ValueError(f"Invalid characters in environment variable value for {key}: {clean!r}")
    return clean


def _validate_env_dict(env: Dict[Any, Any]) -> Dict[str, str]:
    if not isinstance(env, dict):
        raise TypeError("Environment variables must be provided as a dictionary.")

    sanitized: Dict[str, str] = {}
    for raw_key, raw_val in env.items():
        if not _is_str(raw_key) or not _is_str(raw_val):
            _logger.warning("Non-string env entry ignored")
            continue
        try:
            key = _sanitize_key(raw_key)
            val = _sanitize_value(key, raw_val)
        except ValueError as exc:
            _logger.warning("Skipping environment variable due to sanitisation error: %s", exc)
            continue
        sanitized[key] = val
    return sanitized


def _redact_auth_info(info: Dict[str, str]) -> Dict[str, str]:
    redacted: Dict[str, str] = {}
    secret_keywords = {"PASSWORD", "KEY", "TOKEN", "SECRET"}
    for k, v in info.items():
        if any(secret in k for secret in secret_keywords):
            redacted[k] = "***redacted***"
        else:
            redacted[k] = v
    return redacted


def authenticate_environment(env_vars: Dict[Any, Any]) -> Dict[str, str]:
    try:
        env = _validate_env_dict(env_vars)
    except (TypeError, ValueError) as exc:
        _logger.error("Failed to validate environment variables: %s", exc)
        raise ValueError("Invalid environment input.") from exc

    auth_info: Dict[str, str] = {}
    version = "unknown"

    os_keys = {
        "OS_AUTH_URL",
        "OS_USERNAME",
        "OS_PASSWORD",
        "OS_PROJECT_NAME",
        "OS_TENANT_NAME",
        "OS_USER_DOMAIN_NAME",
        "OS_PROJECT_DOMAIN_NAME",
    }
    os_present = os_keys.intersection(env.keys())
    required_os = {"OS_AUTH_URL", "OS_USERNAME", "OS_PASSWORD"}
    if required_os.issubset(os_present):
        if "OS_PROJECT_NAME" in env:
            version = "2.0"
        elif "OS_TENANT_NAME" in env:
            version = "1.0"
        else:
            version = "2.0"
        for key in required_os.union({"OS_PROJECT_NAME", "OS_TENANT_NAME",
                                     "OS_USER_DOMAIN_NAME", "OS_PROJECT_DOMAIN_NAME"}):
            if key in env:
                auth_info[key] = env[key]

    st_keys = {"ST_AUTH", "ST_USER", "ST_KEY"}
    st_present = st_keys.intersection(env.keys())
    required_st = {"ST_AUTH", "ST_USER", "ST_KEY"}
    if required_st.issubset(st_present):
        version = "1.0"
        for key in required_st:
            auth_info[key] = env[key]

    if not auth_info:
        _logger.warning("No supported authentication variables found.")
        raise ValueError("Authentication variables missing or unsupported.")

    auth_info["auth_version"] = version
    _logger.debug("Auth info prepared: %s", _redact_auth_info(auth_info))
    return auth_info

import os
