import re
from typing import Optional


def get_file_path(filename: str, parent_id: Optional[str] = None) -> str:
    """
    Returns a normalized absolute path for a file based on the SHA-256 hash of its name.
    The path format is: /files/attachments/<parent_id>/<hash_prefix>/<hash>
    """
    # Basic type checks
    if not isinstance(filename, str):
        raise ValueError("Filename must be a string.")
    if parent_id is not None and not isinstance(parent_id, str):
        raise ValueError("Parent ID must be a string if provided.")

    # Sanitize filename: remove directory components and control characters
    safe_name = os.path.basename(filename).strip()
    if not safe_name:
        raise ValueError("Filename cannot be empty after sanitization.")
    if not re.fullmatch(r"[A-Za-z0-9._-]+", safe_name):
        raise ValueError("Filename contains invalid characters.")
    if safe_name in {".", ".."}:
        raise ValueError("Filename cannot be '.' or '..'.")

    # Sanitize parent_id if provided
    if parent_id is not None:
        safe_parent = parent_id.strip()
        if not safe_parent:
            raise ValueError("Parent ID cannot be empty after sanitization.")
        if not re.fullmatch(r"[A-Za-z0-9._-]+", safe_parent):
            raise ValueError("Parent ID contains invalid characters.")
        if safe_parent in {".", ".."}:
            raise ValueError("Parent ID cannot be '.' or '..'.")
    else:
        safe_parent = None

    # Compute SHA-256 hash of the filename
    try:
        file_hash = hashlib.sha256(safe_name.encode("utf-8")).hexdigest()
    except Exception as exc:
        raise ValueError("Failed to compute hash.") from exc

    # Build the absolute directory structure
    base_dir = os.path.abspath(os.path.join(os.sep, "files", "attachments"))
    parts = [base_dir]
    if safe_parent:
        parts.append(safe_parent)
    parts.append(file_hash[:3])
    parts.append(file_hash)

    path = os.path.join(*parts)

    # Return normalized absolute path
    return os.path.normpath(path)

