# Whitelisted builtâins
_WHITELIST = {
    'abs', 'all', 'any', 'bool', 'chr', 'dict', 'enumerate', 'float',
    'int', 'len', 'list', 'max', 'min', 'pow', 'range', 'str',
    'sum', 'tuple', 'zip', 'print', 'sorted',
}

# Blacklisted names that must not be called
_CALL_BLACKLIST = {
    'eval', 'exec', 'open', '__import__', 'compile',
    'globals', 'locals', 'vars', 'subprocess', 'os', 'sys',
}

_MAX_OUTPUT_BYTES = 1_048_576  # 1â¯MiB
_CPU_TIME_LIMIT = 2            # seconds
_MEM_LIMIT_BYTES = 100 * 1024 * 1024  # 100â¯MiB


def _build_safe_builtins():
