    builtin_src = __builtins__ if isinstance(__builtins__, dict) else __builtins__.__dict__
    return {name: builtin_src[name] for name in _WHITELIST if name in builtin_src}


def _validate_ast(tree):
    """Raise ValueError if the AST contains disallowed constructs."""
    for node in ast.walk(tree):
        if isinstance(node, (ast.Import, ast.ImportFrom, ast.Attribute)):
            raise ValueError("disallowed operation detected")
        if isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name) and node.func.id in _CALL_BLACKLIST:
                raise ValueError("disallowed operation detected")
        if isinstance(node, ast.Name):
            if node.id.startswith('__') and node.id.endswith('__'):
                raise ValueError("disallowed operation detected")


class _LimitedStringIO(io.StringIO):
    """StringIO that stops writing after a byte limit is reached."""
    def __init__(self, max_bytes):
        super().__init__()
        self._max_bytes = max_bytes
        self._current_bytes = 0

    def write(self, s):
        if self._current_bytes >= self._max_bytes:
            raise MemoryError("output size limit exceeded")
        encoded = s.encode(self.encoding or 'utf-8')
        remaining = self._max_bytes - self._current_bytes
        if len(encoded) > remaining:
            encoded = encoded[:remaining]
            s = encoded.decode(self.encoding or 'utf-8', errors='ignore')
            raise MemoryError("output size limit exceeded")
        self._current_bytes += len(encoded)
        return super().write(s)


