def _monitor_child(proc: multiprocessing.Process, timeout: float):
    """Terminate child process if it exceeds CPU or memory limits (psutil optional)."""
    try:
        import psutil
        p = psutil.Process(proc.pid)
        start = time.time()
        while proc.is_alive():
