    process.join(_CPU_TIME_LIMIT + 1)  # Additional buffer for wallâclock

    if process.is_alive():
        process.terminate()
        return ["Error: execution timeout"]

    if parent_conn.poll():
        return parent_conn.recv()
    return ["Error: execution failed"]

