    "LPT2",
    "LPT3",
    "LPT4",
    "LPT5",
    "LPT6",
    "LPT7",
    "LPT8",
    "LPT9",
}


def is_safe_filename(name: str) -> bool:
    if not (0 < len(name) <= 255):
        return False
    if os.path.isabs(name):
        return False
    separators = {os.sep}
    if os.altsep:
        separators.add(os.altsep)
    if any(sep in name for sep in separators):
        return False
    try:
        if ".." in Path(name).parts:
            return False
    except Exception:
        return False
    if not re.fullmatch(r"[A-Za-z0-9._-]+", name):
        return False
    base_name = name.split(".", 1)[0].upper()
    if base_name in RESERVED_WINDOWS_NAMES:
        return False
    return True


def is_valid_url(url: str) -> bool:
    try:
        result = urllib.parse.urlparse(url)
        return result.scheme in ("http", "https") and bool(result.netloc)
    except Exception:
        return False


def _ip_is_private(ip: str) -> bool:
    try:
        addr = ipaddress.ip_address(ip)
        if isinstance(addr, ipaddress.IPv6Address) and addr.ipv4_mapped:
            return _ip_is_private(str(addr.ipv4_mapped))
        return (
            addr.is_private
            or addr.is_loopback
            or addr.is_link_local
            or addr.is_multicast
            or addr.is_reserved
            or addr.is_unspecified
        )
    except ValueError:
        return True  # treat unparsable as unsafe


def _resolve_host(host: str):
    try:
        infos = socket.getaddrinfo(host, None)
        return {info[4][0] for info in infos}
    except socket.gaierror:
        return set()


def is_allowed_url(url: str, allow_internal: bool = False) -> bool:
    if not is_valid_url(url):
        return False
    parsed = urllib.parse.urlparse(url)
    if parsed.username or parsed.password:
        return False  # reject URLs containing credentials
    hostname = parsed.hostname
    if not hostname:
        return False
    ips = _resolve_host(hostname)
    if not ips:
        return False
    if allow_internal:
        return True
    return all(not _ip_is_private(ip) for ip in ips)


