class CsvExportPipeline:
    def __init__(self, output_path: str):
        self.output_path = Path(output_path)
        self.temp_file = None
        self.file = None
        self.writer = None

    @classmethod
    def from_crawler(cls, crawler):
        output_path = crawler.settings.get("CSV_OUTPUT_PATH")
        return cls(output_path)

    def open_spider(self, spider):
        try:
            self.temp_file = tempfile.NamedTemporaryFile(
                mode="w",
                newline="",
                encoding="utf-8",
                delete=False,
                dir=str(self.output_path.parent),
            )
            self.file = self.temp_file.file
            self.writer = csv.DictWriter(
                self.file,
                fieldnames=["page_url", "page_title", "link_text", "link_href"],
                quoting=csv.QUOTE_ALL,
            )
            self.writer.writeheader()
        except OSError as e:
            spider.logger.error("Failed to open temporary CSV file: %s", e)
            raise CloseSpider(reason="csv_open_error")

    def close_spider(self, spider):
        if self.file:
            try:
                self.file.close()
