import configparser
import os
import sys
import re
import logging
import time
from pathlib import Path
from getpass import getpass
import requests
import tempfile

try:
    import keyring
except ImportError:
    keyring = None

logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s %(levelname)s %(message)s',
    handlers=[logging.StreamHandler(sys.stderr)]
)

CONFIG_DIR = Path.home() / '.myapp'
CONFIG_FILE = CONFIG_DIR / 'config.ini'
USERNAME_PATTERN = re.compile(r'^[A-Za-z0-9._-]{1,64}$')
API_ENDPOINT = 'https://api.thirdparty.com/auth'  # placeholder
SERVICE_NAME = 'myapp'  # keyring service identifier
MAX_RETRIES = 5
BASE_BACKOFF = 1  # seconds

def ensure_config_dir() -> None:
    try:
        CONFIG_DIR.mkdir(mode=0o700, parents=True, exist_ok=True)
        os.chmod(CONFIG_DIR, 0o700)
    except Exception as exc:
        logging.error('Failed to prepare configuration directory: %s', exc)
        sys.exit(1)

def load_config() -> configparser.ConfigParser:
    cfg = configparser.ConfigParser()
    if CONFIG_FILE.is_file():
        try:
            cfg.read(CONFIG_FILE, encoding='utf-8')
        except Exception as exc:
            logging.error('Unable to read configuration file: %s', exc)
            sys.exit(1)
    return cfg

def validate_username(username: str) -> bool:
    return bool(USERNAME_PATTERN.fullmatch(username))

def prompt_credentials() -> tuple[str, str]:
    while True:
        username = input('Enter username: ').strip()
        if not validate_username(username):
            logging.warning('Invalid username format. Use 1-64 alphanumeric characters, ._-')
            continue
        password = getpass('Enter password: ')
        if not password:
            logging.warning('Password cannot be empty.')
            continue
        return username, password

def write_config_atomic(cfg: configparser.ConfigParser) -> None:
    try:
        with tempfile.NamedTemporaryFile('w', delete=False, dir=CONFIG_DIR, encoding='utf-8') as tf:
            cfg.write(tf)
            tf.flush()
            os.fsync(tf.fileno())
        os.chmod(tf.name, 0o600)
        os.replace(tf.name, CONFIG_FILE)
    except Exception as exc:
        logging.error('Failed to write configuration file atomically: %s', exc)
        sys.exit(1)

def store_password(username: str, password: str) -> None:
    if keyring is None:
        logging.error('keyring module not available; cannot store password securely.')
        sys.exit(1)
    try:
        keyring.set_password(SERVICE_NAME, username, password)
    except Exception as exc:
        logging.error('Failed to store password in keyring: %s', exc)
        sys.exit(1)

def retrieve_password(username: str) -> str | None:
    if keyring is None:
        logging.error('keyring module not available; cannot retrieve password.')
        sys.exit(1)
    try:
        return keyring.get_password(SERVICE_NAME, username)
    except Exception as exc:
        logging.error('Failed to retrieve password from keyring: %s', exc)
        return None

def get_credentials() -> tuple[str, str]:
    ensure_config_dir()
    cfg = load_config()
    username = ''
    password = None

    if cfg.has_section('credentials'):
        username = cfg.get('credentials', 'username', fallback='').strip()
        if username and validate_username(username):
            password = retrieve_password(username)

    if not username or not password:
        username, password = prompt_credentials()
        cfg['credentials'] = {'username': username}
        write_config_atomic(cfg)
        store_password(username, password)

    return username, password

def get_api_token() -> str:
    token = os.getenv('API_TOKEN')
    if not token:
        logging.error('API_TOKEN environment variable must be set.')
        sys.exit(1)
    return token

def authenticate(username: str, password: str) -> bool:
    token = get_api_token()
    payload = {'username': username, 'password': password}
    headers = {'Authorization': f'Bearer {token}'}
    attempt = 0

    while attempt < MAX_RETRIES:
        try:
            response = requests.post(
                API_ENDPOINT,
                json=payload,
                headers=headers,
                timeout=10,
                verify=True
            )
            if response.status_code == 200:
                try:
                    data = response.json()
                    return data.get('authenticated') is True
                except ValueError:
                    logging.error('Invalid JSON response from authentication service.')
                    return False
            else:
                logging.warning('Authentication request failed with status code %s.', response.status_code)
                return False
        except requests.RequestException as exc:
            attempt += 1
            backoff = BASE_BACKOFF * (2 ** (attempt - 1))
            logging.error('Network error during authentication (attempt %d/%d): %s', attempt, MAX_RETRIES, exc)
            if attempt >= MAX_RETRIES:
                return False
            time.sleep(backoff)
    return False

def main() -> None:
    username, password = get_credentials()
    success = authenticate(username, password)
    if success:
        logging.info('Authentication successful.')
    else:
        logging.info('Authentication failed.')

if __name__ == '__main__':
    main()

