logger = logging.getLogger(__name__)

# Allowed directory for version files.
BASE_DIR = pathlib.Path("/app/allowed_versions").resolve()


def _validate_metadata_name(name: str) -> None:
    """Ensure metadata_name is a safe identifier."""
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", name):
        raise ValueError("Invalid metadata_name: must be a safe identifier.")


def extract_version_metadata(file_path: str, metadata_name: str) -> dict:
    """
    Reads a text file, extracts a version number from a line matching the pattern
    "Version: x.y.z" (or similar), and returns a dictionary populated with the
    provided metadata name containing the version.

    Args:
        file_path (str): Path to the text file.
        metadata_name (str): Key name for the returned metadata dictionary.

    Returns:
        dict: Dictionary with structure {metadata_name: {"version": "<extracted_version>"}}
    """
    # Validate input types.
    if not isinstance(file_path, str) or not isinstance(metadata_name, str):
        raise ValueError("Both file_path and metadata_name must be strings.")

    # Trim whitespace and ensure nonâempty strings.
    file_path = file_path.strip()
    metadata_name = metadata_name.strip()
    if not file_path:
        raise ValueError("file_path cannot be empty.")
    if not metadata_name:
        raise ValueError("metadata_name cannot be empty.")

    # Validate metadata_name against a safe pattern.
    _validate_metadata_name(metadata_name)

    # Resolve the path securely.
    try:
        path = pathlib.Path(file_path).expanduser().resolve(strict=True)
    except FileNotFoundError as exc:
        raise FileNotFoundError("The specified file does not exist.") from exc
    except Exception as exc:
        raise ValueError("Invalid file path supplied.") from exc

    # Ensure the path is inside the allowed base directory.
    try:
        path.relative_to(BASE_DIR)
    except ValueError as exc:
        raise PermissionError("Access to the specified path is not allowed.") from exc

    # Ensure the path points to a regular file.
    if not path.is_file():
        raise ValueError("The supplied path is not a regular file.")

    # Enforce size limit (1â¯MiB).
    max_size_bytes = 1 * 1024 * 1024
    try:
        if path.stat().st_size > max_size_bytes:
            raise ValueError("File size exceeds allowed limit.")
    except OSError as exc:
        raise ValueError("Unable to access file metadata.") from exc

    version_pattern = re.compile(
        r'^\s*Version\s*[:=]\s*([0-9]+(?:\.[0-9]+){0,2})\s*$',
        re.IGNORECASE
    )

    version = None
    try:
        with path.open('r', encoding='utf-8', errors='replace') as file:
            for line in file:
                match = version_pattern.match(line)
                if match:
                    version = match.group(1)
                    break
    except Exception as exc:
        logger.error("Failed to read the file securely.")
        raise

    if version is None:
        raise ValueError("Version line not found in the file.")

    return {
        metadata_name: {
            "version": version
        }
    }

import argparse
import sys
import re
import os
import logging
from pathlib import Path

# Configuration
BASE_DIR = Path("/allowed/input").resolve()  # directory under which input files must reside
MAX_FILE_SIZE = 10 * 1024 * 1024  # 10â¯MiB
REGEX_TIMEOUT = 1.0  # seconds per match (Pythonâ¯3.11+)

# Logging setup (secure audit log)
LOG_FILE = Path("/var/log/extractor.log")
logging.basicConfig(
    filename=str(LOG_FILE),
    level=logging.ERROR,
    format="%(asctime)s %(levelname)s %(message)s",
)
logger = logging.getLogger(__name__)


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Extract files matching a naming convention from a text file."
    )
    parser.add_argument(
        "input_file",
        type=str,
        help="Path to the input text file.",
    )
    parser.add_argument(
        "--pattern",
        type=str,
        default=r"([a-zA-Z0-9_-]+)-(\d+\.\d+\.\d+)\.tar\.gz",
        help="Regular expression for file naming convention.",
    )
    return parser.parse_args()


def validate_path(file_path: str) -> Path:
    path = Path(file_path).expanduser().resolve()

    # Ensure the path is within the allowed base directory
    try:
        if not path.is_relative_to(BASE_DIR):
            raise ValueError("File is outside the permitted directory.")
    except AttributeError:
        # Fallback for Python < 3.9
        if not str(path).startswith(str(BASE_DIR) + os.sep):
            raise ValueError("File is outside the permitted directory.")

    # Reject symlinks and other nonâregular files
    if path.is_symlink() or not path.is_file():
        raise ValueError("Specified path must be a regular file without symlinks.")

    # Verify size limit
    if path.stat().st_size > MAX_FILE_SIZE:
        raise ValueError("File size exceeds allowed limit.")

    return path


def extract_filenames(file_path: Path, regex: re.Pattern) -> list[str]:
    matches: list[str] = []
    try:
        fd = os.open(str(file_path), os.O_RDONLY | getattr(os, "O_NOFOLLOW", 0))
        with os.fdopen(fd, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                for m in regex.finditer(line):
                    matches.append(m.group(0))
    except OSError as e:
        raise RuntimeError("Failed to read the file.") from e
    return matches


def main() -> None:
    try:
        args = parse_args()
        input_path = validate_path(args.input_file)

        try:
            compiled_regex = re.compile(args.pattern, timeout=REGEX_TIMEOUT)
        except re.error as e:
            raise ValueError("Invalid regular expression.") from e

        filenames = extract_filenames(input_path, compiled_regex)

        for name in filenames:
            print(name)

    except Exception as exc:
        logger.exception("An error occurred")
        print("Error: operation failed", file=sys.stderr)
        sys.exit(1)


if __name__ == "__main__":
    main()

