import os
import stat
import logging
import hashlib

_logger = logging.getLogger(__name__)

# Directory that is allowed for hashing operations.
_ALLOWED_ROOT = os.path.abspath(os.getenv("FILE_HASH_ROOT", "/var/data"))

# Acceptable strong hash algorithms.
_STRONG_ALGOS = {"sha256", "sha384", "sha512"}


def _is_path_allowed(path: str) -> bool:
    """Return True if the real path is a descendant of the allowed root."""
    try:
        real_path = os.path.realpath(path)
        return os.path.commonpath([real_path, _ALLOWED_ROOT]) == _ALLOWED_ROOT
    except Exception as exc:
        _logger.error("Path validation error: %s", exc)
        return False


def calculate_file_hash(file_path: str, hash_obj) -> str | None:
    """
    Compute the hash of a file located under the allowed directory.

    :param file_path: Path to the target file.
    :param hash_obj: Either a hashlib hash object or a string naming a strong algorithm.
    :return: Hexadecimal digest string, or None if the file cannot be processed.
    """
    if not isinstance(file_path, str):
        raise TypeError("file_path must be a string")
    sanitized_path = file_path.strip()
    if not sanitized_path:
        raise ValueError("file_path cannot be empty")
    abs_path = os.path.abspath(sanitized_path)

    if not _is_path_allowed(abs_path):
        _logger.warning("Requested file is outside the allowed directory")
        return None

    # Open file safely, avoiding TOCTOU and symlink races.
    flags = os.O_RDONLY | getattr(os, "O_NOFOLLOW", 0)
    fd = None
    try:
        fd = os.open(abs_path, flags)
        st = os.fstat(fd)
        if not stat.S_ISREG(st.st_mode):
            _logger.warning("Requested path is not a regular file")
            return None

        # Prepare a trusted hash instance.
        if isinstance(hash_obj, str):
            algo = hash_obj.lower()
            if algo not in _STRONG_ALGOS:
                raise ValueError(f"Unsupported hash algorithm: {algo}")
            hash_inst = hashlib.new(algo)
        else:
            if not (hasattr(hash_obj, "update") and hasattr(hash_obj, "hexdigest")):
                raise TypeError("hash_obj must implement update() and hexdigest()")
            algo = getattr(hash_obj, "name", "").lower()
            if algo not in _STRONG_ALGOS:
                raise ValueError(f"Insecure or unknown hash algorithm: {algo}")
            hash_inst = hash_obj

        # Read and hash the file.
        with os.fdopen(fd, "rb") as f:
            fd = None  # fd is now managed by the context manager
            for chunk in iter(lambda: f.read(8192), b""):
                hash_inst.update(chunk)

        return hash_inst.hexdigest()

    except OSError as exc:
        _logger.error("Failed to read the file: %s", exc)
        return None
    finally:
        if fd is not None:
            try:
                os.close(fd)
            except OSError:
                pass

import subprocess
import re
from typing import Sequence, Optional, Tuple, Dict, List, Union


_ALLOWED_COMMANDS: frozenset[Tuple[str, ...]] = frozenset({
    ("/usr/bin/example_job", "status"),
})


def _is_command_allowed(command: Sequence[str]) -> bool:
    return tuple(command) in _ALLOWED_COMMANDS


def _sanitize_env() -> Dict[str, str]:
    # Provide a minimal, safe environment for the subprocess.
    return {}


def check_job_status(command: Union[Sequence[str], List[str]]) -> Optional[int]:
    # Basic type and content validation
    if not isinstance(command, (list, tuple)):
        return None
    if not command:
        return None
    for part in command:
        if not isinstance(part, str) or not part:
            return None

    # Ensure the command matches the whitelist exactly
    if not _is_command_allowed(command):
        return None

    try:
        completed = subprocess.run(
            list(command),
            capture_output=True,
            text=True,
            timeout=30,
            check=False,
            env=_sanitize_env(),
            close_fds=True,
            # Explicitly avoid using a shell
            shell=False,
        )
    except (subprocess.SubprocessError, OSError, ValueError, subprocess.TimeoutExpired):
        return None

    if completed.returncode != 0:
        return 1

    output = completed.stdout[:4096]

    if re.search(r"completed\s+successfully", output, re.IGNORECASE):
        return 0
    if re.search(r"failed", output, re.IGNORECASE):
        return 1

    return None

