namespace SecureDynamicExecutor
{
    internal static class Program
    {
        private const int MaxSourceFileSizeBytes = 100 * 1024; // 100 KB
        private const int MaxArgumentLength = 256;
        private const int ExecutionTimeoutMilliseconds = 30_000; // 30 seconds
        private static readonly string AllowedSourceRoot = Path.GetFullPath(Path.Combine(AppContext.BaseDirectory, "AllowedSources"));
        private static readonly string[] DisallowedNamespacePrefixes = new[]
        {
            "System.IO",
            "System.Net",
            "System.Diagnostics",
            "System.Reflection",
