        {
            try
            {
                EnsureAllowedSourceRootExists();
                EnsureLogDirectoryExists();

                if (args.Length == 0)
                {
                    Console.Error.WriteLine("Usage: SecureDynamicExecutor <source.cs> [-- arg1 arg2 ...]");
                    return;
                }

                int delimiterIndex = Array.IndexOf(args, "--");
                string sourcePath;
                string[] execArgs;

                if (delimiterIndex >= 0)
                {
                    sourcePath = args[0];
                    execArgs = args.Skip(delimiterIndex + 1).ToArray();
                }
                else
                {
                    sourcePath = args[0];
                    execArgs = args.Skip(1).ToArray();
                }

                if (!TryReadAndValidateSource(sourcePath, out string sourceCode))
