                if (sanitizedExecArgs == null)
                {
                    Console.Error.WriteLine("Invalid execution arguments.");
                    return;
                }

                string exePath = CompileSourceToExe(sourceCode);
                if (exePath == null)
                {
                    Console.Error.WriteLine("Compilation failed.");
                    return;
                }

                try
                {
                    ExecuteCompiledExe(exePath, sanitizedExecArgs).Wait();
                }
                finally
                {
                    TryDeleteFile(exePath);
                }
