        private static void EnsureAllowedSourceRootExists()
        {
            if (!Directory.Exists(AllowedSourceRoot))
                Directory.CreateDirectory(AllowedSourceRoot);
        }

        private static void EnsureLogDirectoryExists()
        {
            if (!Directory.Exists(LogDirectory))
                Directory.CreateDirectory(LogDirectory);
