        private static bool TryReadAndValidateSource(string path, out string sourceCode)
        {
            sourceCode = null;
            try
            {
                string fullPath = Path.GetFullPath(path);
                if (!IsPathWithinRoot(fullPath, AllowedSourceRoot))
                    return false;

                if (!File.Exists(fullPath) ||
                    !Path.GetExtension(fullPath).Equals(".cs", StringComparison.OrdinalIgnoreCase))
                    return false;

                var fileInfo = new FileInfo(fullPath);
                if (fileInfo.Length > MaxSourceFileSizeBytes)
                    return false;

                using (var fs = new FileStream(fullPath, FileMode.Open, FileAccess.Read, FileShare.None))
                using (var reader = new StreamReader(fs))
