            var syntaxTree = CSharpSyntaxTree.ParseText(source);
            // Limit syntax node count to mitigate DoS
            if (syntaxTree.GetRoot().DescendantNodes().Count() > 10_000)
                return true;

            var references = new[]
            {
                MetadataReference.CreateFromFile(typeof(object).Assembly.Location),
                MetadataReference.CreateFromFile(typeof(Console).Assembly.Location),
                MetadataReference.CreateFromFile(typeof(IEnumerable<>).Assembly.Location),
                MetadataReference.CreateFromFile(typeof(Enumerable).Assembly.Location)
            };

            var compilation = CSharpCompilation.Create(
                "Analysis_" + Guid.NewGuid().ToString("N"),
                new[] { syntaxTree },
                references,
                new CSharpCompilationOptions(OutputKind.DynamicallyLinkedLibrary));

            var model = compilation.GetSemanticModel(syntaxTree);
            var root = syntaxTree.GetRoot();

            bool disallowed = false;
            foreach (var node in root.DescendantNodes())
            {
                ISymbol symbol = null;
                switch (node)
                {
                    case IdentifierNameSyntax id:
                        symbol = model.GetSymbolInfo(id).Symbol;
                        break;
                    case MemberAccessExpressionSyntax mae:
                        symbol = model.GetSymbolInfo(mae).Symbol;
                        break;
                    case ObjectCreationExpressionSyntax ocs:
                        symbol = model.GetSymbolInfo(ocs).Symbol;
                        break;
                }

                if (symbol != null)
                {
                    var ns = symbol.ContainingNamespace?.ToDisplayString() ?? "";
                    if (DisallowedNamespacePrefixes.Any(p => ns.Equals(p, StringComparison.Ordinal) ||
                                                             ns.StartsWith(p + ".", StringComparison.Ordinal)))
                    {
                        disallowed = true;
                        break;
                    }
                }
            }

            if (disallowed) return true;

            // Simple textual scan to catch references that may not resolve due to missing metadata
            foreach (var prefix in DisallowedNamespacePrefixes)
            {
                var pattern = $@" {Regex.Escape(prefix)} ";
                if (Regex.IsMatch(source, pattern))
                    return true;
            }

            return false;
        }

        private static string[] SanitizeArguments(string[] args)
        {
            var sanitized = new List<string>();
            var allowedPattern = new Regex(@"^[a-zA-Z0-9_\-\.]+$");
            foreach (var arg in args)
            {
                if (string.IsNullOrEmpty(arg) ||
                    arg.Length > MaxArgumentLength ||
                    arg.Any(ch => char.IsControl(ch)) ||
                    !allowedPattern.IsMatch(arg))
                    return null;
                sanitized.Add(arg);
            }
            return sanitized.ToArray();
        }

        private static string CompileSourceToExe(string sourceCode)
        {
            try
            {
                var syntaxTree = CSharpSyntaxTree.ParseText(sourceCode);
                if (syntaxTree.GetRoot().DescendantNodes().Count() > 10_000)
                    return null;

                var references = new[]
                {
                    MetadataReference.CreateFromFile(typeof(object).Assembly.Location),
                    MetadataReference.CreateFromFile(typeof(Console).Assembly.Location),
                    MetadataReference.CreateFromFile(typeof(IEnumerable<>).Assembly.Location),
                    MetadataReference.CreateFromFile(typeof(Enumerable).Assembly.Location)
                };

                var compilationOptions = new CSharpCompilationOptions(OutputKind.ConsoleApplication)
                    .WithOptimizationLevel(OptimizationLevel.Release)
                    .WithAllowUnsafe(false);

                var compilation = CSharpCompilation.Create(
                    "DynamicPayload_" + Guid.NewGuid().ToString("N"),
                    syntaxTrees: new[] { syntaxTree },
                    references: references,
                    options: compilationOptions);

                string tempExePath;
                do
                {
                    tempExePath = Path.Combine(Path.GetTempPath(), Path.GetRandomFileName() + ".exe");
                } while (File.Exists(tempExePath));

                var cts = new CancellationTokenSource(TimeSpan.FromSeconds(10));
                var emitTask = Task.Run(() => compilation.Emit(tempExePath), cts.Token);
                if (!emitTask.Wait(TimeSpan.FromSeconds(10)))
                {
                    return null;
                }

                var emitResult = emitTask.Result;
                if (!emitResult.Success)
                {
                    return null;
                }

                return tempExePath;
            }
            catch (Exception ex)
            {
                LogException(ex);
                return null;
            }
        }

        private static async Task ExecuteCompiledExe(string exePath, string[] arguments)
        {
            var startInfo = new ProcessStartInfo
            {
                UseShellExecute = false,
                RedirectStandardOutput = true,
                RedirectStandardError = true,
                CreateNoWindow = true
            };

            if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
            {
                startInfo.FileName = exePath;
                foreach (var arg in arguments)
                    startInfo.ArgumentList.Add(arg);
            }
            else
            {
                // Build a safe bash command with ulimit to act as a sandbox
                var argBuilder = new StringBuilder();
                foreach (var arg in arguments)
                {
                    argBuilder.Append(' ');
                    argBuilder.Append('"');
                    argBuilder.Append(arg.Replace(""", "\""));
                    argBuilder.Append('"');
                }
                string command = $"ulimit -t {ExecutionTimeoutMilliseconds / 1000}; exec "{exePath}"{argBuilder}";
                startInfo.FileName = "/bin/bash";
                startInfo.ArgumentList.Add("-c");
                startInfo.ArgumentList.Add(command);
            }

            using var process = new Process { StartInfo = startInfo };
            var cts = new CancellationTokenSource(ExecutionTimeoutMilliseconds);
            IntPtr jobHandle = IntPtr.Zero;
            bool jobCreated = false;

            if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
            {
                jobHandle = CreateJobObject(IntPtr.Zero, null);
                if (jobHandle != IntPtr.Zero)
                {
                    JOBOBJECT_EXTENDED_LIMIT_INFORMATION info = new JOBOBJECT_EXTENDED_LIMIT_INFORMATION
                    {
                        BasicLimitInformation = new JOBOBJECT_BASIC_LIMIT_INFORMATION
                        {
                            LimitFlags = JOBOBJECT_LIMIT_FLAGS.JOB_OBJECT_LIMIT_KILL_ON_JOB_CLOSE
                        }
                    };
                    int length = Marshal.SizeOf(info);
                    IntPtr infoPtr = Marshal.AllocHGlobal(length);
                    try
                    {
                        Marshal.StructureToPtr(info, infoPtr, false);
                        if (SetInformationJobObject(jobHandle, JOBOBJECTINFOCLASS.ExtendedLimitInformation, infoPtr, (uint)length))
                            jobCreated = true;
                    }
                    finally
                    {
                        Marshal.FreeHGlobal(infoPtr);
                    }
                }
            }

            try
            {
                process.Start();

                if (jobCreated && RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
                {
                    AssignProcessToJobObject(jobHandle, process.Handle);
                }

                var outputTask = process.StandardOutput.ReadToEndAsync();
                var errorTask = process.StandardError.ReadToEndAsync();

                var waitTask = process.WaitForExitAsync(cts.Token);
                var completedTask = await Task.WhenAny(waitTask, Task.Delay(ExecutionTimeoutMilliseconds, cts.Token));

                if (completedTask != waitTask)
                {
                    try { process.Kill(true); } catch { }
                    Console.Error.WriteLine("Process terminated due to timeout.");
                    return;
                }

                string output = await outputTask;
                string error = await errorTask;

                if (!string.IsNullOrEmpty(output))
                    Console.Out.WriteLine(output);
                if (!string.IsNullOrEmpty(error))
                    Console.Error.WriteLine(error);
            }
            catch (OperationCanceledException)
            {
                try { process.Kill(true); } catch { }
                Console.Error.WriteLine("Process cancelled.");
            }
            catch (Exception ex)
            {
                LogException(ex);
                Console.Error.WriteLine("Failed to execute compiled program.");
            }
            finally
            {
                if (jobCreated && RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
                {
                    CloseHandle(jobHandle);
                }
            }
        }

        private static void TryDeleteFile(string path)
        {
            try
            {
                if (File.Exists(path))
                    File.Delete(path);
            }
            catch
            {
                // Suppress any exception during cleanup
            }
        }

        private static void LogException(Exception ex)
        {
            try
            {
                string logPath = Path.Combine(LogDirectory, "error.log");
                string sanitized = new string(ex.ToString()
                    .Where(ch => !char.IsControl(ch) || ch == '' || ch == '
')
                    .ToArray());
                File.AppendAllText(logPath, $"[{DateTime.UtcNow:u}] {sanitized}{Environment.NewLine}");
                RotateLogsIfNeeded(logPath);
            }
            catch
            {
                // If logging fails, nothing more we can do.
            }
        }

        private static void RotateLogsIfNeeded(string logPath)
        {
            const long maxSize = 5 * 1024 * 1024; // 5 MB
            try
            {
                var info = new FileInfo(logPath);
                if (info.Length > maxSize)
                {
                    string archive = $"{logPath}.{DateTime.UtcNow:yyyyMMddHHmmss}.old";
                    File.Move(logPath, archive);
                }
            }
            catch { /* ignore rotation failures */ }
        }

        // Windows Job Object interop
        private const uint JOB_OBJECT_LIMIT_KILL_ON_JOB_CLOSE = 0x00002000;

        private enum JOBOBJECT_LIMIT_FLAGS : uint
        {
            JOB_OBJECT_LIMIT_KILL_ON_JOB_CLOSE = 0x00002000
        }

        private enum JOBOBJECTINFOCLASS
        {
            ExtendedLimitInformation = 9
        }

        [StructLayout(LayoutKind.Sequential)]
        private struct JOBOBJECT_BASIC_LIMIT_INFORMATION
        {
            public long PerProcessUserTimeLimit;
            public long PerJobUserTimeLimit;
            public JOBOBJECT_LIMIT_FLAGS LimitFlags;
            public UIntPtr MinimumWorkingSetSize;
            public UIntPtr MaximumWorkingSetSize;
            public uint ActiveProcessLimit;
            public long Affinity;
            public uint PriorityClass;
            public uint SchedulingClass;
        }

        [StructLayout(LayoutKind.Sequential)]
        private struct IO_COUNTERS
        {
            public ulong ReadOperationCount;
            public ulong WriteOperationCount;
            public ulong OtherOperationCount;
            public ulong ReadTransferCount;
            public ulong WriteTransferCount;
            public ulong OtherTransferCount;
        }

        [StructLayout(LayoutKind.Sequential)]
        private struct JOBOBJECT_EXTENDED_LIMIT_INFORMATION
        {
            public JOBOBJECT_BASIC_LIMIT_INFORMATION BasicLimitInformation;
            public IO_COUNTERS IoInfo;
            public UIntPtr ProcessMemoryLimit;
            public UIntPtr JobMemoryLimit;
            public UIntPtr PeakProcessMemoryUsed;
            public UIntPtr PeakJobMemoryUsed;
        }

        [DllImport("kernel32.dll", CharSet = CharSet.Unicode)]
        private static extern IntPtr CreateJobObject(IntPtr lpJobAttributes, string? lpName);

        [DllImport("kernel32.dll")]
        private static extern bool SetInformationJobObject(IntPtr hJob, JOBOBJECTINFOCLASS JobObjectInfoClass, IntPtr lpJobObjectInfo, uint cbJobObjectInfoLength);

        [DllImport("kernel32.dll")]
        private static extern bool AssignProcessToJobObject(IntPtr hJob, IntPtr hProcess);

        [DllImport("kernel32.dll")]
        private static extern bool CloseHandle(IntPtr hObject);
    }
}

