import re
import urllib.parse
import ipaddress
import socket
import secrets
import string
from typing import List, Optional, Set

import requests
from requests.exceptions import (
    RequestException,
    Timeout,
    HTTPError,
    ConnectionError,
)


class RegistrationTestError(Exception):
    """Custom exception for registration form testing errors."""


def _is_valid_url(url: str) -> bool:
    """Validate that the provided string is a wellâformed HTTP/HTTPS URL without credentials."""
    try:
        parsed = urllib.parse.urlparse(url)
        if parsed.scheme not in {"http", "https"} or not parsed.netloc:
            return False
        if parsed.username or parsed.password:
            return False
        return True
    except Exception:
        return False


def _resolve_ip_set(hostname: str) -> Set[ipaddress.IPv4Address | ipaddress.IPv6Address]:
    """Resolve all IP addresses for a hostname."""
    try:
        addr_info = socket.getaddrinfo(hostname, None)
    except socket.gaierror:
        return set()
    ips = set()
    for _, _, _, _, sockaddr in addr_info:
        ip_str = sockaddr[0]
        try:
            ips.add(ipaddress.ip_address(ip_str))
        except ValueError:
            continue
    return ips


def _is_public_ip_set(ips: Set[ipaddress.IPv4Address | ipaddress.IPv6Address]) -> bool:
    """Return True if every IP in the set is public (no private, loopback, or linkâlocal)."""
    return all(not (ip.is_private or ip.is_loopback or ip.is_link_local) for ip in ips)


def _is_allowed_host(url: str) -> bool:
    """Return True if the URL points to a public, nonâprivate host."""
    try:
        parsed = urllib.parse.urlparse(url)
        hostname = parsed.hostname
        if not hostname:
            return False
        try:
            ip = ipaddress.ip_address(hostname)
            return not (ip.is_private or ip.is_loopback or ip.is_link_local)
        except ValueError:
            ips = _resolve_ip_set(hostname)
            if not ips:
                return False
            return _is_public_ip_set(ips)
    except Exception:
        return False


def _is_allowed_url(url: str) -> bool:
    """Combine syntactic validation and host allowance checks."""
    return _is_valid_url(url) and _is_allowed_host(url)


def _is_valid_email(email: str) -> bool:
    """Basic email validation with length limits to avoid excessive input."""
    if len(email) > 254:
        return False
    email_regex = re.compile(
        r"^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9-]+\.[a-zA-Z0-9.-]+$"
    )
    return bool(email_regex.fullmatch(email))


def _sanitize_string(value: Optional[str]) -> str:
    """Ensure the value is a string; strip leading/trailing whitespace."""
    if not isinstance(value, str):
        return ""
    return value.strip()


def _generate_mismatched_passwords() -> tuple[str, str]:
    """Generate two different passwords for the mismatched test case."""
    alphabet = string.ascii_letters + string.digits + "!@#$%^&*()-_=+"
    pwd1 = "".join(secrets.choice(alphabet) for _ in range(12))
    while True:
        pwd2 = "".join(secrets.choice(alphabet) for _ in range(12))
        if pwd2 != pwd1:
            break
    return pwd1, pwd2


def test_registration_form(base_url: str, existing_email: str) -> bool:
    """
    Submit a registration form with intentionally invalid data and verify
    that the server returns an appropriate error message.

    Returns:
        True if an expected error message is found in the response,
        False otherwise.
    Raises:
        RegistrationTestError: on validation or unexpected runtime errors.
    """
    if not _is_allowed_url(base_url):
        raise RegistrationTestError("Invalid or disallowed base URL provided.")
    if not _is_valid_email(existing_email):
        raise RegistrationTestError("Invalid email format provided.")

    # Resolve and pin the original host IP set
    parsed_base = urllib.parse.urlparse(base_url)
    original_ips = _resolve_ip_set(parsed_base.hostname)
    if not original_ips or not _is_public_ip_set(original_ips):
        raise RegistrationTestError("Base URL resolves to disallowed IP address.")

    endpoint = urllib.parse.urljoin(base_url.rstrip("/") + "/", "register")
    if not _is_allowed_url(endpoint):
        raise RegistrationTestError("Constructed endpoint URL is invalid or disallowed.")

    pwd, confirm_pwd = _generate_mismatched_passwords()

    payload = {
        "email": _sanitize_string(existing_email),
        "username": "testuser",
        "password": pwd,
        "confirm_password": confirm_pwd,
    }

    expected_errors: List[str] = [
        "passwords do not match",
        "email already registered",
        "already exists",
        "validation error",
    ]

    session = requests.Session()
    try:
        response = session.post(
            endpoint,
            data=payload,
            headers={"Content-Type": "application/x-www-form-urlencoded"},
            timeout=10,
            verify=True,
            allow_redirects=False,
        )

        redirect_limit = 5
        redirects = 0
        while response.is_redirect and redirects < redirect_limit:
            location = response.headers.get("Location")
            if not location:
                raise RegistrationTestError("Redirect without Location header.")
            next_url = urllib.parse.urljoin(response.url, location)

            if not _is_allowed_url(next_url):
                raise RegistrationTestError("Redirect to disallowed URL.")

            # Enforce sameâorigin policy
            orig_parsed = urllib.parse.urlparse(endpoint)
            next_parsed = urllib.parse.urlparse(next_url)
            if (
                orig_parsed.scheme != next_parsed.scheme
                or orig_parsed.hostname != next_parsed.hostname
                or orig_parsed.port != next_parsed.port
            ):
                raise RegistrationTestError("Redirect to different origin not allowed.")

            # DNS pinning: ensure the IP set matches the original
            next_ips = _resolve_ip_set(next_parsed.hostname)
            if next_ips != original_ips:
                raise RegistrationTestError("Redirect resolves to different IP address.")

            # Choose request method per RFC
            if response.status_code in (301, 302, 303):
                method = "GET"
                req_data = None
                req_headers = {}
            else:  # 307, 308
                method = "POST"
                req_data = payload
                req_headers = {"Content-Type": "application/x-www-form-urlencoded"}

            response = session.request(
                method,
                next_url,
                data=req_data,
                headers=req_headers,
                timeout=10,
                verify=True,
                allow_redirects=False,
            )
            redirects += 1

        response.raise_for_status()
    except (Timeout, ConnectionError) as e:
        raise RegistrationTestError("Network issue during request.") from e
    except HTTPError as e:
        response = e.response
    except RequestException as e:
        raise RegistrationTestError("Unexpected request error.") from e
    finally:
        session.close()

    content = response.text.lower()
    return any(err in content for err in expected_errors)

CREATE OR REPLACE FUNCTION manage_triggers(
    p_schema        TEXT,
    p_table         TEXT,
    p_source_table  TEXT,
    p_language      TEXT DEFAULT 'plpgsql'
) RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    rec                 RECORD;
    v_lang_exists       BOOLEAN;
    v_drop_sql          TEXT;
    v_create_sql        TEXT;
    v_func_exists       BOOLEAN;
    v_sec_def           BOOLEAN;
    v_trust_lang        BOOLEAN;
    v_source_regclass   REGCLASS;
    v_owner_sysid       OID;
BEGIN
    -- Isolate from caller's search_path
    PERFORM set_config('search_path', 'pg_catalog, pg_temp', true);

    -- Validate identifiers (schema, table)
    IF NOT p_schema ~ '^[a-z_][a-z0-9_]*$' ILIKE p_schema THEN
        RAISE EXCEPTION 'Invalid schema name';
    END IF;
    IF NOT p_table ~ '^[a-z_][a-z0-9_]*$' ILIKE p_table THEN
        RAISE EXCEPTION 'Invalid table name';
    END IF;

    -- Validate source table name (schema.table or table)
    IF NOT p_source_table ~ '^([a-z_][a-z0-9_]*\.)?[a-z_][a-z0-9_]*$' ILIKE p_source_table THEN
        RAISE EXCEPTION 'Invalid source table name';
    END IF;
    BEGIN
        v_source_regclass := p_source_table::regclass;
    EXCEPTION
        WHEN OTHERS THEN
            RAISE EXCEPTION 'Source table % does not exist or is not a relation', p_source_table;
    END;

    -- Restrict language to trusted list (currently only plpgsql)
    IF p_language <> 'plpgsql' THEN
        RAISE EXCEPTION 'Unsupported language %', p_language;
    END IF;

    -- Verify caller has privilege to manage triggers on the target table
    IF NOT has_table_privilege(SESSION_USER, p_schema || '.' || p_table, 'TRIGGER') THEN
        RAISE EXCEPTION 'Insufficient privileges to manage triggers on %.%', p_schema, p_table;
    END IF;

    -- Ensure required language exists; do not create new languages
    SELECT EXISTS (SELECT 1 FROM pg_language WHERE lanname = p_language) INTO v_lang_exists;
    IF NOT v_lang_exists THEN
        RAISE EXCEPTION 'Required language % does not exist', p_language;
    END IF;

    -- Obtain the OID of the caller for ownership checks
    SELECT usesysid INTO v_owner_sysid FROM pg_user WHERE usename = SESSION_USER;

    -- Drop existing triggers following naming convention trg_<table>_*
    FOR rec IN
        SELECT tgname
        FROM pg_trigger
        WHERE tgrelid = (p_schema || '.' || p_table)::regclass
          AND tgname LIKE format('trg_%s_%%', p_table)
          AND tgowner = v_owner_sysid
    LOOP
        v_drop_sql := format('DROP TRIGGER IF EXISTS %I ON %I.%I', rec.tgname, p_schema, p_table);
        EXECUTE v_drop_sql;
    END LOOP;

    -- Set a statement timeout for the dynamic SELECT (5 seconds)
    PERFORM set_config('statement_timeout', '5s', true);

    -- Process rows returned by the source table
    FOR rec IN EXECUTE format('SELECT trigger_name, tg_when, tg_event, tg_function FROM %s', quote_ident(p_source_table))
    LOOP
        -- Expected columns: trigger_name, tg_when, tg_event, tg_function
        IF rec.trigger_name IS NULL OR rec.tg_when IS NULL OR rec.tg_event IS NULL OR rec.tg_function IS NULL THEN
            CONTINUE;
        END IF;

        -- Validate identifiers
        IF NOT rec.trigger_name ~ '^[a-z_][a-z0-9_]*$' ILIKE rec.trigger_name THEN
            RAISE EXCEPTION 'Invalid trigger name %', rec.trigger_name;
        END IF;
        IF NOT rec.tg_function ~ '^[a-z_][a-z0-9_]*$' ILIKE rec.tg_function THEN
            RAISE EXCEPTION 'Invalid trigger function name %', rec.tg_function;
        END IF;

        -- Validate tg_when and tg_event against whitelists
        IF rec.tg_when NOT IN ('BEFORE','AFTER','INSTEAD OF') THEN
            RAISE EXCEPTION 'Invalid tg_when value: %', rec.tg_when;
        END IF;
        IF rec.tg_event NOT IN ('INSERT','UPDATE','DELETE','TRUNCATE') THEN
            RAISE EXCEPTION 'Invalid tg_event value: %', rec.tg_event;
        END IF;

        -- Verify that the function exists in the specified schema and is not SECURITY DEFINER
        SELECT EXISTS (
                 SELECT 1
                 FROM pg_proc p
                 JOIN pg_namespace n ON n.oid = p.pronamespace
                 WHERE p.proname = rec.tg_function
                   AND n.nspname = p_schema
               ) INTO v_func_exists;

        IF NOT v_func_exists THEN
            RAISE EXCEPTION 'Trigger function % does not exist in schema %', rec.tg_function, p_schema;
        END IF;

        SELECT prosecdef,
               (SELECT lantrusted FROM pg_language l WHERE l.oid = p.prolang)
          INTO v_sec_def, v_trust_lang
          FROM pg_proc p
          JOIN pg_namespace n ON n.oid = p.pronamespace
         WHERE p.proname = rec.tg_function
           AND n.nspname = p_schema;

        IF v_sec_def THEN
            RAISE EXCEPTION 'Trigger function % must not be SECURITY DEFINER', rec.tg_function;
        END IF;

        IF NOT v_trust_lang THEN
            RAISE EXCEPTION 'Trigger function % must be written in a trusted language', rec.tg_function;
        END IF;

        v_create_sql := format(
            'CREATE TRIGGER %I %s %s ON %I.%I FOR EACH ROW EXECUTE FUNCTION %I.%I()',
            rec.trigger_name,
            rec.tg_when,
            rec.tg_event,
            p_schema,
            p_table,
            p_schema,
            rec.tg_function
        );
        EXECUTE v_create_sql;
    END LOOP;

EXCEPTION
    WHEN OTHERS THEN
        RAISE LOG 'manage_triggers error (user=%): %', SESSION_USER, SQLERRM;
        RAISE;
END;
$$;

