import sys
import argparse
import base64
import hashlib
import getpass
import hmac

from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC
from cryptography.hazmat.primitives.ciphers.aead import AESGCM

# Constants
ALLOWED_HASH_ALGS = {"sha256", "sha384", "sha512"}
SALT_SIZE = 16          # bytes
NONCE_SIZE = 12          # bytes (recommended for AES-GCM)
TAG_SIZE = 16            # bytes (AES-GCM tag)
KEY_SIZE = 32            # bytes (AES-256)
DEFAULT_KDF_ITERATIONS = 1_000_000
MAX_INPUT_SIZE = 1 * 1024 * 1024  # 1 MiB
MAX_B64_LENGTH = 2 * MAX_INPUT_SIZE  # rough upper bound for base64 length


def error_exit(message: str):
    sys.stderr.write(f"Error: {message}
")
    sys.exit(1)


def parse_args():
    parser = argparse.ArgumentParser(
        description="Hash and decrypt data using a safe algorithm."
    )
    parser.add_argument(
        "data",
        help="Base64-encoded input containing salt, nonce, ciphertext, and tag."
    )
    parser.add_argument(
        "algorithm",
        help="Hash algorithm to use (sha256, sha384, sha512)."
    )
    parser.add_argument(
        "--iterations",
        type=int,
        default=DEFAULT_KDF_ITERATIONS,
        help=f"KDF iteration count (default: {DEFAULT_KDF_ITERATIONS})."
    )
    return parser.parse_args()


def validate_algorithm(alg: str) -> str:
    alg_lower = alg.lower()
    if alg_lower not in ALLOWED_HASH_ALGS:
        error_exit(f"Unsupported hash algorithm: {alg}")
    return alg_lower


def decode_input(b64_data: str) -> bytes:
    # Preliminary size check on the base64 string to avoid large decode work
    if len(b64_data) > MAX_B64_LENGTH:
        error_exit("Input base64 data exceeds maximum allowed length.")
    try:
        raw = base64.b64decode(b64_data, validate=True)
    except (base64.binascii.Error, ValueError):
        error_exit("Input data is not valid base64.")
    if len(raw) > MAX_INPUT_SIZE:
        error_exit("Decoded data exceeds maximum allowed size of 1â¯MiB.")
    return raw


def compute_hash(data: bytes, algorithm: str) -> str:
    try:
        h = hashlib.new(algorithm)
        h.update(data)
        return h.hexdigest()
    except Exception:
        error_exit("Failed to compute hash.")


def derive_key(password: bytes, salt: bytes, iterations: int) -> bytes:
    try:
        kdf_inst = PBKDF2HMAC(
            algorithm=hashes.SHA256(),
            length=KEY_SIZE,
            salt=salt,
            iterations=iterations,
        )
        return kdf_inst.derive(password)
    except Exception:
        error_exit("Decryption failed.")  # Generic message


def decrypt_aes_gcm(key: bytes, nonce: bytes, ciphertext: bytes, tag: bytes) -> bytes:
    try:
        aesgcm = AESGCM(key)
        return aesgcm.decrypt(nonce, ciphertext + tag, None)
    except Exception:
        error_exit("Decryption failed.")  # Generic message


def sanitize_output(text: str) -> str:
    return "".join(ch if ch.isprintable() else "?" for ch in text)


def main():
    args = parse_args()
    algorithm = validate_algorithm(args.algorithm)
    raw_input = decode_input(args.data)

    if len(raw_input) < SALT_SIZE + NONCE_SIZE + TAG_SIZE:
        error_exit("Input data is too short to contain required fields.")

    # Extract components
    offset = 0
    salt = raw_input[offset:offset + SALT_SIZE]
    offset += SALT_SIZE
    nonce = raw_input[offset:offset + NONCE_SIZE]
    offset += NONCE_SIZE
    tag = raw_input[-TAG_SIZE:]
    ciphertext = raw_input[offset:-TAG_SIZE]

    if not ciphertext:
        error_exit("Ciphertext component is empty.")

    # Prompt for password securely
    try:
        password_str = getpass.getpass("Password: ")
    except Exception:
        error_exit("Failed to read password.")
    if not password_str:
        error_exit("Password cannot be empty.")

    # Convert password to mutable bytearray for secure wipe
    pwd_bytes = bytearray(password_str.encode('utf-8'))
    # Remove reference to the original string
    password_str = None

    # Derive decryption key
    key = derive_key(bytes(pwd_bytes), salt, args.iterations)

    # Wipe password from memory
    for i in range(len(pwd_bytes)):
        pwd_bytes[i] = 0
    pwd_bytes = None

    # Decrypt
    plaintext = decrypt_aes_gcm(key, nonce, ciphertext, tag)

    # Output plaintext safely
    try:
        decoded = plaintext.decode('utf-8', errors='replace')
        safe_output = sanitize_output(decoded)
        print(f"Decrypted data: {safe_output}")
    except Exception:
        error_exit("Failed to decode decrypted data.")


if __name__ == "__main__":
    try:
        main()
    except Exception:
        sys.stderr.write("An unexpected error occurred.
")
        sys.exit(1)

