import os
import re
import sqlite3
import logging
from pathlib import Path
from typing import Any, Dict, List

# Configure logging for production use
logging.basicConfig(
    level=logging.WARNING,
    format="%(asctime)s %(levelname)s %(name)s %(message)s",
    filename=str(Path(__file__).with_name("securedb.log")),
    filemode="a",
)
_logger = logging.getLogger(__name__)

_TABLE_NAME_PATTERN = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

# Adjusted limits to more realistic values
_MAX_COLUMNS = 100
_MAX_STRING_LENGTH = 200_000      # maximum allowed characters for string values
_MAX_BYTES_LENGTH = 1_000_000     # maximum allowed bytes for BLOB values

_ALLOWED_DB_DIR = Path(__file__).parent / "databases"
_ALLOWED_DB_DIR.mkdir(mode=0o700, exist_ok=True)


class SecureDBError(Exception):
    """Custom exception for secure DB operations."""


def _quote_identifier(name: str) -> str:
    """Safely quote SQLite identifiers."""
    escaped = name.replace('"', '""')
    return f'"{escaped}"'


def _validate_table_name(name: str) -> None:
    if not isinstance(name, str) or not _TABLE_NAME_PATTERN.fullmatch(name):
        raise SecureDBError("Invalid table name.")


def _validate_column_names(columns: List[str]) -> None:
    for col in columns:
        if not isinstance(col, str) or not _TABLE_NAME_PATTERN.fullmatch(col):
            raise SecureDBError(f"Invalid column name: {col}")


def _validate_row_data(data: Dict[str, Any]) -> None:
    if not isinstance(data, dict) or not data:
        raise SecureDBError("Row data must be a nonâempty dictionary.")
    if len(data) > _MAX_COLUMNS:
        raise SecureDBError("Row data exceeds allowed column count.")
    for col, val in data.items():
        if not isinstance(col, str) or not _TABLE_NAME_PATTERN.fullmatch(col):
            raise SecureDBError(f"Invalid column name: {col}")
        if not isinstance(val, (str, int, float, bytes, type(None))):
            raise SecureDBError(f"Unsupported value type for column {col}.")
        if isinstance(val, str) and len(val) > _MAX_STRING_LENGTH:
            raise SecureDBError(f"String value for column {col} exceeds maximum length.")
        if isinstance(val, bytes) and len(val) > _MAX_BYTES_LENGTH:
            raise SecureDBError(f"Bytes value for column {col} exceeds maximum length.")


def _validate_db_path(db_path: str) -> Path:
    """Ensure the database path is within the allowed directory and has .db extension."""
    if not isinstance(db_path, str):
        raise SecureDBError("Database path must be a string.")
    p = Path(db_path)
    if p.is_absolute():
        raise SecureDBError("Absolute paths are not allowed for database files.")
    if ".." in p.parts:
        raise SecureDBError("Parent directory references are not allowed in database path.")
    if p.suffix.lower() != ".db":
        raise SecureDBError("Database file must have a .db extension.")
    resolved = (_ALLOWED_DB_DIR / p).resolve()
    try:
        # Proper hierarchical check, caseâaware on Windows
        if not resolved.is_relative_to(_ALLOWED_DB_DIR.resolve()):
            raise SecureDBError("Database path resolves outside the permitted directory.")
    except AttributeError:  # Python < 3.9 fallback
        if not str(resolved).startswith(str(_ALLOWED_DB_DIR.resolve())):
            raise SecureDBError("Database path resolves outside the permitted directory.")
    return resolved


def _fetch_table_columns(conn: sqlite3.Connection, table: str) -> List[str]:
    try:
        cur = conn.execute(f"PRAGMA table_info({_quote_identifier(table)})")
        return [row[1] for row in cur.fetchall()]
    except sqlite3.Error as e:
        _logger.error("Failed to retrieve table schema.")
        if _logger.isEnabledFor(logging.DEBUG):
            _logger.debug("Schema retrieval error details: %s", e)
        raise SecureDBError("Database schema error.") from e


def _open_secure_connection(db_file: Path) -> sqlite3.Connection:
    """Open SQLite connection with TOCTOU mitigation and enforce PRAGMAs."""
    # Open the file descriptor without following symlinks (Unix only)
    if os.name != "nt":
        fd = os.open(str(db_file), os.O_RDWR | os.O_NOFOLLOW)
        os.close(fd)  # descriptor only used for validation; SQLite will reopen safely
    conn = sqlite3.connect(
        str(db_file),
        detect_types=sqlite3.PARSE_DECLTYPES | sqlite3.PARSE_COLNAMES,
        isolation_level="DEFERRED",
        timeout=5.0,
        uri=False,
        check_same_thread=False,
    )
    # Reâverify the resolved path after opening to mitigate race conditions
    try:
        db_path_real = Path(conn.execute("PRAGMA database_list").fetchone()[2]).resolve()
        if not db_path_real.is_relative_to(_ALLOWED_DB_DIR.resolve()):
            raise SecureDBError("Opened database path is outside the allowed directory.")
    except Exception as e:
        conn.close()
        raise SecureDBError("Database path verification failed.") from e

    # Enforce foreign keys
    conn.execute("PRAGMA foreign_keys = ON")
    conn.row_factory = sqlite3.Row
    return conn


def perform_insert_and_query(
    db_path: str,
    table_name: str,
    row_data: Dict[str, Any],
) -> List[Dict[str, Any]]:
    """
    Insert a new row into ``table_name`` and return all rows after the commit.

    Args:
        db_path: Path to the SQLite database file (relative to allowed directory).
        table_name: Target table name (validated against a whitelist pattern).
        row_data: Mapping of column names to values for the new row.

    Returns:
        List of rows as dictionaries.

    Raises:
        SecureDBError: On validation or database errors.
    """
    _validate_table_name(table_name)
    _validate_row_data(row_data)

    safe_db_path = _validate_db_path(db_path)

    try:
        conn = _open_secure_connection(safe_db_path)
    except sqlite3.Error as e:
        _logger.error("Unable to open database.")
        if _logger.isEnabledFor(logging.DEBUG):
            _logger.debug("Database connection error: %s", e)
        raise SecureDBError("Database connection error.") from e

    try:
        with conn:
            allowed_columns = _fetch_table_columns(conn, table_name)
            _validate_column_names(allowed_columns)
            invalid_cols = set(row_data.keys()) - set(allowed_columns)
            if invalid_cols:
                raise SecureDBError(f"Invalid columns for table {table_name}: {invalid_cols}")

            placeholders = ", ".join("?" for _ in row_data)
            columns_sql = ", ".join(_quote_identifier(col) for col in row_data.keys())
            sql_insert = (
                f"INSERT INTO {_quote_identifier(table_name)} "
                f"({columns_sql}) VALUES ({placeholders})"
            )
            conn.execute(sql_insert, tuple(row_data.values()))

            cur = conn.execute(f"SELECT * FROM {_quote_identifier(table_name)}")
            rows = [dict(row) for row in cur.fetchall()]
            return rows
    except sqlite3.IntegrityError as e:
        _logger.warning("Integrity constraint violation on insert.")
        if _logger.isEnabledFor(logging.DEBUG):
            _logger.debug("Integrity error details: %s", e)
        raise SecureDBError("Data integrity error.") from e
    except sqlite3.Error as e:
        _logger.error("Database operation failed.")
        if _logger.isEnabledFor(logging.DEBUG):
            _logger.debug("Database operation error: %s", e)
        raise SecureDBError("Database operation error.") from e
    finally:
        try:
            conn.close()
        except Exception as e:
            if _logger.isEnabledFor(logging.DEBUG):
                _logger.debug("Error closing database connection: %s", e)

import logging
import time
import uuid

from django.conf import settings
from django.core.cache import cache
from django.core.exceptions import ValidationError
from django.core.validators import MaxLengthValidator
from django.db import models
from django.http import (
    HttpResponseBadRequest,
    HttpResponseForbidden,
    HttpResponseServerError,
    HttpResponseTooManyRequests,
)
from django.shortcuts import get_object_or_404, render
from django.utils import timezone
from django.views.decorators.csrf import csrf_protect
from ipware import get_client_ip
from django.contrib.auth.hashers import make_password, check_password

logger = logging.getLogger(__name__)

# Settings defaults (can be overridden in project settings)
RATE_LIMIT_WINDOW = getattr(settings, "RATE_LIMIT_WINDOW", 15 * 60)  # seconds
RATE_LIMIT_MAX_ATTEMPTS = getattr(settings, "RATE_LIMIT_MAX_ATTEMPTS", 5)


def _validate_password_complexity(password: str) -> None:
    if len(password) < 8:
        raise ValidationError(
            "Password must be at least 8 characters long."
        )
    if not any(c.islower() for c in password):
        raise ValidationError(
            "Password must include at least one lowercase letter."
        )
    if not any(c.isupper() for c in password):
        raise ValidationError(
            "Password must include at least one uppercase letter."
        )
    if not any(c.isdigit() for c in password):
        raise ValidationError(
            "Password must include at least one digit."
        )
    special_chars = set('!@#$%^&*()_+-=[]{};'":,.<>/?\|`~')
    if not any(c in special_chars for c in password):
        raise ValidationError(
            "Password must include at least one special character."
        )


class SecureEventManager(models.Manager):
    def filter_by_location_and_audience(self, location: str, audience: str):
        if not isinstance(location, str) or not isinstance(audience, str):
            raise ValueError("Invalid filter parameters")
        return super().get_queryset().filter(
            location__iexact=location.strip(),
            audience__iexact=audience.strip(),
        )


class Event(models.Model):
    title = models.CharField(
        max_length=200,
        validators=[MaxLengthValidator(200)],
        help_text="Event title",
    )
    date = models.DateField(help_text="Event date")
    time = models.TimeField(help_text="Event start time")
    location = models.CharField(
        max_length=200,
        validators=[MaxLengthValidator(200)],
        help_text="Event location",
    )
    audience = models.CharField(
        max_length=100,
        validators=[MaxLengthValidator(100)],
        help_text="Target audience",
    )
    access_password_hash = models.CharField(
        max_length=255,
        editable=False,
    )

    objects = SecureEventManager()

    class Meta:
        ordering = ["date", "time"]

    def clean(self):
        if any(ord(ch) < 32 for ch in self.title):
            raise ValidationError("Title contains invalid characters")
        if self.date < timezone.now().date():
            raise ValidationError("Event date cannot be in the past")

    def set_access_password(self, raw_password: str):
        if not isinstance(raw_password, str):
            raise ValueError("Password must be a string")
        _validate_password_complexity(raw_password)
        self.access_password_hash = make_password(raw_password)

    def verify_access_password(self, raw_password: str) -> bool:
        if not self.access_password_hash:
            return False
        return check_password(raw_password, self.access_password_hash)


def _get_client_ip_safe(request) -> str:
    """
    Returns a validated client IP address.
    If the IP cannot be determined, returns an empty string.
    """
    client_ip, _ = get_client_ip(request, request_header_order=["HTTP_X_FORWARDED_FOR", "REMOTE_ADDR"])
    return client_ip or ""


def _check_rate_limit(event: Event, ip: str):
    """
    Returns a tuple (allowed: bool, attempt_count: int).
    """
    if not ip:
        # Treat missing IP as separate bucket using a UUID
        ip = f"missing_{uuid.uuid4().hex}"
    count_key = f"event_{event.pk}_attempts_{ip}"
    first_key = f"event_{event.pk}_first_{ip}"
    now = time.time()

    first_attempt = cache.get(first_key)
    if first_attempt is None:
        cache.set(first_key, now, timeout=RATE_LIMIT_WINDOW)
        cache.set(count_key, 0, timeout=RATE_LIMIT_WINDOW)
        first_attempt = now

    if now - first_attempt > RATE_LIMIT_WINDOW:
        cache.set(first_key, now, timeout=RATE_LIMIT_WINDOW)
        cache.set(count_key, 0, timeout=RATE_LIMIT_WINDOW)
        first_attempt = now

    try:
        count = cache.incr(count_key)
    except ValueError:
        cache.set(count_key, 1, timeout=RATE_LIMIT_WINDOW)
        count = 1

    allowed = count <= RATE_LIMIT_MAX_ATTEMPTS
    return allowed, count


@csrf_protect
def event_detail_view(request, pk):
    """
    View that renders an event page after password verification,
    enforcing CSRF protection, rateâlimiting, and HTTPS.
    """
    if not request.is_secure():
        return HttpResponseForbidden("HTTPS is required.")

    event = get_object_or_404(Event, pk=pk)

    ip = _get_client_ip_safe(request)
    if ip == "":
        return HttpResponseBadRequest("Unable to determine client IP.")

    allowed, attempt_count = _check_rate_limit(event, ip)
    if not allowed:
        return HttpResponseTooManyRequests(
            "Too many attempts. Please try again later."
        )

    backoff_key = f"event_{event.pk}_backoff_{ip}"
    backoff_until = cache.get(backoff_key)
    now = time.time()
    if backoff_until and now < backoff_until:
        return HttpResponseTooManyRequests(
