class SecureDataLoaderError(Exception):
    """Base exception for SecureDataLoader."""


class InvalidPathError(SecureDataLoaderError):
    """Raised when a provided file path is invalid."""


class DataLoadError(SecureDataLoaderError):
    """Raised when loading data fails."""


class RenderError(SecureDataLoaderError):
    """Raised when rendering zip data fails."""


def _load_json(file_path: str) -> Any:
    """Load a JSON file with size limit and simple structural validation."""
    if not os.path.isfile(file_path):
        raise DataLoadError(f"File does not exist: {file_path}")

    file_size = os.path.getsize(file_path)
    if file_size > MAX_JSON_SIZE:
        raise DataLoadError(f"JSON file too large ({file_size} bytes).")

    original_limit = sys.getrecursionlimit()
    sys.setrecursionlimit(min(original_limit, 2000))
    try:
        with open(file_path, "r", encoding="utf-8") as f:
            data = json.load(f)
            return data
    except (json.JSONDecodeError, OSError) as exc:
        raise DataLoadError(f"Failed to load JSON from {file_path}") from exc
    finally:
        sys.setrecursionlimit(original_limit)


def _validate_path(path: str, allowed_dir: str) -> None:
    """Validate that the path is a string, absolute, exists, and stays within allowed_dir."""
    if not isinstance(path, str):
        raise InvalidPathError("Path must be a string.")
    if not os.path.isabs(path):
        raise InvalidPathError("Path must be absolute.")

    real_path = os.path.realpath(path)
    real_allowed = os.path.realpath(allowed_dir)

    if os.path.commonpath([real_path, real_allowed]) != real_allowed:
        raise InvalidPathError("Path traversal detected.")

    if not os.path.isfile(real_path):
        raise InvalidPathError(f"File does not exist: {real_path}")


def _sanitize_filename(name: str) -> str:
    """Return a safe filename; raise RenderError if unsafe."""
    norm = os.path.normpath(name)
    if os.path.isabs(norm):
        raise RenderError("Absolute filename generated.")
    if ".." in norm.split(os.sep):
        raise RenderError("Path traversal in filename.")
    if "\" in norm:
        raise RenderError("Backslash in filename is not allowed.")
    if os.sep in norm:
