import logging
import urllib.parse
from pathlib import Path
from typing import Dict, Any, Generator
from contextlib import AbstractContextManager, contextmanager

from sqlalchemy import create_engine, text
from sqlalchemy.engine import Engine
from sqlalchemy.orm import sessionmaker, Session
from sqlalchemy.exc import SQLAlchemyError

# Configure logger without exposing sensitive data
logger = logging.getLogger(__name__)
if not logger.handlers:
    handler = logging.StreamHandler()
    formatter = logging.Formatter("%(asctime)s %(levelname)s %(message)s")
    handler.setFormatter(formatter)
    logger.addHandler(handler)
logger.setLevel(logging.INFO)

_ALLOWED_SCHEMES = {
    "postgresql",
    "postgresql+psycopg2",
    "mysql",
    "mysql+mysqlconnector",
    "sqlite",
}

# Base directory for allowed SQLite databases
_SQLITE_BASE_DIR = Path.cwd() / "sqlite_dbs"
_SQLITE_BASE_DIR.mkdir(parents=True, exist_ok=True)


def _sanitize_db_url(db_url: str) -> str:
    """Return a version of the DB URL with password removed for safe logging."""
    parsed = urllib.parse.urlparse(db_url)
    netloc = ""
    if parsed.username:
        netloc = parsed.username + "@"
    netloc += parsed.hostname or ""
    if parsed.port:
        netloc += f":{parsed.port}"
    sanitized = urllib.parse.urlunparse(
        parsed._replace(netloc=netloc)
    )
    return sanitized


def _validate_db_url(db_url: str) -> str:
    """Validate a database URL against allowâlist, enforce TLS, and restrict SQLite paths."""
    if not isinstance(db_url, str):
        raise ValueError("Database URL must be a string")
    parsed = urllib.parse.urlparse(db_url)

    if parsed.scheme not in _ALLOWED_SCHEMES:
        raise ValueError(f"Unsupported database scheme: {parsed.scheme}")

    # Networked DBs must have a hostname
    if parsed.scheme != "sqlite" and not parsed.hostname:
        raise ValueError("Networked database URL must include a hostname")

    # Enforce TLS/SSL for networked DBs
    if parsed.scheme != "sqlite":
        query = urllib.parse.parse_qs(parsed.query)
        if parsed.scheme.startswith("postgresql"):
            sslmode = query.get("sslmode", [])
            if not any(mode.lower().startswith("require") for mode in sslmode):
                raise ValueError("PostgreSQL URL must specify sslmode=require")
        elif parsed.scheme.startswith("mysql"):
            tls = query.get("tls", [])
            ssl = query.get("ssl", [])
            if not (any(val.lower() in ("true", "1") for val in tls) or
                    any(val.lower() in ("true", "1") for val in ssl)):
                raise ValueError("MySQL URL must enable TLS (tls=true or ssl=true)")

    # SQLite specific checks
    if parsed.scheme == "sqlite":
        # Obtain the filesystem path portion
        path_str = parsed.path
        if not path_str:
            raise ValueError("SQLite URL must contain a file path")
        # Resolve to absolute path and ensure it resides within the allowed base directory
        db_path = (Path(path_str).expanduser()).resolve()
        try:
            db_path.relative_to(_SQLITE_BASE_DIR)
        except ValueError:
            raise ValueError(
                f"SQLite database path {db_path} is outside the permitted directory {_SQLITE_BASE_DIR}"
            )
        # Disallow traversals like '..' explicitly (redundant after resolve check)
        if ".." in db_path.parts:
            raise ValueError("SQLite database path must not contain parent directory references")
    return db_url


class MultiDBConnectionManager(AbstractContextManager):
    """
    Context manager that creates SQLAlchemy engines and sessions for multiple databases,
    and ensures all resources are cleaned up after use.
    """

    def __init__(self, db_urls: Dict[str, str]):
        """
        :param db_urls: Mapping of logical name -> database URL.
        """
        if not isinstance(db_urls, dict):
            raise ValueError("db_urls must be a dictionary")
        self._db_urls = {name: _validate_db_url(url) for name, url in db_urls.items()}
        self._engines: Dict[str, Engine] = {}
        self._sessions: Dict[str, Session] = {}

    def __enter__(self) -> Dict[str, Session]:
        for name, url in self._db_urls.items():
            try:
                engine = create_engine(
                    url,
                    future=True,
                    pool_size=5,
                    max_overflow=10,
                    pool_pre_ping=True,
                )
                SessionLocal = sessionmaker(bind=engine, autoflush=False, autocommit=False, future=True)
                session = SessionLocal()
                self._engines[name] = engine
                self._sessions[name] = session
            except SQLAlchemyError as exc:
                safe_url = _sanitize_db_url(url)
                logger.error("Failed to connect to database %s (URL: %s): %s", name, safe_url, str(exc))
                self._cleanup()
                raise RuntimeError(f"Unable to establish connection for {name}") from exc
        return self._sessions

    def __exit__(self, exc_type, exc_val, exc_tb) -> bool:
        self._cleanup()
        return False  # Do not suppress exceptions

    def _cleanup(self) -> None:
        """Close all sessions and dispose of engines."""
        for name, session in self._sessions.items():
            try:
                session.close()
            except Exception as exc:
                logger.warning("Error closing session for %s: %s", name, str(exc))
        for name, engine in self._engines.items():
            try:
                engine.dispose()
            except Exception as exc:
                logger.warning("Error disposing engine for %s: %s", name, str(exc))
        self._sessions.clear()
        self._engines.clear()


@contextmanager
def attach_multiple_databases(db_urls: Dict[str, str]) -> Generator[Dict[str, Session], None, None]:
    """
    Context manager that creates a MultiDBConnectionManager and yields its sessions.
    Ensures proper cleanup without requiring the caller to manage __exit__ manually.
    """
    manager = MultiDBConnectionManager(db_urls)
    try:
        sessions = manager.__enter__()
        yield sessions
    finally:
        manager.__exit__(None, None, None)


# Example usage guarded by __name__ to avoid side effects on import
if __name__ == "__main__":
