                result = sess.execute(text("SELECT 1")).scalar()
                logger.info("Result from %s: %s", name, result)
    except Exception as e:
        logger.error("Operation failed: %s", str(e))

import uuid
import re
import logging
from typing import Any, Callable, List, Dict, Optional, Union

# Configure a secure logger (no sensitive data)
logger = logging.getLogger(__name__)
if not logger.handlers:
    handler = logging.StreamHandler()
    formatter = logging.Formatter("%(asctime)s %(levelname)s %(message)s")
    handler.setFormatter(formatter)
    logger.addHandler(handler)
logger.setLevel(logging.INFO)

MAX_TYPE_NAME_LEN = 64  # reasonable limit for a controller type name


class ControllerError(Exception):
    """Custom exception for controller creation errors."""
    pass


class Controller:
    """Represents a controller with a unique ID, sequencer, and system."""

    __slots__ = ("_id", "_sequencer", "_system", "_active")

    def __init__(self, controller_id: str, sequencer: Any, system: Any) -> None:
        self._id = controller_id
        self._sequencer = sequencer
        self._system = system
        self._active = False

    @property
    def id(self) -> str:
        return self._id

    @property
    def sequencer(self) -> Any:
        return self._sequencer

    @property
    def system(self) -> Any:
        return self._system

    def start(self) -> None:
        """Activate the controller safely."""
        if self._active:
            logger.info("Controller %s already started", self._id)
            return
        try:
            if hasattr(self._sequencer, "initialize"):
                self._sequencer.initialize()
            if hasattr(self._system, "enable"):
                self._system.enable()
            self._active = True
            logger.info("Controller %s started", self._id)
        except Exception:
            logger.exception("Failed to start controller %s", self._id)
            raise ControllerError("Unable to start controller") from None

    def stop(self) -> None:
        """Deactivate the controller safely."""
        if not self._active:
            logger.info("Controller %s already stopped", self._id)
            return
        try:
            if hasattr(self._sequencer, "shutdown"):
                self._sequencer.shutdown()
            if hasattr(self._system, "disable"):
                self._system.disable()
            self._active = False
            logger.info("Controller %s stopped", self._id)
        except Exception:
            logger.exception("Failed to stop controller %s", self._id)
            raise ControllerError("Unable to stop controller") from None

    def status(self) -> str:
        """Return a simple status string."""
        return "active" if self._active else "inactive"


def _validate_type_name(name: str) -> None:
    """Ensure the type name contains only safe characters and is bounded."""
    if not isinstance(name, str):
        raise ControllerError("Controller type must be a string")
    if len(name) > MAX_TYPE_NAME_LEN:
        raise ControllerError(f"Controller type name too long (max {MAX_TYPE_NAME_LEN})")
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", name):
        raise ControllerError(f"Invalid controller type name: {name}")


def _validate_count(count: Any) -> int:
    """Validate and sanitize the count value."""
    if not isinstance(count, int):
        raise ControllerError("Count must be an integer")
    if count < 0:
        raise ControllerError("Count cannot be negative")
    return count


def create_controllers(
    specs: List[Dict[str, Any]],
    sequencer_factories: Dict[str, Callable[[], Any]],
    system_factories: Dict[str, Callable[[], Any]],
    max_total_controllers: int = 1000,
    max_per_type: Optional[int] = None,
) -> List[Controller]:
    """
    Create a list of Controller objects based on supplied specifications.

    :param specs: List of dictionaries, each with keys:
                  - "type": str indicating controller type
                  - "count": int number of controllers to create
    :param sequencer_factories: Mapping of type name to a callable returning a sequencer.
    :param system_factories: Mapping of type name to a callable returning a system.
    :param max_total_controllers: Upper bound to prevent resource exhaustion.
    :param max_per_type: Optional upper bound per controller type.
    :return: List of initialized Controller instances.
    :raises ControllerError: If validation fails or creation encounters an error.
    """
    if not isinstance(specs, list):
        raise ControllerError("Specs must be a list")
    if not isinstance(sequencer_factories, dict) or not all(callable(f) for f in sequencer_factories.values()):
        raise ControllerError("Sequencer factories must be a dict of callables")
    if not isinstance(system_factories, dict) or not all(callable(f) for f in system_factories.values()):
        raise ControllerError("System factories must be a dict of callables")

    total_requested = 0
    per_type_counts: Dict[str, int] = {}

    for spec in specs:
        if not isinstance(spec, dict):
            raise ControllerError("Each spec entry must be a dict")
        if "type" not in spec or "count" not in spec:
            raise ControllerError("Spec missing required keys: 'type' and 'count'")
        _validate_type_name(spec["type"])
        cnt = _validate_count(spec["count"])
        total_requested += cnt

        t = spec["type"]
        per_type_counts[t] = per_type_counts.get(t, 0) + cnt

    if total_requested > max_total_controllers:
        raise ControllerError(
            f"Requested controllers ({total_requested}) exceed allowed maximum ({max_total_controllers})"
        )

    if max_per_type is not None:
        for t, cnt in per_type_counts.items():
            if cnt > max_per_type:
                raise ControllerError(
                    f"Requested controllers for type '{t}' ({cnt}) exceed per-type maximum ({max_per_type})"
                )

