        raise CssProcessingError("Parent directory must not be a symlink")

    os.makedirs(parent_dir, exist_ok=True)

    flags = os.O_WRONLY | os.O_CREAT | os.O_TRUNC
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW
    mode = 0o600

    fd = os.open(real_path, flags, mode)
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            f.write(content)
    except Exception:
        os.close(fd)
        raise


def _compile_regex(pattern: str, flags: int) -> re_extended.Pattern:
    if len(pattern) > MAX_REGEX_LENGTH:
        raise CssProcessingError("Regex pattern is too long")
    try:
        return re_extended.compile(pattern, flags=flags, timeout=REGEX_TIMEOUT_SECONDS)
    except re_extended.TimeoutError:
        raise CssProcessingError("Regex compilation timed out")
    except re_extended.error as exc:
        raise CssProcessingError("Invalid regular expression") from exc


def process_css_url(
    url: str,
    pattern: str,
    repl: str,
    output_path: str,
    regex_flags: int = re.MULTILINE
) -> str:
    try:
        parsed = _validate_url(url)
        original_css = _fetch_css(parsed)

        compiled = _compile_regex(pattern, regex_flags)
        # Apply substitution with execution timeout to avoid ReDoS.
        try:
            modified_css = compiled.sub(repl, original_css, timeout=CSS_CONTENT_TIMEOUT_SECONDS)
        except re_extended.TimeoutError:
            raise CssProcessingError("Regex substitution timed out")

        target_path = os.path.abspath(os.path.join(OUTPUT_BASE_DIR, output_path))
        _write_output(modified_css, target_path)

        digest = hashlib.sha256(modified_css.encode("utf-8")).hexdigest()
        return digest
    except CssProcessingError:
        raise
    except Exception as exc:
        raise CssProcessingError("An unexpected error occurred") from exc

import os
import re
import shlex
import subprocess
import logging

logger = logging.getLogger(__name__)

# Configuration
ALLOWED_INPUT_DIR = "/var/media/input"
ALLOWED_OUTPUT_DIR = "/var/media/output"
ALLOWED_EXTENSIONS = {".mp4", ".mkv", ".mov", ".avi"}
MAX_FRAMERATE = 240  # frames per second
MAX_BITRATE = 500_000_000  # bits per second (500â¯M)
MAX_WIDTH = 3840  # maximum video width
MAX_HEIGHT = 2160  # maximum video height
MAX_COMMAND_LENGTH = 4096  # bytes
MAX_FILENAME_LENGTH = 255  # bytes


def _is_path_allowed(path: str, base_dir: str) -> str:
    """
    Resolve *path* and ensure it stays inside *base_dir*.
    Returns the absolute real path if allowed, otherwise raises ValueError.
    """
    if "://" in path:
        raise ValueError("Protocol prefixes are not allowed in file paths")
    if os.path.isabs(path):
        raise ValueError("Absolute paths are not allowed")
    real_path = os.path.realpath(os.path.join(base_dir, path))
    base_real = os.path.realpath(base_dir)
    if not (real_path == base_real or real_path.startswith(base_real + os.sep)):
        raise ValueError("Path escapes allowed directory")
    if os.path.islink(real_path):
        raise ValueError("Symlink paths are not allowed")
    return real_path


def _validate_bitrate(value: str) -> int:
    """
    Validate bitrate string with optional unit suffix and return bitrate in bits per second.
    """
    pattern = re.compile(r"(\d+)([kKmM]?)")
    m = pattern.fullmatch(value)
    if not m:
        raise ValueError("Invalid bitrate format")
    number = int(m.group(1))
    unit = m.group(2).lower()
    multipliers = {
        "": 1,
        "k": 1_000,
        "m": 1_000_000,
    }
    multiplier = multipliers.get(unit)
    if multiplier is None:
        raise ValueError("Unsupported bitrate unit")
    bitrate = number * multiplier
    if bitrate <= 0 or bitrate > MAX_BITRATE:
        raise ValueError(f"Bitrate out of allowed range (0 < bitrate â¤ {MAX_BITRATE})")
    return bitrate


def _validate_scale(filter_str: str) -> None:
    """
    Validate simple scale filter and enforce dimension limits.
    """
    m = re.fullmatch(r"scale=(\d+):(\d+)", filter_str)
    if not m:
        raise ValueError("Only simple scale filters are allowed")
    width = int(m.group(1))
    height = int(m.group(2))
    if not (0 < width <= MAX_WIDTH) or not (0 < height <= MAX_HEIGHT):
        raise ValueError(
            f"Scale dimensions out of allowed range (width â¤ {MAX_WIDTH}, height â¤ {MAX_HEIGHT})"
        )


def _validate_output_filename(filename: str) -> None:
    """
    Validate output filename for length, control characters, leading '@', and allowed extension.
    """
    if filename.startswith("@"):
        raise ValueError("Responseâfile syntax is not allowed")
    if len(filename) > MAX_FILENAME_LENGTH:
        raise ValueError("Output filename exceeds maximum length")
    if any(ord(c) < 32 for c in filename):
        raise ValueError("Output filename contains control characters")
    _, ext = os.path.splitext(filename)
    if ext.lower() not in ALLOWED_EXTENSIONS:
        raise ValueError("Invalid or unsupported output file extension")


def run_ffmpeg_command(command: str) -> str:
    """
    Execute a validated ffmpeg command and return its stdout.
    Raises detailed exceptions on validation or execution failures.
    """
    if not isinstance(command, str):
        raise TypeError("command must be a string")
    if len(command) > MAX_COMMAND_LENGTH:
        raise ValueError("Command length exceeds the allowed limit")

    try:
        args = shlex.split(command, posix=True)
    except ValueError as exc:
        raise ValueError("Failed to parse command") from exc

    if not args or args[0] != "ffmpeg":
        raise ValueError("Command must start with 'ffmpeg'")

    i = 1
    while i < len(args):
        token = args[i]

        if token == "-i":
            i += 1
            if i >= len(args):
                raise ValueError("Missing input file after -i")
            input_path = args[i]
            if "�" in input_path:
                raise ValueError("Invalid NUL byte in input file path")
            resolved_input = _is_path_allowed(input_path, ALLOWED_INPUT_DIR)
            args[i] = resolved_input
        elif token == "-r":
            i += 1
            if i >= len(args):
                raise ValueError("Missing framerate after -r")
            fr_str = args[i]
            if not re.fullmatch(r"\d+(?:\.\d+)?", fr_str):
                raise ValueError("Invalid framerate format")
            fr_value = float(fr_str)
            if not (0 < fr_value <= MAX_FRAMERATE):
                raise ValueError(
                    f"Framerate out of allowed range (0 < framerate â¤ {MAX_FRAMERATE})"
                )
        elif token == "-b:v":
            i += 1
            if i >= len(args):
                raise ValueError("Missing bitrate after -b:v")
            _validate_bitrate(args[i])
        elif token == "-vf":
            i += 1
            if i >= len(args):
                raise ValueError("Missing video filter after -vf")
            _validate_scale(args[i])
        elif token.startswith("-"):
            raise ValueError(f"Unsupported option: {token}")
        else:
            # Output file handling
            _validate_output_filename(token)
            resolved_output = _is_path_allowed(token, ALLOWED_OUTPUT_DIR)
            args[i] = resolved_output

        i += 1

    logger.debug("Executing ffmpeg command with %d arguments", len(args))

    try:
        result = subprocess.run(
            args,
            capture_output=True,
            text=True,
            check=False,
            shell=False,
        )
        if result.returncode != 0:
            logger.warning("ffmpeg exited with non-zero status %s", result.returncode)
            raise RuntimeError("ffmpeg execution failed")
        return result.stdout
    except Exception as exc:
        logger.exception("Failed to execute ffmpeg command")
        raise RuntimeError("Execution of ffmpeg failed") from exc

