class TestEnvironment:
    """
    Sets up a secure desktop environment for Java tests and loads test expectations.
    Use as a context manager to ensure proper teardown.
    """

    _BASE_EXPECTATIONS_DIR = pathlib.Path("/opt/test_expectations").resolve()
    _SAFE_WORKING_BASE = pathlib.Path("/tmp/test_workdir").resolve()
    _JAVA_WHITELIST_DIR = pathlib.Path("/usr/bin").resolve()
    _ALLOWED_JAVA_BINARIES = {"java", "java7", "java8", "java11", "java17"}
    _ALLOWED_ENV_VARS = {
        "PATH",
        "HOME",
        "LANG",
        "LC_ALL",
        "LC_CTYPE",
        "LC_MESSAGES",
        "LC_COLLATE",
        "LC_NUMERIC",
        "DISPLAY",
        "TERM",
        "USER",
        "LOGNAME",
    }
    _Xvfb_COMMAND = ["Xvfb"]
    _Xvfb_ARGS = ["-screen", "0", "1024x768x24", "-nolisten", "tcp"]
    _DISPLAY_PATTERN = re.compile(r"^:\d+$")
    _ENV_VARS_TO_REMOVE = {"LD_PRELOAD", "LD_LIBRARY_PATH", "PYTHONPATH", "PYTHONHOME"}

    def __init__(
        self,
        expectations_path: str,
        working_dir: Optional[str] = None,
        display: str = ":99",
    ) -> None:
        self.display = self._validate_display(display)
        self.xvfb_process: Optional[subprocess.Popen] = None
        self._display_lock_fd: Optional[int] = None
        self._display_lock_path: Optional[pathlib.Path] = None
        self.expectations: Dict[str, Any] = {}
        self._original_environ = os.environ.copy()
        self._working_dir_fd: Optional[int] = None
        self.working_dir: Optional[pathlib.Path] = None

        self._ensure_safe_working_base()

        # Validate expectations path
        exp_path = self._resolve_path(expectations_path, must_exist=True)
        if not self._is_subpath(exp_path, self._BASE_EXPECTATIONS_DIR):
            raise ValueError("Expectations file is outside allowed directory.")
        self.expectations_path = exp_path

        # Validate working directory
        if working_dir:
            wd_path = self._resolve_path(working_dir, must_exist=True)
            if not wd_path.is_dir():
                raise ValueError("Working directory is not a directory.")
            if not self._is_subpath(wd_path, self._SAFE_WORKING_BASE):
                raise ValueError("Working directory is outside the safe working base.")
            # Open directory with O_NOFOLLOW to prevent symlink attacks
            self._working_dir_fd = os.open(
                str(wd_path), os.O_RDONLY | os.O_DIRECTORY | getattr(os, "O_NOFOLLOW", 0)
            )
            self.working_dir = pathlib.Path(f"/proc/self/fd/{self._working_dir_fd}")
        else:
            self.working_dir = None

        # Drop privileges if running as root
        self._drop_privileges()

    def __enter__(self) -> "TestEnvironment":
        self._start_desktop()
        self._load_expectations()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb) -> None:
        self._stop_desktop()
        if self._working_dir_fd is not None:
            os.close(self._working_dir_fd)
            self._working_dir_fd = None
        os.environ.clear()
        os.environ.update(self._original_environ)

    def _ensure_safe_working_base(self) -> None:
        """Create the safe working base with restrictive permissions if it does not exist."""
        try:
            self._SAFE_WORKING_BASE.mkdir(mode=0o700, parents=True, exist_ok=True)
            # Ensure the directory is not worldâwritable
            st = self._SAFE_WORKING_BASE.stat()
            if st.st_mode & 0o022:
                raise RuntimeError("Safe working base has insecure permissions.")
        except OSError as e:
            raise RuntimeError(f"Unable to prepare safe working base: {e}") from e

    def _is_subpath(self, child: pathlib.Path, parent: pathlib.Path) -> bool:
        try:
            child.relative_to(parent)
            return True
        except ValueError:
            return False

    def _resolve_path(self, path_str: str, must_exist: bool = False) -> pathlib.Path:
        try:
            return pathlib.Path(path_str).expanduser().resolve(strict=must_exist)
        except FileNotFoundError as e:
            raise ValueError(f"Path resolution failed: {e}") from None

    def _drop_privileges(self) -> None:
        if os.geteuid() != 0:
            return
        try:
            nobody = pwd.getpwnam("nobody")
            os.setgid(nobody.pw_gid)
            os.setuid(nobody.pw_uid)
            os.setgroups([])
            logger.info("Dropped privileges to 'nobody'.")
        except Exception as e:
            logger.error("Failed to drop privileges: %s", e)
            raise RuntimeError("Cannot drop privileges.") from None

    def _sanitize_env(self, extra: Optional[Dict[str, str]] = None) -> Dict[str, str]:
        env: Dict[str, str] = {}
        env["PATH"] = "/usr/bin:/bin"
        for var in self._ALLOWED_ENV_VARS:
            if var in self._original_environ:
                env[var] = self._original_environ[var]
        if extra:
            env.update(extra)  # extra overrides any existing entry
        return env

    def _validate_display(self, display: str) -> str:
        if not self._DISPLAY_PATTERN.match(display):
            raise ValueError("Display must match pattern ':<number>'.")
        return display

    def _acquire_display_lock(self) -> None:
        lock_path = pathlib.Path(f"/tmp/.X{self.display[1:]}-lock")
        flags = (
            os.O_CREAT
            | os.O_EXCL
            | os.O_WRONLY
            | getattr(os, "O_NOFOLLOW", 0)
        )
        try:
            fd = os.open(str(lock_path), flags, 0o600)
        except FileExistsError:
            raise RuntimeError(f"Display {self.display} appears to be in use.") from None
        except OSError as e:
            raise RuntimeError(f"Unable to create display lock: {e}") from e

        # Verify that the opened file is a regular file (defenseâinâdepth)
        try:
            st = os.fstat(fd)
            if not stat.S_ISREG(st.st_mode):
                os.close(fd)
                raise RuntimeError("Display lock is not a regular file (possible symlink attack).")
        except Exception:
            os.close(fd)
            raise

        self._display_lock_fd = fd
        self._display_lock_path = lock_path

    def _release_display_lock(self) -> None:
        if self._display_lock_fd is not None:
            os.close(self._display_lock_fd)
            self._display_lock_fd = None
        if self._display_lock_path and self._display_lock_path.exists():
            try:
                self._display_lock_path.unlink()
            except OSError:
                pass
            self._display_lock_path = None

    def _start_desktop(self) -> None:
        # Verify Xvfb binary existence in a safe location
        xvfb_path = shutil.which(self._Xvfb_COMMAND[0])
        if not xvfb_path or not pathlib.Path(xvfb_path).resolve().is_file():
            raise RuntimeError("Xvfb binary not found or not executable.")
        self._acquire_display_lock()
        env = self._sanitize_env({"DISPLAY": self.display})
        cmd = self._Xvfb_COMMAND + [self.display] + self._Xvfb_ARGS
        try:
            self.xvfb_process = subprocess.Popen(
                cmd,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                env=env,
                close_fds=True,
            )
            logger.info("Started Xvfb on display %s.", self.display)
        except OSError as e:
            self._release_display_lock()
            if e.errno == errno.ENOENT:
                raise RuntimeError("Xvfb not found on system.") from None
            raise RuntimeError("Failed to start Xvfb.") from e

    def _stop_desktop(self) -> None:
        if self.xvfb_process:
            self.xvfb_process.terminate()
            try:
                self.xvfb_process.wait(timeout=5)
                logger.info("Xvfb terminated gracefully.")
            except subprocess.TimeoutExpired:
                self.xvfb_process.kill()
                logger.warning("Xvfb killed after timeout.")
            self.xvfb_process = None
        self._release_display_lock()

    def _load_expectations(self) -> None:
        try:
            with open(self.expectations_path, "r", encoding="utf-8") as f:
                data = json.load(f)
        except json.JSONDecodeError as e:
            raise ValueError("Expectations file contains invalid JSON.") from e
        except Exception as e:
            logger.error("Failed to load expectations: %s", e)
            raise RuntimeError("Unable to load expectations.") from e

        if not isinstance(data, dict):
            raise ValueError("Expectations JSON must be an object.")
        self.expectations = data
        logger.info("Loaded expectations from %s.", self.expectations_path)

    def get_expectation(self, key: str, default: Any = None) -> Any:
        return self.expectations.get(key, default)

    def _validate_java_cmd(self, java_cmd: List[str]) -> List[str]:
        if not isinstance(java_cmd, list) or not all(isinstance(arg, str) for arg in java_cmd):
            raise ValueError("java_cmd must be a list of strings.")
        executable_path = pathlib.Path(java_cmd[0]).resolve()
        if not executable_path.is_file():
            raise ValueError("Java executable not found.")
        if executable_path.is_symlink():
            raise ValueError("Java executable must not be a symlink.")
        if not os.access(str(executable_path), os.X_OK):
            raise ValueError("Java executable is not executable.")
        if not self._is_subpath(executable_path, self._JAVA_WHITELIST_DIR):
            raise ValueError("Java executable is not in the allowed directory.")
        if executable_path.name not in self._ALLOWED_JAVA_BINARIES:
            raise ValueError("Java executable is not an allowed binary.")
        return java_cmd

    def run_java_test(self, java_cmd: List[str]) -> int:
        """
        Executes a Java test command within the prepared environment.
        Returns the process exit code.
        """
        cmd = self._validate_java_cmd(java_cmd)
        env = self._sanitize_env({"DISPLAY": self.display})
        cwd = str(self.working_dir) if self.working_dir else None

        # Reâvalidate working directory just before execution (defenseâinâdepth)
        if self.working_dir:
            try:
                wd_real = pathlib.Path(cwd).resolve(strict=True)
                if not self._is_subpath(wd_real, self._SAFE_WORKING_BASE):
                    raise RuntimeError("Working directory changed to an unsafe location.")
            except Exception as e:
                logger.error("Working directory validation failed: %s", e)
                return -1

        try:
            result = subprocess.run(
                cmd,
                cwd=cwd,
                env=env,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                timeout=300,
                check=False,
                text=True,
                close_fds=True,
            )
            logger.info("Java test completed with exit code %d.", result.returncode)
            return result.returncode
        except subprocess.TimeoutExpired:
            logger.error("Java test timed out.")
            return -1
        except Exception as e:
            logger.error("Error running Java test: %s", e)
            return -1

