import json
from decimal import Decimal
from typing import Any, Callable, Optional

class SafeJsonError(Exception):
    """Exception raised for safe JSON deserialization errors."""
    pass

_MAX_INPUT_SIZE = 1_048_576  # 1â¯MiB
_DEFAULT_MAX_DEPTH = 1000

def _default_key_decoder(key: str) -> Any:
    """Identity decoder for dictionary keys."""
    return key

def _validate_key(key: Any) -> None:
    """Ensure a dictionary key is hashable."""
    try:
        hash(key)
    except Exception as exc:
        raise SafeJsonError("Decoded dictionary key is not hashable.") from exc

def safe_json_load(
    data: str,
    *,
    key_decoder: Optional[Callable[[str], Any]] = None,
    max_depth: int = _DEFAULT_MAX_DEPTH,
) -> Any:
    """
    Deserialize a JSON string into Python objects with optional nonâstring
    dictionary key decoding.

    Args:
        data: JSON document as a string.
        key_decoder: Callable to transform dictionary keys. Defaults to identity.
        max_depth: Maximum allowed nesting depth for the resulting structure.

    Returns:
        The deserialized Python object.

    Raises:
        SafeJsonError: If input is invalid or deserialization fails.
    """
    # Input validation
    if not isinstance(data, str):
        raise SafeJsonError("Input must be a string.")
    if len(data) > _MAX_INPUT_SIZE:
        raise SafeJsonError("Input exceeds maximum allowed size.")
    if not isinstance(max_depth, int) or max_depth <= 0:
        raise SafeJsonError("max_depth must be a positive integer.")

    decoder = key_decoder if key_decoder is not None else _default_key_decoder

    def _object_hook(obj: dict) -> dict:
        """Convert dictionary keys using the provided decoder, ensuring uniqueness."""
        new_obj = {}
        for k, v in obj.items():
            new_key = decoder(k)
            _validate_key(new_key)
            if new_key in new_obj:
                raise SafeJsonError("Duplicate key after decoding.")
            new_obj[new_key] = v
        return new_obj

    def _enforce_depth(root: Any) -> None:
        """Iterative depth check to avoid recursion limits."""
        stack = [(root, 0)]
        while stack:
            current, depth = stack.pop()
            if depth > max_depth:
                raise SafeJsonError("Maximum nesting depth exceeded.")
            if isinstance(current, dict):
                for val in current.values():
                    stack.append((val, depth + 1))
            elif isinstance(current, list):
                for item in current:
                    stack.append((item, depth + 1))

    # Disallow NaN/Infinity by forcing json to raise on such constants
    def _reject_constant(constant: str) -> Any:
        raise SafeJsonError(f"Invalid JSON constant: {constant}")

    try:
        result = json.loads(
            data,
            object_hook=_object_hook,
            parse_float=Decimal,
            parse_int=int,
            parse_constant=_reject_constant,
            strict=True,
        )
        _enforce_depth(result)
        return result
    except (json.JSONDecodeError, TypeError, ValueError) as exc:
        raise SafeJsonError("Failed to parse JSON.") from exc
    except SafeJsonError:
        raise
    except Exception as exc:
        raise SafeJsonError("Unexpected error during JSON deserialization.") from exc

