    _, ext = os.path.splitext(filename.lower())
    return ext in ALLOWED_EXTENSIONS

def safe_join(directory: str, filename: str) -> str:
    final_path = os.path.abspath(os.path.join(directory, filename))
    if not final_path.startswith(os.path.abspath(directory) + os.sep):
        raise ValueError("Attempted directory traversal")
    return final_path

