def upload():
    error_msg = None
    result = None

    if request.method == "POST":
        client_ip = request.remote_addr or "unknown"
        _ip_upload_counts[client_ip] = _ip_upload_counts.get(client_ip, 0) + 1
        if _ip_upload_counts[client_ip] > MAX_SUBDIRS_PER_IP:
            error_msg = "Upload rate limit exceeded."
        else:
            if len([d for d in os.listdir(UPLOAD_ROOT) if os.path.isdir(os.path.join(UPLOAD_ROOT, d))]) >= MAX_SUBDIRS:
                error_msg = "Server upload capacity reached."
            elif "upload_file" not in request.files:
                error_msg = "No file part in request."
            else:
                file = request.files["upload_file"]
                if file.filename == "":
                    error_msg = "No selected file."
                else:
                    filename = secure_filename(file.filename)
                    if not allowed_file(filename):
                        error_msg = "File type not allowed."
