                                "filename": html.escape(filename),
                                "size": file_size,
                                "param": safe_param,
                                "download_url": f"/download/{subdir}/{filename}"
                            }
                        except Exception:
                            error_msg = "An error occurred while processing the upload."

    return render_template_string(HTML_TEMPLATE, error=error_msg, result=result)

@app.route("/download/<subdir>/<filename>", methods=["GET"])
def download(subdir: str, filename: str):
    if not subdir.isalnum():
        abort(400)
    safe_name = secure_filename(filename)
    directory = safe_join(UPLOAD_ROOT, subdir)
    return send_from_directory(directory, safe_name, as_attachment=True)

if __name__ == "__main__":
    app.run(host="127.0.0.1", port=5000, debug=False)

