import os
import re
import pwd
import shutil
import logging
import subprocess
import stat
from pathlib import Path
from typing import Sequence, List

# Configuration
_ALLOWED_COMMANDS = {"ls", "ping", "cat"}            # whitelist of allowed executables
_ALLOWED_READ_DIR = "/var/readable"                 # base directory allowed for `cat`
_SAFE_PATH = "/usr/bin:/bin"                        # trusted PATH for resolution
_COMMAND_TIMEOUT = 30                               # seconds
_MAX_OUTPUT_SIZE = 1_048_576                        # 1 MB
_MAX_PING_COUNT = 100                               # maximum allowed ping count

# Resolve absolute paths for allowed commands using a trusted PATH at import time
_ABSOLUTE_COMMANDS = {
    cmd: shutil.which(cmd, path=_SAFE_PATH) or f"/bin/{cmd}"
    for cmd in _ALLOWED_COMMANDS
}

_logger = logging.getLogger(__name__)
if not _logger.handlers:
    _handler = logging.StreamHandler()
    _formatter = logging.Formatter("%(asctime)s - %(levelname)s - %(message)s")
    _handler.setFormatter(_formatter)
    _logger.addHandler(_handler)
_logger.setLevel(logging.INFO)


class OutputTooLargeError(RuntimeError):
    """Raised when command output exceeds the allowed size."""


def _drop_privileges():
    """Drop root privileges to the unprivileged 'nobody' user if running as root."""
    if os.geteuid() == 0:
        try:
            pw = pwd.getpwnam("nobody")
            os.setgid(pw.pw_gid)
            os.setuid(pw.pw_uid)
            if os.geteuid() == 0:
                raise PermissionError("Privilege drop failed, still running as root")
        except Exception as exc:
            _logger.warning("Failed to drop privileges: %s", exc)
            raise PermissionError(f"Failed to drop privileges: {exc}") from exc


def _mask_sensitive(arg: str) -> str:
    """Mask common sensitive patterns in a command argument."""
    if re.search(r"(?i)(?:password|pwd|pass|secret|token|key|api[_-]?key)", arg):
        return "[REDACTED]"
    return arg


def _sanitize_command(command: Sequence[str]) -> List[str]:
    """Return a sanitized copy of the command for safe logging."""
    sanitized = []
    skip_next = False
    for i, arg in enumerate(command):
        if skip_next:
            skip_next = False
            continue
        masked = _mask_sensitive(arg)
        if re.fullmatch(r"-[A-Za-z]$", arg) and i + 1 < len(command):
            sanitized.append(masked)
            sanitized.append("[REDACTED]")
            skip_next = True
        else:
            sanitized.append(masked)
    return sanitized


def _validate_cat_paths(args: List[str]) -> List[str]:
    """Validate and resolve paths for `cat` command using realpath to avoid symlink bypass."""
    resolved = []
    base_real = Path(_ALLOWED_READ_DIR).resolve()
    for arg in args:
        if arg.startswith("-"):
            raise PermissionError("Options are not allowed with 'cat'")
        candidate = Path(_ALLOWED_READ_DIR, arg).resolve()
        if not str(candidate).startswith(str(base_real) + os.sep):
            raise PermissionError(f"Access to '{arg}' is not permitted")
        resolved.append(str(candidate))
    return resolved


def _validate_ping_args(args: List[str]) -> List[str]:
    """Validate arguments for `ping` â allow only a target and optional -c count."""
    if not args:
        raise PermissionError("ping requires a target")
    allowed_flags = {"-c"}
    i = 0
    validated = []
    while i < len(args):
        arg = args[i]
        if arg in allowed_flags:
            if i + 1 >= len(args):
                raise PermissionError(f"Missing value for flag '{arg}'")
            if arg == "-c":
                try:
                    count = int(args[i + 1])
                except ValueError:
                    raise PermissionError("Ping count must be integer")
                if not (0 < count <= _MAX_PING_COUNT):
                    raise PermissionError(f"Ping count must be between 1 and {_MAX_PING_COUNT}")
            validated.append(arg)
            validated.append(args[i + 1])
            i += 2
        elif arg.startswith("-"):
            raise PermissionError(f"Flag '{arg}' is not permitted with ping")
        else:
            validated.append(arg)
            i += 1
    # Ensure exactly one target (non-flag argument)
    targets = [a for a in validated if not a.startswith("-")]
    if len(targets) != 1:
        raise PermissionError("Exactly one target must be specified for ping")
    return validated


def _validate_command(command: Sequence[str]) -> List[str]:
    """Validate that the command is allowed, properly typed, and arguments are safe."""
    if not isinstance(command, (list, tuple)):
        raise TypeError("command must be a list or tuple of strings")
    if not all(isinstance(arg, str) for arg in command):
        raise TypeError("all command arguments must be strings")
    if not command:
        raise ValueError("command cannot be empty")

    executable = command[0]
    if executable not in _ALLOWED_COMMANDS:
        raise PermissionError(f"Executable '{executable}' is not allowed")

    abs_executable = _ABSOLUTE_COMMANDS.get(executable)
    if not abs_executable or not os.path.isabs(abs_executable):
        raise PermissionError(f"Could not resolve absolute path for '{executable}'")

    # Verify the executable is a regular file, owned by root, and not a symlink
    exec_path = Path(abs_executable)
    try:
        st = exec_path.lstat()
    except OSError as exc:
        raise PermissionError(f"Unable to stat executable '{abs_executable}': {exc}") from exc
    if stat.S_ISLNK(st.st_mode):
        raise PermissionError(f"Executable '{abs_executable}' must not be a symlink")
    if not stat.S_ISREG(st.st_mode):
        raise PermissionError(f"Executable '{abs_executable}' is not a regular file")
    if st.st_uid != 0:
        raise PermissionError(f"Executable '{abs_executable}' must be owned by root")

    cmd_list = list(command)
    cmd_list[0] = str(exec_path)

    if executable == "cat":
        cmd_list[1:] = _validate_cat_paths(cmd_list[1:])
    elif executable == "ping":
        cmd_list[1:] = _validate_ping_args(cmd_list[1:])

    return cmd_list


def run_secure_command(command: Sequence[str]) -> bytes:
    """
    Execute a whitelisted command with strict controls:
    - Enforced timeout
    - Output size limit (streamed)
    - Sanitized logging
    - Minimal trusted environment
    - Privilege dropping before execution
    Returns the command's stdout as bytes.
    """
    cmd_list = _validate_command(command)
    sanitized = _sanitize_command(cmd_list)
    _logger.info("Executed command: %s", sanitized)

    safe_env = {"PATH": _SAFE_PATH}

    preexec = _drop_privileges if os.geteuid() == 0 else None

    proc = subprocess.Popen(
        cmd_list,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
        env=safe_env,
        close_fds=True,
        preexec_fn=preexec,
    )

    try:
        stdout_data, _ = proc.communicate(timeout=_COMMAND_TIMEOUT)
        if len(stdout_data) > _MAX_OUTPUT_SIZE:
            proc.kill()
            raise OutputTooLargeError(
                f"Command output size {len(stdout_data)} exceeds limit of {_MAX_OUTPUT_SIZE} bytes"
            )
    except subprocess.TimeoutExpired:
        proc.kill()
        _logger.error(
            "Command %s timed out after %s seconds", sanitized, _COMMAND_TIMEOUT
        )
        raise
    finally:
        if proc.stdout:
            proc.stdout.close()

    if proc.returncode != 0:
        _logger.error(
            "Command %s failed with return code %s", sanitized, proc.returncode
        )
        raise subprocess.CalledProcessError(
            returncode=proc.returncode,
            cmd=cmd_list,
            output=stdout_data,
        )

    _logger.debug("Command output (first 200 bytes): %s", stdout_data[:200])
    return stdout_data

