    return p.resolve()


def _is_trusted_repo_path(path: pathlib.Path) -> bool:
    trusted_root = _get_trusted_root()
    try:
        path.relative_to(trusted_root)
        return True
    except ValueError:
        return False


def _safe_write_error(message: str) -> None:
    sys.stderr.write(f"Error: {str(message)}
")


def _open_repository_safe(repo_path: pathlib.Path, ui_obj: hg_ui.ui) -> hg.repository:
    # Open directory with O_NOFOLLOW to avoid symlink race
    flags = os.O_RDONLY | os.O_DIRECTORY
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW
    fd = None
    try:
        fd = os.open(str(repo_path), flags)
        # Verify it's still a directory (fstat)
        st = os.fstat(fd)
        if not stat.S_ISDIR(st.st_mode):
            raise RuntimeError("Repository path is no longer a directory")
    finally:
        if fd is not None:
            os.close(fd)

    repo = hg.repository(ui_obj, str(repo_path))

    # Reâvalidate after opening to mitigate TOCTOU
    resolved = pathlib.Path(repo_path).resolve()
    if not _is_trusted_repo_path(resolved):
        raise RuntimeError("Repository resolved outside of trusted root after opening")
    return repo


def get_changeset_info(repo_path: pathlib.Path, rev: str) -> dict:
    ui_obj = _get_sandboxed_ui()
    try:
        repo = _open_repository_safe(repo_path, ui_obj)
    except error.RepoError as e:
        raise RuntimeError(f"Unable to open Mercurial repository: {e}") from e
    except Exception as e:
        raise RuntimeError(f"Repository validation failed: {e}") from e

    try:
        ctx = repo[rev]
    except (error.LookupError, error.RepoLookupError) as e:
        raise ValueError(f"Changeset identifier not found: {e}") from e

    tags = ctx.tags()
    primary_tag = tags[-1] if tags else ""
    parent_hashes = [p.hex() for p in ctx.parents()]
    timestamp, tz = ctx.date()
    return {
        "tag": primary_tag,
        "date": {"timestamp": timestamp, "timezone": tz},
        "author": ctx.user(),
        "parents": parent_hashes,
        "comment": ctx.description(),
    }


def main() -> None:
    try:
        _ = _get_trusted_root()
    except RuntimeError as e:
        _safe_write_error(e)
        sys.exit(1)

    parser = argparse.ArgumentParser(description="Retrieve Mercurial changeset information")
    parser.add_argument("repo", help="Path to the Mercurial repository")
    parser.add_argument("rev", help="Changeset identifier (hash, tag, or revision number)")
    args = parser.parse_args()

    try:
        repo_path = _sanitize_path(args.repo)
    except ValueError as exc:
        _safe_write_error(exc)
        sys.exit(1)

    if not _is_trusted_repo_path(repo_path):
        _safe_write_error("Repository path is not in a trusted location")
        sys.exit(1)

    if not _is_valid_rev(args.rev):
        _safe_write_error("Invalid changeset identifier format")
        sys.exit(1)

    try:
        info = get_changeset_info(repo_path, args.rev)
    except (RuntimeError, ValueError) as exc:
        _safe_write_error(exc)
        sys.exit(1)
    except Exception:
        _safe_write_error("Unexpected failure while processing request")
        sys.exit(1)

    sys.stdout.write(json.dumps(info, ensure_ascii=False, indent=2) + "
")


if __name__ == "__main__":
    main()

import os
import stat
import json
import logging
import pathlib
import configparser as _configparser

# Configure logger with a default StreamHandler if none are set
logger = logging.getLogger(__name__)
if not logger.handlers or all(isinstance(h, logging.NullHandler) for h in logger.handlers):
    sh = logging.StreamHandler()
    sh.setLevel(logging.INFO)
    sh.setFormatter(logging.Formatter("%(asctime)s - %(name)s - %(levelname)s - %(message)s"))
    logger.addHandler(sh)

MAX_CONFIG_SIZE = 1 * 1024 * 1024  # 1 MiB


class SecureProcessingError(Exception):
    """Generic error raised for all processing failures without leaking details."""
    pass


def _raise_secure(e: Exception) -> None:
    """Log a sanitized error message and raise a generic exception for expected errors."""
    if isinstance(e, (OSError, json.JSONDecodeError, _configparser.Error)):
        logger.error("Processing error: %s", e.__class__.__name__)
        raise SecureProcessingError("An internal error occurred.") from None
    raise e


def _is_relative_to(child: pathlib.Path, parent: pathlib.Path) -> bool:
    """Backport of pathlib.Path.is_relative_to for Python < 3.9."""
    try:
        child.relative_to(parent)
        return True
    except Exception:
        return False


def _contains_symlink(path: pathlib.Path) -> bool:
    """Return True if any component of the path (including the final one) is a symlink."""
    for part in path.parents:
        if part.is_symlink():
            return True
        if part == path:
            break
    return path.is_symlink()


def _validate_path(input_path: str, base_dir: pathlib.Path) -> pathlib.Path:
    """Validate that the input path is a safe child of base_dir and contains no symlinks."""
    if not isinstance(input_path, str):
        raise SecureProcessingError("Invalid input type.")
    if "�" in input_path:
        raise SecureProcessingError("Input contains null byte.")

    candidate = base_dir / input_path

    # Reject any component that is a symlink before resolution
    if _contains_symlink(candidate):
        raise SecureProcessingError("Symlink detected in path.")

    try:
        resolved = candidate.resolve(strict=False)
    except Exception as e:
        _raise_secure(e)

    # Verify the resolved path stays within the base directory
    if hasattr(resolved, "is_relative_to"):
        is_relative = resolved.is_relative_to(base_dir)
    else:
        is_relative = _is_relative_to(resolved, base_dir)

    if not is_relative:
        raise SecureProcessingError("Path traversal detected.")

    return resolved


def load_configuration(file_name: str, base_directory: str = "/etc/myapp"):
    """
    Load a configuration file securely, handling Python version differences.
    Returns the parsed configuration as a dictionary.
    """
    try:
        base_dir = pathlib.Path(base_directory).resolve(strict=True)
        config_path = _validate_path(file_name, base_dir)

        # Open the file atomically, prevent following symlinks
        fd = os.open(str(config_path), os.O_RDONLY | os.O_NOFOLLOW)
        cfg_file = None
        try:
            st = os.fstat(fd)

            # Ensure regular file
            if not stat.S_ISREG(st.st_mode):
                raise SecureProcessingError("Configuration file is not a regular file.")

            # Size limit
            if st.st_size > MAX_CONFIG_SIZE:
                raise SecureProcessingError("Configuration file too large.")

            # Permission checks
            if st.st_mode & (stat.S_IWGRP | stat.S_IWOTH):
                raise SecureProcessingError(
                    "Configuration file must not be writable by group or others."
                )
            if st.st_uid != os.getuid():
                raise SecureProcessingError("Configuration file must be owned by the running user.")

            cfg_file = os.fdopen(fd, "r", encoding="utf-8")
            parser = _configparser.ConfigParser()
            parser.read_file(cfg_file)
        finally:
            if cfg_file is not None:
                try:
                    cfg_file.close()
                except Exception:
                    pass
            else:
                try:
                    os.close(fd)
                except Exception:
                    pass

        config_dict = {section: dict(parser.items(section)) for section in parser.sections()}
        return config_dict
    except SecureProcessingError:
        raise
    except Exception as e:
        _raise_secure(e)


def parse_json_input(json_string: str):
    """
    Parse a JSON string safely after validating its length and content.
    Returns the resulting Python object.
    """
    try:
        if not isinstance(json_string, str):
            raise SecureProcessingError("Invalid input type.")
        if len(json_string) > 10_000:
            raise SecureProcessingError("Input exceeds maximum allowed size.")
        if "�" in json_string:
            raise SecureProcessingError("Input contains null byte.")
        return json.loads(json_string)
    except json.JSONDecodeError as e:
        _raise_secure(e)
    except SecureProcessingError:
        raise
    except Exception as e:
        _raise_secure(e)

import os
import sys
import pathlib
import ast
import logging

logger = logging.getLogger(__name__)

_DEFAULT_MAX_CONFIG_SIZE = 1 * 1024 * 1024  # 1â¯MiB
_MAX_CONFIG_SIZE_ENV = "MAX_CONFIG_SIZE"
_MAX_NESTING = 10  # maximum allowed literal nesting depth
_MAX_ALLOWED_SIZE = 10 * 1024 * 1024  # 10â¯MiB upper bound for env override


def _get_max_config_size() -> int:
    """Determine the maximum allowed config size, respecting an environment variable."""
    env_val = os.getenv(_MAX_CONFIG_SIZE_ENV)
    if env_val:
        try:
            size = int(env_val)
            # Enforce lower bound of 1 byte and upper bound of 10â¯MiB
            return max(1, min(size, _MAX_ALLOWED_SIZE))
        except (ValueError, TypeError):
            logger.debug("Invalid %s value; using default size.", _MAX_CONFIG_SIZE_ENV)
    return _DEFAULT_MAX_CONFIG_SIZE


def _safe_literal(node: ast.AST, _depth: int = 0):
    """Recursively evaluate an AST node using only safe literal structures."""
    if _depth > _MAX_NESTING:
        raise ValueError("Exceeded maximum literal nesting depth")
    if isinstance(node, ast.Constant):
        return node.value
    if isinstance(node, ast.Tuple):
        return tuple(_safe_literal(elt, _depth + 1) for elt in node.elts)
    if isinstance(node, ast.List):
        return [_safe_literal(elt, _depth + 1) for elt in node.elts]
    if isinstance(node, ast.Dict):
        return {
            _safe_literal(k, _depth + 1): _safe_literal(v, _depth + 1)
            for k, v in zip(node.keys, node.values)
        }
    if isinstance(node, ast.UnaryOp) and isinstance(node.op, (ast.UAdd, ast.USub)):
        operand = _safe_literal(node.operand, _depth + 1)
        return +operand if isinstance(node.op, ast.UAdd) else -operand
    if isinstance(node, ast.BinOp) and isinstance(
        node.op, (ast.Add, ast.Sub, ast.Mult, ast.Div, ast.Mod, ast.Pow)
    ):
        left = _safe_literal(node.left, _depth + 1)
        right = _safe_literal(node.right, _depth + 1)
        return {
            ast.Add: lambda a, b: a + b,
            ast.Sub: lambda a, b: a - b,
            ast.Mult: lambda a, b: a * b,
            ast.Div: lambda a, b: a / b,
            ast.Mod: lambda a, b: a % b,
            ast.Pow: lambda a, b: a ** b,
        }[type(node.op)](left, right)
    raise ValueError("Unsupported expression in configuration")


def load_config(file_path: str, silent: bool = False) -> bool:
    """Load configuration from a file containing only simple assignments.
    Returns True on success, False on failure.
    """
    # Input validation
    if not isinstance(file_path, str) or not file_path or "�" in file_path:
        if not silent:
            sys.stderr.write("Failed to load configuration.
")
        return False

    try:
        base_dir = pathlib.Path.cwd().resolve()
        abs_path = pathlib.Path(file_path).resolve()
    except Exception as exc:
        logger.debug("Path resolution error: %s", exc)
        if not silent:
            sys.stderr.write("Failed to load configuration.
")
        return False

    # Ensure the target file resides inside the current working directory
    try:
        if hasattr(abs_path, "is_relative_to"):
            if not abs_path.is_relative_to(base_dir):
                raise ValueError("Path outside allowed directory")
        else:
            # Fallback for Python <3.9
            if not str(abs_path).startswith(str(base_dir) + os.sep):
                raise ValueError("Path outside allowed directory")
    except Exception:
        if not silent:
            sys.stderr.write("Failed to load configuration.
")
        return False

    # Verify file existence
    if not abs_path.is_file():
        if not silent:
            sys.stderr.write("Failed to load configuration.
")
        return False

    # Verify size limits
    max_size = _get_max_config_size()
    try:
        if abs_path.stat().st_size > max_size:
            if not silent:
                sys.stderr.write("Failed to load configuration.
")
            return False
    except Exception as exc:
        logger.debug("File stat error: %s", exc)
        if not silent:
            sys.stderr.write("Failed to load configuration.
")
        return False

    # Read file contents
    try:
        code = abs_path.read_text(encoding="utf-8")
    except Exception as exc:
        logger.debug("File read error: %s", exc)
        if not silent:
            sys.stderr.write("Failed to load configuration.
")
        return False

    # Parse and evaluate assignments safely
    try:
        tree = ast.parse(code, filename=str(abs_path), mode="exec")
        for stmt in tree.body:
            if isinstance(stmt, ast.Assign):
                if (
                    len(stmt.targets) != 1
                    or not isinstance(stmt.targets[0], ast.Name)
                ):
                    raise ValueError("Invalid assignment target")
                var_name = stmt.targets[0].id
                try:
                    var_value = _safe_literal(stmt.value)
                except RecursionError as exc:
                    raise ValueError("Literal nesting too deep") from exc
                # Placeholder for future use; currently ignored
                _ = (var_name, var_value)
            elif isinstance(stmt, ast.Expr) and isinstance(stmt.value, ast.Constant):
                # Allow module docstring or stray literals; ignore safely
                continue
            else:
                raise ValueError("Unsupported statement in configuration")
    except Exception as exc:
        logger.debug("Configuration parsing error: %s", exc)
        if not silent:
            sys.stderr.write("Failed to load configuration.
")
        return False

    return True

import os
import sys
import logging
import ast
import multiprocessing
import threading
import platform
from types import MappingProxyType
from queue import Empty

# Ensure required thirdâparty dependencies are present
try:
    import psutil  # required for memory monitoring
except ImportError as exc:
    raise RuntimeError(
        "The psutil library is required for memory monitoring. Install it before running."
    ) from exc

# Configure logging securely
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler(sys.stdout)],
)

# Whitelisted snippet identifiers and their source code (immutable)
SNIPPETS = MappingProxyType(
    {
        "hello_world": "print('Hello, world!')",
        "calc_sum": "result = sum([1, 2, 3, 4, 5])
print('Sum:', result)",
    }
)

# Minimal allowed builtâins for snippet execution
_ALLOWED_BUILTINS = MappingProxyType(
    {
        "print": print,
        "sum": sum,
        "range": range,
        "len": len,
    }
)

# Development mode toggle (should be False in production)
DEV_MODE = os.getenv("DEV_MODE", "false").lower() == "true"


def _sanitize_flag(flag: str) -> str:
    if not isinstance(flag, str):
        raise ValueError("Flag must be a string")
    flag = flag.strip()
    if len(flag) > 64:
        raise ValueError("Flag too long")
    if flag not in SNIPPETS:
        raise ValueError("Invalid snippet identifier")
    return flag


# Whitelist of AST node types that are considered safe
_ALLOWED_AST_NODES = (
    ast.Module,
    ast.Expr,
    ast.Assign,
    ast.AugAssign,
    ast.AnnAssign,
    ast.Name,
    ast.Load,
    ast.Store,
    ast.Constant,
    ast.BinOp,
    ast.UnaryOp,
    ast.BoolOp,
    ast.Compare,
    ast.Call,
    ast.If,
    ast.While,
    ast.For,
    ast.Break,
    ast.Continue,
    ast.Pass,
    ast.Return,
    ast.List,
    ast.Tuple,
    ast.Dict,
    ast.Set,
)


def _is_safe_snippet(snippet: str) -> bool:
    try:
        tree = ast.parse(snippet, mode="exec")
    except SyntaxError:
        return False

    for node in ast.walk(tree):
        if not isinstance(node, _ALLOWED_AST_NODES):
            return False

        if isinstance(node, ast.Call):
            # Only allow calls to whitelisted builtâins
            if isinstance(node.func, ast.Name):
                if node.func.id not in _ALLOWED_BUILTINS:
                    return False
            else:
                return False

    return True


# Validate all hardâcoded snippets at import time
for _id, _code in SNIPPETS.items():
    if not _is_safe_snippet(_code):
        raise RuntimeError(f"Unsafe snippet detected in whitelist: {_id}")


def _apply_unix_limits() -> None:
    if platform.system() != "Linux" and platform.system() != "Darwin":
        raise RuntimeError("Resource limits are only supported on Unix platforms.")
    try:
        import resource

        # CPU time limit: 2 seconds
        resource.setrlimit(resource.RLIMIT_CPU, (2, 2))
        # Memory limit: 50â¯MiB
        mem_limit = 50 * 1024 * 1024
        resource.setrlimit(resource.RLIMIT_AS, (mem_limit, mem_limit))
    except Exception as exc:
        raise RuntimeError(f"Failed to apply Unix resource limits: {exc}") from exc


def _monitor_memory(pid: int, mem_limit: int, stop_event: threading.Event) -> None:
    try:
        proc = psutil.Process(pid)
        while not stop_event.is_set():
            try:
                rss = proc.memory_info().rss
                if rss > mem_limit:
                    logging.warning(
                        "Memory limit exceeded (%.2fâ¯MiB > %.2fâ¯MiB). Terminating.",
                        rss / (1024 * 1024),
                        mem_limit / (1024 * 1024),
                    )
                    proc.terminate()
                    break
            except psutil.NoSuchProcess:
                break
            stop_event.wait(0.1)
    except Exception as exc:
        logging.debug("Memory monitor failed: %s", exc)


def _execute_snippet(snippet: str) -> None:
    if not _is_safe_snippet(snippet):
        raise ValueError("Snippet contains disallowed constructs")
    safe_globals = {"__builtins__": _ALLOWED_BUILTINS}
    _apply_unix_limits()
    exec(snippet, safe_globals, {})


def _run_snippet_in_process(snippet: str) -> None:
    def target(q):
        try:
            _execute_snippet(snippet)
            q.put((True, None))
        except Exception as e:
            q.put((False, str(e)))

    queue = multiprocessing.Queue()
    proc = multiprocessing.Process(target=target, args=(queue,))
    proc.start()

    # Memory monitoring (crossâplatform)
    stop_event = threading.Event()
    mem_limit = 50 * 1024 * 1024  # 50â¯MiB
    monitor_thread = threading.Thread(
        target=_monitor_memory, args=(proc.pid, mem_limit, stop_event), daemon=True
    )
    monitor_thread.start()

    proc.join(5)  # timeout in seconds
    stop_event.set()
    monitor_thread.join()

    if proc.is_alive():
        proc.terminate()
        proc.join()
        logging.error("Snippet execution timed out")
        return

    try:
        success, detail = queue.get(timeout=2)
    except Empty:
        logging.error("Snippet process exited without returning a result")
        return

    if not success:
        logging.error("Snippet execution failed: %s", detail)


def load_and_run(flag: str) -> None:
    try:
        sanitized_flag = _sanitize_flag(flag)
        snippet_code = SNIPPETS[sanitized_flag]
        _run_snippet_in_process(snippet_code)
    except Exception as exc:
        logging.error("Error processing flag: %s", exc)


def _development_code() -> None:
    logging.info("Running development code")
    sample_data = {"a": 1, "b": 2}
    logging.debug("Sample data: %s", sample_data)


if __name__ == "__main__":
    input_flag = os.getenv("SNIPPET_FLAG", "")
    if input_flag:
        load_and_run(input_flag)
    else:
        logging.warning("No SNIPPET_FLAG provided")
    if DEV_MODE:
        _development_code()

import ast
import math
import logging
from typing import Any, Callable, Mapping

# Configuration constants
MAX_ABS_NUMERIC_VALUE = 10 ** 12          # Upper bound for numeric results
MAX_CONTAINER_SIZE = 1000                # Maximum length of any list/tuple created
MAX_SHIFT_AMOUNT = 1_000_000              # Upper bound for shift counts
MAX_POWER_EXPONENT = 30                   # Upper bound for exponent values

# Configure logger (sanitize output)
logger = logging.getLogger(__name__)
if not logger.handlers:
    handler = logging.StreamHandler()
    formatter = logging.Formatter("%(asctime)s - %(levelname)s - %(message)s")
    handler.setFormatter(formatter)
    logger.addHandler(handler)
logger.setLevel(logging.ERROR)


def _check_numeric(value: Any) -> Any:
    """Enforce numeric limits on integers and floats."""
    if isinstance(value, (int, float)):
        if abs(value) > MAX_ABS_NUMERIC_VALUE:
            raise ValueError("Numeric result out of allowed range")
    return value


def _safe_pow(base: Any, exp: Any) -> Any:
    if not isinstance(exp, int):
        raise ValueError("Exponent must be an integer")
    if exp < 0:
        raise ValueError("Negative exponents are not allowed")
    if exp > MAX_POWER_EXPONENT:
        raise ValueError("Exponent too large")
    return _check_numeric(pow(base, exp))


def _safe_lshift(val: Any, shift: Any) -> Any:
    if not isinstance(shift, int):
        raise ValueError("Shift amount must be an integer")
    if shift < 0 or shift > MAX_SHIFT_AMOUNT:
        raise ValueError("Shift amount out of allowed range")
    return _check_numeric(val << shift)


def _safe_rshift(val: Any, shift: Any) -> Any:
    if not isinstance(shift, int):
        raise ValueError("Shift amount must be an integer")
    if shift < 0 or shift > MAX_SHIFT_AMOUNT:
        raise ValueError("Shift amount out of allowed range")
    return _check_numeric(val >> shift)


def _safe_mult(left: Any, right: Any) -> Any:
    # Guard container multiplication for size explosion
    if isinstance(left, (list, tuple, str)) and isinstance(right, int):
        if len(left) * right > MAX_CONTAINER_SIZE:
            raise ValueError("Resulting container would be too large")
    if isinstance(right, (list, tuple, str)) and isinstance(left, int):
        if len(right) * left > MAX_CONTAINER_SIZE:
            raise ValueError("Resulting container would be too large")
    return _check_numeric(left * right)


def _safe_sorted(iterable: Any, *args, **kwargs) -> Any:
    try:
        length = len(iterable)
    except Exception:
        raise ValueError("Object passed to sorted must have a length")
    if length > MAX_CONTAINER_SIZE:
        raise ValueError("Sequence too large for sorted")
    return sorted(iterable, *args, **kwargs)


class SafeExpressionEvaluator(ast.NodeVisitor):
    """
    Recursively evaluate a whitelist of safe AST nodes.
    """

    _allowed_binops: Mapping[type, Callable[[Any, Any], Any]] = {
        ast.Add: lambda a, b: _check_numeric(a + b),
        ast.Sub: lambda a, b: _check_numeric(a - b),
        ast.Mult: _safe_mult,
        ast.Div: lambda a, b: _check_numeric(a / b),
        ast.FloorDiv: lambda a, b: _check_numeric(a // b),
        ast.Mod: lambda a, b: _check_numeric(a % b),
        ast.Pow: _safe_pow,
        ast.LShift: _safe_lshift,
        ast.RShift: _safe_rshift,
        ast.BitOr: lambda a, b: _check_numeric(a | b),
        ast.BitXor: lambda a, b: _check_numeric(a ^ b),
        ast.BitAnd: lambda a, b: _check_numeric(a & b),
    }

    _allowed_unaryops: Mapping[type, Callable[[Any], Any]] = {
        ast.UAdd: lambda a: +a,
        ast.USub: lambda a: -a,
        ast.Invert: lambda a: ~a,
        ast.Not: lambda a: not a,
    }

    def __init__(self, name_map: dict):
        self.name_map = name_map

    def visit(self, node: ast.AST) -> Any:
        method = f"visit_{node.__class__.__name__}"
        visitor = getattr(self, method, self.generic_visit)
        return visitor(node)

    def visit_Expression(self, node: ast.Expression) -> Any:
        return self.visit(node.body)

    def visit_Constant(self, node: ast.Constant) -> Any:
        return node.value

    # Compatibility for older Python versions
    def visit_Num(self, node: ast.Num) -> Any:  # pragma: no cover
        return node.n

    def visit_Str(self, node: ast.Str) -> Any:  # pragma: no cover
        return node.s

    def visit_Name(self, node: ast.Name) -> Any:
        if isinstance(node.ctx, ast.Load):
            if node.id in self.name_map:
                return self.name_map[node.id]
            raise NameError(f"Name '{node.id}' is not allowed")
        raise ValueError("Invalid context for Name node")

    def visit_Call(self, node: ast.Call) -> Any:
        if not isinstance(node.func, ast.Name):
            raise ValueError("Only direct function calls are allowed")
        func_name = node.func.id
        if func_name not in self.name_map:
            raise NameError(f"Function '{func_name}' is not allowed")
        func = self.name_map[func_name]
        args = [self.visit(arg) for arg in node.args]
        kwargs = {
            kw.arg: self.visit(kw.value) for kw in node.keywords if kw.arg is not None
        }
        return func(*args, **kwargs)

    def visit_BinOp(self, node: ast.BinOp) -> Any:
        op_type = type(node.op)
        if op_type not in self._allowed_binops:
