}

_ALLOWED_UNITS = {"hex", "bytes", "base64", "int"}

MAX_STRINGS = 10_000
MAX_BYTES_PER_STRING = 1_048_576  # 1â¯MiB


def _validate_strings(strings: Iterable) -> List[bytes]:
    if not isinstance(strings, (list, tuple)):
        raise TypeError("Input must be a list or tuple of strings.")
    if len(strings) > MAX_STRINGS:
        raise ValueError("Too many strings provided.")
    encoded: List[bytes] = []
    for item in strings:
