import hashlib
import re
import errno
import stat
import shlex
import tempfile

class SingleInstanceError(Exception):
    """Raised when another instance of the process is already running."""
    pass

def _sanitize_process_name(name: str) -> str:
    if not isinstance(name, str):
        raise ValueError("Process name must be a string")
    if not re.fullmatch(r"[A-Za-z0-9._-]+", name):
        raise ValueError("Invalid process name")
    return name

def _hash_args(args):
    if not isinstance(args, (list, tuple)):
        raise ValueError("Args must be a list or tuple")
    hasher = hashlib.sha256()
    for arg in args:
        if not isinstance(arg, str):
            raise ValueError("All command line arguments must be strings")
        hasher.update(arg.encode('utf-8') + b'�')
    return hasher.hexdigest()

def _secure_pidfile_dir() -> str:
    """Return a directory that is private to the current user and suitable for pidfiles."""
    xdg = os.getenv("XDG_RUNTIME_DIR")
    if xdg:
        try:
            st = os.stat(xdg)
            if (stat.S_ISDIR(st.st_mode) and
                st.st_uid == os.getuid() and
                (st.st_mode & (stat.S_IRWXG | stat.S_IRWXO)) == 0):
                return xdg
        except OSError:
            pass

    run_user = f"/run/user/{os.getuid()}"
    try:
        st = os.stat(run_user)
        if (stat.S_ISDIR(st.st_mode) and
            st.st_uid == os.getuid() and
            (st.st_mode & (stat.S_IRWXG | stat.S_IRWXO)) == 0):
            return run_user
    except OSError:
        pass

    fallback = os.path.join(tempfile.gettempdir(), f"singleinstance_{os.getuid()}")
    try:
        os.mkdir(fallback, mode=0o700)
    except FileExistsError:
        st = os.lstat(fallback)
        if not stat.S_ISDIR(st.st_mode) or stat.S_ISLNK(st.st_mode):
            raise RuntimeError("Insecure fallback pidfile directory")
    else:
        st = os.stat(fallback)
        if (st.st_uid != os.getuid() or
            (st.st_mode & (stat.S_IRWXG | stat.S_IRWXO)) != 0):
            raise RuntimeError("Insecure fallback pidfile directory")
    return fallback

def _pidfile_path(process_name: str, args_hash: str) -> str:
    runtime_dir = _secure_pidfile_dir()
    filename = f"{process_name}_{args_hash}.pid"
    return os.path.join(runtime_dir, filename)

def _write_pidfile(path: str, pid: int):
    flags = os.O_WRONLY | os.O_CREAT | os.O_EXCL | getattr(os, "O_NOFOLLOW", 0)
    mode = 0o600
    fd = None
    try:
        fd = os.open(path, flags, mode)
        with os.fdopen(fd, "w") as f:
            f.write(str(pid))
        fd = None
    except OSError as e:
        if e.errno == errno.EEXIST:
            raise
        if hasattr(errno, "ELOOP") and e.errno == errno.ELOOP:
            raise SingleInstanceError("Invalid pidfile path")
        raise
    finally:
        if fd is not None:
            os.close(fd)

def _read_pidfile_secure(path: str) -> int:
    flags = os.O_RDONLY | getattr(os, "O_NOFOLLOW", 0)
    fd = None
    try:
        fd = os.open(path, flags)
        st = os.fstat(fd)

        if not stat.S_ISREG(st.st_mode):
            raise SingleInstanceError("Invalid pidfile")
        if st.st_uid != os.getuid():
            raise SingleInstanceError("Invalid pidfile")
        max_size = 64
        if st.st_size > max_size:
            raise SingleInstanceError("Invalid pidfile")
        content = b""
        while len(content) < max_size:
            chunk = os.read(fd, max_size - len(content))
            if not chunk:
                break
            content += chunk
        if not content:
            raise SingleInstanceError("Invalid pidfile")
        return int(content.strip())
    except (OSError, ValueError) as e:
        raise SingleInstanceError("Invalid pidfile") from e
    finally:
        if fd is not None:
            os.close(fd)

def _is_process_running(pid: int) -> bool:
    try:
        os.kill(pid, 0)
    except OSError as e:
        if e.errno == errno.ESRCH:
            return False
        if e.errno == errno.EPERM:
            return True
        raise
    return True

def ensure_single_instance(process_name: str, cmd_args) -> tuple[int, str, str]:
    name = _sanitize_process_name(process_name)
    args_hash = _hash_args(cmd_args)
    pidfile = _pidfile_path(name, args_hash)

