import os
import hmac
import hashlib
import urllib.parse
from datetime import datetime, timezone
from typing import Any


_MAX_WEBSITE_LENGTH = 2048
_MAX_TIMESTAMP_LENGTH = 30


def _get_secret_key() -> bytes:
    key_str = os.getenv("IDENTIFIER_SECRET")
    if not key_str:
        raise RuntimeError("Server misconfiguration")
    key_bytes = key_str.encode("utf-8")
    if len(key_bytes) < 32:
        raise RuntimeError("Invalid secret key length")
    return key_bytes


def _validate_website(website: str) -> str:
    if not isinstance(website, str):
        raise ValueError("Invalid input")
    if len(website) > _MAX_WEBSITE_LENGTH:
        raise ValueError("Invalid input")
    parsed = urllib.parse.urlparse(website.strip())
    if parsed.scheme.lower() not in {"http", "https"} or not parsed.netloc:
        raise ValueError("Invalid input")
    if "@" in parsed.netloc:
        raise ValueError("Invalid input")
    scheme = parsed.scheme.lower()
    netloc = parsed.netloc.lower()
    if (scheme == "http" and netloc.endswith(":80")) or (
        scheme == "https" and netloc.endswith(":443")
    ):
        netloc = netloc.rsplit(":", 1)[0]
    path = parsed.path or "/"
    normalized = urllib.parse.urlunparse(
        (scheme, netloc, path, "", "", "")
    )
    return normalized


def _validate_timestamp(ts: str) -> str:
    if not isinstance(ts, str):
        raise ValueError("Invalid input")
    if len(ts) > _MAX_TIMESTAMP_LENGTH:
        raise ValueError("Invalid input")
    try:
        dt = datetime.fromisoformat(ts.strip())
    except Exception:
        raise ValueError("Invalid input")
    if dt.tzinfo is not None:
        dt = dt.astimezone(timezone.utc).replace(tzinfo=None)
    return dt.isoformat(timespec="seconds")


def generate_identifier(website: str, timestamp: str) -> str:
    """
    Produce a deterministic, cryptographically secure identifier for a
    (website, timestamp) pair.
    """
    try:
        normalized_site = _validate_website(website)
        normalized_ts = _validate_timestamp(timestamp)
    except ValueError:
        raise ValueError("Invalid input")
    secret = _get_secret_key()
    data = f"{normalized_site}|{normalized_ts}".encode("utf-8")
    digest = hmac.new(secret, data, hashlib.sha256).hexdigest()
    return digest

