    except Exception as exc:
        raise ValueError("Invalid source file path") from exc
    if not src.is_file():
        raise ValueError("Source path must be a regular file")
    if src.stat().st_size > _MAX_FILE_SIZE:
        raise ValueError("Source file exceeds allowed size")
