    if Path(name).name != name:
        raise ValueError("ZIP file name must not contain path separators")
    if not name.lower().endswith(_ALLOWED_ZIP_SUFFIX):
        raise ValueError(f"ZIP file name must end with '{_ALLOWED_ZIP_SUFFIX}'")
    return name


def _prepare_destination_dir(dest: str) -> Path:
    try:
        dest_path = Path(dest).resolve()
    except Exception as exc:
        raise ValueError("Invalid destination directory") from exc
    if dest_path.is_symlink():
        raise ValueError("Destination directory must not be a symbolic link")
