import subprocess
import pathlib
import shutil
import traceback
import logging

# Setup secure logger
log_path = "/var/log/script_secure.log"
logger = logging.getLogger("secure_script")
logger.setLevel(logging.INFO)
handler = logging.FileHandler(log_path) if os.access(os.path.dirname(log_path), os.W_OK) else logging.StreamHandler(sys.stderr)
formatter = logging.Formatter("%(asctime)s %(levelname)s %(message)s")
handler.setFormatter(formatter)
logger.addHandler(handler)

# Verify required OS feature
if not hasattr(os, "O_NOFOLLOW"):
    logger.critical("O_NOFOLLOW not supported on this platform. Exiting.")
    raise RuntimeError("Platform does not support required O_NOFOLLOW flag.")

# Determine a safe absolute path to the `date` binary.
SAFE_PATHS = "/usr/bin:/bin"
_DATE_BIN = shutil.which("date", path=SAFE_PATHS)
if not _DATE_BIN:
    logger.critical("Unable to locate trusted 'date' binary.")
    raise RuntimeError("Unable to locate trusted 'date' binary.")

# Verify binary integrity: owned by root and not writable by group/others
def _verify_binary(path: str) -> None:
    try:
        st = os.stat(path)
        if st.st_uid != 0:
            raise PermissionError("Binary is not owned by root.")
        if st.st_mode & (stat.S_IWGRP | stat.S_IWOTH):
            raise PermissionError("Binary is writable by group/others.")
    except OSError as e:
        raise RuntimeError("Failed to stat the binary.") from e

_verify_binary(_DATE_BIN)

ALLOWED_BASE = pathlib.Path(__file__).resolve().parent

def _run_date_command(args):
    """Execute a date command safely and return its stripped output."""
    if not args or args[0] != _DATE_BIN:
        raise ValueError("Invalid command for date execution.")
    try:
        result = subprocess.run(
            args,
            capture_output=True,
            text=True,
            check=True,
        )
        output = result.stdout
        if not output:
            raise RuntimeError("Empty output from date command")
        return output.strip()
    except subprocess.CalledProcessError as e:
        raise RuntimeError("Failed to execute date command") from e

def get_current_date():
    """Return (year, month, day) for today using the date command."""
    output = _run_date_command([_DATE_BIN, "+%Y %m %d"])
    parts = output.split()
    if len(parts) != 3:
        raise ValueError("Unexpected format from date command")
    return tuple(parts)

MAX_DAYS_OFFSET = 3650  # 10 years

def get_past_date(days: int):
    """Return (year, month, day) for the date 'days' ago using the date command."""
    if days < 0:
        raise ValueError("Days offset must be non-negative")
    if days > MAX_DAYS_OFFSET:
        raise ValueError(f"Days offset exceeds maximum allowed ({MAX_DAYS_OFFSET})")
    command = [_DATE_BIN, "-d", f"-{days} days", "+%Y %m %d"]
    output = _run_date_command(command)
    parts = output.split()
    if len(parts) != 3:
        raise ValueError("Unexpected format from date command")
    return tuple(parts)

def _open_file_no_follow(path: pathlib.Path):
    """Open a file descriptor without following symlinks and verify it's not a symlink."""
    flags = os.O_RDONLY | os.O_CLOEXEC | os.O_NOFOLLOW
    try:
        fd = os.open(str(path), flags)
    except FileNotFoundError as e:
        raise FileNotFoundError("Specified file does not exist") from e
    except IsADirectoryError as e:
        raise IsADirectoryError("Specified path is a directory") from e
    except PermissionError as e:
        raise PermissionError("Permission denied when accessing the file") from e
    except OSError as e:
        raise RuntimeError("Unable to open the file securely") from e

    # Verify descriptor does not refer to a symlink (race condition mitigation)
    try:
        st = os.fstat(fd)
        if stat.S_ISLNK(st.st_mode):
            os.close(fd)
            raise PermissionError("Symlinked files are not allowed")
    except OSError as e:
        os.close(fd)
        raise RuntimeError("Failed to stat opened file.") from e

    return fd

def read_last_entry(file_path: str) -> str:
    """Read the last non-empty line from a file and ensure it matches YYYYMMDD."""
    # Resolve to absolute path without following symlinks
    path = pathlib.Path(file_path).absolute()

    # Ensure the path is within the allowed base directory
    try:
        path.relative_to(ALLOWED_BASE)
    except ValueError as e:
        raise PermissionError("Access to the specified file is not allowed") from e

    fd = _open_file_no_follow(path)
    try:
        with os.fdopen(fd, "r", encoding="utf-8") as f:
            last_valid = None
            for line in f:
                entry = line.strip()
                if entry:
                    if not re.fullmatch(r"\d{8}", entry):
                        raise ValueError("File entry does not match YYYYMMDD format")
                    last_valid = entry
            if last_valid is None:
                raise ValueError("File contains no valid entries")
            return last_valid
    finally:
        # fd is closed automatically by fdopen context manager
        pass

def parse_yyyymmdd(entry: str):
    """Extract year, month, day strings from a YYYYMMDD entry."""
    return entry[0:4], entry[4:6], entry[6:8]

def main():
    if len(sys.argv) != 3:
        print("Usage: script.py <days_offset> <file_path>", file=sys.stderr)
        sys.exit(1)

    try:
        days_offset = int(sys.argv[1])
        if days_offset < 0:
            raise ValueError()
        if days_offset > MAX_DAYS_OFFSET:
            raise ValueError()
    except ValueError:
        print("Invalid days offset; must be a non-negative integer within allowed range.", file=sys.stderr)
        sys.exit(1)

    file_path = sys.argv[2]

    try:
        cur_year, cur_month, cur_day = get_current_date()
        past_year, past_month, past_day = get_past_date(days_offset)
        last_entry = read_last_entry(file_path)
        entry_year, entry_month, entry_day = parse_yyyymmdd(last_entry)

        print(f"Current date: {cur_year}-{cur_month}-{cur_day}")
        print(f"Date {days_offset} days ago: {past_year}-{past_month}-{past_day}")
        print(f"Last file entry: {entry_year}-{entry_month}-{entry_day}")

    except Exception as e:
        if os.getenv("SCRIPT_DEBUG") == "1":
            traceback.print_exc()
        else:
            logger.error("Error processing request: %s", str(e))
            print("An error occurred while processing the request.", file=sys.stderr)
        sys.exit(1)

