import argparse
import json
import logging
import os
import pathlib
import shutil
import socket
import sys
import tarfile
import tempfile
import urllib.parse
import urllib.request
import urllib.error
import zipfile
import ipaddress

# Configure minimal logging
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler(sys.stderr)],
)
logger = logging.getLogger(__name__)

MAX_DOWNLOAD_SIZE = 100 * 1024 * 1024      # 100â¯MiB
MAX_EXTRACT_SIZE = 500 * 1024 * 1024      # 500â¯MiB
MAX_EXTRACT_FILES = 10_000                # Prevent zipâbomb style attacks
MAX_REDIRECTS = 5                         # Limit redirect chain length


def _is_private_ip(host: str) -> bool:
    try:
        infos = socket.getaddrinfo(host, None)
    except socket.gaierror:
        return True
    for info in infos:
        ip = info[4][0]
        try:
            ip_obj = ipaddress.ip_address(ip)
            if ip_obj.is_private:
                return True
        except (ValueError, ipaddress.AddressValueError):
            continue
    return False


def _assert_not_private_ip(url: str) -> None:
    """Reâresolve the hostname at request time and ensure it is not private."""
    parsed = urllib.parse.urlparse(url)
    host = parsed.hostname or ""
    if _is_private_ip(host):
        raise ValueError(f"URL resolves to a private or unresolvable host: {url}")


def validate_url(url: str) -> str:
    """Validate URL scheme, netloc, enforce HTTPS and block private IPs."""
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme != "https":
        raise ValueError(f"Only HTTPS URLs are allowed: {url}")
    if not parsed.netloc:
        raise ValueError(f"Invalid URL netloc in '{url}'")
    host = parsed.hostname or ""
    if _is_private_ip(host):
        raise ValueError(f"URL points to a private or unresolvable host: {url}")
    return url


def _redacted_url(url: str) -> str:
    p = urllib.parse.urlparse(url)
    return f"{p.scheme}://{p.netloc}{p.path}"


class NoRedirectHandler(urllib.request.HTTPRedirectHandler):
    def redirect_request(self, req, fp, code, msg, hdrs, newurl):
        raise urllib.error.HTTPError(req.full_url, code, "Redirect blocked", hdrs, fp)


def _open_url_no_redirect(url: str):
    opener = urllib.request.build_opener(NoRedirectHandler)
    return opener.open(url, timeout=30)


def download_file(url: str, dest_path: pathlib.Path) -> None:
    """Download a file with size limit, strict redirect handling and set restrictive permissions."""
    current_url = validate_url(url)
    redirects = 0
    while True:
        # Ensure the resolved IP is still public just before the request
        _assert_not_private_ip(current_url)

        try:
            with _open_url_no_redirect(current_url) as response, open(dest_path, "wb") as out_file:
                total = 0
                while True:
                    chunk = response.read(8192)
                    if not chunk:
                        break
                    total += len(chunk)
                    if total > MAX_DOWNLOAD_SIZE:
                        raise ValueError("Download exceeds maximum allowed size")
                    out_file.write(chunk)
            os.chmod(dest_path, 0o600)
            break
        except urllib.error.HTTPError as e:
            if 300 <= e.code < 400:
                if redirects >= MAX_REDIRECTS:
                    raise ValueError("Too many redirects")
                location = e.headers.get("Location")
                if not location:
                    raise ValueError("Redirect response missing Location header")
                new_url = urllib.parse.urljoin(current_url, location)
                current_url = validate_url(new_url)
                redirects += 1
                continue
            else:
                logger.error("HTTP error while downloading %s: %s", _redacted_url(url), e)
                raise
        except Exception as e:
            logger.error("Failed to download %s: %s", _redacted_url(url), e)
            raise


def _extract_tar_member(tar: tarfile.TarFile, member: tarfile.TarInfo,
                        dest_dir: pathlib.Path, extracted_so_far: int,
                        file_count: int) -> tuple[int, int]:
    member_path = (dest_dir / member.name).resolve()
    if not member_path.is_relative_to(dest_dir.resolve()):
        raise ValueError("Tar archive contains unsafe path")
    if member.islnk() or member.issym():
        raise ValueError("Symlinks are not allowed in tar archives")
    if member.type not in (tarfile.REGTYPE,):
        raise ValueError("Non-regular file types are not allowed in tar archives")
    if member.size + extracted_so_far > MAX_EXTRACT_SIZE:
        raise ValueError("Extraction exceeds maximum allowed size")
    if file_count + 1 > MAX_EXTRACT_FILES:
        raise ValueError("Extraction exceeds maximum file count")

    # Extract the file data manually to control permissions
    if member.isdir():
        member_path.mkdir(parents=True, exist_ok=True)
        os.chmod(member_path, 0o700)
    else:
        member_path.parent.mkdir(parents=True, exist_ok=True)
        with tar.extractfile(member) as src, open(member_path, "wb") as dst:
            shutil.copyfileobj(src, dst)
        os.chmod(member_path, 0o600)

    return extracted_so_far + member.size, file_count + 1


def safe_extract_tar(tar_path: pathlib.Path, dest_dir: pathlib.Path) -> None:
    extracted = 0
    file_count = 0
    with tarfile.open(tar_path) as tar:
        for member in tar.getmembers():
            extracted, file_count = _extract_tar_member(
                tar, member, dest_dir, extracted, file_count
            )


def _is_zip_symlink(zip_info: zipfile.ZipInfo) -> bool:
    return (zip_info.external_attr >> 16) & 0o120000 == 0o120000


def safe_extract_zip(zip_path: pathlib.Path, dest_dir: pathlib.Path) -> None:
    extracted = 0
    file_count = 0
    with zipfile.ZipFile(zip_path, "r") as zip_ref:
        for info in zip_ref.infolist():
            target_path = (dest_dir / info.filename).resolve()
            if not target_path.is_relative_to(dest_dir.resolve()):
                raise ValueError("Zip archive contains unsafe path")
            if _is_zip_symlink(info):
                raise ValueError("Symlinks are not allowed in zip archives")
            if info.file_size + extracted > MAX_EXTRACT_SIZE:
                raise ValueError("Extraction exceeds maximum allowed size")
            if file_count + 1 > MAX_EXTRACT_FILES:
                raise ValueError("Extraction exceeds maximum file count")
            if info.is_dir():
                target_path.mkdir(parents=True, exist_ok=True)
                os.chmod(target_path, 0o700)
            else:
                target_path.parent.mkdir(parents=True, exist_ok=True)
                with target_path.open("wb") as f:
                    f.write(zip_ref.read(info))
                os.chmod(target_path, 0o600)
                extracted += info.file_size
            file_count += 1


def extract_archive(archive_path: pathlib.Path, dest_dir: pathlib.Path) -> None:
    name = archive_path.name.lower()
    if name.endswith(".zip"):
        safe_extract_zip(archive_path, dest_dir)
    elif any(name.endswith(ext) for ext in (".tar.gz", ".tgz", ".tar", ".tar.bz2", ".tbz")):
        safe_extract_tar(archive_path, dest_dir)
    else:
        raise ValueError(f"Unsupported archive format: {archive_path.name}")


def move_contents(src_dir: pathlib.Path, dst_dir: pathlib.Path) -> None:
    for item in src_dir.iterdir():
        target = dst_dir / item.name
        if target.exists():
            if target.is_dir():
                shutil.rmtree(target)
            else:
                target.unlink()
        shutil.move(str(item), str(target))


def process_product(product: str, packages: list, build_dir: pathlib.Path) -> None:
    staging_dir = safe_join(build_dir, product, "staging")
    final_dir = safe_join(build_dir, product, "final")
    os.makedirs(staging_dir, mode=0o700, exist_ok=False)
    os.makedirs(final_dir, mode=0o700, exist_ok=False)

    for pkg_url in packages:
        try:
            url = validate_url(pkg_url)
            parsed = urllib.parse.urlparse(url)
            filename = urllib.parse.unquote(os.path.basename(parsed.path))
            if not filename:
                raise ValueError(f"Cannot determine filename from URL: {url}")
            download_path = safe_join(staging_dir, filename)

            logger.info("Downloading %s", _redacted_url(url))
            download_file(url, download_path)

            with tempfile.TemporaryDirectory(dir=staging_dir) as tmp_extract:
                extract_dir = pathlib.Path(tmp_extract)
                logger.info("Extracting %s", download_path.name)
                extract_archive(download_path, extract_dir)
                move_contents(extract_dir, final_dir)

        except Exception as exc:
            logger.error("Error processing package for product '%s': %s", product, exc)
            raise

    zip_path = safe_join(build_dir, f"{product}_final")
    try:
        logger.info("Creating zip archive for product %s", product)
        archive_file = shutil.make_archive(str(zip_path), "zip", root_dir=str(final_dir))
        os.chmod(archive_file, 0o600)
    except Exception as exc:
        logger.error("Failed to create zip for product '%s': %s", product, exc)
        raise


def load_products(json_path: pathlib.Path) -> dict:
    try:
        with json_path.open("r", encoding="utf-8") as f:
            data = json.load(f)
        if not isinstance(data, dict):
            raise ValueError("JSON root must be an object")
        for key, value in data.items():
            if not isinstance(key, str) or not isinstance(value, list):
                raise ValueError("Invalid product entry")
        return data
    except Exception as exc:
        logger.error("Failed to load products JSON: %s", exc)
        raise


def safe_join(base: pathlib.Path, *paths: str) -> pathlib.Path:
    """Join paths safely without allowing path traversal."""
    base_path = pathlib.Path(base).resolve()
    current = base_path
    for part in paths:
        if pathlib.PurePath(part).is_absolute():
            raise ValueError("Path traversal detected")
        for element in pathlib.Path(part).parts:
            if element == "..":
                raise ValueError("Path traversal detected")
        current = current / part
        # Resolve any existing symlinks in intermediate components
        current = current.resolve(strict=False)
        try:
            current.relative_to(base_path)
        except ValueError:
            raise ValueError("Path traversal detected")
    return current


def main() -> None:
    parser = argparse.ArgumentParser(description="Build product packages")
    parser.add_argument(
        "--products-json",
        type=str,
        required=True,
        help="Path to JSON file containing product -> package URL mapping",
    )
    parser.add_argument(
        "--build-dir",
        type=str,
        required=True,
        help="Path to the build directory (must be an existing absolute path)",
    )
    args = parser.parse_args()

    try:
        build_dir = pathlib.Path(args.build_dir).resolve(strict=True)
        if not build_dir.is_dir():
            raise ValueError("Build directory is not a directory")
    except Exception as exc:
        logger.error("Invalid build directory: %s", exc)
        sys.exit(1)

    try:
        products_path = pathlib.Path(args.products_json).resolve(strict=True)
        if not products_path.is_file():
            raise ValueError("Products JSON path is not a file")
    except Exception as exc:
        logger.error("Invalid products JSON path: %s", exc)
        sys.exit(1)

    try:
        products = load_products(products_path)
    except Exception:
        sys.exit(1)

    for product, package_list in products.items():
        try:
            logger.info("Processing product: %s", product)
            process_product(product, package_list, build_dir)
        except Exception:
            logger.error("Aborting due to errors with product '%s'", product)
            sys.exit(1)

    logger.info("All products processed successfully")


if __name__ == "__main__":
    main()

