# ANSI color codes
COLOR_CMD = "[92m"      # Green
COLOR_INP = "[94m"      # Blue
COLOR_OUT = "[93m"      # Yellow
COLOR_ERR = "[91m"      # Red
COLOR_RESET = "[0m"

# Whitelist of allowed commands and their permitted arguments
ALLOWED_CMDS = {
    "ls": {"-l", "-a", "--color=never"},
    "echo": set(),
    "date": set(),
    "whoami": set(),
}

# Maximum number of bytes to keep from command output (prevent OOM)
MAX_OUTPUT_BYTES = 1_000_000  # 1â¯MiB
# Maximum length for a single argument (prevent huge payloads)
MAX_ARG_LENGTH = 4096

# Regex to strip ANSI escape sequences from userâcontrolled strings
_ANSI_ESCAPE_RE = re.compile(r"\[[0-9;]*[mK]")

def strip_ansi(s: str) -> str:
    """Remove ANSI escape sequences."""
    return _ANSI_ESCAPE_RE.sub("", s)

def remove_control_chars(s: str) -> str:
    """Remove nonâprintable control characters."""
    return re.sub(r"[�-]", "", s)

def sanitize_description(s: str) -> str:
    """Fully sanitize description strings for terminal output."""
    return remove_control_chars(strip_ansi(s))

def safe_load_json(path: str) -> dict:
    """Load JSON file safely and ensure it is a dict of strings."""
    try:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        if not isinstance(data, dict):
            raise ValueError("JSON topâlevel element must be an object.")
        for k, v in data.items():
            if not isinstance(k, str) or not isinstance(v, str):
                raise ValueError("All keys and values must be strings.")
        return data
    except (OSError, json.JSONDecodeError, ValueError) as e:
        sys.stderr.write(f"{COLOR_ERR}Failed to load JSON file: {e}{COLOR_RESET}
")
        sys.exit(1)

def validate_ls_argument(arg: str) -> None:
    """Validate arguments for ls command."""
    if arg.startswith('-'):
        if arg not in ALLOWED_CMDS["ls"]:
            raise ValueError(f"Flag {arg!r} not permitted for ls.")
    else:
        # Disallow absolute paths and parentâdirectory traversal
        if os.path.isabs(arg):
            raise ValueError("Absolute paths are not allowed for ls.")
        norm = os.path.normpath(arg)
        if norm.startswith("..") or "/.." in norm or "..\" in norm:
            raise ValueError("Parent directory traversal is not allowed for ls.")
