        if len(arg) > MAX_ARG_LENGTH:
            raise ValueError("Path argument too long for ls.")

def sanitize_command(cmd: str) -> list:
    """Validate command against whitelist and return tokenised args."""
    parts = shlex.split(cmd)
    if not parts:
        raise ValueError("Command is empty.")
    cmd_name = parts[0]
    if cmd_name not in ALLOWED_CMDS:
        raise ValueError(f"Command {cmd_name!r} is not permitted.")
    allowed_args = ALLOWED_CMDS[cmd_name]
    for arg in parts[1:]:
        if len(arg) > MAX_ARG_LENGTH:
            raise ValueError("Argument exceeds maximum allowed length.")
        if cmd_name == "ls":
            validate_ls_argument(arg)
