            if arg not in allowed_args:
                raise ValueError(f"Argument {arg!r} not permitted for {cmd_name}.")
    return parts

def execute_command(args: list) -> str:
    """Run command with limited output size and timeout."""
    try:
        # Apply a fileâsize limit to the child process (prevents large writes to files)
        def preexec():
            resource.setrlimit(resource.RLIMIT_FSIZE, (MAX_OUTPUT_BYTES, MAX_OUTPUT_BYTES))

        proc = subprocess.Popen(
            args,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            preexec_fn=preexec,
