            ready_fds, _, _ = select.select(
                [fd for fd in (proc.stdout, proc.stderr) if fd],
                [],
                [],
                0.1,
            )
            if not ready_fds and proc.poll() is not None:
                # Process finished and no more data
                break

            for fd in ready_fds:
                chunk = fd.read(1024)
                if not chunk:
                    continue
                chunk_bytes = len(chunk)
                if total_bytes + chunk_bytes > MAX_OUTPUT_BYTES:
                    # Truncate and kill the process
                    allowed = MAX_OUTPUT_BYTES - total_bytes
                    output_chunks.append(chunk[:allowed])
                    total_bytes = MAX_OUTPUT_BYTES
                    proc.kill()
                    break
                else:
                    output_chunks.append(chunk)
                    total_bytes += chunk_bytes

