    parser = argparse.ArgumentParser(
        description="Execute whitelisted commands defined in a JSON file."
    )
    parser.add_argument("json_file", help="Path to JSON file containing commands.")
    parser.add_argument(
        "--no-pause",
        action="store_true",
        help="Do not pause after each command.",
    )
