Interrupted by user.
")
                sys.exit(1)

    try:
        final_json = json.dumps(results, indent=2, ensure_ascii=False)
        print(f"{COLOR_OUT}Collected Results:{COLOR_RESET}
{final_json}")
    except Exception as e:
        sys.stderr.write(f"{COLOR_ERR}Failed to serialize results: {e}{COLOR_RESET}
")

