import java.io.*;
import java.nio.file.*;
import java.util.*;
import java.util.concurrent.atomic.AtomicLong;
import java.util.regex.Pattern;

public class AntlrRunner {

    private static final Path BASE = Paths.get("/opt/antlr-workspace").toAbsolutePath();
    private static final Path JAR_PATH;

    private static final Map<String, Boolean> ALLOWED_OPTIONS;
    private static final Pattern PACKAGE_PATTERN = Pattern.compile("^[a-zA-Z_][a-zA-Z0-9_]*(\.[a-zA-Z_][a-zA-Z0-9_]*)*$");
    private static final Pattern SIMPLE_ALPHANUMERIC = Pattern.compile("^[A-Za-z0-9._-]+$");
    private static final Pattern LANGUAGE_PATTERN = Pattern.compile("^[A-Za-z]+$");
    private static final long MAX_OUTPUT_BYTES = 1_048_576L; // 1 MB

    static {
        Map<String, Boolean> opts = new HashMap<>();
        opts.put("-listener", false);
        opts.put("-no-listener", false);
        opts.put("-visitor", false);
        opts.put("-no-visitor", false);
        opts.put("-encoding", true);
        opts.put("-lib", true);
        opts.put("-package", true);
        opts.put("-Dlanguage", true);
        ALLOWED_OPTIONS = Collections.unmodifiableMap(opts);

        Path jar = BASE.resolve("lib").resolve("antlr.jar");
        try {
            Path resolvedJar = jar.toRealPath(); // resolve all symlinks
            if (!resolvedJar.startsWith(BASE)) {
                throw new IllegalStateException("ANTLR jar resolves outside of sandbox: " + resolvedJar);
            }
            if (!Files.isRegularFile(resolvedJar)) {
                throw new IllegalStateException("ANTLR jar not found at expected location: " + resolvedJar);
            }
            JAR_PATH = resolvedJar;
        } catch (IOException e) {
            throw new IllegalStateException("Failed to resolve ANTLR jar: " + e.getMessage(), e);
        }
    }

    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: java AntlrRunner <outputDir> <grammarFile> [options...]");
            System.exit(1);
        }

        Path outputDir = sanitizePath(args[0], true);
        Path grammarFile = sanitizePath(args[1], false);

        if (outputDir == null || grammarFile == null) {
            System.err.println("Invalid directory or file path.");
            System.exit(1);
        }

        if (!Files.isDirectory(outputDir)) {
            System.err.println("Output directory does not exist or is not a directory: " + outputDir);
            System.exit(1);
        }

        if (!Files.isRegularFile(grammarFile)) {
            System.err.println("Grammar file does not exist or is not a regular file: " + grammarFile);
            System.exit(1);
        }

        List<String> command = new ArrayList<>();
        command.add("java");
        command.add("-jar");
        command.add(JAR_PATH.toString());
        command.add("-o");
        command.add(outputDir.toString());

        for (int i = 2; i < args.length; ) {
            String opt = args[i];
            Boolean expectsValue = ALLOWED_OPTIONS.get(opt);
            if (expectsValue == null) {
                System.err.println("Disallowed option detected: " + opt);
                System.exit(1);
            }
            command.add(opt);
            i++;
            if (expectsValue) {
                if (i >= args.length) {
                    System.err.println("Option " + opt + " requires a value.");
                    System.exit(1);
                }
                String val = args[i];
                if (val.startsWith("-")) {
                    System.err.println("Invalid value for option " + opt + ": " + val);
                    System.exit(1);
                }
                // Validate option value semantics
                switch (opt) {
                    case "-encoding":
                        if (!SIMPLE_ALPHANUMERIC.matcher(val).matches() || val.length() > 50) {
                            System.err.println("Invalid encoding value: " + val);
                            System.exit(1);
                        }
                        break;
                    case "-lib":
                        Path libPath = sanitizePath(val, true);
                        if (libPath == null || !Files.isDirectory(libPath)) {
                            System.err.println("Invalid library path for -lib: " + val);
                            System.exit(1);
                        }
                        val = libPath.toString();
                        break;
                    case "-package":
                        if (!PACKAGE_PATTERN.matcher(val).matches() || val.length() > 100) {
                            System.err.println("Invalid package name: " + val);
                            System.exit(1);
                        }
                        break;
                    case "-Dlanguage":
                        if (!LANGUAGE_PATTERN.matcher(val).matches() || val.length() > 20) {
                            System.err.println("Invalid language specification: " + val);
                            System.exit(1);
                        }
                        break;
                    default:
                        // No extra validation needed
                        break;
                }
                command.add(val);
                i++;
            }
        }

        command.add(grammarFile.toString());

        ProcessBuilder pb = new ProcessBuilder(command);
        pb.redirectErrorStream(false);
        pb.directory(BASE.toFile());

        try {
            Process process = pb.start();

            Thread outThread = new Thread(new StreamGobbler(process.getInputStream(), System.out));
            Thread errThread = new Thread(new StreamGobbler(process.getErrorStream(), System.err));

            outThread.start();
            errThread.start();

            int exitCode = process.waitFor();
            outThread.join();
            errThread.join();

            if (exitCode != 0) {
                System.err.println("ANTLR tool exited with code " + exitCode);
                System.exit(exitCode);
            }
        } catch (IOException e) {
            System.err.println("I/O error while executing ANTLR tool: " + e.getMessage());
            System.exit(1);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            System.err.println("Execution was interrupted.");
            System.exit(1);
        }
    }

    private static Path sanitizePath(String input, boolean allowDirectory) {
        try {
            Path candidate = Paths.get(input).normalize();
            Path resolved = BASE.resolve(candidate).normalize().toAbsolutePath();
            resolved = resolved.toRealPath(); // resolve all symlinks
            if (!resolved.startsWith(BASE)) {
                return null;
            }
            if (!allowDirectory && Files.isDirectory(resolved)) {
                return null;
            }
            return resolved;
        } catch (InvalidPathException | IOException | SecurityException e) {
            return null;
        }
    }

    private static class StreamGobbler implements Runnable {
        private final InputStream stream;
        private final PrintStream out;

        StreamGobbler(InputStream stream, PrintStream out) {
            this.stream = stream;
            this.out = out;
        }

        @Override
        public void run() {
            byte[] buffer = new byte[8192];
            AtomicLong total = new AtomicLong(0);
            int read;
            try (InputStream is = stream) {
                while ((read = is.read(buffer)) != -1) {
                    long current = total.addAndGet(read);
                    if (current > MAX_OUTPUT_BYTES) {
                        int allowed = (int) (read - (current - MAX_OUTPUT_BYTES));
                        if (allowed > 0) {
                            out.write(buffer, 0, allowed);
                        }
                        out.flush();
                        out.println("[Output truncated after reaching limit]");
                        break;
                    }
                    out.write(buffer, 0, read);
                }
            } catch (IOException ignored) {
            }
        }
    }
}

