import os
import json
import logging
import re
import urllib.parse
import urllib.request
import urllib.error
from typing import Optional

YOUTUBE_API_ENDPOINT = "https://www.googleapis.com/youtube/v3/search"
YOUTUBE_WATCH_URL = "https://www.youtube.com/watch?v={video_id}"

YOUTUBE_VIDEO_ID_REGEX = re.compile(
    r"(?:v=|/)([0-9A-Za-z_-]{11})(?:[&?]|$)"
)
RAW_VIDEO_ID_REGEX = re.compile(r"^[0-9A-Za-z_-]{11}$")
API_KEY_REGEX = re.compile(r"^[A-Za-z0-9_-]{10,}$")

_ALLOWED_SCHEMES = {"https"}
_ALLOWED_HOSTS = {"youtube.com", "www.youtube.com", "youtu.be"}


def _is_allowed_scheme(url: str) -> bool:
    """Return True if the URL uses an allowed network scheme."""
    try:
        parsed = urllib.parse.urlparse(url)
        return parsed.scheme.lower() in _ALLOWED_SCHEMES
    except Exception:
        return False


def _extract_video_id_from_url(url: str) -> Optional[str]:
    """Extract a YouTube video ID from a given URL if present, scheme and host are allowed."""
    parsed = urllib.parse.urlparse(url)
    if not parsed.scheme or not parsed.netloc:
        return None
    if parsed.scheme.lower() not in _ALLOWED_SCHEMES:
        return None
    host = parsed.hostname.lower() if parsed.hostname else ""
    if host not in _ALLOWED_HOSTS:
        return None

    query_params = urllib.parse.parse_qs(parsed.query)
    if "v" in query_params and query_params["v"]:
        candidate = query_params["v"][0]
        if RAW_VIDEO_ID_REGEX.fullmatch(candidate):
            return candidate

    match = YOUTUBE_VIDEO_ID_REGEX.search(url)
    if match:
        return match.group(1)
    return None


def resolve_youtube_url(track_name: str, logger: logging.Logger) -> Optional[str]:
    """
    Resolve a track name or YouTube URL to a canonical YouTube watch URL.

    Args:
        track_name: Input string, either a raw track name or a YouTube URL.
        logger: Logger instance for debug messages.

    Returns:
        A string with the YouTube watch URL, or None if resolution fails.
    """
    if not isinstance(track_name, str):
        logger.info("Invalid input type for track name.")
        raise TypeError("track_name must be a string.")

    query = track_name.strip()
    if not query:
        logger.info("Empty track name after stripping.")
        return None
    if len(query) > 256:
        logger.info("Input exceeds maximum allowed length.")
        return None
    if any(ord(ch) < 32 for ch in query):
        logger.info("Input contains control characters.")
        return None

    video_id = _extract_video_id_from_url(query)
    if video_id:
        return YOUTUBE_WATCH_URL.format(video_id=video_id)

    api_key = os.getenv("YOUTUBE_API_KEY")
    if not api_key:
        logger.info("YouTube API key not configured.")
        raise EnvironmentError("YouTube API key not set in environment.")
    if not API_KEY_REGEX.fullmatch(api_key):
        logger.info("Invalid API key format detected.")
        raise EnvironmentError("Invalid YouTube API key format.")

    params = {
        "part": "snippet",
        "q": query,
        "type": "video",
        "maxResults": "1",
        "key": api_key,
    }
    url = f"{YOUTUBE_API_ENDPOINT}?{urllib.parse.urlencode(params)}"

    if not _is_allowed_scheme(url):
        logger.info("Disallowed URL scheme in API request.")
        return None

    request = urllib.request.Request(
        url,
        headers={
            "Accept": "application/json",
            "User-Agent": "secure-youtube-resolver/1.0",
        },
        method="GET",
    )

    try:
        with urllib.request.urlopen(request, timeout=10) as resp:
            if resp.status != 200:
                logger.info("YouTube API returned non-200 status.")
                return None
            resp_body = resp.read()
    except urllib.error.HTTPError:
        logger.info("HTTP error while contacting YouTube API.")
        return None
    except urllib.error.URLError:
        logger.info("URL error while contacting YouTube API.")
        return None
    except Exception:
        logger.info("Unexpected error during YouTube API request.")
        return None

    try:
        data = json.loads(resp_body.decode("utf-8"))
    except json.JSONDecodeError:
        logger.info("Failed to parse JSON response from YouTube API.")
        return None

    items = data.get("items")
    if not items:
        logger.info("YouTube API response contains no items.")
        return None

    video_id = items[0].get("id", {}).get("videoId")
    if not video_id:
        logger.info("Video ID missing in YouTube API result.")
        return None

    return YOUTUBE_WATCH_URL.format(video_id=video_id)

