import os
import pathlib
import subprocess
import hashlib
import stat
import fcntl

# Absolute path to the trusted validator binary
VALIDATOR_ABSOLUTE_PATH = "/usr/local/bin/validator"  # replace with the real path

# Expected SHAâ256 hash of the validator binary (hex string). Must be nonâempty in production.
EXPECTED_VALIDATOR_HASH = "e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855"  # placeholder

# Maximum allowed size for the file to be validated (10â¯MiB)
MAX_FILE_SIZE = 10 * 1024 * 1024

# Minimal safe environment for the validator
SAFE_ENV = {}

def print_error(message: str) -> None:
    """Write error messages to stderr without leaking sensitive information."""
    sys.stderr.write(f"Error: {message}
")
    sys.stderr.flush()

def verify_validator(fd: int) -> bool:
    """Verify the validator binary opened via file descriptor."""
    try:
        st = os.fstat(fd)
        if not stat.S_ISREG(st.st_mode):
            return False

        sha256 = hashlib.sha256()
        with os.fdopen(os.dup(fd), "rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                sha256.update(chunk)

        return sha256.hexdigest() == EXPECTED_VALIDATOR_HASH
    except Exception:
        return False

def open_and_validate_file(path_str: str) -> pathlib.Path:
    """Open the target file atomically, ensure it is a regular file, and enforce size limits."""
    fd = os.open(path_str, os.O_RDONLY | os.O_NOFOLLOW)
    try:
        st = os.fstat(fd)
        if not stat.S_ISREG(st.st_mode):
            raise OSError("Not a regular file")
        if st.st_size > MAX_FILE_SIZE:
            raise OSError("File size exceeds allowed limit")
    finally:
        os.close(fd)

    return pathlib.Path(path_str)

def sanitize_error(err: str, limit: int = 500) -> str:
    err = err.strip()
    if len(err) > limit:
        err = err[:limit] + "..."
    return err

def open_validator_fd(path: str) -> int:
    """Open validator binary with O_NOFOLLOW and acquire an exclusive lock."""
    fd = os.open(path, os.O_RDONLY | os.O_NOFOLLOW)
    try:
        fcntl.flock(fd, fcntl.LOCK_EX)
        st = os.fstat(fd)
        if not (st.st_mode & (stat.S_IXUSR | stat.S_IXGRP | stat.S_IXOTH)):
            raise OSError("Validator is not executable")
    except Exception:
        os.close(fd)
        raise
    return fd

def main() -> None:
    if len(sys.argv) != 2:
        print_error("Usage: script.py <file_path>")
        sys.exit(1)

    raw_path = sys.argv[1]
    try:
        file_path = pathlib.Path(raw_path).expanduser()
        if not file_path.is_absolute():
            file_path = (pathlib.Path.cwd() / file_path).resolve()
        else:
            file_path = file_path.resolve()
    except Exception:
        print_error("Invalid file path.")
        sys.exit(1)

    # Restrict processing to files within the current working directory
    cwd = pathlib.Path.cwd().resolve()
    try:
        file_path.relative_to(cwd)
    except ValueError:
        print_error("File path is outside the allowed directory.")
        sys.exit(1)

    try:
        open_and_validate_file(str(file_path))
    except Exception as e:
        print_error(str(e) or "Unable to read the specified file or it is not a regular file.")
        sys.exit(1)

    # Ensure a real validator hash is configured
    if EXPECTED_VALIDATOR_HASH in ("", "e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855"):
        print_error("Validator hash is not configured with a real value.")
        sys.exit(1)

    try:
        validator_fd = open_validator_fd(VALIDATOR_ABSOLUTE_PATH)
    except OSError:
        print_error("Validator binary is missing, not executable, or is a symlink.")
        sys.exit(1)

    try:
        if not verify_validator(validator_fd):
            print_error("Validator integrity check failed.")
            sys.exit(1)

        validator_path_fd = f"/proc/self/fd/{validator_fd}"
        result = subprocess.run(
            [validator_path_fd, str(file_path)],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            timeout=30,
            env=SAFE_ENV,
            pass_fds=(validator_fd,),
        )
    except subprocess.TimeoutExpired:
        print_error("Validation timed out.")
        sys.exit(1)
    except OSError:
        print_error("Failed to execute the validation tool.")
        sys.exit(1)
    finally:
        os.close(validator_fd)

    if result.returncode == 0:
        sys.exit(0)
    else:
        error_output = sanitize_error(result.stderr)
        if error_output:
            print_error(error_output)
        else:
            print_error("Validation failed.")
        sys.exit(result.returncode if result.returncode != 0 else 1)

if __name__ == "__main__":
    main()

import json
import logging
import re
import socket
import ipaddress
from typing import Any, Dict, Optional
from urllib.parse import urlparse

import requests

logging.basicConfig(level=logging.INFO)
_logger = logging.getLogger(__name__)

_TOKEN_RE = re.compile(r'^[A-Za-z0-9\-_\.]+$')
_ALLOWED_SCHEMES = {"http", "https"}


def _is_private_ip(address: str) -> bool:
    try:
        ip = ipaddress.ip_address(address)
        return ip.is_private or ip.is_loopback or ip.is_reserved or ip.is_link_local
    except ValueError:
        # Not a valid IP address
        return False


def _host_is_allowed(hostname: str) -> bool:
    # Reject obvious internal hostnames
    if hostname.lower() in {"localhost", "127.0.0.1", "::1"}:
        return False

    try:
        addr_info = socket.getaddrinfo(hostname, None)
    except socket.gaierror:
        return False

    for family, _, _, _, sockaddr in addr_info:
        ip_str = sockaddr[0]
        if _is_private_ip(ip_str):
            return False
    return True


def _is_valid_url(url: str) -> bool:
    try:
        result = urlparse(url)
        if result.scheme not in _ALLOWED_SCHEMES:
            return False
        if not result.netloc:
            return False
        if result.username or result.password:
            return False
        if "@" in result.netloc:
            # Additional safeguard against hidden userâinfo
            return False
        hostname = result.hostname
        if not hostname:
            return False
        return _host_is_allowed(hostname)
    except Exception:
        return False


def post_json(url: str, payload: Dict[str, Any], token: str, timeout: float = 10.0) -> Optional[requests.Response]:
    """
    Send a POST request with a JSON payload.

    Args:
        url: Destination URL (must be HTTP or HTTPS and not point to internal resources).
        payload: Dictionary to be JSONâencoded and sent as the request body.
        token: Access token used for the Authorization header.
        timeout: Request timeout in seconds.

    Returns:
        requests.Response object on success, otherwise None.
    """
    if not isinstance(url, str) or not _is_valid_url(url):
        raise ValueError("Invalid URL provided.")
    if not isinstance(token, str) or not token:
        raise ValueError("Invalid authorization token.")
    if not _TOKEN_RE.fullmatch(token):
        raise ValueError("Authorization token contains illegal characters.")
    if not isinstance(payload, dict):
        raise ValueError("Payload must be a dictionary.")

    try:
        json_data = json.dumps(payload, ensure_ascii=False, separators=(",", ":"))
    except (TypeError, ValueError) as exc:
        raise ValueError("Payload is not JSON serializable.") from exc

    headers = {
        "Content-Type": "application/json",
        "Authorization": f"Bearer {token}",
    }

    try:
        response = requests.post(
            url,
            data=json_data,
            headers=headers,
            timeout=timeout,
            verify=True,
            allow_redirects=False,
        )
        response.raise_for_status()
        return response
    except requests.RequestException as exc:
        _logger.error("HTTP request failed: %s", str(exc))
        return None

