import logging
import re
import socket
import ipaddress
from urllib.parse import urljoin, urlparse

import requests
from requests.exceptions import RequestException, Timeout

logger = logging.getLogger(__name__)
logger.addHandler(logging.NullHandler())

class AssetUpdateError(Exception):
    """Generic error for asset update failures without leaking internal details."""
    pass

def _is_public_ip(ip: str) -> bool:
    try:
        addr = ipaddress.ip_address(ip)
        return not (addr.is_private or addr.is_loopback or addr.is_reserved or addr.is_link_local)
    except ValueError:
        return False

def _hostname_resolves_to_public(hostname: str) -> bool:
    try:
        infos = socket.getaddrinfo(hostname, None)
        return any(_is_public_ip(info[4][0]) for info in infos)
    except socket.gaierror:
        return False

def _is_valid_url(url: str) -> bool:
    """Validate that the URL uses HTTPS, has a netloc, and resolves to a public address."""
    try:
        parsed = urlparse(url)
        if parsed.scheme != "https" or not parsed.netloc:
            return False
        hostname = parsed.hostname
        return hostname is not None and _hostname_resolves_to_public(hostname)
    except Exception:
        return False

def _sanitize_name(name: str) -> str:
    name = name.strip()
    if not (1 <= len(name) <= 100):
        raise ValueError("Asset name must be between 1 and 100 characters.")
    if not re.fullmatch(r"[A-Za-z0-9 _-]+", name):
        raise ValueError("Asset name contains illegal characters.")
    return name

def _validate_token(token: str) -> None:
    if not token or not isinstance(token, str):
        raise ValueError("Authentication token must be a nonâempty string.")
    # Basic pattern check for JWTâlike token (optional)
    if not re.fullmatch(r"[A-Za-z0-9\-_\.]+", token):
        raise ValueError("Authentication token contains illegal characters.")

def _sanitize_json(data: dict) -> dict:
    """Remove potentially unsafe keys and ensure simple JSON types."""
    if not isinstance(data, dict):
        raise AssetUpdateError("Unexpected JSON structure.")
    safe_data = {}
    for k, v in data.items():
        if isinstance(k, str) and not k.startswith("__"):
            if isinstance(v, (str, int, float, bool, type(None), list, dict)):
                safe_data[k] = v
    return safe_data

def update_asset_type(
    base_url: str,
    asset_type_id: str,
    new_name: str,
    auth_token: str,
    timeout: int = 5,
    ca_bundle: str | None = None,
) -> dict:
    """
    Update an asset type by creating a new one with a renamed value
    and deleting the original entry.

    Parameters
    ----------
    base_url : str
        Base HTTPS URL of the asset service.
    asset_type_id : str
        Identifier of the asset type to replace; must be URLâsafe.
    new_name : str
        Desired new name for the asset type.
    auth_token : str
        Bearer token used for authentication.
    timeout : int, optional
        Seconds to wait for each HTTP request.
    ca_bundle : str | None, optional
        Path to a CA bundle for TLS verification. If omitted, system defaults are used.

    Returns
    -------
    dict
        JSON representation of the newly created asset type.

    Raises
    ------
    AssetUpdateError
        If any step of the process fails.
    ValueError
        If inputs are malformed.
    """
    if not _is_valid_url(base_url):
        raise ValueError("Base URL must be a valid public HTTPS URL.")

    if not re.fullmatch(r"[A-Za-z0-9_-]+", asset_type_id):
        raise ValueError("Asset type ID contains illegal characters.")

    new_name = _sanitize_name(new_name)
    _validate_token(auth_token)

    session = requests.Session()
    session.headers.update({
        "Accept": "application/json",
        "Content-Type": "application/json",
        "Authorization": f"Bearer {auth_token}",
    })
    session.verify = ca_bundle if ca_bundle is not None else True

    # Helper to perform a request with consistent parameters
    def _do_request(method: str, url: str, **kwargs):
        try:
            resp = session.request(method, url, timeout=timeout, **kwargs)
            resp.raise_for_status()
            return resp
        except (RequestException, Timeout) as exc:
            logger.debug("%s request to %s failed: %s", method, url, exc, exc_info=True)
            raise

    # Step 1: Retrieve current asset type
    get_url = urljoin(base_url, f"asset-types/{asset_type_id}")
    try:
        resp = _do_request("GET", get_url)
        current_asset = _sanitize_json(resp.json())
    except ValueError:
        logger.debug("Invalid JSON in GET response.", exc_info=True)
        raise AssetUpdateError("Malformed response from server.") from None
    except Exception as exc:
        raise AssetUpdateError("Failed to retrieve current asset type.") from None

    # Step 2: Create new asset type with updated name
    create_url = urljoin(base_url, "asset-types")
    payload = {
        "name": new_name,
        **{k: v for k, v in current_asset.items() if k not in ("id", "name")}
    }
    try:
        resp = _do_request("POST", create_url, json=payload)
        new_asset = _sanitize_json(resp.json())
    except ValueError:
        logger.debug("Invalid JSON in POST response.", exc_info=True)
        raise AssetUpdateError("Malformed response when creating asset.") from None
    except Exception as exc:
        raise AssetUpdateError("Failed to create updated asset type.") from None

    # Step 3: Delete the old asset type
    delete_url = urljoin(base_url, f"asset-types/{asset_type_id}")
    try:
        _do_request("DELETE", delete_url)
    except Exception:
        # Roll back creation of the new asset
        rollback_id = new_asset.get("id")
        if rollback_id:
            rollback_url = urljoin(base_url, f"asset-types/{rollback_id}")
            try:
                _do_request("DELETE", rollback_url)
            except Exception:
                logger.debug("Rollback deletion failed.", exc_info=True)
        raise AssetUpdateError("Failed to delete original asset type.") from None

    return new_asset

import json
import logging
import sys
import socket
import ipaddress
from typing import Any, Dict, List
from urllib.parse import urlparse

import requests
from requests.exceptions import (
    RequestException,
    Timeout,
    TooManyRedirects,
    HTTPError,
)

# Configure logger
logger = logging.getLogger(__name__)
handler = logging.StreamHandler(sys.stderr)
formatter = logging.Formatter("%(asctime)s - %(levelname)s - %(message)s")
handler.setFormatter(formatter)
logger.addHandler(handler)
logger.setLevel(logging.INFO)

# Constants
MAX_CONTENT_LENGTH = 1_048_576  # 1 MB
ALLOWED_SCHEMES = {"https", "http"}  # https preferred, but http allowed for internal services


class ApiFetchError(Exception):
    """Generic error raised for API fetching problems."""


def _is_private_ip(ip: str) -> bool:
    """Return True if the IP address is private or loopback."""
    try:
        addr = ipaddress.ip_address(ip)
        return addr.is_private or addr.is_loopback
    except ValueError:
        return False


def _is_valid_hostname(hostname: str) -> bool:
    """Basic validation for hostname characters."""
    if not hostname:
        return False
    allowed = set("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-.")
    return all(c in allowed for c in hostname)


def _is_valid_url(url: str) -> bool:
    """Validate URL scheme, hostname, and ensure it does not resolve to private IPs."""
    try:
        result = urlparse(url)
        if result.scheme not in ALLOWED_SCHEMES or not result.netloc:
            return False

        hostname = result.hostname
        if not hostname or not _is_valid_hostname(hostname):
            return False

        # Resolve hostname to IPs and reject if any IP is private/loopback
        try:
            addr_info = socket.getaddrinfo(hostname, None)
        except socket.gaierror:
            return False

        for family, _, _, _, sockaddr in addr_info:
            ip = sockaddr[0]
            if _is_private_ip(ip):
                return False
        return True
    except Exception:
        return False


def _validate_structure(data: Any, required_keys: List[str]) -> List[Dict[str, Any]]:
    """
    Ensure the payload is a list of dicts containing at least the required keys.
    Returns the validated list or raises ApiFetchError.
    """
    if not isinstance(data, list):
        raise ApiFetchError("Response JSON is not a list as expected.")
    for idx, item in enumerate(data):
        if not isinstance(item, dict):
            raise ApiFetchError(f"Item at index {idx} is not an object.")
        missing = [k for k in required_keys if k not in item]
        if missing:
            raise ApiFetchError(
                f"Item at index {idx} missing keys: {', '.join(missing)}"
            )
    return data  # type: ignore[return-value]


def _read_limited_json(response: requests.Response) -> Any:
    """
    Read JSON response with size limitation.
    Raises ApiFetchError if size exceeds limit or JSON is invalid.
    """
    content_length = response.headers.get("Content-Length")
    if content_length is not None:
        try:
            if int(content_length) > MAX_CONTENT_LENGTH:
                raise ApiFetchError("Response payload exceeds allowed size.")
        except ValueError:
            pass  # ignore malformed header

    gathered = bytearray()
    try:
        for chunk in response.iter_content(chunk_size=8192):
            if not chunk:
                continue
            gathered.extend(chunk)
            if len(gathered) > MAX_CONTENT_LENGTH:
                raise ApiFetchError("Response payload exceeds allowed size.")
    finally:
        response.close()

    try:
        text = gathered.decode(response.encoding or "utf-8")
        return json.loads(text)
    except (UnicodeDecodeError, json.JSONDecodeError) as e:
        logger.warning("Invalid JSON response.")
        raise ApiFetchError("Failed to decode JSON.") from e


def fetch_and_validate(
    url: str, required_keys: List[str], *, timeout: int = 10
) -> List[Dict[str, Any]]:
    """
    Fetch JSON data from a REST endpoint, verify it is a list of objects with required keys.
    """
    # Input validation
    if not _is_valid_url(url):
        raise ApiFetchError("Invalid URL provided.")
    if not isinstance(required_keys, list) or not all(isinstance(k, str) for k in required_keys):
        raise ApiFetchError("required_keys must be a list of strings.")

    try:
        response = requests.get(
            url,
            timeout=timeout,
            verify=True,  # Enforce TLS verification
            allow_redirects=False,
            stream=True,
        )
        response.raise_for_status()
    except (Timeout, TooManyRedirects) as e:
        logger.warning("Network issue while contacting API: %s", e.__class__.__name__)
        raise ApiFetchError("Network timeout or redirect error.") from e
    except HTTPError as e:
        logger.warning("HTTP error %s from API.", e.response.status_code)
        raise ApiFetchError("Unexpected HTTP response.") from e
    except RequestException as e:
        logger.warning("RequestException encountered.")
        raise ApiFetchError("Failed to fetch data from API.") from e

    # Content-Type validation (allow only JSON)
    ct = response.headers.get("Content-Type", "")
    if "application/json" not in ct.lower():
        response.close()
        raise ApiFetchError("Response content is not JSON.")

    payload = _read_limited_json(response)

    # Validate structure
    return _validate_structure(payload, required_keys)

import json
import logging
import socket
import ssl
import urllib.error
import urllib.parse
import urllib.request
import ipaddress
import concurrent.futures
from typing import Any, Dict, List, Tuple

logger = logging.getLogger(__name__)
logger.setLevel(logging.INFO)
handler = logging.StreamHandler()
formatter = logging.Formatter("%(asctime)s %(levelname)s %(name)s %(message)s")
handler.setFormatter(formatter)
logger.addHandler(handler)


class DeleteResourceError(Exception):
    """Custom exception for delete_resource failures."""


def _is_ip_private(ip: str) -> bool:
    try:
        addr = ipaddress.ip_address(ip)
        return (
            addr.is_private
            or addr.is_loopback
            or addr.is_link_local
            or addr.is_unspecified
        )
    except ValueError:
        return False


def _resolve_host(host: str, timeout: float = 5.0) -> List[str]:
    """Resolve host to a list of IP addresses with a timeout."""
    def _lookup() -> List[str]:
        infos = socket.getaddrinfo(host, None, proto=socket.IPPROTO_TCP)
        return list({info[4][0] for info in infos})

    with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:
        future = executor.submit(_lookup)
        try:
            return future.result(timeout=timeout)
        except concurrent.futures.TimeoutError as exc:
            raise DeleteResourceError(f"DNS resolution timed out for host '{host}'") from exc
        except socket.gaierror as exc:
            raise DeleteResourceError(f"DNS resolution failed for host '{host}': {exc}") from exc
        except Exception as exc:
            raise DeleteResourceError(f"Unexpected error during DNS resolution for host '{host}': {exc}") from exc


def _validate_url(url: str) -> Tuple[urllib.parse.ParseResult, str]:
    """Validate URL scheme and that it does not resolve to private IPs.
    Returns the parsed URL and a safe IP address (first resolved IP)."""
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme not in ("http", "https"):
        raise ValueError("URL must use http or https scheme")
    if not parsed.netloc:
        raise ValueError("URL must have a network location")

    host = parsed.hostname
    if not host:
        raise ValueError("URL must contain a valid hostname")

    ip_addresses = _resolve_host(host)
    for ip in ip_addresses:
        if _is_ip_private(ip):
            raise ValueError(f"URL resolves to a prohibited IP address: {ip}")

    # Return first IP (any valid public IP) for pinning.
    safe_ip = ip_addresses[0]
    return parsed, safe_ip


def _sanitize_payload(payload: Dict[str, Any]) -> bytes:
    """Serialize payload to JSON bytes after basic validation."""
    if not isinstance(payload, dict):
        raise ValueError("Payload must be a dictionary")
    try:
        return json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    except (TypeError, ValueError) as exc:
        raise ValueError("Payload contains non-serializable values") from exc


def _build_opener(context: ssl.SSLContext) -> urllib.request.OpenerDirector:
    """Create an opener that disables redirects and enforces SSL verification."""
    class NoRedirectHandler(urllib.request.HTTPRedirectHandler):
        def redirect_request(self, req, fp, code, msg, hdrs, newurl):
            raise urllib.error.HTTPError(
                req.full_url,
                code,
                f"Redirects are disabled (received {code})",
                hdrs,
                fp,
            )

    return urllib.request.build_opener(NoRedirectHandler, urllib.request.HTTPSHandler(context=context))


def _ip_to_host(ip: str, port: int | None) -> str:
    """Return a host component suitable for URLs, handling IPv6."""
    if ":" in ip:  # IPv6
        host = f"[{ip}]"
    else:
        host = ip
    if port:
        host = f"{host}:{port}"
    return host


def delete_resource(url: str, payload: Dict[str, Any], expected_message: str) -> Dict[str, Any]:
    """
    Send a POST request to delete a resource and verify the response.

    Args:
        url: Target endpoint.
        payload: JSON-serializable data to include in the request body.
        expected_message: The exact value expected in the response's 'message' field.

    Returns:
        The parsed JSON response as a dictionary.

    Raises:
        DeleteResourceError: For any failure during the operation.
    """
    parsed_url, safe_ip = _validate_url(url)
    data = _sanitize_payload(payload)

    # Build URL that pins to the resolved IP.
    port_part = f":{parsed_url.port}" if parsed_url.port else ""
    ip_host = _ip_to_host(safe_ip, parsed_url.port)
    path = parsed_url.path or "/"
    if parsed_url.query:
        path = f"{path}?{parsed_url.query}"
    pinned_url = f"{parsed_url.scheme}://{ip_host}{path}"

    # Preserve original Host header (including original port if nonâstandard).
    original_host = parsed_url.hostname
    if parsed_url.port and not ((parsed_url.scheme == "http" and parsed_url.port == 80) or
                                (parsed_url.scheme == "https" and parsed_url.port == 443)):
        original_host = f"{original_host}:{parsed_url.port}"

    request = urllib.request.Request(
        pinned_url,
        data=data,
        method="POST",
        headers={
            "Content-Type": "application/json",
            "Host": original_host,
        },
    )

    # Enforce SSL verification explicitly.
    ssl_context = ssl.create_default_context()
    opener = _build_opener(ssl_context)

    MAX_RESPONSE_SIZE = 1024 * 1024  # 1â¯MiB

    try:
        with opener.open(request, timeout=10) as resp:
            content_type = resp.headers.get_content_type()
            if content_type != "application/json":
                raise DeleteResourceError(f"Unexpected content type: {content_type}")

            # Enforce size limit based on Content-Length if provided.
            content_length = resp.headers.get("Content-Length")
            if content_length is not None:
                try:
                    length = int(content_length)
                    if length > MAX_RESPONSE_SIZE:
                        raise DeleteResourceError(f"Response size {length} exceeds limit of {MAX_RESPONSE_SIZE} bytes")
                except ValueError:
                    pass  # ignore malformed header and rely on read limit

            resp_body = resp.read(MAX_RESPONSE_SIZE + 1)
            if len(resp_body) > MAX_RESPONSE_SIZE:
                raise DeleteResourceError("Response exceeds maximum allowed size")

            charset = resp.headers.get_content_charset() or "utf-8"
            resp_text = resp_body.decode(charset, errors="replace")

        try:
            response_data = json.loads(resp_text)
        except json.JSONDecodeError as exc:
            raise DeleteResourceError("Invalid JSON response") from exc

        if not isinstance(response_data, dict):
            raise DeleteResourceError("Response JSON is not an object")

        message = response_data.get("message")
        if message != expected_message:
            raise DeleteResourceError(f"Unexpected message: {message!r}")

        logger.info("POST request to %s completed successfully", url)
        return response_data

    except urllib.error.HTTPError as exc:
        logger.error("HTTP error while contacting %s: %s", url, exc)
        raise DeleteResourceError(f"HTTP error: {exc.code}") from exc
    except urllib.error.URLError as exc:
        logger.error("Network error while contacting %s: %s", url, exc)
        raise DeleteResourceError("Network error occurred") from exc
    except DeleteResourceError:
        raise
    except Exception as exc:
        logger.exception("Unexpected error during delete_resource")
        raise DeleteResourceError("Unexpected error") from exc

import hashlib
import secrets
from typing import Optional


def hash_message(
    message: str,
    algorithm: str = "sha256",
    salt: Optional[bytes] = None,
    iterations: int = 200_000,
) -> str:
    """
    Derive a secure hash of a message using a KDF (PBKDF2-HMAC) with a random or supplied salt.

    Returns a string in the format ``salt_hex$hash_hex``.
    """
    # Validate input types
    if not isinstance(message, str):
        raise TypeError("Message must be a string")
    if not isinstance(algorithm, str):
        raise TypeError("Algorithm must be a string")
    if not isinstance(iterations, int) or iterations <= 0:
        raise ValueError("Iterations must be a positive integer")
    if salt is not None and not isinstance(salt, (bytes, bytearray)):
        raise TypeError("Salt must be bytes or None")

    # Normalize and validate algorithm name
    algo = algorithm.strip().lower()
    if not algo:
        raise ValueError("Algorithm name cannot be empty")
    allowed_algorithms = {"sha256", "sha384", "sha512"}
    if algo not in allowed_algorithms:
        raise ValueError(f"Unsupported algorithm: {algorithm}")

    # Generate a random salt if not provided
    if salt is None:
        salt = secrets.token_bytes(16)  # 128âbit random salt

    # Derive the key using PBKDF2-HMAC
    try:
        derived_key = hashlib.pbkdf2_hmac(algo, message.encode("utf-8"), salt, iterations)
    except (ValueError, TypeError) as exc:
        raise RuntimeError("Key derivation failed") from exc

    # Return the salt and derived key in hex representation
    return f"{salt.hex()}${derived_key.hex()}"

import urllib.request
import urllib.error
import urllib.parse
import json
import logging
import re
import ssl
import ipaddress
import socket
from typing import Any, Dict, Optional

MAX_RESPONSE = 5 * 1024 * 1024  # 5â¯MiB
_ALLOWED_HOSTS = set()  # Populate with explicit hostnames if an allowâlist is desired


def _log_url_validation_error(exc: Exception) -> None:
    logging.getLogger(__name__).debug("URL validation error: %s", exc)


def _is_valid_https_url(url: str) -> bool:
    """Validate URL syntax and HTTPS scheme."""
    try:
        parsed = urllib.parse.urlparse(url)
        if parsed.scheme.lower() != "https" or not parsed.netloc:
            return False
        host = parsed.hostname
        if not host:
            return False
        # Simple hostname format check for nonâIP hosts
        if not re.fullmatch(r"(?:[a-zA-Z0-9-]+\.)+[a-zA-Z]{2,}", host):
            try:
                ipaddress.ip_address(host)  # Accept IPv4/IPv6 literal syntax
            except ValueError:
                return False
        return True
    except Exception as exc:  # pragma: no cover
        _log_url_validation_error(exc)
        return False


def _host_is_allowed(host: str) -> bool:
    """Check the resolved IPs are globally routable and optionally match an allowâlist."""
    try:
        if _ALLOWED_HOSTS and host not in _ALLOWED_HOSTS:
            return False
        addrinfo = socket.getaddrinfo(host, None, proto=socket.IPPROTO_TCP)
        for _, _, _, _, sockaddr in addrinfo:
            ip_str = sockaddr[0]
            ip = ipaddress.ip_address(ip_str)
            if not ip.is_global:
                return False
        return True
    except Exception as exc:  # pragma: no cover
        logging.getLogger(__name__).debug("Host allowâlist validation error: %s", exc)
        return False


def _sanitize_asset_id(asset_id: Any) -> Optional[str]:
    """Accept only integerâlike or UUIDâlike identifiers."""
    if isinstance(asset_id, int):
        return str(asset_id)
    if isinstance(asset_id, str):
        if re.fullmatch(r"\d+", asset_id):
            return asset_id
        if re.fullmatch(
            r"[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[1-5][0-9a-fA-F]{3}-[89abAB][0-9a-fA-F]{3}-[0-9a-fA-F]{12}",
            asset_id,
        ):
            return asset_id
    return None


class _NoRedirect(urllib.request.HTTPRedirectHandler):
    """Prevent automatic following of redirects."""

    def redirect_request(self, req, fp, code, msg, hdrs, newurl):
        return None


def _redact_url(url: str) -> str:
    """Remove query strings and fragments from URLs for safe logging."""
    parsed = urllib.parse.urlparse(url)
    redacted = parsed._replace(query="", fragment="")
    return urllib.parse.urlunparse(redacted)


def test_asset_type_api(base_url: str, asset_type_id: Any, logger: logging.Logger) -> Dict[str, Any]:
    """
    Test retrieval (GET) and deletion (DELETE) of an asset type endpoint.

    Returns a dictionary with status information for each operation.
    """
    result: Dict[str, Any] = {"get": None, "delete": None}

    if not _is_valid_https_url(base_url):
        logger.error("Invalid base URL; must be HTTPS and syntactically correct.")
        return result

    sanitized_id = _sanitize_asset_id(asset_type_id)
    if sanitized_id is None:
        logger.error("Invalid asset type identifier supplied.")
        return result

    endpoint = urllib.parse.urljoin(base_url.rstrip("/") + "/", f"asset-types/{urllib.parse.quote(sanitized_id)}")
    parsed_host = urllib.parse.urlparse(endpoint).hostname
    if not parsed_host or not _host_is_allowed(parsed_host):
        logger.error("Endpoint host validation failed for SSRF protection.")
        return result

    headers = {"Accept": "application/json"}
    ssl_context = ssl.create_default_context()
    opener = urllib.request.build_opener(_NoRedirect)

    def _make_request(method: str) -> Optional[Dict[str, Any]]:
        req = urllib.request.Request(url=endpoint, method=method, headers=headers)
        try:
            with opener.open(req, timeout=10, context=ssl_context) as resp:
                content_type = resp.headers.get("Content-Type", "")
                if "application/json" not in content_type.lower():
                    logger.warning("%s response not JSON (Content-Type: %s).", method, content_type)
                    return None

                raw = resp.read(MAX_RESPONSE + 1)
                if len(raw) > MAX_RESPONSE:
                    logger.error("%s response exceeds maximum allowed size.", method)
                    return {"status": resp.status, "error": "response_too_large"}

                charset = resp.headers.get_content_charset() or "utf-8"
                try:
                    data = json.loads(raw.decode(charset))
                    return {"status": resp.status, "data": data}
                except json.JSONDecodeError:
                    logger.error("%s response contains invalid JSON.", method)
                    return {"status": resp.status, "data": None}
        except urllib.error.HTTPError as e:
            if 300 <= e.code < 400:
                logger.error("%s request resulted in a redirect to %s, which is blocked.", method, e.headers.get("Location"))
                return {"status": e.code, "error": "redirect_blocked"}
            logger.error("%s request failed with HTTP status %s.", method, e.code)
            return {"status": e.code, "error": "http_error"}
        except urllib.error.URLError as e:
            logger.error("%s request failed due to network error: %s.", method, e.reason)
            return {"status": None, "error": "url_error"}
        except Exception:
            logger.exception("%s request encountered an unexpected error.", method)
            return {"status": None, "error": "unexpected_error"}

    logger.info("Testing GET on %s", _redact_url(endpoint))
    result["get"] = _make_request("GET")

    logger.info("Testing DELETE on %s", _redact_url(endpoint))
    result["delete"] = _make_request("DELETE")

    return result

import json
import logging
import socket
import urllib.parse
from typing import Any, Dict, Optional, Set

import requests
import ipaddress
from requests.exceptions import RequestException
from json import JSONDecodeError

_logger = logging.getLogger(__name__)
if not _logger.handlers:
    handler = logging.StreamHandler()
    formatter = logging.Formatter("%(asctime)s - %(levelname)s - %(message)s")
    handler.setFormatter(formatter)
    _logger.addHandler(handler)
    _logger.setLevel(logging.INFO)

# ---------- Configuration ----------
ALLOWED_HOSTS: Set[str] = {"example.com"}  # empty set disables hostname whitelist
MAX_JSON_SIZE = 10 * 1024  # 10 KiB
MAX_KEYS = 100
MAX_DEPTH = 5
MAX_STRING_LENGTH = 200
MAX_LIST_LENGTH = 100
# -----------------------------------


def _is_private_ip(ip_str: str) -> bool:
    try:
        ip = ipaddress.ip_address(ip_str)
        return ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_reserved
    except ValueError:
        return False


def _resolve_hostname(hostname: str) -> Set[str]:
    """Return a set of resolved IP addresses for a hostname."""
    try:
        infos = socket.getaddrinfo(hostname, None)
        return {info[4][0] for info in infos}
    except socket.gaierror:
        return set()


def _validate_url(url: str) -> str:
    parsed = urllib.parse.urlparse(url)

    if parsed.scheme not in ("https", "http"):
        raise ValueError("URL must use http or https scheme")
    if not parsed.netloc:
        raise ValueError("URL must contain a network location")

    hostname = parsed.hostname
    if not hostname:
        raise ValueError("URL must contain a hostname")

    # Hostname whitelist (if configured)
    if ALLOWED_HOSTS and hostname.lower() not in {h.lower() for h in ALLOWED_HOSTS}:
        raise ValueError(f"Hostname '{hostname}' is not in the allowed list")

    # Resolve and block private IPs
    resolved_ips = _resolve_hostname(hostname)
    if not resolved_ips:
        raise ValueError(f"Unable to resolve hostname '{hostname}'")
    for ip in resolved_ips:
        if _is_private_ip(ip):
            raise ValueError(f"Hostname '{hostname}' resolves to disallowed IP address {ip}")

    # Return a normalized URL without query or fragment
    return urllib.parse.urlunparse(parsed._replace(query="", fragment=""))


def _check_limits(data: Any, depth: int = 0) -> None:
    if depth > MAX_DEPTH:
        raise ValueError("Data depth exceeds allowed maximum")
    if isinstance(data, dict):
        if len(data) > MAX_KEYS:
            raise ValueError("Dictionary contains too many keys")
        for key, value in data.items():
            if isinstance(key, str) and len(key) > MAX_STRING_LENGTH:
                raise ValueError("Dictionary key length exceeds allowed limit")
            _check_limits(value, depth + 1)
    elif isinstance(data, list):
        if len(data) > MAX_LIST_LENGTH:
            raise ValueError("List contains too many items")
        for item in data:
            _check_limits(item, depth + 1)
    elif isinstance(data, str):
        if len(data) > MAX_STRING_LENGTH:
            raise ValueError("String length exceeds allowed limit")
    # Other scalar types (int, float, bool, None) are safe


def _sanitize_dict(data: Dict[Any, Any]) -> None:
    if not isinstance(data, dict):
        raise ValueError("Expected a dictionary")
    _check_limits(data)
    try:
        serialized = json.dumps(data)
    except (TypeError, ValueError) as exc:
        raise ValueError("Dictionary contains nonâserializable values") from exc
    if len(serialized.encode("utf-8")) > MAX_JSON_SIZE:
        raise ValueError("Serialized JSON exceeds allowed size")


def post_then_delete(
    server_url: str,
    payload: Dict[Any, Any],
    query_params: Dict[Any, Any],
    check_key: str,
    check_value: Any,
    timeout: float = 5.0,
) -> Optional[Dict[Any, Any]]:
    """
    Sends a POST request with JSON payload, validates the response, and if a
    specific key/value pair exists, performs a DELETE request with given query
    parameters. Returns the decoded JSON response when the condition is met,
    otherwise None.
    """
    try:
        url = _validate_url(server_url)
        _sanitize_dict(payload)
        _sanitize_dict(query_params)

        with requests.Session() as session:
            # Ensure default SSL handling (hostname verification)
            session.verify = True

            # POST request
            post_resp = session.post(
                url,
                json=payload,
                headers={"Content-Type": "application/json"},
                timeout=timeout,
                allow_redirects=False,
            )
            post_resp.raise_for_status()
            try:
                data = post_resp.json()
            except JSONDecodeError as e:
                _logger.error("Failed to decode JSON from POST response")
                raise RuntimeError("Invalid response format") from e

            # Check key/value condition
            if data.get(check_key) != check_value:
                return None

            # DELETE request with query parameters
            delete_resp = session.delete(
                url,
                params=query_params,
                timeout=timeout,
                allow_redirects=False,
            )
            delete_resp.raise_for_status()

            return data

    except (ValueError, RequestException) as e:
        _logger.error("Request failed")
        raise RuntimeError("Operation could not be completed") from e
